/// `%keywords` (`%k`) — stryke language keyword name → category
/// (`"control"`, `"decl"`, `"exception"`, `"phase"`, `"concurrency"`,
/// `"oo"`, `"operator"`, `"visibility"`). Disjoint from `%b` (callable
/// builtins) and `%a` (aliases): a name is in exactly one of the three.
/// `%all = %a + %b + %k` — the union of every name stryke recognizes.
pub fn keywords_hash_map() -> indexmap::IndexMap<String, StrykeValue> {
    KEYWORDS
        .iter()
        .map(|(n, c)| (n.to_string(), StrykeValue::string(c.to_string())))
        .collect()
}

/// O(1) keyword check. Replaces the LSP's local `KW` slice + binary_search
/// with a single source of truth shared with `%k`.
pub fn is_stryke_keyword(name: &str) -> bool {
    KEYWORDS.binary_search_by_key(&name, |(n, _)| *n).is_ok()
}

/// Operator symbol → category. Sigil characters, arithmetic, comparison,
/// pipeline arrows, assignment forms, and other syntactic operators stryke
/// recognises at the token level. Disjoint from `KEYWORDS` — word operators
/// (`and`, `or`, `eq`, `cmp`, `x`, …) live in `KEYWORDS` with category
/// `"operator"`; only symbol/punctuation operators appear here.
///
/// Sorted alphabetically by spelling (ASCII order) so `binary_search`
/// stays valid. The exact spellings match what the lexer emits in
/// `token.rs` (`Token::Plus` → `"+"`, `Token::ThreadArrowPar` → `"~>"`,
/// `Token::DefinedOr` → `"//"`, …).
///
/// Categories:
///   `arith`     — `+ - * / % **`
///   `compare`   — `== != < > <= >= <=>`
///   `logical`   — `&& || // ! ^^`
///   `bitwise`   — `& | ^ ~ << >>`
///   `assign`    — `= += -= *= /= %= **= .= &= |= ^= <<= >>= ||= &&= //= x= ~~=`
///   `string`    — `. x`
///   `binding`   — `=~ !~`
///   `pipeline`  — `|> ~> ~|> ~p> ~d> ~>>` and last-stage variants
///   `range`     — `.. ...`
///   `arrow`     — `-> => ~~`
///   `deref`     — `\` (reference-of)
///   `inc`       — `++ --`
///   `ternary`   — `? :`
///   `sigil`     — `$ @ %` (also a modulo operator in expression context)
///   `punct`     — `( ) [ ] { } , ; <>`
pub const OPERATORS: &[(&str, &str)] = &[
    ("!", "logical"),
    ("!=", "compare"),
    ("!~", "binding"),
    ("$", "sigil"),
    ("%", "sigil"),
    ("%=", "assign"),
    ("&", "bitwise"),
    ("&&", "logical"),
    ("&&=", "assign"),
    ("&=", "assign"),
    ("(", "punct"),
    (")", "punct"),
    ("*", "arith"),
    ("**", "arith"),
    ("**=", "assign"),
    ("*=", "assign"),
    ("+", "arith"),
    ("++", "inc"),
    ("+=", "assign"),
    (",", "punct"),
    ("-", "arith"),
    ("--", "inc"),
    ("-=", "assign"),
    ("->", "arrow"),
    (".", "string"),
    ("..", "range"),
    ("...", "range"),
    (".=", "assign"),
    ("/", "arith"),
    ("//", "logical"),
    ("//=", "assign"),
    ("/=", "assign"),
    (":", "ternary"),
    (";", "punct"),
    ("<", "compare"),
    ("<<", "bitwise"),
    ("<<=", "assign"),
    ("<=", "compare"),
    ("<=>", "compare"),
    ("<>", "punct"),
    ("=", "assign"),
    ("==", "compare"),
    ("=>", "arrow"),
    ("=~", "binding"),
    (">", "compare"),
    (">=", "compare"),
    (">>", "bitwise"),
    (">>=", "assign"),
    ("?", "ternary"),
    ("??", "logical"),
    ("??=", "assign"),
    ("@", "sigil"),
    ("[", "punct"),
    ("\\", "deref"),
    ("]", "punct"),
    ("^", "bitwise"),
    ("^=", "assign"),
    ("{", "punct"),
    ("|", "bitwise"),
    ("|=", "assign"),
    ("|>", "pipeline"),
    ("||", "logical"),
    ("||=", "assign"),
    ("}", "punct"),
    ("~", "bitwise"),
    ("~>", "pipeline"),
    ("~>>", "pipeline"),
    ("~>p", "pipeline"),
    ("~d>", "pipeline"),
    ("~p>", "pipeline"),
    ("~|>", "pipeline"),
    ("~~", "arrow"),
];

/// `%operators` (`%o`) — operator symbol → category. Mirrors `OPERATORS`.
pub fn operators_hash_map() -> indexmap::IndexMap<String, StrykeValue> {
    OPERATORS
        .iter()
        .map(|(n, c)| (n.to_string(), StrykeValue::string(c.to_string())))
        .collect()
}

/// O(1) operator-symbol check.
pub fn is_stryke_operator(name: &str) -> bool {
    OPERATORS.binary_search_by_key(&name, |(n, _)| *n).is_ok()
}

/// Special variable spelling (sigil included) → category. Every entry has
/// a matching LSP hover doc in `lsp.rs::doc_for_label_text`. Categories
/// group related spellings so user code can filter by purpose:
///
///   `topic`         — `$_ @_ _`
///   `error`         — `$! $@ $? $^E`
///   `pid`           — `$$`
///   `regex-match`   — `$& $' $` $+ $^N $^R`
///   `regex-capture` — `$1`..`$9` `@+ @- @^CAPTURE @^CAPTURE_ALL`
///   `io`            — `$, $\ $/ $" $. $| $~ $^A $^L $^F`
///   `process`       — `$< $> $( $)`
///   `args`          — `@ARGV $ARGV @F @INC %INC`
///   `env`           — `%ENV`
///   `signal`        — `%SIG`
///   `script`        — `$0 __FILE__ __LINE__ __PACKAGE__ __SUB__`
///   `caret`         — `$^C $^D $^H $^I $^M $^O $^P $^S $^T $^V $^W $^X %^H %^HOOK`
///   `subscript`     — `$;`
