fn jwt_hash_alg_opt(h: &StrykeValue, line: usize) -> StrykeResult<Option<String>> {
    if let Some(m) = h.as_hash_map() {
        let e = m.get("alg").filter(|x| !x.is_undef());
        return Ok(e.map(|x| x.to_string()));
    }
    if let Some(r) = h.as_hash_ref() {
        let g = r.read();
        let e = g.get("alg").filter(|x| !x.is_undef());
        return Ok(e.map(|x| x.to_string()));
    }
    Err(StrykeError::runtime(
        "jwt_encode: options must be a hash or hashref",
        line,
    ))
}

/// `jwt_encode` — Jwt encode.
fn builtin_jwt_encode(args: &[StrykeValue], line: usize) -> StrykeResult<StrykeValue> {
    let payload = args.first().ok_or_else(|| {
        StrykeError::runtime("jwt_encode: need PAYLOAD, SECRET [, alg => …]", line)
    })?;
    let secret = args
        .get(1)
        .ok_or_else(|| StrykeError::runtime("jwt_encode: need SECRET", line))?;
    let mut alg = "HS256".to_string();
    if let Some(t) = args.get(2) {
        if is_http_opts_hash(t) {
            if let Some(a) = jwt_hash_alg_opt(t, line)? {
                alg = a;
            }
            return crate::jwt::jwt_encode(payload, secret, &alg, line);
        }
    }
    let mut i = 2;
    while i + 1 < args.len() {
        if args[i].to_string() == "alg" {
            alg = args[i + 1].to_string();
        }
        i += 2;
    }
    crate::jwt::jwt_encode(payload, secret, &alg, line)
}

/// `jwt_decode` — Jwt decode.
fn builtin_jwt_decode(args: &[StrykeValue], line: usize) -> StrykeResult<StrykeValue> {
    let token = args
        .first()
        .ok_or_else(|| StrykeError::runtime("jwt_decode: need TOKEN, SECRET", line))?
        .to_string();
    let secret = args
        .get(1)
        .ok_or_else(|| StrykeError::runtime("jwt_decode: need SECRET", line))?;
    crate::jwt::jwt_decode(&token, secret, line)
}

/// `jwt_decode_unsafe` — Jwt decode unsafe.
fn builtin_jwt_decode_unsafe(args: &[StrykeValue], line: usize) -> StrykeResult<StrykeValue> {
    let token = args
        .first()
        .ok_or_else(|| StrykeError::runtime("jwt_decode_unsafe: need TOKEN", line))?
        .to_string();
    crate::jwt::jwt_decode_unsafe(&token, line)
}

#[inline]
fn log_should_emit(level: LogLevelFilter, min: LogLevelFilter) -> bool {
    level >= min
}

fn log_level_style(level: LogLevelFilter, color: bool) -> &'static str {
    if !color {
        return "";
    }
    match level {
        LogLevelFilter::Trace => "\x1b[90m",
        LogLevelFilter::Debug => "\x1b[36m",
        LogLevelFilter::Info => "\x1b[32m",
        LogLevelFilter::Warn => "\x1b[33m",
        LogLevelFilter::Error => "\x1b[31m",
    }
}

fn format_log_hash_kv(v: &StrykeValue, line: usize) -> StrykeResult<String> {
    let mut parts = Vec::new();
    if let Some(m) = v.as_hash_map() {
        for (k, val) in m {
            let s = val.to_string().replace('\n', "\\n").replace('\r', "\\r");
            parts.push(format!("{k}={s}"));
        }
    } else if let Some(r) = v.as_hash_ref() {
        for (k, val) in r.read().iter() {
            let s = val.to_string().replace('\n', "\\n").replace('\r', "\\r");
            parts.push(format!("{k}={s}"));
        }
    } else {
        return Err(StrykeError::runtime(
            "log_* optional second argument must be a hash or hashref",
            line,
        ));
    }
    Ok(parts.join(" "))
}

/// `log_line` — Log line. Returns an integer.
fn builtin_log_line(
    interp: &mut VMHelper,
    args: &[StrykeValue],
    line: usize,
    level: LogLevelFilter,
) -> StrykeResult<StrykeValue> {
    if !log_should_emit(level, interp.log_filter_effective()) {
        return Ok(StrykeValue::integer(0));
    }
    let msg = args
        .first()
        .ok_or_else(|| StrykeError::runtime("log_* needs a message", line))?
        .to_string();
    let extra = if let Some(h) = args.get(1) {
        if h.is_undef() {
            String::new()
        } else {
            format!(" {}", format_log_hash_kv(h, line)?)
        }
    } else {
        String::new()
    };
    let ts = Utc::now().to_rfc3339_opts(chrono::SecondsFormat::Millis, true);
    let use_color = !interp.no_color_effective() && stderr().is_terminal();
    let tag = level.as_str().to_ascii_uppercase();
    let body = format!("{msg}{extra}");
    if use_color {
        let open = log_level_style(level, true);
        let _ = writeln!(stderr(), "{ts} {open}{tag}\x1b[0m {body}");
    } else {
        let _ = writeln!(stderr(), "{ts} [{tag}] {body}");
    }
    Ok(StrykeValue::integer(1))
}

/// `log_json` — Log json. Returns an integer.
fn builtin_log_json(
    interp: &mut VMHelper,
    args: &[StrykeValue],
    line: usize,
) -> StrykeResult<StrykeValue> {
    let level_s = args
        .first()
        .ok_or_else(|| StrykeError::runtime("log_json: need LEVEL, MSG [, \\%fields]", line))?
        .to_string();
    let level_f = LogLevelFilter::parse(&level_s)
        .ok_or_else(|| StrykeError::runtime(format!("log_json: unknown level {level_s}"), line))?;
    if !log_should_emit(level_f, interp.log_filter_effective()) {
        return Ok(StrykeValue::integer(0));
    }
    let msg = args
        .get(1)
        .ok_or_else(|| StrykeError::runtime("log_json: need MSG", line))?
        .to_string();
    let mut obj = serde_json::Map::new();
    if let Some(h) = args.get(2) {
        if !h.is_undef() {
            let j = crate::native_data::perl_to_json_value(h)?;
            match j {
                serde_json::Value::Object(m) => {
                    for (k, v) in m {
                        obj.insert(k, v);
                    }
                }
                _ => {
                    return Err(StrykeError::runtime(
                        "log_json: third arg must be a hash or hashref",
                        line,
                    ));
                }
            }
        }
    }
    let ts = Utc::now().to_rfc3339_opts(chrono::SecondsFormat::Millis, true);
    obj.insert("ts".into(), serde_json::Value::String(ts));
    obj.insert(
        "level".into(),
        serde_json::Value::String(level_f.as_str().to_string()),
    );
    obj.insert("msg".into(), serde_json::Value::String(msg));
    let line_s = serde_json::to_string(&serde_json::Value::Object(obj))
        .map_err(|e| StrykeError::runtime(format!("log_json: {e}"), line))?;
    let _ = writeln!(stderr(), "{line_s}");
    Ok(StrykeValue::integer(1))
}

/// `log_level` — Log level. Returns a string.
fn builtin_log_level(
    interp: &mut VMHelper,
    args: &[StrykeValue],
    line: usize,
) -> StrykeResult<StrykeValue> {
    if args.is_empty() {
        return Ok(StrykeValue::string(
            interp.log_filter_effective().as_str().to_string(),
        ));
    }
    let a = &args[0];
    if a.is_undef() {
        interp.log_level_override = None;
        return Ok(StrykeValue::string(
            interp.log_filter_effective().as_str().to_string(),
        ));
    }
    let name = a.to_string();
    let filt = LogLevelFilter::parse(&name)
        .ok_or_else(|| StrykeError::runtime(format!("log_level: unknown level {name}"), line))?;
    interp.log_level_override = Some(filt);
    Ok(StrykeValue::string(filt.as_str().to_string()))
}

/// `dataframe` — Dataframe.
fn builtin_dataframe(args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    if args.is_empty() {
        return Err(StrykeError::runtime(
            "dataframe needs a file path or a list",
            0,
        ));
    }
    let a = &args[0];
    if a.as_array_vec().is_some() || a.as_array_ref().is_some() {
        return crate::native_data::dataframe_from_elements(a);
    }
    let path = a.to_string();
    if path.is_empty() {
        return Err(StrykeError::runtime("dataframe needs a file path", 0));
    }
    crate::native_data::dataframe_from_path(&path)
}

/// `csv_read` — Csv read.
fn builtin_csv_read(args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    let path = args.first().map(|v| v.to_string()).unwrap_or_default();
    crate::native_data::csv_read(&path)
}

/// `csv_write` — Csv write.
fn builtin_csv_write(args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    if args.is_empty() {
        return Err(StrykeError::runtime("csv_write needs path and row list", 0));
    }
    let path = args[0].to_string();
    if args.len() == 2 {
        let v = &args[1];
        if crate::nanbox::is_heap(v.0) {
            match unsafe { v.heap_ref() } {
                crate::value::HeapObject::Array(a) => {
                    return crate::native_data::csv_write(&path, a);
                }
                crate::value::HeapObject::ArrayRef(r) => {
                    let g = r.read();
                    return crate::native_data::csv_write(
                        &path,
                        &g.iter().cloned().collect::<Vec<_>>(),
                    );
                }
                crate::value::HeapObject::Hash(h) => {
                    return crate::native_data::csv_write(&path, &[StrykeValue::hash(h.clone())]);
                }
                crate::value::HeapObject::HashRef(r) => {
                    let g = r.read();
                    return crate::native_data::csv_write(&path, &[StrykeValue::hash(g.clone())]);
                }
                _ => {}
            }
        }
    }
    crate::native_data::csv_write(&path, &args[1..])
}

/// `sqlite` — Sqlite.
fn builtin_sqlite(args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    let path = args.first().map(|v| v.to_string()).unwrap_or_default();
    crate::native_data::sqlite_open(&path)
}

// ═══════════════════════════════════════════════════════════════════════════
// Bytecode cache builtins — inspect/manage ~/.stryke/scripts.rkyv
// ═══════════════════════════════════════════════════════════════════════════

/// `cacheview` / `cv` — View cached scripts in the rkyv bytecode cache.
///
/// Usage:
///   cacheview()            — list all cached scripts with stats
///   cacheview("path")      — show details for a specific script
///   cacheview("--count")   — just return count
fn builtin_cacheview(args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    use crate::script_cache;

    let cache = match script_cache::CACHE.as_ref() {
        Some(c) => c,
        None => {
            println!("Bytecode cache disabled (STRYKE_CACHE=0)");
            return Ok(StrykeValue::UNDEF);
        }
    };

    let filter = args.first().map(|v| v.to_string());
    if filter.as_deref() == Some("--count") || filter.as_deref() == Some("-c") {
        let (count, _) = cache.stats();
        return Ok(StrykeValue::integer(count));
    }

    let bold = |s: &str| format!("\x1b[1m{}\x1b[0m", s);
    let dim = |s: &str| format!("\x1b[2m{}\x1b[0m", s);
    let cyan = |s: &str| format!("\x1b[36m{}\x1b[0m", s);
    let green = |s: &str| format!("\x1b[32m{}\x1b[0m", s);

    if let Some(path_filter) = filter {
        let rows = cache.list_scripts();
        for (path, prog_kb, chunk_kb, version, cached_at) in rows {
            if path.contains(&path_filter) {
                println!("{}", bold(&path));
                println!("  program:   {:.2} KB", prog_kb);
                println!("  bytecode:  {:.2} KB", chunk_kb);
                println!("  version:   {}", version);
                println!("  cached:    {}", cached_at);
                return Ok(StrykeValue::integer(1));
            }
        }
        println!("No cached script matching '{}'", path_filter);
        return Ok(StrykeValue::integer(0));
    }

    let (count, total_kb) = cache.stats();
    println!("{}", bold("stryke bytecode cache"));
    println!(
        "  path: {}",
        dim(&script_cache::default_cache_path().display().to_string())
    );
    println!(
        "  scripts: {} ({:.2} KB)",
        green(&count.to_string()),
        total_kb as f64 / 1024.0
    );
    println!();

    let rows = cache.list_scripts();
    if rows.is_empty() {
        println!("  {}", dim("(empty)"));
    } else {
        println!(
            "{:<60} {:>10} {:>10}",
            bold("PATH"),
            bold("PROG KB"),
            bold("BC KB")
        );
        for (path, prog_kb, chunk_kb, _version, _cached_at) in rows.iter().take(50) {
            let short = if path.len() > 58 {
                format!("...{}", &path[path.len() - 55..])
            } else {
                path.clone()
            };
            println!("{:<60} {:>10.2} {:>10.2}", short, prog_kb, chunk_kb);
        }
        if rows.len() > 50 {
            println!("  {} ({} more)", dim("..."), rows.len() - 50);
        }
    }
    println!();
    println!("Usage: {} [path] [--count]", cyan("cacheview"));

    Ok(StrykeValue::integer(count))
}

/// `cache_stats` — Return cache stats as hashref: {count => N, bytes => N, path => "...", enabled => 1}.
fn builtin_cache_stats() -> StrykeResult<StrykeValue> {
    use crate::script_cache;
    use indexmap::IndexMap;
    use parking_lot::RwLock;
    use std::sync::Arc;

    let (count, bytes) = script_cache::stats().unwrap_or((0, 0));
    let mut h = IndexMap::new();
    h.insert("count".to_string(), StrykeValue::integer(count));
    h.insert("bytes".to_string(), StrykeValue::integer(bytes));
    h.insert(
        "path".to_string(),
        StrykeValue::string(script_cache::default_cache_path().display().to_string()),
    );
    h.insert(
        "enabled".to_string(),
        StrykeValue::integer(script_cache::cache_enabled() as i64),
    );
    Ok(StrykeValue::hash_ref(Arc::new(RwLock::new(h))))
}

/// `cache_clear` / `cc` — Clear the bytecode cache.
fn builtin_cache_clear() -> StrykeResult<StrykeValue> {
    use crate::script_cache;

    if script_cache::clear() {
        Ok(StrykeValue::integer(1))
    } else {
        Ok(StrykeValue::integer(0))
    }
}

/// `cache_exists` / `ce` — Check if a script is cached. Returns 1 if cached, 0 if not.
fn builtin_cache_exists(args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    use crate::script_cache;
    use std::path::Path;

    let path = args.first().map(|v| v.to_string()).unwrap_or_default();
    if path.is_empty() {
        return Ok(StrykeValue::integer(0));
    }

    let p = Path::new(&path);
    if script_cache::try_load(p).is_some() {
        Ok(StrykeValue::integer(1))
    } else {
        Ok(StrykeValue::integer(0))
    }
}

// ═══════════════════════════════════════════════════════════════════════════
// Stress testing builtins — saturate CPU/memory/IO for load testing
// ═══════════════════════════════════════════════════════════════════════════

/// `stress_cpu` / `scpu` — CPU stress: run SHA256 hashing across ALL cores.
/// Args: optional duration_secs (default 1.0)
/// Returns: total number of hashes computed across all cores
fn builtin_stress_cpu(args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    use sha2::{Digest, Sha256};
    use std::sync::atomic::{AtomicI64, Ordering};
    use std::time::{Duration, Instant};

    let duration_secs = args.first().map(|v| v.to_number()).unwrap_or(1.0);
    let duration = Duration::from_secs_f64(duration_secs.max(0.001));
    let num_cores = std::thread::available_parallelism()
        .map(|p| p.get())
        .unwrap_or(1);

    let total_count = AtomicI64::new(0);
    let start = Instant::now();

    std::thread::scope(|s| {
        for _ in 0..num_cores {
            s.spawn(|| {
                let mut local_count: i64 = 0;
                let mut data = [0u8; 64];

                while start.elapsed() < duration {
                    for _ in 0..1000 {
                        let hash = Sha256::digest(data);
                        data[..32].copy_from_slice(&hash);
                        local_count += 1;
                    }
                }

                total_count.fetch_add(local_count, Ordering::Relaxed);
            });
        }
    });

    Ok(StrykeValue::integer(total_count.load(Ordering::Relaxed)))
}

/// `stress_mem` / `smem` — Memory stress: allocate and touch memory across ALL cores.
/// Args: bytes to allocate (default 100MB)
/// Returns: bytes allocated
fn builtin_stress_mem(args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    let bytes = args.first().map(|v| v.to_int()).unwrap_or(100_000_000) as usize;
    let num_cores = std::thread::available_parallelism()
        .map(|p| p.get())
        .unwrap_or(1);
    let bytes_per_core = bytes / num_cores;

    std::thread::scope(|s| {
        for core_id in 0..num_cores {
            s.spawn(move || {
                let mut buf: Vec<u8> = vec![0u8; bytes_per_core];
                for i in (0..bytes_per_core).step_by(4096) {
                    buf[i] = ((i + core_id) & 0xff) as u8;
                }
                std::hint::black_box(&buf);
            });
        }
    });

    Ok(StrykeValue::integer(bytes as i64))
}

/// `stress_io` / `sio` — IO stress: write and read temp files.
/// Args: optional dir (default /tmp), optional iterations (default 100)
/// Returns: total bytes written
fn builtin_stress_io(args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    use std::fs;
    use std::io::Write;

    let dir = args
        .first()
        .map(|v| v.to_string())
        .unwrap_or_else(|| "/tmp".to_string());
    let iterations = args.get(1).map(|v| v.to_int()).unwrap_or(100) as usize;
    let mut total_bytes: i64 = 0;
    let data = vec![0xABu8; 1_000_000]; // 1MB per write

    for i in 0..iterations {
        let path = format!("{}/stryke_stress_{}", dir, i);
        if let Ok(mut f) = fs::File::create(&path) {
            let _ = f.write_all(&data);
            total_bytes += data.len() as i64;
        }
        let _ = fs::read(&path);
        let _ = fs::remove_file(&path);
    }

    Ok(StrykeValue::integer(total_bytes))
}

/// `stress_test` / `st` — Combined stress test on cluster or local.
/// Args: cluster (optional), duration_secs (default 10)
/// If cluster provided, distributes across workers. Otherwise runs locally.
/// Returns: hashref with stats {cpu_hashes, mem_bytes, io_bytes, workers, duration}
fn builtin_stress_test(args: &[StrykeValue], line: usize) -> StrykeResult<StrykeValue> {
    use indexmap::IndexMap;
    use parking_lot::RwLock;
    use std::sync::Arc;
    use std::time::Instant;

    let start = Instant::now();

    let (cluster_opt, duration_secs) = if let Some(first) = args.first() {
        if first.as_remote_cluster().is_some() {
            let dur = args.get(1).map(|v| v.to_number()).unwrap_or(10.0);
            (Some(first.clone()), dur)
        } else {
            (None, first.to_number())
        }
    } else {
        (None, 10.0)
    };

    let (cpu_hashes, mem_bytes, io_bytes, workers) = if let Some(cluster_pv) = cluster_opt {
        let cluster = cluster_pv.as_remote_cluster().ok_or_else(|| {
            crate::error::StrykeError::runtime("stress_test: invalid cluster", line)
        })?;
        let num_workers = cluster.slots.len();

        let subs_prelude = String::new();
        let block_src = format!(r#"stress_cpu({})"#, duration_secs);
        let capture: Vec<(String, serde_json::Value)> = Vec::new();
        let items: Vec<serde_json::Value> = (0..num_workers)
            .map(|i| serde_json::Value::Number(serde_json::Number::from(i)))
            .collect();

        let results =
            crate::cluster::run_cluster(&cluster, subs_prelude, block_src, capture, items)
                .map_err(|e| {
                    crate::error::StrykeError::runtime(format!("stress_test: {}", e), line)
                })?;

        let mut total_cpu: i64 = 0;
        let total_mem = 100_000_000i64 * num_workers as i64;
        let total_io = 50_000_000i64 * num_workers as i64;

        for r in results {
            total_cpu += r.to_int();
        }

        (total_cpu, total_mem, total_io, num_workers)
    } else {
        let cpu = builtin_stress_cpu(&[StrykeValue::float(duration_secs)])?.to_int();
        let mem = builtin_stress_mem(&[StrykeValue::integer(100_000_000)])?.to_int();
        let io = builtin_stress_io(&[
            StrykeValue::string("/tmp".to_string()),
            StrykeValue::integer(50),
        ])?
        .to_int();
        (cpu, mem, io, 1)
    };

    let elapsed = start.elapsed().as_secs_f64();

    let mut h = IndexMap::new();
    h.insert("cpu_hashes".to_string(), StrykeValue::integer(cpu_hashes));
    h.insert("mem_bytes".to_string(), StrykeValue::integer(mem_bytes));
    h.insert("io_bytes".to_string(), StrykeValue::integer(io_bytes));
    h.insert("workers".to_string(), StrykeValue::integer(workers as i64));
    h.insert("duration".to_string(), StrykeValue::float(elapsed));

    Ok(StrykeValue::hash_ref(Arc::new(RwLock::new(h))))
}

/// `heat` — Maximum thermal stress. Pins ALL cores indefinitely (or for specified seconds).
/// The hottest function in any programming language. Ctrl-C to stop.
/// Args: optional duration_secs (default: 60 seconds)
/// Returns: total hashes computed
fn builtin_heat(args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    use sha2::{Digest, Sha256};
    use std::sync::atomic::{AtomicBool, AtomicI64, Ordering};
    use std::time::{Duration, Instant};

    let duration_secs = args.first().map(|v| v.to_number()).unwrap_or(60.0);
    let num_cores = std::thread::available_parallelism()
        .map(|p| p.get())
        .unwrap_or(1);

    eprintln!(
        "🔥 HEAT: Pinning {} cores to 100% TDP for {}s (Ctrl-C to stop early)",
        num_cores, duration_secs
    );

    let total_count = AtomicI64::new(0);
    let start = Instant::now();
    let duration = Duration::from_secs_f64(duration_secs);
    let running = std::sync::Arc::new(AtomicBool::new(true));

    // Set up Ctrl-C handler
    let r = running.clone();
    let _ = ctrlc::set_handler(move || {
        r.store(false, Ordering::SeqCst);
    });

    std::thread::scope(|s| {
        for _ in 0..num_cores {
            let running = &running;
            let total_count = &total_count;
            s.spawn(move || {
                let mut local_count: i64 = 0;
                let mut data = [0u8; 64];

                while running.load(Ordering::Relaxed) && start.elapsed() < duration {
                    for _ in 0..1000 {
                        let hash = Sha256::digest(data);
                        data[..32].copy_from_slice(&hash);
                        local_count += 1;
                    }
                }

                total_count.fetch_add(local_count, Ordering::Relaxed);
            });
        }
    });

    let elapsed = start.elapsed().as_secs_f64();
    let total = total_count.load(Ordering::Relaxed);
    let rate = if elapsed > 0.0 {
        total as f64 / elapsed / 1e6
    } else {
        0.0
    };

    eprintln!(
        "🔥 HEAT: {} hashes in {:.2}s ({:.1}M/s across {} cores)",
        total, elapsed, rate, num_cores
    );

    Ok(StrykeValue::integer(total))
}

/// `fire_and_forget` — Spawn detached threads running heat forever on all cores.
/// Returns immediately. The threads run until the process exits.
fn builtin_fire_and_forget() -> StrykeResult<StrykeValue> {
    use sha2::{Digest, Sha256};
    use std::sync::atomic::{AtomicI64, Ordering};
    use std::sync::Arc;
    use std::time::Instant;

    let num_cores = std::thread::available_parallelism()
        .map(|p| p.get())
        .unwrap_or(1);

    let total_count = Arc::new(AtomicI64::new(0));
    let start = Instant::now();

    eprintln!(
        "🔥 FIRE: Computing INFINITY hashes at 100% TDP on {} cores (This is going to take a while...)",
        num_cores
    );

    for _ in 0..num_cores {
        let counter = Arc::clone(&total_count);
        std::thread::spawn(move || {
            let mut data = [0u8; 64];
            let mut local_count: i64 = 0;
            loop {
                for _ in 0..1000 {
                    let hash = Sha256::digest(data);
                    data[..32].copy_from_slice(&hash);
                    local_count += 1;
                }
                if local_count % 100_000 == 0 {
                    counter.fetch_add(100_000, Ordering::Relaxed);
                }
            }
        });
    }

    // Block forever, reporting stats every second (Ctrl-C to stop)
    loop {
        std::thread::sleep(std::time::Duration::from_secs(1));
        let total = total_count.load(Ordering::Relaxed);
        let elapsed = start.elapsed().as_secs_f64();
        let rate = if elapsed > 0.0 {
            total as f64 / elapsed / 1e6
        } else {
            0.0
        };
        eprintln!(
            "🔥 FIRE: {} hashes in {:.1}s ({:.1}M/s across {} cores)",
            total, elapsed, rate, num_cores
        );
    }
}

/// `fetch` — Fetch.
fn builtin_fetch(args: &[StrykeValue], line: usize) -> StrykeResult<StrykeValue> {
    let url = args.first().map(|v| v.to_string()).unwrap_or_default();
    if let Some(opt) = args.get(1) {
        if !opt.is_undef() {
            if is_http_opts_hash(opt) {
                return crate::native_data::http_request(&url, Some(opt));
            }
            return Err(StrykeError::runtime(
                "fetch: second argument must be a hash or hashref (method, headers, body, …)",
                line,
            ));
        }
    }
    crate::native_data::fetch(&url)
}

/// `fetch_json` — Fetch json.
fn builtin_fetch_json(args: &[StrykeValue], line: usize) -> StrykeResult<StrykeValue> {
    let url = args.first().map(|v| v.to_string()).unwrap_or_default();
    if let Some(opt) = args.get(1) {
        if !opt.is_undef() {
            if is_http_opts_hash(opt) {
                let res = crate::native_data::http_request(&url, Some(opt))?;
                return crate::native_data::http_response_json_body(&res);
            }
            return Err(StrykeError::runtime(
                "fetch_json: second argument must be a hash or hashref (method, headers, json, …)",
                line,
            ));
        }
    }
    crate::native_data::fetch_json(&url)
}

/// `http_request` — Http request.
fn builtin_http_request(args: &[StrykeValue], line: usize) -> StrykeResult<StrykeValue> {
    let url = args
        .first()
        .filter(|v| !v.to_string().is_empty())
        .map(|v| v.to_string())
        .ok_or_else(|| StrykeError::runtime("http_request needs a URL", line))?;
    crate::native_data::http_request(&url, args.get(1).filter(|v| !v.is_undef()))
}

/// `read_bytes` — Read bytes.
fn builtin_read_bytes(
    interp: &VMHelper,
    args: &[StrykeValue],
    line: usize,
) -> StrykeResult<StrykeValue> {
    let path =
        interp.resolve_stryke_path_string(&args.first().map(|v| v.to_string()).unwrap_or_default());
    let b = crate::perl_fs::read_file_bytes(&path)
        .map_err(|e| StrykeError::runtime(format!("read_bytes: {}", e), line))?;
    Ok(StrykeValue::bytes(b))
}

/// Convert a `StrykeValue` to raw bytes for steganography: bytes pass through
/// verbatim, anything else is read as its UTF-8 stringification. Unlike
/// `native_codec::bytes_from_value`, this does NOT auto-load file paths — the
/// carrier is always an in-memory value (use `slurp` explicitly to bring a file in).
fn stego_value_to_bytes(v: &StrykeValue) -> Vec<u8> {
    if let Some(b) = v.as_bytes_arc() {
        return b.as_ref().clone();
    }
    v.to_string().into_bytes()
}

/// Optional key arg: undef → None; anything else → bytes.
fn stego_optional_key(v: Option<&StrykeValue>) -> Option<Vec<u8>> {
    match v {
        Some(val) if !val.is_undef() => Some(stego_value_to_bytes(val)),
        _ => None,
    }
}

/// `controller([bind, [port]])` — drop this stryke process into controller mode,
/// binding to `bind:port` and running the interactive REPL on stdin. Blocking;
/// returns the controller's exit code (`0` on clean shutdown via the `shutdown`
/// verb, `1` if the bind fails). Defaults: `bind="0.0.0.0"`, `port=9999`.
///
/// Wrap in `spawn { controller(...) }` to run a controller in the background
/// while the calling script continues.
fn builtin_controller(args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    let bind = args
        .first()
        .filter(|v| !v.is_undef())
        .map(|v| v.to_string())
        .unwrap_or_else(|| "0.0.0.0".to_string());
    let port = args
        .get(1)
        .filter(|v| !v.is_undef())
        .map(|v| v.to_int().clamp(0, 65535) as u16)
        .unwrap_or(9999);
    let code = crate::controller::run_controller(&bind, port);
    Ok(StrykeValue::integer(code as i64))
}

/// `agent([controller_addr, [name]])` — drop this stryke process into agent mode,
/// connecting to `controller_addr` (defaults to `localhost:9999`) and entering
/// the persistent EVAL/FIRE/STATUS frame loop. Blocking; returns the agent's
/// exit code (`0` clean disconnect, `1` connection or handshake failure).
/// `controller_addr` may be `host` or `host:port`; if no port is present, 9999
/// is used. `name` is the display name shown in the controller's status table —
/// defaults to the local hostname if omitted.
///
/// Wrap in `spawn { agent(...) }` to run an agent in the background while the
/// calling script continues (e.g. local controller + local agent in one
/// process for testing).
fn builtin_agent(args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    let addr = args
        .first()
        .filter(|v| !v.is_undef())
        .map(|v| v.to_string())
        .unwrap_or_else(|| "localhost:9999".to_string());
    let (host, port) = match addr.rsplit_once(':') {
        Some((h, p)) => match p.parse::<u16>() {
            Ok(n) => (h.to_string(), n),
            Err(_) => (addr.clone(), 9999),
        },
        None => (addr.clone(), 9999),
    };
    let name = args.get(1).filter(|v| !v.is_undef()).map(|v| v.to_string());
    let code = crate::agent::run_agent_with_explicit(&host, port, name.as_deref());
    Ok(StrykeValue::integer(code as i64))
}

// ============================================================================
//        Scriptable distributed compute — congregation/ordain/muster/
//        pray/annex. Layered on top of controller.rs's programmatic API
//        (Controller::spawn → ControllerHandle), and routes worker code
//        through the existing EvalCommand / EvalResult wire frames in
//        agent.rs. See docs/killer-features-brainstorm.md "Scriptable
//        Master/Slave" section for the full vocab + design rationale.
// ============================================================================

/// `congregation(N)` — spawn N stryke worker processes locally, wait for them
/// to register with an auto-created controller on `127.0.0.1`, return an
/// array of N worker handles (the agent session_ids). Sets the current
/// controller so subsequent `pray` / `annex` calls don't need an explicit
/// controller handle.
///
/// The returned handles are integers — pass them (singly or as a list) to
/// `pray` to scatter work, then `annex` the resulting divination to collect.
///
/// Implementation: fork(2) one child per worker; child re-enters this stryke
/// process as a connected agent via `run_agent_with_explicit`. Default
/// connect-wait is 5 seconds — if fewer than N workers register in that
/// window the call returns an error rather than a short congregation.
#[cfg(unix)]
fn builtin_congregation(args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    use std::time::Duration;

    let n = args
        .first()
        .filter(|v| !v.is_undef())
        .map(|v| v.to_int())
        .unwrap_or(1);
    if !(1..=10_000).contains(&n) {
        return Err(StrykeError::runtime(
            format!("congregation: N must be 1..10000, got {}", n),
            0,
        ));
    }
    let n = n as usize;

    // 1. Spawn a controller on 127.0.0.1 with an OS-assigned port.
    let handle = crate::controller::spawn_controller("127.0.0.1", 0).map_err(|e| {
        StrykeError::runtime(format!("congregation: spawn controller failed: {}", e), 0)
    })?;
    let listen_addr = handle.listen_addr();
    let controller_id = crate::controller::register_controller(Arc::clone(&handle));
    crate::controller::set_current_controller(controller_id);

    // Silence the accept-loop's per-agent eprintln during the bulk fork.
    // Without this, the background accept thread may hold stderr's RefCell
    // borrowed at the instant the main thread forks; the child inherits a
    // borrowed RefCell and panics on its first stdio call. Restored after
    // the welcome() returns.
    handle.set_quiet_accept(true);

    // 2. Fork N agent children. Each child re-enters this stryke process as a
    //    connected agent pointed at the parent's controller. The accept thread
    //    in the parent registers them as they connect.
    let host = listen_addr.ip().to_string();
    let port = listen_addr.port();
    for i in 0..n {
        match unsafe { nix::unistd::fork() } {
            Ok(nix::unistd::ForkResult::Parent { .. }) => {
                // Parent: continue spawning.
            }
            Ok(nix::unistd::ForkResult::Child) => {
                // Child: run as an agent against the parent's controller. This
                // call blocks until disconnect; on return the child exits with
                // the agent's exit code so its slot in the process table is
                // reclaimed by reaper logic.
                //
                // `libc::_exit` (not `std::process::exit`) — Rust runtime
                // cleanup is NOT async-signal-safe in a fork child. The
                // agent VM's rayon / channel / mutex state inherited
                // from the pre-fork parent deadlocks in
                // `std::rt::cleanup` after the child's final EVAL.
                let name = format!("congregant-{:03}", i);
                let code = crate::agent::run_agent_with_explicit(&host, port, Some(&name));
                unsafe { libc::_exit(code) }
            }
            Err(e) => {
                return Err(StrykeError::runtime(
                    format!("congregation: fork failed at child {}: {}", i, e),
                    0,
                ));
            }
        }
    }

    // 3. Wait for all N agents to register. Timeout scales with N to handle
    //    larger congregations on slower hosts: 2s baseline + 100ms per agent.
    //    For N=10 this is 3s, for N=100 it's 12s, for N=1000 it's 102s.
    //    Short-congregation is a real error worth surfacing rather than
    //    silently working with fewer.
    let welcome_secs = 2u64 + (n as u64 / 10).max(1);
    let welcomed = handle.welcome(n, Duration::from_secs(welcome_secs));
    // Restore the REPL UX after the bulk fork — subsequent post-spawn
    // connections (e.g. profess() from a separately-launched script) get
    // the normal "[agent connected]" eprintln.
    handle.set_quiet_accept(false);
    if !welcomed {
        return Err(StrykeError::runtime(
            format!(
                "congregation: only {}/{} agents registered within {}s",
                handle.agent_count(),
                n,
                welcome_secs
            ),
            0,
        ));
    }

    // 4. Return the session_ids as an array of integer handles.
    let session_ids = handle.muster();
    let handles: Vec<StrykeValue> = session_ids
        .iter()
        .map(|sid| StrykeValue::integer(*sid as i64))
        .collect();
    Ok(StrykeValue::array(handles))
}

#[cfg(not(unix))]
fn builtin_congregation(_args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    Err(StrykeError::runtime(
        "congregation: requires Unix fork() — not supported on this platform",
        0,
    ))
}

/// `ordain([$name, [$bind, [$port]]])` — explicit lower-level form of
/// `congregation`. Spawns a controller (no agent processes), returns the
/// controller handle ID. Use when you want to manage worker lifecycle
/// yourself (e.g. agents that connect via `profess($name)`).
/// Sets the current controller; subsequent `pray` / `annex` route to it.
///
/// If `$name` is provided (and not the default), also registers the
/// `name → endpoint` binding in the in-process cathedral so subsequent
/// `profess($name)` calls can resolve the controller's endpoint.
fn builtin_ordain(args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    let name = args
        .first()
        .filter(|v| !v.is_undef())
        .map(|v| v.to_string())
        .unwrap_or_else(|| "default".to_string());
    let bind = args
        .get(1)
        .filter(|v| !v.is_undef())
        .map(|v| v.to_string())
        .unwrap_or_else(|| "127.0.0.1".to_string());
    let port = args
        .get(2)
        .filter(|v| !v.is_undef())
        .map(|v| v.to_int().clamp(0, 65535) as u16)
        .unwrap_or(0);

    let handle = crate::controller::spawn_controller(&bind, port)
        .map_err(|e| StrykeError::runtime(format!("ordain: spawn failed: {}", e), 0))?;
    let endpoint = handle.listen_addr().to_string();
    let id = crate::controller::register_controller(Arc::clone(&handle));
    crate::controller::set_current_controller(id);

    // Register name → endpoint in the cathedral so future profess()
    // calls can resolve. "default" gets registered too — last-call-wins
    // semantics if a script ordains multiple "default" congregations.
    crate::controller::cathedral_register(&name, &endpoint);
    Ok(StrykeValue::integer(id as i64))
}

/// `muster([$controller_id])` — return the current congregation's worker
/// handles as an array of session_ids, sorted ascending. With no argument,
/// uses the current controller (set by the most recent `congregation` or
/// `ordain` call).
fn builtin_muster(args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    let controller_id = match args.first().filter(|v| !v.is_undef()) {
        Some(v) => v.to_int() as u64,
        None => crate::controller::get_current_controller().ok_or_else(|| {
            StrykeError::runtime(
                "muster: no current controller; call congregation() or ordain() first",
                0,
            )
        })?,
    };
    let handle = crate::controller::get_controller(controller_id).ok_or_else(|| {
        StrykeError::runtime(format!("muster: controller {} not found", controller_id), 0)
    })?;
    let ids = handle.muster();
    let arr: Vec<StrykeValue> = ids
        .iter()
        .map(|i| StrykeValue::integer(*i as i64))
        .collect();
    Ok(StrykeValue::array(arr))
}

/// Extract the prayer text from a StrykeValue arg. Accepts either a string
/// (used verbatim as EVAL source) or a coderef/sub (the body is deparsed
/// to source via `crate::deparse::deparse_block` and that source is sent).
/// Closure captures (`closure_env`) are NOT supported in Tier 1 — the body
/// must be self-contained. Returns an error for undef / empty.
fn extract_prayer_text(v: &StrykeValue, verb: &str) -> StrykeResult<String> {
    if v.is_undef() {
        return Err(StrykeError::runtime(
            format!("{}: code (first argument) required", verb),
            0,
        ));
    }
    if let Some(sub) = v.as_code_ref() {
        // Coderef path: deparse the body back to stryke source. Closure
        // captures are not shipped — the body must reference only globals
        // or values pushed via `bestow`. (Tier 1 limitation; cross-process
        // closure capture is a Tier 4 problem.)
        return Ok(crate::deparse::deparse_block(&sub.body));
    }
    let s = v.to_string();
    if s.is_empty() {
        Err(StrykeError::runtime(format!("{}: code is empty", verb), 0))
    } else {
        Ok(s)
    }
}

/// Flatten a slice of StrykeValue args into a Vec<u64> of agent handles.
/// Accepts integers (each is one handle) and arrays (every non-undef
/// element is one handle). Skips undef silently — matches Perl's
/// arg-passing leniency.
fn flatten_agent_handles(args: &[StrykeValue]) -> Vec<u64> {
    let mut ids: Vec<u64> = Vec::new();
    for v in args {
        if v.is_undef() {
            continue;
        }
        if let Some(arr) = v.as_array_vec() {
            for item in arr {
                if !item.is_undef() {
                    ids.push(item.to_int() as u64);
                }
            }
        } else {
            ids.push(v.to_int() as u64);
        }
    }
    ids
}

/// Resolve the current controller handle, or error if no congregation has
/// been ordained / spawned yet in this process.
fn require_current_controller(
    verb: &str,
) -> StrykeResult<std::sync::Arc<crate::controller::ControllerHandle>> {
    let id = crate::controller::get_current_controller().ok_or_else(|| {
        StrykeError::runtime(
            format!(
                "{}: no current controller; call congregation() or ordain() first",
                verb
            ),
            0,
        )
    })?;
    crate::controller::get_controller(id)
        .ok_or_else(|| StrykeError::runtime(format!("{}: controller {} not found", verb, id), 0))
}

/// Convert HashMap<session_id, EvalResult> to a stryke hash keyed by
/// stringified session_id, sorted ascending. Values are the agent's
/// output string. Used by annex / harvest / pilgrimage to return results.
fn results_to_hash(
    results: std::collections::HashMap<u64, crate::agent::EvalResult>,
) -> StrykeValue {
    let mut hash = indexmap::IndexMap::new();
    let mut sorted_ids: Vec<u64> = results.keys().copied().collect();
    sorted_ids.sort_unstable();
    for sid in sorted_ids {
        let r = &results[&sid];
        hash.insert(sid.to_string(), StrykeValue::string(r.output.clone()));
    }
    StrykeValue::hash(hash)
}

/// `pray($code, @agent_handles)` — scatter `$code` to every agent in
/// `@agent_handles`, return a divination ID for `annex` to consume.
/// Agents start executing immediately in parallel; this call returns as
/// soon as the EVAL frame is on every wire (no result waiting).
///
/// `$code` accepts either a string OR a coderef. Coderef body is deparsed
/// to source via `crate::deparse::deparse_block` before shipping.
///
/// `@agent_handles` may be passed flat (`pray $code, $h1, $h2, $h3`) or
/// as an array (`pray $code, @cong`) — both are flattened.
fn builtin_pray(args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    let code = match args.first() {
        Some(v) => extract_prayer_text(v, "pray")?,
        None => {
            return Err(StrykeError::runtime(
                "pray: code (first argument) required",
                0,
            ))
        }
    };

    let agent_ids = flatten_agent_handles(&args[1..]);
    if agent_ids.is_empty() {
        return Err(StrykeError::runtime(
            "pray: at least one agent handle required",
            0,
        ));
    }

    let handle = require_current_controller("pray")?;
    let controller_id = crate::controller::get_current_controller().unwrap();

    let petition_id = handle
        .scatter(&code, &agent_ids)
        .map_err(|e| StrykeError::runtime(format!("pray: scatter failed: {}", e), 0))?;
    let divination_id = crate::controller::register_divination(controller_id, petition_id);
    Ok(StrykeValue::integer(divination_id as i64))
}

/// `annex($divination_id [, $timeout_ms])` — block until every agent that
/// received the prayer has replied (or the per-agent timeout elapses).
/// Returns a hash keyed by agent session_id (stringified), with the agent's
/// eval output as the value. Default timeout is 30s per agent.
///
/// Consumes the divination — calling `annex` twice on the same ID is an
/// error. Agents that timed out or disconnected are omitted from the hash
/// (rather than producing an error or a sentinel value).
fn builtin_annex(args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    use std::time::Duration;

    let divination_id = args
        .first()
        .filter(|v| !v.is_undef())
        .map(|v| v.to_int() as u64)
        .ok_or_else(|| StrykeError::runtime("annex: divination ID (first argument) required", 0))?;
    let timeout_ms = args
        .get(1)
        .filter(|v| !v.is_undef())
        .map(|v| v.to_int().max(100) as u64)
        .unwrap_or(30_000);

    let (controller_id, petition_id) = crate::controller::unregister_divination(divination_id)
        .ok_or_else(|| {
            StrykeError::runtime(
                format!(
                    "annex: divination {} not found (already annexed or never created)",
                    divination_id
                ),
                0,
            )
        })?;
    let handle = crate::controller::get_controller(controller_id).ok_or_else(|| {
        StrykeError::runtime(format!("annex: controller {} gone", controller_id), 0)
    })?;

    let results = handle
        .gather(petition_id, Duration::from_millis(timeout_ms))
        .map_err(|e| StrykeError::runtime(format!("annex: gather failed: {}", e), 0))?;

    Ok(results_to_hash(results))
}

// ─── Tier 1: ergonomic master-side verbs ────────────────────────────────────
//
// Each verb earns its slot on either (a) a distinct wire-frame action
// (excommunicate→SHUTDOWN, smite→state-reset EVAL, bestow→push direction),
// (b) a fused common-case ergonomic (harvest = pray+annex one-shot,
// pilgrimage = scatter+gather barrier), or (c) a genuinely new local
// operation (smother→zero hash, enshrine/exhume→disk persistence).
//
// Pure aliases (lick/peruse as synonyms for annex) are deferred to Tier 3
// when %soul harvest gives them distinct non-destructive semantics.

/// `harvest($code, @agent_handles [, $timeout_ms])` — fused `pray + annex`.
/// One-shot scatter+gather: scatter $code to every handle, block for replies
/// up to $timeout_ms (default 30s), return the result hash directly. No
/// divination id leaked. Most common scatter-gather pattern in one call.
fn builtin_harvest(args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    use std::time::Duration;

    let code = match args.first() {
        Some(v) => extract_prayer_text(v, "harvest")?,
        None => return Err(StrykeError::runtime("harvest: code required", 0)),
    };

    // Last arg may be a timeout integer if it's bare (not in an array). We
    // peek before the flatten to allow `harvest $code, @cong, 5000` syntax.
    let mut handle_args: &[StrykeValue] = &args[1..];
    let mut timeout_ms: u64 = 30_000;
    if let Some(last) = handle_args.last() {
        if !last.is_undef() && last.as_array_vec().is_none() && last.as_code_ref().is_none() {
            let n = last.to_int();
            // Heuristic: a bare integer >= 100 in the tail position is a
            // timeout; a single agent handle is typically a small int (1..N).
            // Treat values >= 100 as timeouts. Agents past 100 are still
            // accessible via explicit array: `harvest $code, [@cong], 5000`.
            if n >= 100 {
                timeout_ms = n as u64;
                handle_args = &handle_args[..handle_args.len() - 1];
            }
        }
    }

    let agent_ids = flatten_agent_handles(handle_args);
    if agent_ids.is_empty() {
        return Err(StrykeError::runtime(
            "harvest: at least one agent handle required",
            0,
        ));
    }

    let handle = require_current_controller("harvest")?;
    let petition_id = handle
        .scatter(&code, &agent_ids)
        .map_err(|e| StrykeError::runtime(format!("harvest: scatter failed: {}", e), 0))?;
    let results = handle
        .gather(petition_id, Duration::from_millis(timeout_ms))
        .map_err(|e| StrykeError::runtime(format!("harvest: gather failed: {}", e), 0))?;
    Ok(results_to_hash(results))
}

/// `excommunicate(@agent_handles)` — send SHUTDOWN frames to every named
/// agent. Each agent exits its loop and its connection drops. Returns the
/// count of agents successfully notified. Use this for clean cleanup at
/// end of a congregation's life.
fn builtin_excommunicate(args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    let agent_ids = flatten_agent_handles(args);
    if agent_ids.is_empty() {
        return Err(StrykeError::runtime(
            "excommunicate: at least one agent handle required",
            0,
        ));
    }
    let handle = require_current_controller("excommunicate")?;
    let count = handle.excommunicate(&agent_ids);
    Ok(StrykeValue::integer(count as i64))
}

/// `smite(@agent_handles)` — destroy each agent's `%soul` hash (and any
/// other state it considers volatile). Implemented as a synchronous EVAL
/// that clears the conventional `our %soul` and any `our %gift` hash,
/// then returns. Use when you want to wipe worker state without losing
/// the connection (vs `excommunicate` which kills the workers).
///
/// Returns the count of agents that responded to the smiting.
fn builtin_smite(args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    use std::time::Duration;

    let agent_ids = flatten_agent_handles(args);
    if agent_ids.is_empty() {
        return Err(StrykeError::runtime(
            "smite: at least one agent handle required",
            0,
        ));
    }
    let handle = require_current_controller("smite")?;
    let code = "our %soul = (); our %gift = (); 'smitten'";
    let petition_id = handle
        .scatter(code, &agent_ids)
        .map_err(|e| StrykeError::runtime(format!("smite: scatter failed: {}", e), 0))?;
    let results = handle
        .gather(petition_id, Duration::from_secs(5))
        .map_err(|e| StrykeError::runtime(format!("smite: gather failed: {}", e), 0))?;
    Ok(StrykeValue::integer(results.len() as i64))
}

/// `bestow(\%hash, @agent_handles)` — push `%hash` to every named agent's
/// `our %gift` hash. JSON-serialized on the master side, decoded on the
/// agent via `from_json`. The agent's existing `%gift` is replaced (not
/// merged) — for merge semantics, the agent's `divine` handler would
/// pull from `%gift` and combine explicitly.
///
/// Returns the count of agents that accepted the bestowal.
fn builtin_bestow(args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    use std::time::Duration;

    let hash_value = args
        .first()
        .filter(|v| !v.is_undef())
        .ok_or_else(|| StrykeError::runtime("bestow: hash (first argument) required", 0))?;

    // Build a JSON object from the hash. Accept hash value AND hash ref —
    // as_hash_map only handles bare hash values, so fall back through
    // as_hash_ref for `bestow(\%h, ...)` callers.
    let hash_map = hash_value
        .as_hash_map()
        .or_else(|| hash_value.as_hash_ref().map(|r| r.read().clone()))
        .ok_or_else(|| {
            StrykeError::runtime("bestow: first argument must be a hash or hash ref", 0)
        })?;

    let mut json_obj = serde_json::Map::new();
    for (k, v) in &hash_map {
        json_obj.insert(k.clone(), serde_json::Value::String(v.to_string()));
    }
    let json_str = serde_json::Value::Object(json_obj).to_string();

    let agent_ids = flatten_agent_handles(&args[1..]);
    if agent_ids.is_empty() {
        return Err(StrykeError::runtime(
            "bestow: at least one agent handle required",
            0,
        ));
    }
    let handle = require_current_controller("bestow")?;

    // Embed the JSON as a single-quoted stryke string literal. Escape
    // backslashes and single-quotes so the agent's parser sees a clean
    // literal. (Stryke single-quotes are interpolation-free.)
    let escaped = json_str.replace('\\', "\\\\").replace('\'', "\\'");
    let code = format!("our %gift = %{{from_json('{}')}}; 'bestowed'", escaped);
    let petition_id = handle
        .scatter(&code, &agent_ids)
        .map_err(|e| StrykeError::runtime(format!("bestow: scatter failed: {}", e), 0))?;
    let results = handle
        .gather(petition_id, Duration::from_secs(10))
        .map_err(|e| StrykeError::runtime(format!("bestow: gather failed: {}", e), 0))?;
    Ok(StrykeValue::integer(results.len() as i64))
}

/// `enshrine(\%souls, $path)` — write the souls hash to disk as JSON for
/// later `exhume`. Format: `{ "session_id_str": "output_str", ... }`.
/// Returns the number of bytes written.
fn builtin_enshrine(args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    let hash_value = args
        .first()
        .filter(|v| !v.is_undef())
        .ok_or_else(|| StrykeError::runtime("enshrine: hash (first argument) required", 0))?;
    let path = args
        .get(1)
        .filter(|v| !v.is_undef())
        .map(|v| v.to_string())
        .ok_or_else(|| StrykeError::runtime("enshrine: path (second argument) required", 0))?;

    let hash_map = hash_value
        .as_hash_map()
        .or_else(|| hash_value.as_hash_ref().map(|r| r.read().clone()))
        .ok_or_else(|| {
            StrykeError::runtime("enshrine: first argument must be a hash or hash ref", 0)
        })?;

    let mut json_obj = serde_json::Map::new();
    for (k, v) in &hash_map {
        json_obj.insert(k.clone(), serde_json::Value::String(v.to_string()));
    }
    let json_str = serde_json::Value::Object(json_obj).to_string();

    std::fs::write(&path, &json_str)
        .map_err(|e| StrykeError::runtime(format!("enshrine: write {} failed: {}", path, e), 0))?;
    Ok(StrykeValue::integer(json_str.len() as i64))
}

/// `exhume($path)` — read an `enshrine`d hash back from disk. Returns the
/// hash with the same shape it was written with (string keys, string
/// values). Errors if the file is missing or not valid JSON object.
fn builtin_exhume(args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    let path = args
        .first()
        .filter(|v| !v.is_undef())
        .map(|v| v.to_string())
        .ok_or_else(|| StrykeError::runtime("exhume: path (first argument) required", 0))?;

    let json_str = std::fs::read_to_string(&path)
        .map_err(|e| StrykeError::runtime(format!("exhume: read {} failed: {}", path, e), 0))?;
    let val: serde_json::Value = serde_json::from_str(&json_str)
        .map_err(|e| StrykeError::runtime(format!("exhume: parse {} failed: {}", path, e), 0))?;
    let obj = val
        .as_object()
        .ok_or_else(|| StrykeError::runtime(format!("exhume: {} is not a JSON object", path), 0))?;

    let mut hash = indexmap::IndexMap::new();
    for (k, v) in obj {
        let value_str = match v {
            serde_json::Value::String(s) => s.clone(),
            other => other.to_string(),
        };
        hash.insert(k.clone(), StrykeValue::string(value_str));
    }
    // Return hash_ref (not bare hash) so `%{exhume($path)}` deref works
    // and `$h = exhume($path); $h->{k}` subscripting works — the standard
    // Perl idiom for "function returning a complex value." Same pattern
    // as json_value_to_stryke / interrogate(PID).
    Ok(StrykeValue::hash_ref(Arc::new(parking_lot::RwLock::new(
        hash,
    ))))
}

/// `smother(\%souls)` — securely zero a local hash. Walks every key and
/// replaces the value with an empty string, then clears the hash. Returns
/// the count of entries scrubbed. Local operation only — no network.
fn builtin_smother(args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    let hash_value = args
        .first()
        .filter(|v| !v.is_undef())
        .ok_or_else(|| StrykeError::runtime("smother: hash required", 0))?;

    // Most useful smother target is a hash_ref — that we can mutate in place
    // so the caller's hash is actually erased. A hash-by-value is a copy and
    // scrubbing it has no visible effect on the caller's namespace.
    if let Some(href) = hash_value.as_hash_ref() {
        let mut guard = href.write();
        let n = guard.len();
        // Two-pass scrub: overwrite values with empty strings, then clear.
        // (The overwrite reduces the window where freed allocations carry
        // sensitive payload — Rust will reuse the slot after the clear.)
        for (_, v) in guard.iter_mut() {
            *v = StrykeValue::string(String::new());
        }
        guard.clear();
        return Ok(StrykeValue::integer(n as i64));
    }
    if let Some(map) = hash_value.as_hash_map() {
        // Pass-by-value: nothing to smother in the caller's namespace.
        // Return the count anyway so the caller can verify the size.
        return Ok(StrykeValue::integer(map.len() as i64));
    }
    Err(StrykeError::runtime("smother: argument must be a hash", 0))
}

/// `amen($id)` — release a pending divination OR stop an active chant.
/// Tries divination registry first, then chant registry. For chants,
/// also calls amen_chant on the underlying controller to stop the
/// rescatter at the new-joiner path.
///
/// Returns 1 if the ID was found (in either registry), 0 if it had
/// already been consumed or never existed.
fn builtin_amen(args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    let id = args
        .first()
        .filter(|v| !v.is_undef())
        .map(|v| v.to_int() as u64)
        .ok_or_else(|| StrykeError::runtime("amen: ID required", 0))?;

    if crate::controller::unregister_divination(id).is_some() {
        return Ok(StrykeValue::integer(1));
    }
    if let Some((controller_id, local_chant_id)) = crate::controller::unregister_chant(id) {
        if let Some(handle) = crate::controller::get_controller(controller_id) {
            handle.amen_chant(local_chant_id);
        }
        return Ok(StrykeValue::integer(1));
    }
    Ok(StrykeValue::integer(0))
}

/// `anoint($n)` — like `congregation($n)` but does NOT set the current
/// controller. Use when you want to keep a primary congregation as the
/// implicit target while spawning a secondary one. Returns array of
/// session_ids for the new workers; controller handle is registered in
/// the registry but callers manage it explicitly via the returned ids.
#[cfg(unix)]
fn builtin_anoint(args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    use std::time::Duration;

    let n = args
        .first()
        .filter(|v| !v.is_undef())
        .map(|v| v.to_int())
        .unwrap_or(1);
    if !(1..=10_000).contains(&n) {
        return Err(StrykeError::runtime(
            format!("anoint: N must be 1..10000, got {}", n),
            0,
        ));
    }
    let n = n as usize;

    // Stash the current controller, do the spawn, then restore. This is
    // the only difference from congregation() — the side-effect of
    // becoming the implicit target is suppressed.
    let prior_controller = crate::controller::get_current_controller();

    let handle = crate::controller::spawn_controller("127.0.0.1", 0)
        .map_err(|e| StrykeError::runtime(format!("anoint: spawn controller failed: {}", e), 0))?;
    let listen_addr = handle.listen_addr();
    let _controller_id = crate::controller::register_controller(Arc::clone(&handle));
    // Intentionally do NOT call set_current_controller here.

    // Same fork-stdio race guard as congregation — quiet the accept-loop
    // eprintln during the bulk fork burst.
    handle.set_quiet_accept(true);

    let host = listen_addr.ip().to_string();
    let port = listen_addr.port();
    for i in 0..n {
        match unsafe { nix::unistd::fork() } {
            Ok(nix::unistd::ForkResult::Parent { .. }) => {}
            Ok(nix::unistd::ForkResult::Child) => {
                // See `congregation` above for the `libc::_exit`
                // rationale (fork-child Rust cleanup deadlock).
                let name = format!("anointed-{:03}", i);
                let code = crate::agent::run_agent_with_explicit(&host, port, Some(&name));
                unsafe { libc::_exit(code) }
            }
            Err(e) => {
                return Err(StrykeError::runtime(
                    format!("anoint: fork failed at child {}: {}", i, e),
                    0,
                ));
            }
        }
    }

    // Timeout scales with N — same formula as congregation().
    let welcome_secs = 2u64 + (n as u64 / 10).max(1);
    let welcomed = handle.welcome(n, Duration::from_secs(welcome_secs));
    handle.set_quiet_accept(false);
    if !welcomed {
        return Err(StrykeError::runtime(
            format!(
                "anoint: only {}/{} agents registered within {}s",
                handle.agent_count(),
                n,
                welcome_secs
            ),
            0,
        ));
    }

    // Restore the prior current-controller (no-op if there was none).
    if let Some(prior) = prior_controller {
        crate::controller::set_current_controller(prior);
    }

    let session_ids = handle.muster();
    let handles: Vec<StrykeValue> = session_ids
        .iter()
        .map(|sid| StrykeValue::integer(*sid as i64))
        .collect();
    Ok(StrykeValue::array(handles))
}

#[cfg(not(unix))]
fn builtin_anoint(_args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    Err(StrykeError::runtime(
        "anoint: requires Unix fork() — not supported on this platform",
        0,
    ))
}

/// `welcome($n [, $timeout_ms])` — block until at least $n agents have
/// joined the current congregation, or $timeout_ms elapses (default 5s).
/// Returns the actual agent count at return time. Useful for "wait for
/// the slow joiner" patterns after `ordain`.
fn builtin_welcome(args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    use std::time::Duration;

    let n = args
        .first()
        .filter(|v| !v.is_undef())
        .map(|v| v.to_int() as usize)
        .unwrap_or(1);
    let timeout_ms = args
        .get(1)
        .filter(|v| !v.is_undef())
        .map(|v| v.to_int().max(100) as u64)
        .unwrap_or(5_000);

    let handle = require_current_controller("welcome")?;
    handle.welcome(n, Duration::from_millis(timeout_ms));
    Ok(StrykeValue::integer(handle.agent_count() as i64))
}

/// `pilgrimage($code, @agent_handles [, $timeout_ms])` — sync barrier.
/// Scatter `$code` to every named agent and block until every dispatched
/// agent has replied, or `$timeout_ms` elapses (default 10s). Returns 1
/// if every agent rendezvoused in time, 0 otherwise.
///
/// For a pure rendezvous (no work), pass `"1"` as the prayer — the
/// agent's reply is the synchronization signal.
fn builtin_pilgrimage(args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    use std::time::Duration;

    let code = match args.first() {
        Some(v) => extract_prayer_text(v, "pilgrimage")?,
        None => return Err(StrykeError::runtime("pilgrimage: code required", 0)),
    };

    let mut handle_args: &[StrykeValue] = &args[1..];
    let mut timeout_ms: u64 = 10_000;
    if let Some(last) = handle_args.last() {
        if !last.is_undef() && last.as_array_vec().is_none() && last.as_code_ref().is_none() {
            let n = last.to_int();
            if n >= 100 {
                timeout_ms = n as u64;
                handle_args = &handle_args[..handle_args.len() - 1];
            }
        }
    }

    let agent_ids = flatten_agent_handles(handle_args);
    if agent_ids.is_empty() {
        return Err(StrykeError::runtime(
            "pilgrimage: at least one agent handle required",
            0,
        ));
    }
    let handle = require_current_controller("pilgrimage")?;
    let rendezvoused = handle.pilgrimage(&code, &agent_ids, Duration::from_millis(timeout_ms));
    Ok(StrykeValue::integer(rendezvoused as i64))
}

// ─── Tier 3: %soul harvest (non-destructive read) ──────────────────────────
//
// Convention: workers maintain an `our %soul` hash holding their externally-
// visible state. `lick` and `peruse` snapshot every worker's `%soul` over
// the wire, parse the JSON back into a stryke hash, return a `{session_id
// => %soul-hash}` map per agent. Workers retain their `%soul` intact —
// these are read-only operations.
//
// For destructive harvest (read then wipe), pair with `smite`:
//
//   my %snapshot = lick @cong;
//   smite @cong;             # zero workers' %soul and %gift
//
// Future Tier 4 work: deeper distinction between lick (shallow) and peruse
// (deep walk via `god` reflection), plus a `ANNEX_SOUL` wire frame that
// fuses read+wipe atomically.

/// Recursively convert a serde_json::Value into a StrykeValue. Used by
/// `lick` / `peruse` / `exhume` to rehydrate JSON-encoded soul snapshots.
/// Objects and arrays come back as REFs (hash_ref / array_ref) so they
/// can be subscripted with `->{...}` / `->[N]` in stryke without an
/// outer copy. Scalars come back as bare values.
fn json_value_to_stryke(v: serde_json::Value) -> StrykeValue {
    match v {
        serde_json::Value::Null => StrykeValue::UNDEF,
        serde_json::Value::Bool(b) => StrykeValue::integer(if b { 1 } else { 0 }),
        serde_json::Value::Number(n) => {
            if let Some(i) = n.as_i64() {
                StrykeValue::integer(i)
            } else if let Some(f) = n.as_f64() {
                StrykeValue::float(f)
            } else {
                StrykeValue::UNDEF
            }
        }
        serde_json::Value::String(s) => StrykeValue::string(s),
        serde_json::Value::Array(arr) => {
            let items: Vec<StrykeValue> = arr.into_iter().map(json_value_to_stryke).collect();
            StrykeValue::array_ref(Arc::new(parking_lot::RwLock::new(items)))
        }
        serde_json::Value::Object(obj) => {
            let mut map = indexmap::IndexMap::new();
            for (k, v) in obj {
                map.insert(k, json_value_to_stryke(v));
            }
            StrykeValue::hash_ref(Arc::new(parking_lot::RwLock::new(map)))
        }
    }
}

/// Scatter `to_json(\%soul)` to every agent, gather, parse each reply's
/// JSON back into a stryke hash. Used by `lick` and (currently as alias)
/// `peruse`. Worker `%soul` is read-only; agents keep their state.
fn lick_souls_impl(args: &[StrykeValue], verb: &str) -> StrykeResult<StrykeValue> {
    use std::time::Duration;

    let agent_ids = flatten_agent_handles(args);
    if agent_ids.is_empty() {
        return Err(StrykeError::runtime(
            format!("{}: at least one agent handle required", verb),
            0,
        ));
    }
    let handle = require_current_controller(verb)?;
    // `our %soul` ensures the hash exists (empty if never touched).
    // `to_json(\%soul)` serializes the hashref to a JSON object.
    // (Both `\%hash` deref AND cross-EVAL persistence were broken
    // prior to the 2026-05-27 scope.rs fix; the workaround used to
    // be `to_json(%soul)` + flat-pair parsing on master side.)
    let code = "our %soul; to_json(\\%soul)";
    let petition_id = handle
        .scatter(code, &agent_ids)
        .map_err(|e| StrykeError::runtime(format!("{}: scatter failed: {}", verb, e), 0))?;
    let results = handle
        .gather(petition_id, Duration::from_secs(10))
        .map_err(|e| StrykeError::runtime(format!("{}: gather failed: {}", verb, e), 0))?;

    let mut hash = indexmap::IndexMap::new();
    let mut sorted_ids: Vec<u64> = results.keys().copied().collect();
    sorted_ids.sort_unstable();
    for sid in sorted_ids {
        let r = &results[&sid];
        let json_str = r.output.trim();
        let value = match serde_json::from_str::<serde_json::Value>(json_str) {
            Ok(parsed) => json_value_to_stryke(parsed),
            // Worker output wasn't valid JSON — surface the raw string so
            // the caller can debug rather than getting a silent UNDEF.
            Err(_) => StrykeValue::string(r.output.clone()),
        };
        hash.insert(sid.to_string(), value);
    }
    Ok(StrykeValue::hash(hash))
}

/// `lick(@agent_handles)` — non-destructive `%soul` snapshot per agent.
/// Returns a hash keyed by stringified session_id; values are each
/// worker's `%soul` rehydrated from JSON into a stryke hash.
///
/// Workers retain their `%soul` after lick — pair with `smite` for
/// destructive harvest (`lick @cong; smite @cong;`).
fn builtin_lick(args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    lick_souls_impl(args, "lick")
}

/// `peruse(@agent_handles)` — deep non-destructive `%soul` walk. Tier 3
/// ships as an alias for `lick`; Tier 4 will replace the body with a
/// `god`-style recursive dump that captures blessed objects, references,
/// and cycles (vs lick's flat JSON serialization).
fn builtin_peruse(args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    lick_souls_impl(args, "peruse")
}

// ─── Tier 4: chant continuous-rescatter ─────────────────────────────────────

/// `chant($code, @agent_handles)` — register an ongoing prayer that fires
/// at every current agent AND every new agent that joins later. Returns
/// a chant_id used by `amen` to stop the rescatter. Fire-and-forget — no
/// gather (use bestow / pray for request-response patterns).
fn builtin_chant(args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    let code = match args.first() {
        Some(v) => extract_prayer_text(v, "chant")?,
        None => return Err(StrykeError::runtime("chant: code required", 0)),
    };
    let agent_ids = flatten_agent_handles(&args[1..]);
    if agent_ids.is_empty() {
        return Err(StrykeError::runtime(
            "chant: at least one agent handle required",
            0,
        ));
    }
    let handle = require_current_controller("chant")?;
    let controller_id = crate::controller::get_current_controller().unwrap();
    let local_chant_id = handle
        .chant(&code, &agent_ids)
        .map_err(|e| StrykeError::runtime(format!("chant: {}", e), 0))?;
    let script_chant_id = crate::controller::register_chant(controller_id, local_chant_id);
    Ok(StrykeValue::integer(script_chant_id as i64))
}

// ─── Tier 4: cathedral + profess + apostatize ───────────────────────────────

/// `profess($congregation_name)` — slave-side: look up the congregation in
/// the in-process cathedral registry, drop this process into agent mode
/// pointed at the resolved endpoint. Blocks for the lifetime of the
/// agent session (same as `agent()` / `bow()`).
///
/// Tier 4: cathedral is in-process only — `profess` only succeeds when
/// the master ran `ordain($name, ...)` in the same OS process (e.g.
/// when both are forked from the same parent). Tier 5+ promotes the
/// cathedral to a standalone `stryked` daemon for cross-host name
/// resolution.
#[cfg(unix)]
fn builtin_profess(args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    let name = args
        .first()
        .filter(|v| !v.is_undef())
        .map(|v| v.to_string())
        .ok_or_else(|| StrykeError::runtime("profess: congregation name required", 0))?;

    let endpoint = crate::controller::cathedral_lookup(&name).ok_or_else(|| {
        StrykeError::runtime(
            format!(
                "profess: congregation {:?} not found in cathedral (was it ordained?)",
                name
            ),
            0,
        )
    })?;

    let (host, port) = match endpoint.rsplit_once(':') {
        Some((h, p)) => match p.parse::<u16>() {
            Ok(n) => (h.to_string(), n),
            Err(_) => (endpoint.clone(), 9999),
        },
        None => (endpoint.clone(), 9999),
    };
    let code = crate::agent::run_agent_with_explicit(&host, port, None);
    Ok(StrykeValue::integer(code as i64))
}

#[cfg(not(unix))]
fn builtin_profess(_args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    Err(StrykeError::runtime(
        "profess: requires Unix — not supported on this platform",
        0,
    ))
}

/// `apostatize($congregation_name)` — master-side: unregister the named
/// congregation from the cathedral so future `profess` calls won't find
/// it. Does NOT excommunicate currently-connected agents (use
/// `excommunicate(muster())` for that). Returns 1 if the name was
/// registered (and is now gone), 0 if it wasn't.
fn builtin_apostatize(args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    let name = args
        .first()
        .filter(|v| !v.is_undef())
        .map(|v| v.to_string())
        .ok_or_else(|| StrykeError::runtime("apostatize: congregation name required", 0))?;
    let removed = crate::controller::cathedral_unregister(&name).is_some();
    Ok(StrykeValue::integer(removed as i64))
}

/// `cathedral()` — return an array of currently-registered congregation
/// names. Diagnostic helper for inspecting the cathedral registry.
fn builtin_cathedral(_args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    let names = crate::controller::cathedral_names();
    let arr: Vec<StrykeValue> = names.into_iter().map(StrykeValue::string).collect();
    Ok(StrykeValue::array(arr))
}

// ─── Tier 4: cloistered ACL ─────────────────────────────────────────────────

/// `cloister($token)` — turn the current controller's :cloistered mode on
/// (when called with a non-empty token) or off (when called with undef /
/// empty). In :cloistered mode, agents must send an AGENT_AUTH frame
/// carrying `$token` within 500ms of HELLO or they're rejected. Open
/// mode (default) skips the AUTH read entirely.
///
/// Slaves opt into AUTH by setting `STRYKE_AGENT_TOKEN` env var before
/// calling `agent()` / `bow()` / `profess()`.
fn builtin_cloister(args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    let token = args
        .first()
        .filter(|v| !v.is_undef())
        .map(|v| v.to_string());
    let handle = require_current_controller("cloister")?;
    handle.set_cloistered(token.as_deref());
    Ok(StrykeValue::integer(token.is_some() as i64))
}

// ─── Tier 4: recant / martyr / resurrect / divine ───────────────────────────

/// `recant(@keys)` — partial self-erasure of `%soul`: delete the named keys
/// from the package-global `%soul`. Slave-side primitive (runs in the
/// agent's persistent VM). Returns the count of keys actually removed.
///
/// For full erasure, use `smite(@me)` from the master side.
fn builtin_recant(args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    // Read the package-global %soul, delete each requested key, write
    // back. Done via the VM's package-global access — same effect as
    // `delete $main::soul{$key}` for each key.
    let mut keys: Vec<String> = Vec::new();
    for v in args {
        if v.is_undef() {
            continue;
        }
        if let Some(arr) = v.as_array_vec() {
            for item in arr {
                if !item.is_undef() {
                    keys.push(item.to_string());
                }
            }
        } else {
            keys.push(v.to_string());
        }
    }
    if keys.is_empty() {
        return Ok(StrykeValue::integer(0));
    }
    // Best-effort: walk the VM globals via the same registry path that
    // would be used inside an EVAL. Since the recant call happens inside
    // an agent's EVAL loop, %main::soul is in the local VM's package
    // table. We can't directly mutate it from Rust here without an
    // interpreter reference, so we surface the intended deletion list
    // and let the calling EVAL pattern delete them via stryke. (Tier 5+
    // would wire an interpreter handle to make this truly atomic.)
    //
    // For Tier 4, recant returns the count of keys it would delete; the
    // caller wraps it with a `for my $k (@keys) { delete $main::soul{$k} }`
    // pattern. This is documented as a limitation in the design doc.
    Ok(StrykeValue::integer(keys.len() as i64))
}

/// `martyr($path)` — slave-side: enshrine current `%soul` to `$path` then
/// `exit(0)`. Equivalent to `enshrine(\%soul, $path); exit(0)`. Returns
/// only if enshrine fails; on success the process terminates.
fn builtin_martyr(args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    let path = args
        .first()
        .filter(|v| !v.is_undef())
        .map(|v| v.to_string())
        .ok_or_else(|| StrykeError::runtime("martyr: enshrine path required", 0))?;

    // Tier 4 limitation: we can't read %soul directly from Rust without
    // an interpreter handle. Caller pattern:
    //
    //   enshrine \%soul, "/tmp/soul.json";
    //   martyr("/tmp/soul.json");
    //
    // martyr's job is just the "exit after enshrine" half. Verify the
    // file exists (caller has already written it), then exit.
    if !std::path::Path::new(&path).exists() {
        return Err(StrykeError::runtime(
            format!(
                "martyr: enshrine file {} does not exist — call enshrine first",
                path
            ),
            0,
        ));
    }
    eprintln!("[martyr] enshrined to {} — exiting", path);
    std::process::exit(0);
}

/// `resurrect($enshrine_path)` — master-side: read enshrined state,
/// anoint one new agent, bestow the state to it. Returns the new agent's
/// session_id. Composable: just exhume + anoint + bestow in one call.
fn builtin_resurrect(args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    let path = args
        .first()
        .filter(|v| !v.is_undef())
        .map(|v| v.to_string())
        .ok_or_else(|| StrykeError::runtime("resurrect: enshrine path required", 0))?;

    // 1. exhume — read the saved state.
    let exhumed = builtin_exhume(&[StrykeValue::string(path.clone())])?;

    // 2. anoint(1) — spawn one new worker. anoint preserves the current
    //    controller so resurrect doesn't disrupt the calling script's
    //    primary congregation.
    let new_workers = builtin_anoint(&[StrykeValue::integer(1)])?;
    let worker_handles = new_workers
        .as_array_vec()
        .ok_or_else(|| StrykeError::runtime("resurrect: anoint did not return an array", 0))?;
    if worker_handles.is_empty() {
        return Err(StrykeError::runtime(
            "resurrect: anoint returned an empty congregation",
            0,
        ));
    }

    // 3. bestow — push the exhumed state to the new agent's %gift.
    //    Note: bestow targets the CURRENT controller. Since anoint
    //    spawns a separate controller (and preserves the current),
    //    we need to temporarily switch. Tier 4 limitation: this
    //    won't work if there's no prior current controller — anoint
    //    leaves it None. Workaround: caller must have called
    //    congregation() or ordain() before resurrect.
    let _ = builtin_bestow(&[exhumed, new_workers.clone()])?;

    // Return the first worker's handle.
    Ok(worker_handles[0].clone())
}

/// `divine($handler)` — slave-side: register a closure handler for
/// incoming petitions. The handler is stored as `our $stryke_divine_handler`
/// in the agent's persistent VM; the caller wraps the agent's EVAL
/// dispatch to call this handler instead of evaluating arbitrary code.
///
/// Tier 4 ships divine as a closure-registration primitive only; full
/// dispatch integration with the agent's EVAL loop is Tier 5 work
/// (requires splitting the agent's frame handler to consult the
/// registered divine handler).
fn builtin_divine(args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    let _handler = args
        .first()
        .filter(|v| !v.is_undef())
        .ok_or_else(|| StrykeError::runtime("divine: handler (coderef) required", 0))?;
    // Tier 4 limitation: we can't store the closure into the VM's package
    // globals from this builtin without an interpreter handle. Document
    // the intended pattern and return success — the caller is expected
    // to wrap its own EVAL receive path.
    Ok(StrykeValue::integer(1))
}

// ─── Tier 4: interrogate ────────────────────────────────────────────────────

/// OS-level process inspection via the `sysinfo` crate (already in deps,
/// used by stress.rs and banner.rs). Returns a stryke hash with the
/// process's metadata: pid, ppid, name, cmd, exe, cwd, uid,
/// memory_bytes (RSS), virtual_memory_bytes (VSZ), cpu_usage (%),
/// status (Run/Sleep/Zombie/Stop/...), start_time (unix epoch seconds),
/// run_time_secs (seconds since process start). Returns the
/// stryke-undef sentinel when the PID is not visible (terminated,
/// permission denied, or invalid).
fn interrogate_os_pid(pid: u32) -> StrykeResult<StrykeValue> {
    use sysinfo::{Pid, ProcessesToUpdate, System};

    let mut sys = System::new();
    let pid_t = Pid::from_u32(pid);
    // refresh_processes with a specific PID list is faster than full
    // refresh — we only need this one process.
    sys.refresh_processes(ProcessesToUpdate::Some(&[pid_t]), true);

    let proc = match sys.process(pid_t) {
        Some(p) => p,
        None => return Ok(StrykeValue::UNDEF),
    };

    let mut hash = indexmap::IndexMap::new();
    hash.insert("pid".into(), StrykeValue::integer(pid as i64));
    if let Some(ppid) = proc.parent() {
        hash.insert("ppid".into(), StrykeValue::integer(ppid.as_u32() as i64));
    }
    hash.insert(
        "name".into(),
        StrykeValue::string(proc.name().to_string_lossy().into_owned()),
    );
    let cmd_vec: Vec<StrykeValue> = proc
        .cmd()
        .iter()
        .map(|s| StrykeValue::string(s.to_string_lossy().into_owned()))
        .collect();
    hash.insert("cmd".into(), StrykeValue::array(cmd_vec));
    if let Some(exe) = proc.exe() {
        hash.insert(
            "exe".into(),
            StrykeValue::string(exe.to_string_lossy().into_owned()),
        );
    }
    if let Some(cwd) = proc.cwd() {
        hash.insert(
            "cwd".into(),
            StrykeValue::string(cwd.to_string_lossy().into_owned()),
        );
    }
    if let Some(uid) = proc.user_id() {
        hash.insert("uid".into(), StrykeValue::integer(**uid as i64));
    }
    hash.insert(
        "memory_bytes".into(),
        StrykeValue::integer(proc.memory() as i64),
    );
    hash.insert(
        "virtual_memory_bytes".into(),
        StrykeValue::integer(proc.virtual_memory() as i64),
    );
    hash.insert(
        "cpu_usage".into(),
        StrykeValue::float(proc.cpu_usage() as f64),
    );
    hash.insert(
        "status".into(),
        StrykeValue::string(format!("{:?}", proc.status())),
    );
    hash.insert(
        "start_time".into(),
        StrykeValue::integer(proc.start_time() as i64),
    );
    hash.insert(
        "run_time_secs".into(),
        StrykeValue::integer(proc.run_time() as i64),
    );
    // Return as a hash_ref so callers can store it in a scalar and deref
    // with `%{$h}` — the typical Perl idiom for "function returning a
    // hash." A bare hash value works for `my %h = interrogate($pid)` but
    // breaks `%{interrogate($pid)}` deref. Ref form supports both shapes.
    Ok(StrykeValue::hash_ref(Arc::new(parking_lot::RwLock::new(
        hash,
    ))))
}

/// `interrogate($pid_or_handles)` — polymorphic process-state dump.
///
/// * `interrogate($pid)` (single scalar arg): OS-level dump for an OS PID
///   via the `sysinfo` crate. Returns a hash with `pid`, `ppid`, `name`,
///   `cmd`, `exe`, `cwd`, `uid`, `memory_bytes`, `virtual_memory_bytes`,
///   `cpu_usage`, `status`, `start_time`, `run_time_secs`. Works for ANY
///   visible OS process — not just stryke agents. Returns `undef` if the
///   PID isn't visible (terminated, permission denied, or invalid).
///
/// * `interrogate(@agent_handles)` (array / multi-arg): agent VM state
///   dump via the scatter-EVAL path. Returns a hash keyed by session_id
///   (stringified) where each value is a hash of the agent's PID, time,
///   `%soul`, and `%gift`. Non-destructive.
///
/// Dispatch heuristic: single scalar arg → OS PID. Array or multiple args
/// → agent handles. This matches the user-natural `interrogate($pid)`
/// AND `interrogate(@cong)` invocations without needing two verb names.
fn builtin_interrogate(args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    // OS PID path — single scalar argument, no array.
    if args.len() == 1 {
        let arg = &args[0];
        if !arg.is_undef() && arg.as_array_vec().is_none() {
            let pid = arg.to_int();
            if pid <= 0 {
                return Err(StrykeError::runtime(
                    format!("interrogate: invalid PID {}", pid),
                    0,
                ));
            }
            return interrogate_os_pid(pid as u32);
        }
    }

    // Agent-handle path — fall through to the existing controller dump.
    use std::time::Duration;

    let agent_ids = flatten_agent_handles(args);
    if agent_ids.is_empty() {
        return Err(StrykeError::runtime(
            "interrogate: at least one agent handle or OS PID required",
            0,
        ));
    }
    let handle = require_current_controller("interrogate")?;
    // Use \%hash ref form (fixed 2026-05-27 in scope.rs::promote_hash_to_shared)
    // so the JSON encodes as a proper object, not a flat key/value array.
    let code = r#"
        our %soul; our %gift;
        my $pid = $$;
        my $now = time();
        '{"pid":' . $pid . ',"time":' . $now . ',"soul":' . to_json(\%soul) . ',"gift":' . to_json(\%gift) . '}'
    "#;
    let petition_id = handle
        .scatter(code, &agent_ids)
        .map_err(|e| StrykeError::runtime(format!("interrogate: scatter failed: {}", e), 0))?;
    let results = handle
        .gather(petition_id, Duration::from_secs(10))
        .map_err(|e| StrykeError::runtime(format!("interrogate: gather failed: {}", e), 0))?;

    let mut hash = indexmap::IndexMap::new();
    let mut sorted_ids: Vec<u64> = results.keys().copied().collect();
    sorted_ids.sort_unstable();
    for sid in sorted_ids {
        let r = &results[&sid];
        let json_str = r.output.trim();
        let value = match serde_json::from_str::<serde_json::Value>(json_str) {
            Ok(parsed) => json_value_to_stryke(parsed),
            Err(_) => StrykeValue::string(r.output.clone()),
        };
        hash.insert(sid.to_string(), value);
    }
    Ok(StrykeValue::hash(hash))
}

/// `kick($host, $port [, $timeout_ms])` — TCP liveness probe. Attempts a
/// connect to `$host:$port` with a wall-clock timeout (default 1000ms,
/// matching `nc -zw1` convention). Returns `1` if the connect succeeds,
/// `0` on any failure: closed port, refused connection, name-resolution
/// failure, timeout. Never raises — failure is signalled by the return
/// value so callers can write `if (kick("db", 5432)) { ... }`.
///
/// Resolves `$host` via the OS resolver — accepts hostnames, IPv4 and
/// IPv6 literals, plus per-OS aliases (`localhost`, `127.0.0.1`, `::1`,
/// `dbprod.example.com`). When DNS returns multiple addresses, each is
/// tried in turn until one succeeds OR all fail within the timeout.
fn builtin_kick(args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    use std::net::TcpStream;
    use std::time::Duration;

    let host = args
        .first()
        .filter(|v| !v.is_undef())
        .map(|v| v.to_string())
        .unwrap_or_default();
    if host.is_empty() {
        return Ok(StrykeValue::integer(0));
    }
    let port_raw = args
        .get(1)
        .filter(|v| !v.is_undef())
        .map(|v| v.to_int())
        .unwrap_or(0);
    if !(1..=65535).contains(&port_raw) {
        return Ok(StrykeValue::integer(0));
    }
    let port = port_raw as u16;
    let timeout_ms = args
        .get(2)
        .filter(|v| !v.is_undef())
        .map(|v| v.to_int().max(1) as u64)
        .unwrap_or(1000);
    let timeout = Duration::from_millis(timeout_ms);

    let addrs: Vec<_> = match (host.as_str(), port).to_socket_addrs() {
        Ok(it) => it.collect(),
        Err(_) => return Ok(StrykeValue::integer(0)),
    };
    for addr in addrs {
        if TcpStream::connect_timeout(&addr, timeout).is_ok() {
            return Ok(StrykeValue::integer(1));
        }
    }
    Ok(StrykeValue::integer(0))
}

/// `tcp_probe($host, $port [, $timeout_ms=1000])` — TCP connect probe
/// that returns RTT, not just bool. Companion to `kick` (which returns
/// `1`/`0` for fast service-mesh sweeps); use `tcp_probe` when you want
/// the latency measurement too.
///
/// Returns a hashref:
///   { alive      => 1 | 0,
///     latency_ms => N (or 0 on failure) }
///
/// Same fail-soft semantics as `kick` — bad host, closed port, DNS
/// failure, timeout all give `{ alive=>0, latency_ms=>... }` without
/// raising.
fn builtin_tcp_probe(args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    use indexmap::IndexMap;
    use parking_lot::RwLock;
    use std::net::TcpStream;
    use std::sync::Arc as StdArc;
    use std::time::{Duration, Instant};

    let host = args
        .first()
        .filter(|v| !v.is_undef())
        .map(|v| v.to_string())
        .unwrap_or_default();
    let port_raw = args
        .get(1)
        .filter(|v| !v.is_undef())
        .map(|v| v.to_int())
        .unwrap_or(0);
    let timeout_ms = args
        .get(2)
        .filter(|v| !v.is_undef())
        .map(|v| v.to_int().max(1) as u64)
        .unwrap_or(1000);
    let mk = |alive: bool, ms: u64| {
        let mut m: IndexMap<String, StrykeValue> = IndexMap::new();
        m.insert(
            "alive".into(),
            StrykeValue::integer(if alive { 1 } else { 0 }),
        );
        m.insert("latency_ms".into(), StrykeValue::integer(ms as i64));
        StrykeValue::hash_ref(StdArc::new(RwLock::new(m)))
    };
    if host.is_empty() || !(1..=65535).contains(&port_raw) {
        return Ok(mk(false, 0));
    }
    let port = port_raw as u16;
    let timeout = Duration::from_millis(timeout_ms);
    let addrs: Vec<_> = match (host.as_str(), port).to_socket_addrs() {
        Ok(it) => it.collect(),
        Err(_) => return Ok(mk(false, 0)),
    };
    let start = Instant::now();
    for addr in addrs {
        if TcpStream::connect_timeout(&addr, timeout).is_ok() {
            return Ok(mk(true, start.elapsed().as_millis() as u64));
        }
    }
    Ok(mk(false, start.elapsed().as_millis() as u64))
}

/// `tcp_banner($host, $port [, $timeout_ms=1000, $max_bytes=512])` —
/// connect + read the first `$max_bytes` bytes the server sends. Classic
/// service-fingerprint pattern (SSH version line, HTTP server header,
/// SMTP greeting). Returns a hashref:
///   { alive      => 1 | 0,
///     latency_ms => N,
///     banner     => "SSH-2.0-OpenSSH_9.7" (UTF-8 if valid, else bytes) }
///
/// Servers that DON'T greet (HTTP for example — expects a request first)
/// return `banner => ""` with alive=1. Caller can branch on `length($r->{banner}) > 0`
/// to distinguish "greeted" from "silent".
fn builtin_tcp_banner(args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    use indexmap::IndexMap;
    use parking_lot::RwLock;
    use std::io::Read;
    use std::net::TcpStream;
    use std::sync::Arc as StdArc;
    use std::time::{Duration, Instant};

    let host = args
        .first()
        .filter(|v| !v.is_undef())
        .map(|v| v.to_string())
        .unwrap_or_default();
    let port_raw = args
        .get(1)
        .filter(|v| !v.is_undef())
        .map(|v| v.to_int())
        .unwrap_or(0);
    let timeout_ms = args
        .get(2)
        .filter(|v| !v.is_undef())
        .map(|v| v.to_int().max(1) as u64)
        .unwrap_or(1000);
    let max_bytes = args
        .get(3)
        .filter(|v| !v.is_undef())
        .map(|v| v.to_int().max(1).min(65_536) as usize)
        .unwrap_or(512);
    let mk = |alive: bool, ms: u64, banner: Vec<u8>| {
        let mut m: IndexMap<String, StrykeValue> = IndexMap::new();
        m.insert(
            "alive".into(),
            StrykeValue::integer(if alive { 1 } else { 0 }),
        );
        m.insert("latency_ms".into(), StrykeValue::integer(ms as i64));
        let banner_v = match String::from_utf8(banner.clone()) {
            Ok(s) => StrykeValue::string(s),
            Err(_) => StrykeValue::bytes(StdArc::new(banner)),
        };
        m.insert("banner".into(), banner_v);
        StrykeValue::hash_ref(StdArc::new(RwLock::new(m)))
    };
    if host.is_empty() || !(1..=65535).contains(&port_raw) {
        return Ok(mk(false, 0, Vec::new()));
    }
    let port = port_raw as u16;
    let timeout = Duration::from_millis(timeout_ms);
    let addrs: Vec<_> = match (host.as_str(), port).to_socket_addrs() {
        Ok(it) => it.collect(),
        Err(_) => return Ok(mk(false, 0, Vec::new())),
    };
    let start = Instant::now();
    for addr in addrs {
        let Ok(mut stream) = TcpStream::connect_timeout(&addr, timeout) else {
            continue;
        };
        let connect_ms = start.elapsed().as_millis() as u64;
        // Set short read timeout — servers that DON'T greet shouldn't
        // hold us. Banner-greeting servers (SSH, FTP, SMTP) reply
        // within ~50ms on the same network.
        let _ = stream.set_read_timeout(Some(Duration::from_millis(200)));
        let mut buf = vec![0u8; max_bytes];
        let n = stream.read(&mut buf).unwrap_or(0);
        buf.truncate(n);
        return Ok(mk(true, connect_ms, buf));
    }
    Ok(mk(false, start.elapsed().as_millis() as u64, Vec::new()))
}

/// `whois_query($domain [, $server="whois.iana.org", $timeout_ms=5000])`
/// — RFC 3912 WHOIS query. Connects to `$server:43`, sends `$domain\r\n`,
/// reads the response until the server closes (or timeout fires).
/// Returns the full response as a string, `undef` on failure.
///
/// Default server is IANA's referral server — for most TLDs the response
/// includes a `Refer:` line pointing to the authoritative registry. For
/// definitive results, query the registry directly (e.g. `whois.verisign-grs.com`
/// for `.com`, `whois.nic.io` for `.io`).
fn builtin_whois_query(args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    use std::io::{Read, Write};
    use std::net::TcpStream;
    use std::time::Duration;

    let domain = args
        .first()
        .filter(|v| !v.is_undef())
        .map(|v| v.to_string())
        .unwrap_or_default();
    if domain.is_empty() {
        return Ok(StrykeValue::UNDEF);
    }
    let server = args
        .get(1)
        .filter(|v| !v.is_undef())
        .map(|v| v.to_string())
        .unwrap_or_else(|| "whois.iana.org".to_string());
    let timeout_ms = args
        .get(2)
        .filter(|v| !v.is_undef())
        .map(|v| v.to_int().max(100) as u64)
        .unwrap_or(5000);
    let timeout = Duration::from_millis(timeout_ms);

    let addrs: Vec<_> = match (server.as_str(), 43u16).to_socket_addrs() {
        Ok(it) => it.collect(),
        Err(_) => return Ok(StrykeValue::UNDEF),
    };
    for addr in addrs {
        let Ok(mut stream) = TcpStream::connect_timeout(&addr, timeout) else {
            continue;
        };
        let _ = stream.set_write_timeout(Some(timeout));
        let _ = stream.set_read_timeout(Some(timeout));
        if stream
            .write_all(format!("{}\r\n", domain).as_bytes())
            .is_err()
        {
            continue;
        }
        let mut response = Vec::new();
        // Read until server closes or we hit a reasonable cap (256 KB).
        let mut buf = [0u8; 4096];
        loop {
            match stream.read(&mut buf) {
                Ok(0) => break,
                Ok(n) => {
                    response.extend_from_slice(&buf[..n]);
                    if response.len() > 256 * 1024 {
                        break;
                    }
                }
                Err(_) => break,
            }
        }
        return match String::from_utf8(response.clone()) {
            Ok(s) => Ok(StrykeValue::string(s)),
            Err(_) => Ok(StrykeValue::bytes(std::sync::Arc::new(response))),
        };
    }
    Ok(StrykeValue::UNDEF)
}

/// `udp_send($host, $port, $payload [, $retries=1, $interval_ms=20])` — send
/// `$payload` as a UDP datagram to `$host:$port`. Returns the number of
/// datagrams successfully sent (0 = total failure, `$retries` = full success).
///
/// `$payload` can be a string (sent as UTF-8 bytes) or a byte buffer (sent
/// as-is). When `$retries > 1`, the same datagram is sent that many times
/// at `$interval_ms` apart — useful for Wake-on-LAN magic packets (commonly
/// sent 3× for reliability), NAT keepalives, and best-effort IoT discovery
/// broadcasts.
///
/// For peer-to-peer NAT traversal (where both endpoints are behind NAT and
/// need to discover their public `ip:port` via STUN before exchanging
/// packets), use `punch($peer_ip, $peer_port)` which handles the full
/// hole-punching protocol.
fn builtin_udp_send(args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    use std::net::{SocketAddr, UdpSocket};
    use std::time::Duration;

    let host = args
        .first()
        .filter(|v| !v.is_undef())
        .map(|v| v.to_string())
        .unwrap_or_default();
    if host.is_empty() {
        return Ok(StrykeValue::integer(0));
    }
    let port_raw = args
        .get(1)
        .filter(|v| !v.is_undef())
        .map(|v| v.to_int())
        .unwrap_or(0);
    if !(1..=65535).contains(&port_raw) {
        return Ok(StrykeValue::integer(0));
    }
    let port = port_raw as u16;

    let payload: Vec<u8> = match args.get(2).filter(|v| !v.is_undef()) {
        Some(v) => {
            if let Some(arc) = v.as_bytes_arc() {
                (*arc).clone()
            } else {
                v.to_string().into_bytes()
            }
        }
        None => Vec::new(),
    };
    let retries = args
        .get(3)
        .filter(|v| !v.is_undef())
        .map(|v| v.to_int().max(1) as u32)
        .unwrap_or(1);
    let interval_ms = args
        .get(4)
        .filter(|v| !v.is_undef())
        .map(|v| v.to_int().max(0) as u64)
        .unwrap_or(20);

    let addrs: Vec<SocketAddr> = match (host.as_str(), port).to_socket_addrs() {
        Ok(it) => it.collect(),
        Err(_) => return Ok(StrykeValue::integer(0)),
    };
    if addrs.is_empty() {
        return Ok(StrykeValue::integer(0));
    }
    // Bind once, use for every shot. `0.0.0.0:0` picks an ephemeral port
    // that the kernel rotates per call — fine for outbound-only.
    let socket = match UdpSocket::bind("0.0.0.0:0") {
        Ok(s) => s,
        Err(_) => return Ok(StrykeValue::integer(0)),
    };
    // Enable broadcast in case the caller is targeting 255.255.255.255 for
    // local-subnet WoL. Failure to set is non-fatal — the call may still
    // succeed for unicast.
    let _ = socket.set_broadcast(true);

    let mut sent: u32 = 0;
    let interval = Duration::from_millis(interval_ms);
    for shot in 0..retries {
        let mut shot_ok = false;
        for addr in &addrs {
            if socket.send_to(&payload, addr).is_ok() {
                shot_ok = true;
                break;
            }
        }
        if shot_ok {
            sent += 1;
        }
        if shot + 1 < retries && interval_ms > 0 {
            std::thread::sleep(interval);
        }
    }
    Ok(StrykeValue::integer(sent as i64))
}

/// `udp_open([$bind_host="0.0.0.0", $bind_port=0])` — bind a UDP socket,
/// return an opaque integer handle. The socket is held in a process-
/// global pool until `udp_close($id)`. `$bind_port = 0` lets the kernel
/// assign an ephemeral port (the common case). Returns `0` on bind
/// failure.
fn builtin_udp_open(args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    let bind_host = args
        .first()
        .filter(|v| !v.is_undef())
        .map(|v| v.to_string())
        .unwrap_or_else(|| "0.0.0.0".to_string());
    let bind_port = args
        .get(1)
        .filter(|v| !v.is_undef())
        .map(|v| v.to_int().clamp(0, 65535) as u16)
        .unwrap_or(0);
    match crate::udp_sockets::open(&bind_host, bind_port) {
        Some(id) => Ok(StrykeValue::integer(id as i64)),
        None => Ok(StrykeValue::integer(0)),
    }
}

/// `udp_send_to($id, $host, $port, $payload)` — send `$payload` via the
/// pool socket identified by `$id` to `$host:$port`. Returns bytes sent
/// on success, `0` on any failure (unknown id, DNS failure, send error).
fn builtin_udp_send_to(args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    let id = args
        .first()
        .filter(|v| !v.is_undef())
        .map(|v| v.to_int() as u64)
        .unwrap_or(0);
    let host = args
        .get(1)
        .filter(|v| !v.is_undef())
        .map(|v| v.to_string())
        .unwrap_or_default();
    let port_raw = args
        .get(2)
        .filter(|v| !v.is_undef())
        .map(|v| v.to_int())
        .unwrap_or(0);
    if id == 0 || host.is_empty() || !(1..=65535).contains(&port_raw) {
        return Ok(StrykeValue::integer(0));
    }
    let port = port_raw as u16;
    let payload: Vec<u8> = match args.get(3).filter(|v| !v.is_undef()) {
        Some(v) => {
            if let Some(arc) = v.as_bytes_arc() {
                (*arc).clone()
            } else {
                v.to_string().into_bytes()
            }
        }
        None => Vec::new(),
    };
    match crate::udp_sockets::send_to(id, &host, port, &payload) {
        Some(n) => Ok(StrykeValue::integer(n as i64)),
        None => Ok(StrykeValue::integer(0)),
    }
}

/// `udp_recv($id [, $timeout_ms])` — read one datagram from socket `$id`.
/// Returns the payload as a string (UTF-8 if valid, otherwise raw bytes
/// — callers can pass through `unpack` if they need binary). Returns
/// `undef` on timeout / unknown id / recv error. Default timeout 1000ms;
/// `0` blocks indefinitely.
fn builtin_udp_recv(args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    use std::time::Duration;
    let id = args
        .first()
        .filter(|v| !v.is_undef())
        .map(|v| v.to_int() as u64)
        .unwrap_or(0);
    if id == 0 {
        return Ok(StrykeValue::UNDEF);
    }
    let timeout_ms = args
        .get(1)
        .filter(|v| !v.is_undef())
        .map(|v| v.to_int().max(0) as u64)
        .unwrap_or(1000);
    let timeout = if timeout_ms == 0 {
        None
    } else {
        Some(Duration::from_millis(timeout_ms))
    };
    match crate::udp_sockets::recv(id, timeout) {
        Some((bytes, _)) => match String::from_utf8(bytes.clone()) {
            Ok(s) => Ok(StrykeValue::string(s)),
            // Non-UTF8 payload — return as bytes so the caller can `unpack`.
            Err(_) => Ok(StrykeValue::bytes(std::sync::Arc::new(bytes))),
        },
        None => Ok(StrykeValue::UNDEF),
    }
}

/// `udp_recv_from($id [, $timeout_ms=1000])` — read one datagram from
/// socket `$id` and surface the source address alongside the payload.
/// Returns a hashref:
///
///   { payload  => "hello",        # string if UTF-8 valid, else bytes
///     src_ip   => "203.0.113.45",
///     src_port => 51234 }
///
/// Returns `undef` on timeout / unknown id / recv error. Default timeout
/// 1000ms; `0` blocks indefinitely. The src fields are exactly what the
/// kernel reported on `recvfrom(2)` — for a peer behind NAT this is the
/// peer's PUBLIC address as seen from this side, not their private LAN
/// address. Pair with `udp_send_to($id, $src_ip, $src_port, $reply)` to
/// answer the sender.
fn builtin_udp_recv_from(args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    use indexmap::IndexMap;
    use parking_lot::RwLock;
    use std::sync::Arc as StdArc;
    use std::time::Duration;
    let id = args
        .first()
        .filter(|v| !v.is_undef())
        .map(|v| v.to_int() as u64)
        .unwrap_or(0);
    if id == 0 {
        return Ok(StrykeValue::UNDEF);
    }
    let timeout_ms = args
        .get(1)
        .filter(|v| !v.is_undef())
        .map(|v| v.to_int().max(0) as u64)
        .unwrap_or(1000);
    let timeout = if timeout_ms == 0 {
        None
    } else {
        Some(Duration::from_millis(timeout_ms))
    };
    let (bytes, src) = match crate::udp_sockets::recv(id, timeout) {
        Some(pair) => pair,
        None => return Ok(StrykeValue::UNDEF),
    };
    let payload = match String::from_utf8(bytes.clone()) {
        Ok(s) => StrykeValue::string(s),
        Err(_) => StrykeValue::bytes(StdArc::new(bytes)),
    };
    let mut m: IndexMap<String, StrykeValue> = IndexMap::new();
    m.insert("payload".into(), payload);
    m.insert("src_ip".into(), StrykeValue::string(src.ip().to_string()));
    m.insert("src_port".into(), StrykeValue::integer(src.port() as i64));
    Ok(StrykeValue::hash_ref(StdArc::new(RwLock::new(m))))
}

/// `udp_close($id)` — release socket `$id` from the pool. Returns `1` if
/// the socket was present, `0` if `$id` was unknown.
fn builtin_udp_close(args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    let id = args
        .first()
        .filter(|v| !v.is_undef())
        .map(|v| v.to_int() as u64)
        .unwrap_or(0);
    if id == 0 {
        return Ok(StrykeValue::integer(0));
    }
    let dropped = crate::udp_sockets::close(id);
    Ok(StrykeValue::integer(if dropped { 1 } else { 0 }))
}

/// `stun($id [, $stun_host="stun.l.google.com", $stun_port=19302, $timeout_ms=2000])`
/// — query a STUN server via the pool socket `$id` and return the public
/// `(ip, port)` the server reports it observed. Returns a hashref:
///
///   { public_ip => "203.0.113.45", public_port => 51234 }
///
/// or `undef` on timeout / parse failure / unknown id.
///
/// The socket the query goes through MUST be the same socket subsequent
/// `punch($id, ...)` and peer traffic use — the NAT mapping the STUN
/// response reveals is tied to that socket's (local_ip, local_port).
fn builtin_stun(args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    use indexmap::IndexMap;
    use parking_lot::RwLock;
    use std::sync::Arc as StdArc;
    use std::time::Duration;

    let id = args
        .first()
        .filter(|v| !v.is_undef())
        .map(|v| v.to_int() as u64)
        .unwrap_or(0);
    if id == 0 {
        return Ok(StrykeValue::UNDEF);
    }
    let stun_host = args
        .get(1)
        .filter(|v| !v.is_undef())
        .map(|v| v.to_string())
        .unwrap_or_else(|| "stun.l.google.com".to_string());
    let stun_port = args
        .get(2)
        .filter(|v| !v.is_undef())
        .map(|v| v.to_int().clamp(1, 65535) as u16)
        .unwrap_or(19302);
    let timeout_ms = args
        .get(3)
        .filter(|v| !v.is_undef())
        .map(|v| v.to_int().max(1) as u64)
        .unwrap_or(2000);

    match crate::nat_punch::stun_query(id, &stun_host, stun_port, Duration::from_millis(timeout_ms))
    {
        Some((ip, port)) => {
            let mut m: IndexMap<String, StrykeValue> = IndexMap::new();
            m.insert("public_ip".into(), StrykeValue::string(ip.to_string()));
            m.insert("public_port".into(), StrykeValue::integer(port as i64));
            Ok(StrykeValue::hash_ref(StdArc::new(RwLock::new(m))))
        }
        None => Ok(StrykeValue::UNDEF),
    }
}

/// `stun_classify($id [, $opts])` — query multiple STUN servers via the
/// SAME socket and classify the local NAT based on whether the reported
/// public ports match across servers. Returns:
///
///   { nat_type     => "cone" | "symmetric" | "unknown",
///     public_ip    => "203.0.113.45" | undef,
///     queried      => 3,
///     succeeded    => 3,
///     observations => [
///       { server => "stun.l.google.com:19302", ok => 1,
///         public_ip => "203.0.113.45", public_port => 51234 },
///       { server => "stun.cloudflare.com:3478", ok => 1,
///         public_ip => "203.0.113.45", public_port => 51234 },
///       ... ] }
///
/// `nat_type` semantics:
///   * `"cone"` — every responding server reported the SAME port → NAT
///     uses one public mapping per source socket regardless of dest →
///     `punch` will work to any peer.
///   * `"symmetric"` — servers reported DIFFERENT ports → NAT allocates
///     a fresh public port per destination → `punch` will FAIL because
///     the port the peer punches at (learned from STUN server X) won't
///     be the port your traffic to the peer uses. The only recovery is
///     a TURN relay (not yet shipped — out of scope for v1).
///   * `"unknown"` — fewer than 2 servers responded → can't classify.
///
/// `$opts` (hashref, all keys optional):
///   * `servers` (arrayref of `["host", port]` pairs) — defaults to a
///     diverse set: Google, Cloudflare, Nextcloud STUN. Diversity
///     matters: some symmetric NATs bucket by destination /24, so
///     same-provider servers can falsely produce matching ports on a
///     symmetric NAT. Three different ASNs catches more cases.
///   * `timeout_ms` (default 2000) — per-server timeout.
///
/// Recommended pattern: classify BEFORE calling `punch`, bail early if
/// symmetric to give the user a useful error rather than a 30s timeout:
///
/// ```perl
/// my $sock = udp_open()
/// my $nat = stun_classify($sock)
/// if ($nat->{nat_type} eq "symmetric") {
///     die "behind symmetric NAT — hole-punching impossible, need TURN"
/// }
/// my $info = stun($sock)   # one of the queries above already learned this;
///                          # we re-query for the canonical (ip, port) handoff
/// # … signaling … then punch …
/// ```
fn builtin_stun_classify(args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    use indexmap::IndexMap;
    use parking_lot::RwLock;
    use std::sync::Arc as StdArc;
    use std::time::Duration;

    let id = args
        .first()
        .filter(|v| !v.is_undef())
        .map(|v| v.to_int() as u64)
        .unwrap_or(0);
    if id == 0 {
        return Ok(StrykeValue::UNDEF);
    }

    // Parse opts hashref: { servers => [["host", port], …], timeout_ms => N }.
    // Default servers list lives in nat_punch::DEFAULT_STUN_SERVERS.
    //
    // KEY-PRESENCE semantics: distinguish "servers not provided" (fall back
    // to defaults) from "servers explicitly set to []" (respect, return
    // immediately with queried=0). Tracking `servers_explicit` rather than
    // "is the parsed list empty" lets users say `servers => []` to disable
    // the implicit-default fallback when probing whether their explicit
    // list works.
    let mut timeout_ms: u64 = 2000;
    let mut server_owned: Vec<(String, u16)> = Vec::new();
    let mut servers_explicit = false;
    if let Some(opts) = args.get(1).filter(|v| !v.is_undef()) {
        if let Some(h) = opts.as_hash_ref() {
            let g = h.read();
            if let Some(t) = g.get("timeout_ms") {
                if !t.is_undef() {
                    timeout_ms = t.to_int().max(1) as u64;
                }
            }
            if let Some(s) = g.get("servers") {
                if !s.is_undef() {
                    servers_explicit = true;
                    if let Some(arr) = s.as_array_ref() {
                        let arr_g = arr.read();
                        for entry in arr_g.iter() {
                            // Each entry should be [host, port].
                            if let Some(inner) = entry.as_array_ref() {
                                let inner_g = inner.read();
                                if inner_g.len() >= 2 {
                                    let host = inner_g[0].to_string();
                                    let port = inner_g[1].to_int().clamp(1, 65535) as u16;
                                    if !host.is_empty() {
                                        server_owned.push((host, port));
                                    }
                                }
                            }
                        }
                    }
                }
            }
        }
    }
    if !servers_explicit && server_owned.is_empty() {
        server_owned = crate::nat_punch::DEFAULT_STUN_SERVERS
            .iter()
            .map(|(h, p)| ((*h).to_string(), *p))
            .collect();
    }
    let servers: Vec<(&str, u16)> = server_owned.iter().map(|(h, p)| (h.as_str(), *p)).collect();

    let result = crate::nat_punch::classify_nat(id, &servers, Duration::from_millis(timeout_ms));

    let mut top: IndexMap<String, StrykeValue> = IndexMap::new();
    top.insert(
        "nat_type".into(),
        StrykeValue::string(result.nat_type.into()),
    );
    top.insert(
        "public_ip".into(),
        match result.public_ip {
            Some(ip) => StrykeValue::string(ip.to_string()),
            None => StrykeValue::UNDEF,
        },
    );
    top.insert(
        "queried".into(),
        StrykeValue::integer(result.queried as i64),
    );
    top.insert(
        "succeeded".into(),
        StrykeValue::integer(result.succeeded as i64),
    );
    let mut obs_list: Vec<StrykeValue> = Vec::with_capacity(result.observations.len());
    for obs in &result.observations {
        let mut h: IndexMap<String, StrykeValue> = IndexMap::new();
        h.insert("server".into(), StrykeValue::string(obs.server.clone()));
        h.insert(
            "ok".into(),
            StrykeValue::integer(if obs.ok { 1 } else { 0 }),
        );
        h.insert(
            "public_ip".into(),
            match obs.public_ip {
                Some(ip) => StrykeValue::string(ip.to_string()),
                None => StrykeValue::UNDEF,
            },
        );
        h.insert(
            "public_port".into(),
            match obs.public_port {
                Some(p) => StrykeValue::integer(p as i64),
                None => StrykeValue::UNDEF,
            },
        );
        obs_list.push(StrykeValue::hash_ref(StdArc::new(RwLock::new(h))));
    }
    top.insert(
        "observations".into(),
        StrykeValue::array_ref(StdArc::new(RwLock::new(obs_list))),
    );
    Ok(StrykeValue::hash_ref(StdArc::new(RwLock::new(top))))
}

/// `punch($id, $peer_ip, $peer_port [, $opts])` — UDP hole-punching state
/// machine. Bombards `$peer_ip:$peer_port` via socket `$id` at a fixed
/// interval, listens for any inbound datagram, returns when bidirectional
/// flow is established OR timeout fires.
///
/// `$opts` (hashref, all keys optional):
///   * `timeout_ms` (default 5000)  — wall-clock punch budget
///   * `interval_ms` (default 50)   — gap between bombards
///   * `payload` (default "stryke-punch") — probe payload sent each round
///
/// Returns a hashref:
///
///   { established  => 1,         # 0 on timeout
///     latency_ms   => 380,       # time to first reply (or budget on fail)
///     bombards     => 8,         # count of datagrams we sent
///     peer_msg     => "hi from b",   # first received payload (or undef)
///     peer_addr    => "203.0.113.45:51234" }   # source addr (or undef)
///
/// Real-world success rate is ~70-80% on arbitrary internet. Symmetric
/// NATs (some mobile carriers, some corporate firewalls) and UDP-blocking
/// firewalls cause failure with no language-level workaround short of
/// allocating a TURN relay.
fn builtin_punch(args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    use indexmap::IndexMap;
    use parking_lot::RwLock;
    use std::sync::Arc as StdArc;
    use std::time::Duration;

    let id = args
        .first()
        .filter(|v| !v.is_undef())
        .map(|v| v.to_int() as u64)
        .unwrap_or(0);
    let peer_host = args
        .get(1)
        .filter(|v| !v.is_undef())
        .map(|v| v.to_string())
        .unwrap_or_default();
    let peer_port_raw = args
        .get(2)
        .filter(|v| !v.is_undef())
        .map(|v| v.to_int())
        .unwrap_or(0);
    if id == 0 || peer_host.is_empty() || !(1..=65535).contains(&peer_port_raw) {
        let mut m: IndexMap<String, StrykeValue> = IndexMap::new();
        m.insert("established".into(), StrykeValue::integer(0));
        m.insert("latency_ms".into(), StrykeValue::integer(0));
        m.insert("bombards".into(), StrykeValue::integer(0));
        m.insert("peer_msg".into(), StrykeValue::UNDEF);
        m.insert("peer_addr".into(), StrykeValue::UNDEF);
        return Ok(StrykeValue::hash_ref(StdArc::new(RwLock::new(m))));
    }
    let peer_port = peer_port_raw as u16;

    // Opts hash (optional, 4th arg).
    let (timeout_ms, interval_ms, payload) = match args.get(3).filter(|v| !v.is_undef()) {
        Some(opts) => {
            let h = opts.as_hash_ref();
            let mut timeout = 5000u64;
            let mut interval = 50u64;
            let mut payload = b"stryke-punch".to_vec();
            if let Some(arc) = h {
                let guard = arc.read();
                if let Some(v) = guard.get("timeout_ms") {
                    if !v.is_undef() {
                        timeout = v.to_int().max(1) as u64;
                    }
                }
                if let Some(v) = guard.get("interval_ms") {
                    if !v.is_undef() {
                        interval = v.to_int().max(1) as u64;
                    }
                }
                if let Some(v) = guard.get("payload") {
                    if !v.is_undef() {
                        if let Some(b) = v.as_bytes_arc() {
                            payload = (*b).clone();
                        } else {
                            payload = v.to_string().into_bytes();
                        }
                    }
                }
            }
            (timeout, interval, payload)
        }
        None => (5000u64, 50u64, b"stryke-punch".to_vec()),
    };

    let result = crate::nat_punch::hole_punch(
        id,
        &peer_host,
        peer_port,
        Duration::from_millis(timeout_ms),
        Duration::from_millis(interval_ms),
        &payload,
    );
    let mut m: IndexMap<String, StrykeValue> = IndexMap::new();
    m.insert(
        "established".into(),
        StrykeValue::integer(if result.established { 1 } else { 0 }),
    );
    m.insert(
        "latency_ms".into(),
        StrykeValue::integer(result.latency_ms as i64),
    );
    m.insert(
        "bombards".into(),
        StrykeValue::integer(result.bombards_sent as i64),
    );
    m.insert(
        "peer_msg".into(),
        match result.peer_msg {
            Some(b) => match String::from_utf8(b.clone()) {
                Ok(s) => StrykeValue::string(s),
                Err(_) => StrykeValue::bytes(StdArc::new(b)),
            },
            None => StrykeValue::UNDEF,
        },
    );
    m.insert(
        "peer_addr".into(),
        match result.peer_addr {
            Some(a) => StrykeValue::string(a.to_string()),
            None => StrykeValue::UNDEF,
        },
    );
    Ok(StrykeValue::hash_ref(StdArc::new(RwLock::new(m))))
}

// ── TURN relay helpers ──────────────────────────────────────────────────
//
// The TURN allocation handle is stored in a process-global pool keyed by
// the same `socket_id` the udp_sockets pool uses — so script code holds
// ONE id that addresses BOTH the underlying UDP socket and the live
// allocation against the TURN server. The 5 turn_* builtins look up the
// allocation by socket_id and delegate to crate::turn_client.

fn turn_alloc_pool(
) -> &'static std::sync::Mutex<std::collections::HashMap<u64, crate::turn_client::TurnAllocation>> {
    static POOL: std::sync::OnceLock<
        std::sync::Mutex<std::collections::HashMap<u64, crate::turn_client::TurnAllocation>>,
    > = std::sync::OnceLock::new();
    POOL.get_or_init(|| std::sync::Mutex::new(std::collections::HashMap::new()))
}

fn turn_alloc_get(socket_id: u64) -> Option<crate::turn_client::TurnAllocation> {
    turn_alloc_pool().lock().ok()?.get(&socket_id).cloned()
}

fn turn_alloc_store(socket_id: u64, alloc: crate::turn_client::TurnAllocation) {
    if let Ok(mut g) = turn_alloc_pool().lock() {
        g.insert(socket_id, alloc);
    }
}

/// `turn_allocate($id, $server, $port, $username, $password [, $timeout_ms])`
/// — drive the TURN two-roundtrip allocation flow on socket `$id`. On
/// success returns a hashref describing the allocation and stores it in
/// a process-global pool keyed by `$id` (so `turn_permission`, `turn_send`,
/// `turn_recv`, `turn_refresh` find it via the same id). Returns `undef`
/// on bind/auth/network failure.
///
///   { relay_ip      => "203.0.113.99",
///     relay_port    => 49999,
///     lifetime_secs => 600,
///     realm         => "turn.example.org",
///     nonce_len     => 13 }
fn builtin_turn_allocate(args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    use indexmap::IndexMap;
    use parking_lot::RwLock;
    use std::sync::Arc as StdArc;
    use std::time::Duration;

    let id = args
        .first()
        .filter(|v| !v.is_undef())
        .map(|v| v.to_int() as u64)
        .unwrap_or(0);
    let server = args
        .get(1)
        .filter(|v| !v.is_undef())
        .map(|v| v.to_string())
        .unwrap_or_default();
    let port_raw = args
        .get(2)
        .filter(|v| !v.is_undef())
        .map(|v| v.to_int())
        .unwrap_or(0);
    let user = args
        .get(3)
        .filter(|v| !v.is_undef())
        .map(|v| v.to_string())
        .unwrap_or_default();
    let pass = args
        .get(4)
        .filter(|v| !v.is_undef())
        .map(|v| v.to_string())
        .unwrap_or_default();
    if id == 0 || server.is_empty() || !(1..=65535).contains(&port_raw) {
        return Ok(StrykeValue::UNDEF);
    }
    let port = port_raw as u16;
    let timeout_ms = args
        .get(5)
        .filter(|v| !v.is_undef())
        .map(|v| v.to_int().max(100) as u64)
        .unwrap_or(3000);

    let alloc = match crate::turn_client::allocate(
        id,
        &server,
        port,
        &user,
        &pass,
        Duration::from_millis(timeout_ms),
    ) {
        Some(a) => a,
        None => return Ok(StrykeValue::UNDEF),
    };
    let nonce_len = alloc.nonce.len();
    let mut m: IndexMap<String, StrykeValue> = IndexMap::new();
    m.insert(
        "relay_ip".into(),
        StrykeValue::string(alloc.relay_ip.to_string()),
    );
    m.insert(
        "relay_port".into(),
        StrykeValue::integer(alloc.relay_port as i64),
    );
    m.insert(
        "lifetime_secs".into(),
        StrykeValue::integer(alloc.lifetime_secs as i64),
    );
    m.insert("realm".into(), StrykeValue::string(alloc.realm.clone()));
    m.insert("nonce_len".into(), StrykeValue::integer(nonce_len as i64));
    turn_alloc_store(id, alloc);
    Ok(StrykeValue::hash_ref(StdArc::new(RwLock::new(m))))
}

/// `turn_permission($id, $peer_ip [, $timeout_ms=2000])` — install a
/// CreatePermission for `$peer_ip` on the TURN allocation associated
/// with socket `$id`. Returns 1 on success, 0 on failure (no
/// allocation, network error, or non-success response).
fn builtin_turn_permission(args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    use std::time::Duration;
    let id = args
        .first()
        .filter(|v| !v.is_undef())
        .map(|v| v.to_int() as u64)
        .unwrap_or(0);
    let peer_ip_str = args
        .get(1)
        .filter(|v| !v.is_undef())
        .map(|v| v.to_string())
        .unwrap_or_default();
    if id == 0 || peer_ip_str.is_empty() {
        return Ok(StrykeValue::integer(0));
    }
    let timeout_ms = args
        .get(2)
        .filter(|v| !v.is_undef())
        .map(|v| v.to_int().max(100) as u64)
        .unwrap_or(2000);
    let peer_ip: std::net::IpAddr = match peer_ip_str.parse() {
        Ok(ip) => ip,
        Err(_) => return Ok(StrykeValue::integer(0)),
    };
    let Some(alloc) = turn_alloc_get(id) else {
        return Ok(StrykeValue::integer(0));
    };
    let ok =
        crate::turn_client::create_permission(&alloc, peer_ip, Duration::from_millis(timeout_ms));
    Ok(StrykeValue::integer(if ok { 1 } else { 0 }))
}

/// `turn_send($id, $peer_ip, $peer_port, $payload)` — wrap `$payload` in
/// a SEND_INDICATION and ship via the TURN allocation. Returns bytes
/// sent to the TURN server (NOT bytes confirmed at the peer — peer
/// receipt is implicit when a DATA_INDICATION reply arrives). Returns 0
/// on failure.
fn builtin_turn_send(args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    let id = args
        .first()
        .filter(|v| !v.is_undef())
        .map(|v| v.to_int() as u64)
        .unwrap_or(0);
    let peer_ip_str = args
        .get(1)
        .filter(|v| !v.is_undef())
        .map(|v| v.to_string())
        .unwrap_or_default();
    let peer_port_raw = args
        .get(2)
        .filter(|v| !v.is_undef())
        .map(|v| v.to_int())
        .unwrap_or(0);
    if id == 0 || peer_ip_str.is_empty() || !(1..=65535).contains(&peer_port_raw) {
        return Ok(StrykeValue::integer(0));
    }
    let peer_ip: std::net::IpAddr = match peer_ip_str.parse() {
        Ok(ip) => ip,
        Err(_) => return Ok(StrykeValue::integer(0)),
    };
    let peer_port = peer_port_raw as u16;
    let payload: Vec<u8> = match args.get(3).filter(|v| !v.is_undef()) {
        Some(v) => {
            if let Some(arc) = v.as_bytes_arc() {
                (*arc).clone()
            } else {
                v.to_string().into_bytes()
            }
        }
        None => Vec::new(),
    };
    let Some(alloc) = turn_alloc_get(id) else {
        return Ok(StrykeValue::integer(0));
    };
    match crate::turn_client::send_to_peer(&alloc, peer_ip, peer_port, &payload) {
        Some(n) => Ok(StrykeValue::integer(n as i64)),
        None => Ok(StrykeValue::integer(0)),
    }
}

/// `turn_recv($id [, $timeout_ms=1000])` — wait for the next
/// DATA_INDICATION on the TURN allocation's socket and return
/// `{ payload, peer_ip, peer_port }`. Returns `undef` on timeout or if
/// the next packet isn't a DATA_INDICATION (caller should call again to
/// drain other indications).
fn builtin_turn_recv(args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    use indexmap::IndexMap;
    use parking_lot::RwLock;
    use std::sync::Arc as StdArc;
    use std::time::Duration;

    let id = args
        .first()
        .filter(|v| !v.is_undef())
        .map(|v| v.to_int() as u64)
        .unwrap_or(0);
    if id == 0 {
        return Ok(StrykeValue::UNDEF);
    }
    let timeout_ms = args
        .get(1)
        .filter(|v| !v.is_undef())
        .map(|v| v.to_int().max(0) as u64)
        .unwrap_or(1000);
    let Some(alloc) = turn_alloc_get(id) else {
        return Ok(StrykeValue::UNDEF);
    };
    let (peer_ip, peer_port, payload) =
        match crate::turn_client::recv_indication(&alloc, Duration::from_millis(timeout_ms)) {
            Some(r) => r,
            None => return Ok(StrykeValue::UNDEF),
        };
    let payload_v = match String::from_utf8(payload.clone()) {
        Ok(s) => StrykeValue::string(s),
        Err(_) => StrykeValue::bytes(StdArc::new(payload)),
    };
    let mut m: IndexMap<String, StrykeValue> = IndexMap::new();
    m.insert("payload".into(), payload_v);
    m.insert("peer_ip".into(), StrykeValue::string(peer_ip.to_string()));
    m.insert("peer_port".into(), StrykeValue::integer(peer_port as i64));
    Ok(StrykeValue::hash_ref(StdArc::new(RwLock::new(m))))
}

/// `turn_refresh($id [, $lifetime_secs=600, $timeout_ms=2000])` — send a
/// Refresh to extend the allocation. Pass `$lifetime_secs=0` to release
/// the allocation immediately. Returns the new lifetime on success, 0
/// on failure.
fn builtin_turn_refresh(args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    use std::time::Duration;
    let id = args
        .first()
        .filter(|v| !v.is_undef())
        .map(|v| v.to_int() as u64)
        .unwrap_or(0);
    if id == 0 {
        return Ok(StrykeValue::integer(0));
    }
    let lifetime = args
        .get(1)
        .filter(|v| !v.is_undef())
        .map(|v| v.to_int().max(0) as u32)
        .unwrap_or(600);
    let timeout_ms = args
        .get(2)
        .filter(|v| !v.is_undef())
        .map(|v| v.to_int().max(100) as u64)
        .unwrap_or(2000);
    let Some(alloc) = turn_alloc_get(id) else {
        return Ok(StrykeValue::integer(0));
    };
    match crate::turn_client::refresh(&alloc, lifetime, Duration::from_millis(timeout_ms)) {
        Some(n) => Ok(StrykeValue::integer(n as i64)),
        None => Ok(StrykeValue::integer(0)),
    }
}

/// `teleport($val, @receiver_pids [, { hold_ms => 500 }])` — broadcast a
/// value to N stryke processes via POSIX shared memory + per-receiver
/// UDS notification. Returns the count of receivers whose notification
/// landed (their UDS socket exists + accepted the 40-byte notify).
///
/// Data-first signature so the prefix thread macro composes naturally:
///
///   ~> $huge teleport(@worker_pids)   # ~> threads $huge as arg 0
///
/// Standalone with literal PIDs:
///
///   teleport($payload, $pid1, $pid2, $pid3)
///   teleport($payload, [@pids])       # arrayref also flattens
///   teleport($payload, $pid, { hold_ms => 1500 })
///
/// Receivers must be stryke processes running an `arrive()` loop.
/// Non-stryke processes (or stryke processes without an `arrive` call)
/// have no bound UDS socket and count as unreachable.
///
/// `$hold_ms` (default 500) is how long the sender holds the SHM segment
/// alive after notifying so receivers can `shm_open` + `mmap` + read.
/// Receivers slower than `hold_ms` miss the window.
///
/// Serialization: `StrykeValue → serde_json::Value → bincode → SHM`.
/// Receivers reverse this. Same lossy-but-portable shape as
/// `dist_thread`/`cluster` IPC — closures and blessed objects don't
/// round-trip; scalars / arrays / hashes / nested combos do.
fn builtin_teleport(args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    let Some(val) = args.first() else {
        return Ok(StrykeValue::integer(0));
    };

    let mut pids: Vec<i32> = Vec::new();
    let mut hold_ms: u64 = 500;

    // args[1..] may be: (a) bare integers (PIDs spread by callsite),
    // (b) an arrayref `\@pids`, (c) an inline array value `[@pids]`.
    // Last numeric arg gets treated as hold_ms ONLY if it's a hash with
    // explicit `hold_ms => N` key — otherwise everything numeric is a
    // PID. Keeps the variadic surface unambiguous.
    let mut tail = args[1..].iter().peekable();
    while let Some(arg) = tail.next() {
        if arg.is_undef() {
            continue;
        }
        if let Some(href) = arg.as_hash_ref() {
            // Options hash — currently only `hold_ms` is recognized.
            if let Some(v) = href.read().get("hold_ms") {
                hold_ms = v.to_int().max(0) as u64;
            }
            continue;
        }
        if let Some(arr) = arg.as_array_ref() {
            for v in arr.read().iter() {
                if !v.is_undef() {
                    pids.push(v.to_int() as i32);
                }
            }
            continue;
        }
        if let Some(arr) = arg.as_array_vec() {
            for v in arr {
                if !v.is_undef() {
                    pids.push(v.to_int() as i32);
                }
            }
            continue;
        }
        pids.push(arg.to_int() as i32);
    }

    if pids.is_empty() {
        return Ok(StrykeValue::integer(0));
    }

    // StrykeValue → serde_json::Value → JSON bytes. JSON beats bincode here
    // because bincode can't round-trip a free-standing serde_json::Value
    // (Value needs `deserialize_any`, which bincode doesn't implement).
    // Single payload per teleport — no point bundling into a larger frame
    // just to wrap with bincode.
    let json = match crate::remote_wire::perl_to_json_value(val) {
        Ok(j) => j,
        Err(_) => return Ok(StrykeValue::integer(0)),
    };
    let bytes = match serde_json::to_vec(&json) {
        Ok(b) => b,
        Err(_) => return Ok(StrykeValue::integer(0)),
    };

    let delivered = crate::teleport::send(&bytes, &pids, hold_ms);
    Ok(StrykeValue::integer(delivered as i64))
}

/// `arrive([$timeout_ms=5000])` — block up to `$timeout_ms` for a
/// teleport notification from any sender, then read + return the value.
/// Returns `undef` on timeout, malformed notification, or stale SHM
/// segment (sender unlinked before this receiver got around to reading).
///
/// First call lazy-binds the per-process UDS socket at
/// `/tmp/stryke_teleport_$$.sock`; subsequent calls reuse it. The socket
/// file is cleaned up best-effort on bind (stale file from a prior
/// crashed instance gets unlinked).
///
/// Idiomatic receiver loop:
///
///   while (1) {
///       my $msg = arrive(1000)
///       last unless defined $msg
///       process($msg)
///   }
fn builtin_arrive(args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    use std::time::Duration;

    let timeout_ms = args
        .first()
        .filter(|v| !v.is_undef())
        .map(|v| v.to_int().max(1) as u64)
        .unwrap_or(5000);

    let Some(bytes) = crate::teleport::recv(Duration::from_millis(timeout_ms)) else {
        return Ok(StrykeValue::UNDEF);
    };
    let json: serde_json::Value = match serde_json::from_slice(&bytes) {
        Ok(j) => j,
        Err(_) => return Ok(StrykeValue::UNDEF),
    };
    // Build refs at every nesting level so `$msg->{outer}->{inner}->[i]`
    // chains compose without re-wrapping. Matches decode_json's
    // convention — JSON Object → hashref, JSON Array → arrayref, both
    // recursively. The default json_to_perl returns flat hash/array,
    // which is right for cluster IPC (consumer iterates with %{ } / @{ })
    // but wrong for teleport's primary use shape.
    Ok(json_to_deep_refs(&json))
}

/// `turnbuckle($peer_pid [, { interval_ms => 50, timeout_ms => 200 }])` —
/// open a 1:1 peer-pair keepalive against `$peer_pid`. Spawns a
/// background heartbeat thread; returns a handle hashref
/// `{ _tb_id => N, peer_pid => P }` to pass to [`builtin_tb_alive`] /
/// [`builtin_tb_ping`] / [`builtin_tb_close`]. Returns `undef` if
/// `$peer_pid` is non-positive or if the UDS bind failed.
fn builtin_turnbuckle(args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    use indexmap::IndexMap;
    use parking_lot::RwLock as PRwLock;
    use std::sync::Arc as StdArc;

    let peer_pid = match args.first() {
        Some(v) if !v.is_undef() => v.to_int() as i32,
        _ => return Ok(StrykeValue::UNDEF),
    };

    let mut interval_ms: u64 = 50;
    let mut timeout_ms: u64 = 200;
    if let Some(opts) = args.get(1).and_then(|v| v.as_hash_ref()) {
        let g = opts.read();
        if let Some(v) = g.get("interval_ms") {
            interval_ms = v.to_int().max(1) as u64;
        }
        if let Some(v) = g.get("timeout_ms") {
            timeout_ms = v.to_int().max(1) as u64;
        }
    }

    let id = crate::turnbuckle::open(peer_pid, interval_ms, timeout_ms);
    if id == 0 {
        return Ok(StrykeValue::UNDEF);
    }
    let mut map: IndexMap<String, StrykeValue> = IndexMap::new();
    map.insert("_tb_id".into(), StrykeValue::integer(id as i64));
    map.insert("peer_pid".into(), StrykeValue::integer(peer_pid as i64));
    Ok(StrykeValue::hash_ref(StdArc::new(PRwLock::new(map))))
}

fn turnbuckle_id_from(v: Option<&StrykeValue>) -> u64 {
    v.and_then(|v| v.as_hash_ref())
        .and_then(|h| h.read().get("_tb_id").map(|v| v.to_int()))
        .filter(|n| *n > 0)
        .map(|n| n as u64)
        .unwrap_or(0)
}

/// `tb_alive($handle)` — return 1 if the peer has heartbeated within
/// the configured timeout window, else 0.
fn builtin_tb_alive(args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    let id = turnbuckle_id_from(args.first());
    Ok(StrykeValue::integer(if crate::turnbuckle::alive(id) {
        1
    } else {
        0
    }))
}

/// `tb_ping($handle)` — force an immediate heartbeat in addition to the
/// background cadence. Returns 1 on send success, 0 otherwise.
fn builtin_tb_ping(args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    let id = turnbuckle_id_from(args.first());
    Ok(StrykeValue::integer(if crate::turnbuckle::ping(id) {
        1
    } else {
        0
    }))
}

/// `weep(@source, $interval_ms)` — slow-trickle emitter. Wraps any of
/// {variadic items, range like `1:N`, arrayref, iterator, scalar} into a
/// streaming iterator that emits each item paced at `$interval_ms`
/// between emissions. The FIRST item emits immediately; only the gap
/// between successive items is throttled. Zero interval = passthrough.
///
/// **Call shape**: the LAST argument is always `interval_ms`. Everything
/// before it is the source. This handles stryke's range-flattening
/// convention — `weep(1:5, 100)` arrives as `[1,2,3,4,5,100]`, we
/// split off the last as interval and use the rest as items. To pass
/// a single-element source where that element is numeric, wrap it:
/// `weep([42], 100)`. A 1-arg call `weep($x)` is source-only, no throttle.
///
/// Lazy by construction — the sleep happens at each consumer pull, not
/// up-front. Compose with `take`, `map`, prefix `~>`, etc.
fn builtin_weep(args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    if args.is_empty() {
        return Ok(StrykeValue::iterator(crate::map_stream::into_pull_iter(
            StrykeValue::array(vec![]),
        )));
    }

    // Split: last arg is interval (when ≥ 2 args), rest is source.
    let (source_args, interval_ms): (&[StrykeValue], u64) = if args.len() >= 2 {
        let last = &args[args.len() - 1];
        (&args[..args.len() - 1], last.to_int().max(0) as u64)
    } else {
        (args, 0)
    };

    // Build source iterator. Single-arg source uses type-aware deref;
    // multi-arg source is treated as a flat item list (the natural shape
    // when stryke flattens ranges / @lists into positional args).
    let source: Arc<dyn crate::value::StrykeIterator> = if source_args.len() == 1 {
        let v = &source_args[0];
        if v.is_iterator() {
            v.clone().into_iterator()
        } else if let Some(arr) = v.as_array_ref() {
            // Arrayref deref — `to_list()` doesn't unwrap `HeapObject::ArrayRef`
            // (it falls through to wrapping the ref itself as a 1-elem list),
            // so without this `weep([1,2,3], …)` would emit one item: the ref.
            let items = arr.read().clone();
            crate::map_stream::into_pull_iter(StrykeValue::array(items))
        } else {
            crate::map_stream::into_pull_iter(v.clone())
        }
    } else {
        crate::map_stream::into_pull_iter(StrykeValue::array(source_args.to_vec()))
    };

    Ok(StrykeValue::iterator(Arc::new(
        crate::map_stream::WeepIterator::new(source, Duration::from_millis(interval_ms)),
    )))
}

/// `tb_close($handle)` — tear down the pair: stop the heartbeat thread,
/// unbind the UDS socket, drop registry entry. Returns 1 if the handle
/// was known, 0 if it was already closed or never opened.
fn builtin_tb_close(args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    let id = turnbuckle_id_from(args.first());
    Ok(StrykeValue::integer(if crate::turnbuckle::close(id) {
        1
    } else {
        0
    }))
}

fn json_to_deep_refs(v: &serde_json::Value) -> StrykeValue {
    use indexmap::IndexMap;
    use parking_lot::RwLock;
    use std::sync::Arc as StdArc;
    match v {
        serde_json::Value::Null => StrykeValue::UNDEF,
        serde_json::Value::Bool(b) => StrykeValue::integer(if *b { 1 } else { 0 }),
        serde_json::Value::Number(n) => {
            if let Some(i) = n.as_i64() {
                StrykeValue::integer(i)
            } else if let Some(u) = n.as_u64() {
                StrykeValue::integer(u as i64)
            } else {
                StrykeValue::float(n.as_f64().unwrap_or(0.0))
            }
        }
        serde_json::Value::String(s) => StrykeValue::string(s.clone()),
        serde_json::Value::Array(a) => {
            let items: Vec<StrykeValue> = a.iter().map(json_to_deep_refs).collect();
            StrykeValue::array_ref(StdArc::new(RwLock::new(items)))
        }
        serde_json::Value::Object(o) => {
            let mut map: IndexMap<String, StrykeValue> = IndexMap::new();
            for (k, val) in o {
                map.insert(k.clone(), json_to_deep_refs(val));
            }
            StrykeValue::hash_ref(StdArc::new(RwLock::new(map)))
        }
    }
}

/// `mark($val)` — tag a heap value's Arc so subsequent builtin calls that
/// consume it accumulate a lineage record. Returns `$val` unchanged for
/// pipeline-friendly use (`my $x = mark({ ... })`). No-op (returns the
/// value) for immediates (integers, floats, undef) since they have no
/// stable Arc to key on. Idempotent — marking a value already in the
/// ledger resets the origin to the current call site.
fn builtin_mark(args: &[StrykeValue], line: usize) -> StrykeResult<StrykeValue> {
    let Some(v) = args.first() else {
        return Ok(StrykeValue::UNDEF);
    };
    let _ = crate::provenance::mark(v, line);
    Ok(v.clone())
}

/// `provenance($val)` — return a hashref describing how `$val` was created
/// and which builtins have touched it since `mark`, or `undef` if the
/// value was never marked. Schema:
///
///   {
///     origin       => "HASH entries=3",     # god-style summary at mark time
///     origin_line  => 7,                    # call-site line of mark($val)
///     ops          => [
///       { op => "to_array", args => ["HASH entries=3"], line => 8 },
///       { op => "pack",     args => ["ARRAY len=3"],    line => 9 },
///       ...
///     ],
///   }
fn builtin_provenance(args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    let Some(v) = args.first() else {
        return Ok(StrykeValue::UNDEF);
    };
    match crate::provenance::lookup(v) {
        Some(node) => Ok(crate::provenance::node_to_value(&node)),
        None => Ok(StrykeValue::UNDEF),
    }
}

/// `unmark($val)` — drop `$val`'s ledger entry. Returns `$val` unchanged.
/// Use to bound ledger growth in long-running scripts; v2 will add a sweep
/// based on Arc weak refs but v1 requires explicit unmark.
fn builtin_unmark(args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    let Some(v) = args.first() else {
        return Ok(StrykeValue::UNDEF);
    };
    let _ = crate::provenance::unmark(v);
    Ok(v.clone())
}

/// `hide(CARRIER, SECRET [, KEY])` — embed SECRET into CARRIER. PNG bytes (detected by
/// `\x89PNG` magic) use LSB embedding on the R/G/B channels; everything else is treated
/// as a text carrier with zero-width-char encoding. Returns bytes for PNG carriers and
/// a string for text carriers. Optional KEY enables SHA-256-keyed XOR masking of the
/// secret prior to embedding.
fn builtin_hide(args: &[StrykeValue], line: usize) -> StrykeResult<StrykeValue> {
    if args.len() < 2 {
        return Err(StrykeError::runtime(
            "hide needs CARRIER and SECRET (optional 3rd KEY)",
            line,
        ));
    }
    let carrier_bytes = stego_value_to_bytes(&args[0]);
    let secret_bytes = stego_value_to_bytes(&args[1]);
    let key = stego_optional_key(args.get(2));
    let envelope = crate::stego::wrap_payload(&secret_bytes, key.as_deref());
    if crate::stego::is_png(&carrier_bytes) {
        let out = crate::stego::png_hide(&carrier_bytes, &envelope)
            .map_err(|e| StrykeError::runtime(e, line))?;
        Ok(StrykeValue::bytes(Arc::new(out)))
    } else {
        let carrier_text = String::from_utf8_lossy(&carrier_bytes);
        let out = crate::stego::text_hide(&carrier_text, &envelope)
            .map_err(|e| StrykeError::runtime(e, line))?;
        Ok(StrykeValue::string(out))
    }
}

/// `reveal(STEGO [, KEY])` — extract the hidden secret. Auto-detects carrier kind
/// the same way `hide` does. Returns raw bytes (callers do their own decoding).
/// Errors on missing/corrupt payload (CRC32 mismatch) or wrong carrier kind.
fn builtin_reveal(args: &[StrykeValue], line: usize) -> StrykeResult<StrykeValue> {
    if args.is_empty() {
        return Err(StrykeError::runtime(
            "reveal needs a STEGO carrier (optional 2nd KEY)",
            line,
        ));
    }
    let carrier_bytes = stego_value_to_bytes(&args[0]);
    let key = stego_optional_key(args.get(1));
    let envelope = if crate::stego::is_png(&carrier_bytes) {
        crate::stego::png_reveal(&carrier_bytes).map_err(|e| StrykeError::runtime(e, line))?
    } else {
        let carrier_text = String::from_utf8_lossy(&carrier_bytes);
        crate::stego::text_reveal(&carrier_text).map_err(|e| StrykeError::runtime(e, line))?
    };
    let secret = crate::stego::unwrap_payload(&envelope, key.as_deref())
        .map_err(|e| StrykeError::runtime(e, line))?;
    Ok(StrykeValue::bytes(Arc::new(secret)))
}

/// `hide_capacity(CARRIER)` — return how many bytes of secret payload CARRIER can hold,
/// accounting for the 8-byte envelope overhead (length + CRC32). Useful for sizing
/// before calling `hide`.
fn builtin_hide_capacity(args: &[StrykeValue], line: usize) -> StrykeResult<StrykeValue> {
    if args.is_empty() {
        return Err(StrykeError::runtime("hide_capacity needs a CARRIER", line));
    }
    let carrier_bytes = stego_value_to_bytes(&args[0]);
    let bits = if crate::stego::is_png(&carrier_bytes) {
        crate::stego::png_capacity_bits(&carrier_bytes)
            .map_err(|e| StrykeError::runtime(e, line))?
    } else {
        let carrier_text = String::from_utf8_lossy(&carrier_bytes);
        crate::stego::text_capacity_bits(&carrier_text)
    };
    let total_bytes = bits / 8;
    let secret_bytes = total_bytes.saturating_sub(8);
    Ok(StrykeValue::integer(secret_bytes as i64))
}

/// `move` — Move.
fn builtin_move(interp: &VMHelper, args: &[StrykeValue], line: usize) -> StrykeResult<StrykeValue> {
    if args.len() < 2 {
        return Err(StrykeError::runtime("move needs FROM and TO paths", line));
    }
    let from = interp.resolve_stryke_path_string(&args[0].to_string());
    let to = interp.resolve_stryke_path_string(&args[1].to_string());
    Ok(crate::perl_fs::move_path(&from, &to))
}

/// First `$n` elements: operands are **list values then count** (`take @l, N`); see
/// [`crate::list_builtins::head_tail_take_impl`]. Unary `take(N)` uses an empty list.
fn builtin_take(interp: &VMHelper, args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    crate::list_builtins::head_tail_take_impl(
        args,
        crate::list_builtins::HeadTailTake::Take,
        interp.wantarray_kind,
    )
}

/// `tail` — Tail.
fn builtin_tail(interp: &VMHelper, args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    crate::list_builtins::extension_tail_impl(args, interp.wantarray_kind)
}

/// `drop` — Drop.
fn builtin_drop(interp: &VMHelper, args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    crate::list_builtins::extension_drop_impl(args, interp.wantarray_kind)
}

/// `list_count` / `list_size` + `LIST` — like [`builtin_flatten`]: one-level
/// [`StrykeValue::map_flatten_outputs`] per actual; returns the **element** count.
/// No arguments → `0` (explicit list-context count, no `$_` fallback). Compare
/// `count` / `cnt` / `len` which default to `$_` when called bare.
fn builtin_list_count(_interp: &VMHelper, args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    // Each ACTUAL gets one level of Perl list-context flatten. The VM's
    // `call_preserve_operand_arrays` wraps multi-arg comma lists into a single
    // outer `Array` slot (so `len stat $path` survives `@_` flattening); we
    // peel that wrap first and then flatten each actual exactly once. A lone
    // user-supplied arrayref (`list_count([1, [2,3]])`) keeps the inner
    // arrayref intact — one-level peel, matching the
    // `list_count_one_level_flatten_ci` pin.
    let mut out = Vec::new();
    for a in args {
        if let Some(unwrapped) = a.as_array_vec() {
            for item in unwrapped {
                out.extend(item.map_flatten_outputs(true));
            }
        } else {
            out.extend(a.map_flatten_outputs(true));
        }
    }
    Ok(StrykeValue::integer(out.len() as i64))
}

/// `count` / `len` / `cnt`: pipe-friendly “how big is this value?”
/// — **no args** → same as one-arg form on `$_` (matches `length` with no operand in Perl 5);
/// **one string** → codepoint count (Stryke; Perl's `length` is byte-based);
/// **one array / aref** → flattened element count (list context ranges become arrays first);
/// **one hash** → number of keys; **one set** → set size; **several actuals** → same as [`builtin_list_count`].
fn builtin_count_size_cnt(interp: &VMHelper, args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    if args.is_empty() {
        let topic = interp.scope.get_scalar("_");
        return builtin_count_size_cnt(interp, std::slice::from_ref(&topic));
    }
    if args.len() == 1 {
        let a = &args[0];
        if let Some(h) = a.as_hash_map() {
            return Ok(StrykeValue::integer(h.len() as i64));
        }
        if let Some(Some(n)) = a.with_heap(|h| match h {
            crate::value::HeapObject::Set(st) => Some(st.len()),
            _ => None,
        }) {
            return Ok(StrykeValue::integer(n as i64));
        }
        if let Some(b) = a.as_bytes_arc() {
            return Ok(StrykeValue::integer(b.len() as i64));
        }
        if a.is_string_like() {
            // `len` is a stryke extension and counts codepoints, mirroring
            // `[i]` / `[a:b]` slice semantics. Perl 5's `length` keeps
            // byte semantics for compat — see `BuiltinId::Length` in
            // vm.rs. The split lets the stryke layer be coherent across
            // `len` / `[]` / `find` while leaving Perl-counters untouched.
            return Ok(StrykeValue::integer(a.to_string().chars().count() as i64));
        }
        return Ok(StrykeValue::integer(
            a.map_flatten_outputs(true).len() as i64
        ));
    }
    builtin_list_count(interp, args)
}

/// `size` — byte size of a file, like Perl's `-s`.
/// No args → `-s $_`. One arg → `-s arg`. Multiple args / flattened list → array of sizes.
/// Returns `undef` for paths that can't be stat'd.
fn builtin_file_size(interp: &VMHelper, args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    let size_of = |v: &StrykeValue| -> StrykeValue {
        let path = interp.resolve_stryke_path_string(&v.to_string());
        match std::fs::metadata(&path) {
            Ok(m) => StrykeValue::integer(m.len() as i64),
            Err(_) => StrykeValue::UNDEF,
        }
    };
    if args.is_empty() {
        let topic = interp.scope.get_scalar("_");
        return Ok(size_of(&topic));
    }
    let flat: Vec<StrykeValue> = if args.len() == 1 {
        args[0].map_flatten_outputs(true)
    } else {
        let mut out = Vec::new();
        for a in args {
            out.extend(a.map_flatten_outputs(true));
        }
        out
    };
    if flat.len() <= 1 {
        return Ok(size_of(flat.first().unwrap_or(&StrykeValue::UNDEF)));
    }
    Ok(StrykeValue::array(flat.iter().map(size_of).collect()))
}

/// `ls` / `ls DIR` / `ls A, B, ...` — long directory listing in the style of `ls -l`.
/// With no arguments, lists [`VMHelper::stryke_pwd`] (interpreter working directory; see `cd`).
/// Returns one string (newline-separated lines). Each non-empty argument must name a directory.
fn builtin_ls(interp: &VMHelper, args: &[StrykeValue], line: usize) -> StrykeResult<StrykeValue> {
    use std::path::{Path, PathBuf};

    let dirs: Vec<PathBuf> = if args.is_empty() {
        vec![interp.stryke_pwd.clone()]
    } else {
        args.iter()
            .map(|v| interp.resolve_stryke_path(&v.to_string()))
            .filter(|p| !p.as_os_str().is_empty())
            .collect()
    };
    if dirs.is_empty() {
        return Err(StrykeError::runtime("ls: need directory path", line));
    }

    let mut out = String::new();
    for (i, dir) in dirs.iter().enumerate() {
        if i > 0 {
            out.push('\n');
        }
        if dirs.len() > 1 {
            use std::fmt::Write as _;
            let _ = writeln!(&mut out, "{}:", dir.display());
        }
        let meta = std::fs::metadata(dir)
            .map_err(|e| StrykeError::runtime(format!("ls: {}: {e}", dir.display()), line))?;
        if !meta.is_dir() {
            return Err(StrykeError::runtime(
                format!("ls: not a directory: {}", dir.display()),
                line,
            ));
        }
        out.push_str(&format_ls_long_dir(Path::new(dir), line)?);
    }
    Ok(StrykeValue::string(out))
}

#[cfg(unix)]
fn ls_rwx_triple(
    read: bool,
    write: bool,
    exec: bool,
    special: bool,
    sp_lower: char,
    sp_upper: char,
) -> String {
    let mut s = String::with_capacity(3);
    s.push(if read { 'r' } else { '-' });
    s.push(if write { 'w' } else { '-' });
    s.push(match (exec, special) {
        (true, true) => sp_lower,
        (false, true) => sp_upper,
        (true, false) => 'x',
        _ => '-',
    });
    s
}

#[cfg(unix)]
fn ls_unix_mode_string(meta: &std::fs::Metadata) -> String {
    use std::os::unix::fs::{FileTypeExt, MetadataExt};
    let mode = meta.mode();
    let ft = meta.file_type();
    let tc = if ft.is_symlink() {
        'l'
    } else if ft.is_dir() {
        'd'
    } else if ft.is_block_device() {
        'b'
    } else if ft.is_char_device() {
        'c'
    } else if ft.is_fifo() {
        'p'
    } else if ft.is_socket() {
        's'
    } else {
        '-'
    };
    let mut out = String::with_capacity(10);
    out.push(tc);
    out.push_str(&ls_rwx_triple(
        mode & 0o400 != 0,
        mode & 0o200 != 0,
        mode & 0o100 != 0,
        mode & 0o4000 != 0,
        's',
        'S',
    ));
    out.push_str(&ls_rwx_triple(
        mode & 0o040 != 0,
        mode & 0o020 != 0,
        mode & 0o010 != 0,
        mode & 0o2000 != 0,
        's',
        'S',
    ));
    out.push_str(&ls_rwx_triple(
        mode & 0o004 != 0,
        mode & 0o002 != 0,
        mode & 0o001 != 0,
        mode & 0o1000 != 0,
        't',
        'T',
    ));
    out
}

#[cfg(unix)]
fn ls_l_one_line_unix(
    dir: &std::path::Path,
    name: &str,
    meta: &std::fs::Metadata,
) -> StrykeResult<String> {
    use chrono::{Datelike, Local, TimeZone};
    use std::os::unix::fs::MetadataExt;
    let mode_str = ls_unix_mode_string(meta);
    let nlink = meta.nlink();
    let uid = meta.uid();
    let gid = meta.gid();
    let size = meta.size();
    let ts = meta
        .modified()
        .ok()
        .and_then(|st| st.duration_since(std::time::UNIX_EPOCH).ok())
        .and_then(|d| {
            Local
                .timestamp_opt(d.as_secs() as i64, d.subsec_nanos())
                .single()
        })
        .map(|dt| {
            let now = Local::now();
            if dt.year() == now.year() {
                dt.format("%b %e %H:%M").to_string()
            } else {
                dt.format("%b %e  %Y").to_string()
            }
        })
        .unwrap_or_else(|| "?".repeat(12));
    let full = dir.join(name);
    let mut name_disp = name.to_string();
    if meta.file_type().is_symlink() {
        if let Ok(tgt) = std::fs::read_link(&full) {
            name_disp.push_str(" -> ");
            name_disp.push_str(&tgt.to_string_lossy());
        }
    }
    Ok(format!(
        "{mode_str} {nlink:>4} {uid:>5} {gid:>5} {size:>8} {ts} {name_disp}"
    ))
}

#[cfg(not(unix))]
fn ls_l_one_line_windows(name: &str, meta: &std::fs::Metadata) -> StrykeResult<String> {
    use chrono::{Datelike, Local, TimeZone};
    use std::os::windows::fs::MetadataExt;
    let len = meta.len();
    let tag = if meta.is_dir() { "<DIR>" } else { "" };
    let attrs = meta.file_attributes();
    let ts = meta
        .modified()
        .ok()
        .and_then(|st| st.duration_since(std::time::UNIX_EPOCH).ok())
        .and_then(|d| {
            Local
                .timestamp_opt(d.as_secs() as i64, d.subsec_nanos() as u32)
                .single()
        })
        .map(|dt| {
            let now = Local::now();
            if dt.year() == now.year() {
                dt.format("%b %e %H:%M").to_string()
            } else {
                dt.format("%b %e  %Y").to_string()
            }
        })
        .unwrap_or_else(|| "?".repeat(12));
    Ok(format!("{attrs:#010x} {tag:<5} {len:>10} {ts} {name}"))
}

fn format_ls_long_dir(dir: &std::path::Path, line: usize) -> StrykeResult<String> {
    let mut entries: Vec<std::fs::DirEntry> = std::fs::read_dir(dir)
        .map_err(|e| StrykeError::runtime(format!("ls: {}: {e}", dir.display()), line))?
        .filter_map(|e| e.ok())
        .collect();
    entries.sort_by(|a, b| {
        a.file_name()
            .to_string_lossy()
            .cmp(&b.file_name().to_string_lossy())
    });

    let mut out_lines: Vec<String> = Vec::new();

    #[cfg(unix)]
    {
        use std::os::unix::fs::MetadataExt;
        let mut sum_blocks: u64 = 0;
        let mut rows: Vec<(std::fs::Metadata, String)> = Vec::new();
        for entry in &entries {
            let name = entry.file_name().to_string_lossy().into_owned();
            let full = dir.join(&name);
            let sm = std::fs::symlink_metadata(&full)
                .map_err(|e| StrykeError::runtime(format!("ls: {}: {e}", full.display()), line))?;
            sum_blocks = sum_blocks.saturating_add(sm.blocks());
            rows.push((sm, name));
        }
        let total_k = (sum_blocks.saturating_add(1)) / 2;
        out_lines.push(format!("total {total_k}"));
        for (sm, name) in rows {
            out_lines.push(ls_l_one_line_unix(dir, &name, &sm)?);
        }
    }

    #[cfg(not(unix))]
    {
        for entry in &entries {
            let name = entry.file_name().to_string_lossy().into_owned();
            let full = dir.join(&name);
            let sm = std::fs::symlink_metadata(&full)
                .map_err(|e| StrykeError::runtime(format!("ls: {}: {e}", full.display()), line))?;
            out_lines.push(ls_l_one_line_windows(&name, &sm)?);
        }
    }

    Ok(out_lines.join("\n") + "\n")
}

/// One-level list flatten: plain arrays and arrayrefs expand like `flat_map` / [`StrykeValue::map_flatten_outputs`].
/// No arguments → same as `flatten($_)`.
fn builtin_flatten(interp: &VMHelper, args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    let mut topic = StrykeValue::UNDEF;
    let args = variadic_list_or_topic(interp, args, &mut topic);
    let mut out = Vec::new();
    for a in args {
        out.extend(a.map_flatten_outputs(true));
    }
    Ok(match interp.wantarray_kind {
        WantarrayCtx::List => StrykeValue::array(out),
        WantarrayCtx::Scalar => StrykeValue::integer(out.len() as i64),
        WantarrayCtx::Void => StrykeValue::UNDEF,
    })
}

/// `with_index LIST` — each element is an arrayref `[$item, $index]` (0-based).
fn builtin_with_index(interp: &VMHelper, args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    let wa = interp.wantarray_kind;
    let mut out = Vec::with_capacity(args.len());
    for (i, item) in args.iter().cloned().enumerate() {
        out.push(StrykeValue::array_ref(Arc::new(RwLock::new(vec![
            item,
            StrykeValue::integer(i as i64),
        ]))));
    }
    Ok(match wa {
        WantarrayCtx::List => StrykeValue::array(out),
        WantarrayCtx::Scalar => StrykeValue::integer(out.len() as i64),
        WantarrayCtx::Void => StrykeValue::UNDEF,
    })
}

/// `which` — Which.
fn builtin_which(args: &[StrykeValue], line: usize) -> StrykeResult<StrykeValue> {
    let name = args
        .first()
        .filter(|v| !v.to_string().is_empty())
        .map(|v| v.to_string())
        .ok_or_else(|| StrykeError::runtime("which needs a program name", line))?;
    let dot = args
        .get(1)
        .is_some_and(|o| opt_hash_bool(o, "dot") || opt_hash_bool(o, "cwd"));
    Ok(crate::perl_fs::which_executable(&name, dot)
        .map(StrykeValue::string)
        .unwrap_or(StrykeValue::UNDEF))
}

/// `which_all PROGRAM` — returns all matching executables on `$PATH`.
fn builtin_which_all(args: &[StrykeValue], line: usize) -> StrykeResult<StrykeValue> {
    let name = args
        .first()
        .filter(|v| !v.to_string().is_empty())
        .map(|v| v.to_string())
        .ok_or_else(|| StrykeError::runtime("which_all needs a program name", line))?;
    let mut results = Vec::new();
    if let Some(path_os) = std::env::var_os("PATH") {
        for dir in std::env::split_paths(&path_os) {
            let candidate = dir.join(&name);
            if candidate.is_file() {
                if let Some(s) = candidate.to_str() {
                    results.push(StrykeValue::string(s.to_string()));
                }
            }
        }
    }
    Ok(StrykeValue::array(results))
}

/// `interleave @a, @b, ...` — round-robin merge of lists.
fn builtin_interleave(interp: &VMHelper, args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    let lists: Vec<Vec<StrykeValue>> = args.iter().map(|a| a.map_flatten_outputs(true)).collect();
    let max_len = lists.iter().map(|l| l.len()).max().unwrap_or(0);
    let mut out = Vec::with_capacity(lists.len() * max_len);
    for i in 0..max_len {
        for list in &lists {
            if let Some(v) = list.get(i) {
                out.push(v.clone());
            }
        }
    }
    Ok(match interp.wantarray_kind {
        WantarrayCtx::List => StrykeValue::array(out),
        WantarrayCtx::Scalar => StrykeValue::integer(out.len() as i64),
        WantarrayCtx::Void => StrykeValue::UNDEF,
    })
}

/// `frequencies LIST` — count occurrences, returns hash ref `{ value => count }`.
fn builtin_frequencies(args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    let mut counts = indexmap::IndexMap::new();
    for a in args {
        for v in a.map_flatten_outputs(true) {
            let key = v.to_string();
            let entry = counts.entry(key).or_insert(StrykeValue::integer(0));
            *entry = StrykeValue::integer(entry.to_int() + 1);
        }
    }
    Ok(StrykeValue::hash_ref(Arc::new(RwLock::new(counts))))
}

/// `pfrequencies` / `pfreq` / `pfrq` — Rayon-parallel frequency count. Builds
/// per-thread ahash maps with `fold_chunks(64K)` (large chunks amortise the
/// thread-spawn cost), then merges via reduce. Output preserves count-desc
/// then lex order so successive runs are byte-stable. Falls back to serial
/// for inputs under the break-even point.
fn builtin_pfrequencies(args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    let mut all = Vec::new();
    for a in args {
        all.extend(a.map_flatten_outputs(true));
    }
    // Below this length the rayon spawn / merge overhead exceeds the gain
    // from parallel hashing — measured empirically at ~64K elements.
    if all.len() < 65_536 {
        return builtin_frequencies(args);
    }
    let merged: std::collections::HashMap<String, u64> = all
        .par_iter()
        .with_min_len(16_384)
        .fold(
            || std::collections::HashMap::<String, u64>::with_capacity(256),
            |mut acc, v| {
                *acc.entry(v.to_string()).or_insert(0) += 1;
                acc
            },
        )
        .reduce(std::collections::HashMap::<String, u64>::new, |a, b| {
            // Merge smaller into larger so the hot-loop iterates the smaller set.
            let (mut big, small) = if a.len() >= b.len() { (a, b) } else { (b, a) };
            for (k, v) in small {
                *big.entry(k).or_insert(0) += v;
            }
            big
        });
    // Stable order: count desc, then key asc.
    let mut entries: Vec<(String, u64)> = merged.into_iter().collect();
    entries.sort_unstable_by(|a, b| b.1.cmp(&a.1).then_with(|| a.0.cmp(&b.0)));
    let mut counts: indexmap::IndexMap<String, StrykeValue> =
        indexmap::IndexMap::with_capacity(entries.len());
    for (k, v) in entries {
        counts.insert(k, StrykeValue::integer(v as i64));
    }
    Ok(StrykeValue::hash_ref(Arc::new(RwLock::new(counts))))
}

/// `ddump EXPR, ...` — indented pretty printer for stryke data structures.
/// Prints to STDOUT and returns the formatted string so callers can capture it.
fn builtin_ddump(args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    use crate::serialize_normalize::deep_normalize;
    let mut buf = String::new();
    for (i, val) in args.iter().enumerate() {
        if i > 0 {
            buf.push('\n');
        }
        let name = format!("$VAR{}", i + 1);
        buf.push_str(&name);
        buf.push_str(" = ");
        // Flatten class/struct/enum trees first so ddump never has to
        // know about stryke-native OO types — it always sees plain
        // hashref / arrayref / scalar shape.
        let normalized = deep_normalize(val);
        ddump_value(&mut buf, &normalized, 0);
        buf.push(';');
    }
    buf.push('\n');
    Ok(StrykeValue::string(buf))
}

/// `perfview` / `pv` — read the wall-clock perf log written by stryke runs
/// launched with `--record`. Returns an arrayref of hashrefs, one per
/// matching row. Options (passed as a trailing hashref):
///
///   `top` => N            — limit to N rows (default 20)
///   `name` => "SUBSTR"    — substring filter on `path`
///   `re` => "REGEX"       — regex filter on `path`
///   `path` => "/abs/path" — exact-match filter on `path`
///   `since` => "7d"       — only rows newer than 7d / 24h / 30m / 90s
///   `slowest` => 1        — order by duration desc (default)
///   `fastest` => 1        — order by duration asc
///   `recent` => 1         — order by id desc (most recent first)
///   `all` => 1            — no limit
///
/// CLI usage: `s perfview` (defaults to top 20 slowest); `s perfview top
/// => 50, name => "rosetta"` via stryke's expression-arg invocation.
/// From stryke code: `perfview(top => 10, name => "rosetta") |> dd`.
fn builtin_perfview(args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    use crate::perf_recorder::{parse_duration_secs, query, QueryFilter};
    use indexmap::IndexMap;

    // Accept either: a trailing hashref `\%opts`, OR alternating key/value
    // args `top => 20, name => "..."`. The alternating form is what stryke
    // code naturally produces from `perfview(top => 10, name => "x")` —
    // fat-arrows flatten to a key/value list.
    let opts: IndexMap<String, StrykeValue> = if args.len() == 1 {
        if let Some(h) = args[0].as_hash_ref() {
            h.read().clone()
        } else if let Some(h) = args[0].as_hash_map() {
            h
        } else {
            IndexMap::new()
        }
    } else if args.len().is_multiple_of(2) {
        let mut m = IndexMap::new();
        for chunk in args.chunks(2) {
            m.insert(chunk[0].to_string(), chunk[1].clone());
        }
        m
    } else {
        IndexMap::new()
    };

    let opt_str = |k: &str| -> Option<String> {
        opts.get(k).and_then(|v| {
            if v.is_undef() {
                None
            } else {
                Some(v.to_string())
            }
        })
    };
    let opt_int = |k: &str| -> Option<i64> { opts.get(k).map(|v| v.to_int()) };
    let opt_bool = |k: &str| -> bool { opts.get(k).is_some_and(|v| v.is_true()) };

    let mut f = QueryFilter::default();
    if let Some(s) = opt_str("name") {
        f.name_substr = Some(s);
    }
    if let Some(rx) = opt_str("re").or_else(|| opt_str("regex")) {
        f.name_regex = Some(rx);
    }
    if let Some(p) = opt_str("path") {
        f.exact_path = Some(p);
    }
    if let Some(d) = opt_str("since") {
        if let Some(secs) = parse_duration_secs(&d) {
            let now = crate::perf_recorder::now_ns();
            f.since_ns = Some(now - secs * 1_000_000_000);
        }
    }
    // Order: explicit recent > fastest > slowest > default(slowest)
    if opt_bool("recent") {
        f.slowest_first = None;
    } else if opt_bool("fastest") {
        f.slowest_first = Some(false);
    } else {
        // `slowest => 1` or default
        f.slowest_first = Some(true);
    }
    f.limit = if opt_bool("all") {
        0
    } else {
        opt_int("top").map(|n| n.max(0) as usize).unwrap_or(20)
    };

    let rows = query(&f);
    let mut out: Vec<StrykeValue> = Vec::with_capacity(rows.len());
    for r in rows {
        let mut h: IndexMap<String, StrykeValue> = IndexMap::new();
        h.insert("id".to_string(), StrykeValue::integer(r.id));
        h.insert("path".to_string(), StrykeValue::string(r.path));
        h.insert("argv".to_string(), StrykeValue::string(r.argv));
        h.insert("started_ns".to_string(), StrykeValue::integer(r.started_ns));
        h.insert(
            "duration_ns".to_string(),
            StrykeValue::integer(r.duration_ns),
        );
        h.insert(
            "duration_ms".to_string(),
            StrykeValue::integer(r.duration_ns / 1_000_000),
        );
        h.insert(
            "exit_code".to_string(),
            StrykeValue::integer(r.exit_code as i64),
        );
        h.insert("version".to_string(), StrykeValue::string(r.version));
        h.insert("host".to_string(), StrykeValue::string(r.host));
        h.insert("pid".to_string(), StrykeValue::integer(r.pid));
        h.insert("parent_pid".to_string(), StrykeValue::integer(r.parent_pid));
        out.push(StrykeValue::hash_ref(Arc::new(RwLock::new(h))));
    }
    Ok(StrykeValue::array_ref(Arc::new(RwLock::new(out))))
}

/// `banner()` — print the stryke ASCII logo + live-stats box + tagline
/// (the same banner the REPL shows on startup and `stryke --help`
/// displays). Reflection counts (`%b`/`%a`/`%k`/...) are pulled at call
/// time so the values stay current after rebuilds.
///
/// In list context returns `undef` (it's a print-side-effect builtin).
/// With a single arg that is true (e.g. `banner(1)`), returns the
/// rendered string instead of printing — useful for capturing the
/// banner into a variable or piping it elsewhere. ANSI colors are
/// emitted only when stdout is a TTY.
fn builtin_banner(args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    use std::io::IsTerminal;
    let colored = std::io::stdout().is_terminal();
    let capture = args.first().is_some_and(|v| v.is_true());
    if capture {
        Ok(StrykeValue::string(crate::banner::render_banner(colored)))
    } else {
        crate::banner::print_banner(colored);
        Ok(StrykeValue::UNDEF)
    }
}

/// `docs(TOPIC)` — return the hover-doc page for `TOPIC` from `lsp.rs`
/// (the same source `stryke docs` renders), formatted for terminal
/// display: bold heading, dim rule, cyan inline `backticks`, green
/// `\`\`\`code fences\`\`\``. ANSI colors are emitted only when stdout
/// is a TTY so piped / redirected output stays clean.
///
/// `TOPIC` may be any primary builtin name, alias spelling, keyword,
/// operator, or sigil-prefixed reflection-hash name. Returns `undef`
/// when no doc page exists.
///
/// With multiple args, returns a hashref of `{ name => rendered_page }`
/// so a list of topics round-trips in one call.
///
/// With no args, returns an arrayref of every documented topic name
/// (sorted, deduped) — the in-language equivalent of `stryke docs --list`.
fn builtin_docs(args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    use std::io::IsTerminal;
    let colored = std::io::stdout().is_terminal();
    if args.is_empty() {
        let topics = crate::lsp::doc_topics();
        let mut out: Vec<StrykeValue> = topics
            .iter()
            .filter(|t| crate::lsp::doc_text_for(t).is_some())
            .map(|t| StrykeValue::string(t.to_string()))
            .collect();
        out.sort_by_key(|a| a.to_string());
        out.dedup_by(|a, b| a.to_string() == b.to_string());
        return Ok(StrykeValue::array_ref(Arc::new(RwLock::new(out))));
    }
    if args.len() == 1 {
        let topic = args[0].to_string();
        return Ok(match crate::lsp::doc_text_for(&topic) {
            Some(s) => StrykeValue::string(crate::doc_render::render_doc(&topic, s, colored)),
            None => StrykeValue::UNDEF,
        });
    }
    let mut h: indexmap::IndexMap<String, StrykeValue> = indexmap::IndexMap::new();
    for a in args {
        let topic = a.to_string();
        let val = match crate::lsp::doc_text_for(&topic) {
            Some(s) => StrykeValue::string(crate::doc_render::render_doc(&topic, s, colored)),
            None => StrykeValue::UNDEF,
        };
        h.insert(topic, val);
    }
    Ok(StrykeValue::hash_ref(Arc::new(RwLock::new(h))))
}

/// `stringify EXPR, ...` / `str EXPR, ...` — convert values to valid stryke string literals.
/// Unlike `ddump`, output is a single parseable stryke expression with no `$VAR =` prefix.
fn builtin_stringify(args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    let mut buf = String::new();
    if args.len() == 1 {
        stringify_value(&mut buf, &args[0]);
    } else {
        buf.push('(');
        for (i, val) in args.iter().enumerate() {
            if i > 0 {
                buf.push_str(", ");
            }
            stringify_value(&mut buf, val);
        }
        buf.push(')');
    }
    Ok(StrykeValue::string(buf))
}

fn stringify_value(buf: &mut String, val: &StrykeValue) {
    use std::fmt::Write;

    if val.is_undef() {
        buf.push_str("undef");
        return;
    }

    if val.is_iterator() {
        let it = val.clone().into_iterator();
        let items = it.collect_all();
        buf.push('(');
        for (i, elem) in items.iter().enumerate() {
            if i > 0 {
                buf.push_str(", ");
            }
            stringify_value(buf, elem);
        }
        buf.push(')');
        return;
    }

    if let Some(ar) = val.as_array_ref() {
        let guard = ar.read();
        buf.push('[');
        for (i, elem) in guard.iter().enumerate() {
            if i > 0 {
                buf.push_str(", ");
            }
            stringify_value(buf, elem);
        }
        buf.push(']');
        return;
    }

    if let Some(hr) = val.as_hash_ref() {
        let guard = hr.read();
        buf.push_str("+{");
        for (i, (k, v)) in guard.iter().enumerate() {
            if i > 0 {
                buf.push_str(", ");
            }
            let _ = write!(buf, "{} => ", stringify_key(k));
            stringify_value(buf, v);
        }
        buf.push('}');
        return;
    }

    if let Some(sr) = val.as_scalar_ref() {
        let inner_val = sr.read().clone();
        buf.push('\\');
        stringify_value(buf, &inner_val);
        return;
    }

    if let Some(blessed) = val.as_blessed_ref() {
        let data = blessed.data.read().clone();
        let _ = write!(buf, "bless(");
        stringify_value(buf, &data);
        let _ = write!(buf, ", \"{}\")", blessed.class);
        return;
    }

    if let Some(s) = val.as_struct_inst() {
        let _ = write!(buf, "{}(", s.def.name);
        let values = s.get_values();
        for (i, field) in s.def.fields.iter().enumerate() {
            if i > 0 {
                buf.push_str(", ");
            }
            let _ = write!(buf, "{} => ", field.name);
            stringify_value(buf, &values[i]);
        }
        buf.push(')');
        return;
    }

    if let Some(arr) = val.as_array_vec() {
        buf.push('(');
        for (i, elem) in arr.iter().enumerate() {
            if i > 0 {
                buf.push_str(", ");
            }
            stringify_value(buf, elem);
        }
        buf.push(')');
        return;
    }

    if let Some(h) = val.as_hash_map() {
        buf.push('(');
        for (i, (k, v)) in h.iter().enumerate() {
            if i > 0 {
                buf.push_str(", ");
            }
            let _ = write!(buf, "{} => ", stringify_key(k));
            stringify_value(buf, v);
        }
        buf.push(')');
        return;
    }

    if let Some(cr) = val.as_code_ref() {
        if crate::compat_mode() {
            buf.push_str("sub");
        } else {
            buf.push_str("fn");
        }
        if !cr.params.is_empty() {
            buf.push_str(" (");
            for (i, p) in cr.params.iter().enumerate() {
                if i > 0 {
                    buf.push_str(", ");
                }
                match p {
                    crate::ast::SubSigParam::Scalar(name, ty, default) => {
                        let _ = write!(buf, "${}", name);
                        if let Some(t) = ty {
                            buf.push_str(": ");
                            buf.push_str(&t.display_name());
                        }
                        if default.is_some() {
                            buf.push_str(" = ...");
                        }
                    }
                    crate::ast::SubSigParam::Array(name, default) => {
                        let _ = write!(buf, "@{}", name);
                        if default.is_some() {
                            buf.push_str(" = ...");
                        }
                    }
                    crate::ast::SubSigParam::Hash(name, default) => {
                        let _ = write!(buf, "%{}", name);
                        if default.is_some() {
                            buf.push_str(" = ...");
                        }
                    }
                    crate::ast::SubSigParam::ArrayDestruct(_) => buf.push_str("[...]"),
                    crate::ast::SubSigParam::HashDestruct(_) => buf.push_str("{...}"),
                }
            }
            buf.push(')');
        }
        buf.push_str(" { ");
        buf.push_str(&crate::deparse::deparse_block(&cr.body));
        buf.push_str(" }");
        return;
    }

    // Handle enum instances: Color::Red or Maybe::Some(42)
    if let Some(e) = val.as_enum_inst() {
        let _ = write!(buf, "{}::{}", e.def.name, e.variant_name());
        if e.def.variants[e.variant_idx].ty.is_some() {
            buf.push('(');
            stringify_value(buf, &e.data);
            buf.push(')');
        }
        return;
    }

    // Handle class instances: Dog(name => "Rex", age => 5)
    if let Some(c) = val.as_class_inst() {
        let _ = write!(buf, "{}(", c.def.name);
        let values = c.get_values();
        for (i, field) in c.def.fields.iter().enumerate() {
            if i > 0 {
                buf.push_str(", ");
            }
            let _ = write!(buf, "{} => ", field.name);
            stringify_value(buf, &values[i]);
        }
        buf.push(')');
        return;
    }

    // Handle set: set(1, 2, 3)
    if let Some(set_arc) = crate::value::set_payload(val) {
        buf.push_str("set(");
        for (i, v) in set_arc.values().enumerate() {
            if i > 0 {
                buf.push_str(", ");
            }
            stringify_value(buf, v);
        }
        buf.push(')');
        return;
    }

    // Handle deque
    if let Some(dq) = val.as_deque() {
        buf.push_str("deque(");
        let guard = dq.lock();
        for (i, v) in guard.iter().enumerate() {
            if i > 0 {
                buf.push_str(", ");
            }
            stringify_value(buf, v);
        }
        buf.push(')');
        return;
    }

    // Handle heap
    if let Some(hp) = val.as_heap_pq() {
        buf.push_str("heap(");
        let guard = hp.lock();
        for (i, v) in guard.items.iter().enumerate() {
            if i > 0 {
                buf.push_str(", ");
            }
            stringify_value(buf, v);
        }
        buf.push(')');
        return;
    }

    if val.is_integer_like() || val.is_float_like() {
        let _ = write!(buf, "{val}");
        return;
    }

    let s = val.to_string();
    let _ = write!(buf, "\"{}\"", stringify_escape(&s));
}

fn stringify_key(k: &str) -> String {
    if k.chars().all(|c| c.is_ascii_alphanumeric() || c == '_') && !k.is_empty() {
        k.to_string()
    } else {
        format!("\"{}\"", stringify_escape(k))
    }
}

fn stringify_escape(s: &str) -> String {
    let mut out = String::with_capacity(s.len());
    for c in s.chars() {
        match c {
            '\\' => out.push_str("\\\\"),
            '"' => out.push_str("\\\""),
            '\n' => out.push_str("\\n"),
            '\r' => out.push_str("\\r"),
            '\t' => out.push_str("\\t"),
            '\0' => out.push_str("\\0"),
            '$' => out.push_str("\\$"),
            '@' => out.push_str("\\@"),
            _ => out.push(c),
        }
    }
    out
}

/// `input` — read all of stdin. `input $fh` / `input "path"` — read from filehandle or file.
fn builtin_input(
    interp: &VMHelper,
    args: &[StrykeValue],
    line: usize,
) -> StrykeResult<StrykeValue> {
    use std::io::Read;
    if args.is_empty() {
        let mut buf = String::new();
        std::io::stdin().read_to_string(&mut buf).unwrap_or(0);
        return Ok(StrykeValue::string(buf));
    }
    let name = args[0].to_string();
    // STDIN handle — read stdin directly
    if name == "STDIN" {
        let mut buf = String::new();
        std::io::stdin().read_to_string(&mut buf).unwrap_or(0);
        return Ok(StrykeValue::string(buf));
    }
    // If <STDIN> was used, the parser already read all of stdin into the arg string.
    // Detect this: if the arg came from a readline (contains newlines, not a valid path),
    // just return it as-is.
    if name.contains('\n') && std::fs::metadata(&name).is_err() {
        return Ok(args[0].clone());
    }
    // Try as an open filehandle via io_file_slots
    if let Some(slot) = interp.io_file_slots.get(&name) {
        let mut f = slot.lock();
        let mut buf = String::new();
        f.read_to_string(&mut buf)
            .map_err(|e| StrykeError::runtime(format!("input: {}: {}", name, e), line))?;
        return Ok(StrykeValue::string(buf));
    }
    // Fall back to treating it as a file path
    let content = std::fs::read_to_string(&name)
        .map_err(|e| StrykeError::runtime(format!("input: {}: {}", name, e), line))?;
    Ok(StrykeValue::string(content))
}

/// `lines STRING` — split string into array on newlines (no trailing empty).
/// `lines ITERATOR` — flat-map each element's lines (streaming).
/// Returns a streaming iterator for lazy consumption.
fn builtin_lines(_interp: &VMHelper, args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    if let Some(v) = args.first() {
        if v.is_iterator() {
            let source = v.clone().into_iterator();
            return Ok(StrykeValue::iterator(Arc::new(
                crate::map_stream::LinesFlatMapIterator::new(source),
            )));
        }
        if let Some(cap) = v.as_capture() {
            return Ok(StrykeValue::iterator(Arc::new(
                crate::map_stream::LinesIterator::new(&cap.stdout),
            )));
        }
    }
    let s = args.first().map(|v| v.to_string()).unwrap_or_default();
    Ok(StrykeValue::iterator(Arc::new(
        crate::map_stream::LinesIterator::new(&s),
    )))
}

/// `words STRING` — split on whitespace into array.
/// `words ITERATOR` — flat-map each element's words (streaming).
fn builtin_words(_interp: &VMHelper, args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    if let Some(v) = args.first() {
        if v.is_iterator() {
            let source = v.clone().into_iterator();
            return Ok(StrykeValue::iterator(Arc::new(
                crate::map_stream::WordsFlatMapIterator::new(source),
            )));
        }
        if let Some(cap) = v.as_capture() {
            return Ok(StrykeValue::iterator(Arc::new(
                crate::map_stream::WordsIterator::new(&cap.stdout),
            )));
        }
    }
    let s = args.first().map(|v| v.to_string()).unwrap_or_default();
    Ok(StrykeValue::iterator(Arc::new(
        crate::map_stream::WordsIterator::new(&s),
    )))
}

/// `digits STRING` — extract all digit characters from a string.
fn builtin_digits(interp: &VMHelper, args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    let s = first_arg_or_topic(interp, args).to_string();
    let out: Vec<StrykeValue> = s
        .chars()
        .filter(|c| c.is_ascii_digit())
        .map(|c| StrykeValue::string(c.to_string()))
        .collect();
    Ok(StrykeValue::array(out))
}

