/// `thread_count` — current rayon thread pool size.
fn builtin_thread_count() -> StrykeResult<StrykeValue> {
    Ok(StrykeValue::integer(rayon::current_num_threads() as i64))
}

/// `pool_info` — thread pool and parallelism details as hashref.
fn builtin_pool_info() -> StrykeResult<StrykeValue> {
    let cpus = std::thread::available_parallelism()
        .map(|n| n.get() as i64)
        .unwrap_or(1);
    let rayon_threads = rayon::current_num_threads() as i64;
    let mut h = indexmap::IndexMap::new();
    h.insert("cpus".into(), StrykeValue::integer(cpus));
    h.insert("rayon_threads".into(), StrykeValue::integer(rayon_threads));
    h.insert(
        "arch".into(),
        StrykeValue::string(std::env::consts::ARCH.to_string()),
    );
    h.insert(
        "os".into(),
        StrykeValue::string(std::env::consts::OS.to_string()),
    );
    #[cfg(target_os = "macos")]
    {
        // Performance vs efficiency cores
        let mut perfc: i32 = 0;
        let mut len = std::mem::size_of::<i32>();
        let name = std::ffi::CString::new("hw.perflevel0.physicalcpu").unwrap();
        if unsafe {
            libc::sysctlbyname(
                name.as_ptr(),
                &mut perfc as *mut _ as *mut _,
                &mut len,
                std::ptr::null_mut(),
                0,
            )
        } == 0
        {
            h.insert("perf_cores".into(), StrykeValue::integer(perfc as i64));
        }
        let mut effc: i32 = 0;
        let name2 = std::ffi::CString::new("hw.perflevel1.physicalcpu").unwrap();
        if unsafe {
            libc::sysctlbyname(
                name2.as_ptr(),
                &mut effc as *mut _ as *mut _,
                &mut len,
                std::ptr::null_mut(),
                0,
            )
        } == 0
        {
            h.insert("eff_cores".into(), StrykeValue::integer(effc as i64));
        }
    }
    Ok(StrykeValue::hash_ref(Arc::new(parking_lot::RwLock::new(h))))
}

/// `par_bench [N]` — benchmark parallel throughput. Runs N iterations of pmap
/// on a trivial workload and returns ops/sec as hashref.
fn builtin_par_bench(args: &[StrykeValue], _line: usize) -> StrykeResult<StrykeValue> {
    use rayon::prelude::*;
    let n = args.first().map(|v| v.to_int()).unwrap_or(1_000_000) as usize;
    // Sequential
    let start = std::time::Instant::now();
    let _sum: i64 = (0..n as i64).map(|i| i * i).sum();
    let seq_ms = start.elapsed().as_secs_f64() * 1000.0;
    // Parallel
    let start = std::time::Instant::now();
    let _sum: i64 = (0..n as i64).into_par_iter().map(|i| i * i).sum();
    let par_ms = start.elapsed().as_secs_f64() * 1000.0;
    let mut h = indexmap::IndexMap::new();
    h.insert("items".into(), StrykeValue::integer(n as i64));
    h.insert("seq_ms".into(), StrykeValue::float(seq_ms));
    h.insert("par_ms".into(), StrykeValue::float(par_ms));
    h.insert(
        "speedup".into(),
        StrykeValue::float(seq_ms / par_ms.max(0.001)),
    );
    h.insert(
        "threads".into(),
        StrykeValue::integer(rayon::current_num_threads() as i64),
    );
    h.insert(
        "ops_per_sec".into(),
        StrykeValue::integer((n as f64 / (par_ms / 1000.0)) as i64),
    );
    Ok(StrykeValue::hash_ref(Arc::new(parking_lot::RwLock::new(h))))
}
/// `refresh_stashes` — rebuild `%main::` / `%Foo::` package stashes from the
/// current symbol table. Returns the number of packages now visible. The REPL
/// invokes this between lines automatically; scripts that mutate the symbol
/// table mid-run can call it explicitly to update the stash hashes.
fn builtin_refresh_stashes(interp: &mut VMHelper) -> StrykeResult<StrykeValue> {
    interp.refresh_package_stashes();
    // Count distinct `Pkg::` keys now installed. `subs` is the most reliable
    // package-name source.
    let mut pkgs: std::collections::HashSet<&str> = std::collections::HashSet::new();
    for k in interp.subs.keys() {
        if let Some(i) = k.rfind("::") {
            pkgs.insert(&k[..i]);
        } else {
            pkgs.insert("main");
        }
    }
    Ok(StrykeValue::integer(pkgs.len() as i64))
}

