// ── Memory stats ────────────────────────────────────────────────────────

#[cfg(target_os = "linux")]
fn read_meminfo_field(field: &str) -> Option<i64> {
    let data = std::fs::read_to_string("/proc/meminfo").ok()?;
    for line in data.lines() {
        if line.starts_with(field) {
            // Format: "MemTotal:       16384000 kB"
            let kb: i64 = line.split_whitespace().nth(1)?.parse().ok()?;
            return Some(kb * 1024);
        }
    }
    None
}

/// `mem_total` — Total physical RAM in bytes.
#[cfg(target_os = "linux")]
fn builtin_mem_total() -> StrykeResult<StrykeValue> {
    Ok(read_meminfo_field("MemTotal:")
        .map(StrykeValue::integer)
        .unwrap_or(StrykeValue::UNDEF))
}
#[cfg(target_os = "macos")]
fn builtin_mem_total() -> StrykeResult<StrykeValue> {
    let mut val: u64 = 0;
    let mut len = std::mem::size_of::<u64>();
    let name = b"hw.memsize\0";
    let rc = unsafe {
        libc::sysctlbyname(
            name.as_ptr() as *const libc::c_char,
            &mut val as *mut u64 as *mut libc::c_void,
            &mut len,
            std::ptr::null_mut(),
            0,
        )
    };
    Ok(if rc == 0 {
        StrykeValue::integer(val as i64)
    } else {
        StrykeValue::UNDEF
    })
}
#[cfg(not(any(target_os = "linux", target_os = "macos")))]
fn builtin_mem_total() -> StrykeResult<StrykeValue> {
    Ok(StrykeValue::UNDEF)
}

/// `mem_free` — Free physical RAM in bytes.
#[cfg(target_os = "linux")]
fn builtin_mem_free() -> StrykeResult<StrykeValue> {
    Ok(read_meminfo_field("MemAvailable:")
        .or_else(|| read_meminfo_field("MemFree:"))
        .map(StrykeValue::integer)
        .unwrap_or(StrykeValue::UNDEF))
}
#[cfg(target_os = "macos")]
fn builtin_mem_free() -> StrykeResult<StrykeValue> {
    let mut page_size: u64 = 0;
    let mut len = std::mem::size_of::<u64>();
    let name = b"hw.pagesize\0";
    let rc = unsafe {
        libc::sysctlbyname(
            name.as_ptr() as *const libc::c_char,
            &mut page_size as *mut u64 as *mut libc::c_void,
            &mut len,
            std::ptr::null_mut(),
            0,
        )
    };
    if rc != 0 {
        return Ok(StrykeValue::UNDEF);
    }
    // Use vm.page_free_count which is a simple sysctl
    let mut free_pages: u32 = 0;
    len = std::mem::size_of::<u32>();
    let name2 = b"vm.page_free_count\0";
    let rc2 = unsafe {
        libc::sysctlbyname(
            name2.as_ptr() as *const libc::c_char,
            &mut free_pages as *mut u32 as *mut libc::c_void,
            &mut len,
            std::ptr::null_mut(),
            0,
        )
    };
    Ok(if rc2 == 0 {
        StrykeValue::integer(free_pages as i64 * page_size as i64)
    } else {
        StrykeValue::UNDEF
    })
}
#[cfg(not(any(target_os = "linux", target_os = "macos")))]
fn builtin_mem_free() -> StrykeResult<StrykeValue> {
    Ok(StrykeValue::UNDEF)
}

/// `mem_used` — Used physical RAM in bytes (total - free).
fn builtin_mem_used() -> StrykeResult<StrykeValue> {
    let total = builtin_mem_total()?;
    let free = builtin_mem_free()?;
    match (total.as_integer(), free.as_integer()) {
        (Some(t), Some(f)) => Ok(StrykeValue::integer(t - f)),
        _ => Ok(StrykeValue::UNDEF),
    }
}

/// `swap_total` — Total swap space in bytes.
#[cfg(target_os = "linux")]
fn builtin_swap_total() -> StrykeResult<StrykeValue> {
    Ok(read_meminfo_field("SwapTotal:")
        .map(StrykeValue::integer)
        .unwrap_or(StrykeValue::UNDEF))
}
#[cfg(target_os = "macos")]
fn macos_swap_usage() -> Option<(i64, i64, i64)> {
    // xsw_usage is { xsu_total: u64, xsu_avail: u64, xsu_used: u64 }
    #[repr(C)]
    struct XswUsage {
        total: u64,
        avail: u64,
        used: u64,
    }
    let mut usage: XswUsage = unsafe { std::mem::zeroed() };
    let mut len = std::mem::size_of::<XswUsage>();
    let name = b"vm.swapusage\0";
    let rc = unsafe {
        libc::sysctlbyname(
            name.as_ptr() as *const libc::c_char,
            &mut usage as *mut XswUsage as *mut libc::c_void,
            &mut len,
            std::ptr::null_mut(),
            0,
        )
    };
    if rc == 0 {
        Some((usage.total as i64, usage.avail as i64, usage.used as i64))
    } else {
        None
    }
}
#[cfg(target_os = "macos")]
fn builtin_swap_total() -> StrykeResult<StrykeValue> {
    Ok(macos_swap_usage()
        .map(|(t, _, _)| StrykeValue::integer(t))
        .unwrap_or(StrykeValue::UNDEF))
}
#[cfg(not(any(target_os = "linux", target_os = "macos")))]
fn builtin_swap_total() -> StrykeResult<StrykeValue> {
    Ok(StrykeValue::UNDEF)
}

/// `swap_free` — Free swap space in bytes.
#[cfg(target_os = "linux")]
fn builtin_swap_free() -> StrykeResult<StrykeValue> {
    Ok(read_meminfo_field("SwapFree:")
        .map(StrykeValue::integer)
        .unwrap_or(StrykeValue::UNDEF))
}
#[cfg(target_os = "macos")]
fn builtin_swap_free() -> StrykeResult<StrykeValue> {
    Ok(macos_swap_usage()
        .map(|(_, a, _)| StrykeValue::integer(a))
        .unwrap_or(StrykeValue::UNDEF))
}
#[cfg(not(any(target_os = "linux", target_os = "macos")))]
fn builtin_swap_free() -> StrykeResult<StrykeValue> {
    Ok(StrykeValue::UNDEF)
}

/// `swap_used` — Used swap space in bytes.
fn builtin_swap_used() -> StrykeResult<StrykeValue> {
    let total = builtin_swap_total()?;
    let free = builtin_swap_free()?;
    match (total.as_integer(), free.as_integer()) {
        (Some(t), Some(f)) => Ok(StrykeValue::integer(t - f)),
        _ => Ok(StrykeValue::UNDEF),
    }
}

// ── Disk stats ──────────────────────────────────────────────────────────

#[cfg(unix)]
fn statvfs_for(path: &str) -> Option<libc::statvfs> {
    let c_path = CString::new(path).ok()?;
    let mut buf: libc::statvfs = unsafe { std::mem::zeroed() };
    let rc = unsafe { libc::statvfs(c_path.as_ptr(), &mut buf) };
    if rc == 0 {
        Some(buf)
    } else {
        None
    }
}

/// `mounts` — list all mounted filesystems as array of hashrefs.
/// Each hashref: {mount, device, fs_type, total, free, avail, used, use_pct}
#[cfg(target_os = "macos")]
fn builtin_mounts() -> StrykeResult<StrykeValue> {
    use std::ffi::CStr;
    let mut buf: *mut libc::statfs = std::ptr::null_mut();
    let count = unsafe { libc::getmntinfo(&mut buf, libc::MNT_NOWAIT) };
    if count <= 0 || buf.is_null() {
        return Ok(StrykeValue::array(vec![]));
    }
    let entries = unsafe { std::slice::from_raw_parts(buf, count as usize) };
    let mut result = Vec::new();
    for entry in entries {
        let mount = unsafe { CStr::from_ptr(entry.f_mntonname.as_ptr()) }
            .to_string_lossy()
            .to_string();
        let device = unsafe { CStr::from_ptr(entry.f_mntfromname.as_ptr()) }
            .to_string_lossy()
            .to_string();
        let fstype = unsafe { CStr::from_ptr(entry.f_fstypename.as_ptr()) }
            .to_string_lossy()
            .to_string();
        let bsize = entry.f_bsize as i64;
        let total = entry.f_blocks as i64 * bsize;
        let free = entry.f_bfree as i64 * bsize;
        let avail = entry.f_bavail as i64 * bsize;
        let used = total - free;
        let use_pct = if total > 0 {
            used as f64 / total as f64 * 100.0
        } else {
            0.0
        };
        let mut h = indexmap::IndexMap::new();
        h.insert("mount".into(), StrykeValue::string(mount));
        h.insert("device".into(), StrykeValue::string(device));
        h.insert("fs_type".into(), StrykeValue::string(fstype));
        h.insert("total".into(), StrykeValue::integer(total));
        h.insert("free".into(), StrykeValue::integer(free));
        h.insert("avail".into(), StrykeValue::integer(avail));
        h.insert("used".into(), StrykeValue::integer(used));
        h.insert("use_pct".into(), StrykeValue::float(use_pct));
        result.push(StrykeValue::hash_ref(Arc::new(parking_lot::RwLock::new(h))));
    }
    Ok(StrykeValue::array(result))
}

#[cfg(target_os = "linux")]
fn builtin_mounts() -> StrykeResult<StrykeValue> {
    let data = std::fs::read_to_string("/proc/mounts").unwrap_or_default();
    let mut result = Vec::new();
    for line in data.lines() {
        let parts: Vec<&str> = line.split_whitespace().collect();
        if parts.len() < 3 {
            continue;
        }
        let device = parts[0];
        let mount = parts[1];
        let fstype = parts[2];
        // Skip virtual filesystems
        if [
            "proc",
            "sysfs",
            "devpts",
            "tmpfs",
            "cgroup",
            "cgroup2",
            "pstore",
            "securityfs",
            "debugfs",
            "configfs",
            "fusectl",
            "mqueue",
            "hugetlbfs",
            "rpc_pipefs",
            "binfmt_misc",
        ]
        .contains(&fstype)
        {
            continue;
        }
        let mut h = indexmap::IndexMap::new();
        h.insert("mount".into(), StrykeValue::string(mount.to_string()));
        h.insert("device".into(), StrykeValue::string(device.to_string()));
        h.insert("fs_type".into(), StrykeValue::string(fstype.to_string()));
        if let Some(s) = statvfs_for(mount) {
            let bsize = s.f_frsize as i64;
            let total = s.f_blocks as i64 * bsize;
            let free = s.f_bfree as i64 * bsize;
            let avail = s.f_bavail as i64 * bsize;
            let used = total - free;
            let use_pct = if total > 0 {
                used as f64 / total as f64 * 100.0
            } else {
                0.0
            };
            h.insert("total".into(), StrykeValue::integer(total));
            h.insert("free".into(), StrykeValue::integer(free));
            h.insert("avail".into(), StrykeValue::integer(avail));
            h.insert("used".into(), StrykeValue::integer(used));
            h.insert("use_pct".into(), StrykeValue::float(use_pct));
        }
        result.push(StrykeValue::hash_ref(Arc::new(parking_lot::RwLock::new(h))));
    }
    Ok(StrykeValue::array(result))
}

#[cfg(not(unix))]
fn builtin_mounts() -> StrykeResult<StrykeValue> {
    Ok(StrykeValue::array(vec![]))
}

// ── Git builtins (libgit2, no fork) ─────────────────────────────────────

/// Open a git repo from CWD or optional path arg.
fn open_git_repo(
    _interp: &VMHelper,
    args: &[StrykeValue],
    line: usize,
) -> StrykeResult<git2::Repository> {
    let path = if args.is_empty() || args[0].is_undef() || args[0].to_string().is_empty() {
        ".".to_string()
    } else {
        args[0].to_string()
    };
    git2::Repository::discover(&path)
        .map_err(|e| StrykeError::runtime(format!("git: {}: {}", path, e), line))
}

/// `git_log [PATH] [, N]` — last N commits as array of hashrefs.
fn builtin_git_log(
    interp: &VMHelper,
    args: &[StrykeValue],
    line: usize,
) -> StrykeResult<StrykeValue> {
    let repo = open_git_repo(interp, &[], line)?;
    let limit = args.first().map(|v| v.to_int() as usize).unwrap_or(20);
    let mut revwalk = repo
        .revwalk()
        .map_err(|e| StrykeError::runtime(format!("git_log: {}", e), line))?;
    revwalk.push_head().ok();
    revwalk.set_sorting(git2::Sort::TIME).ok();
    let mut result = Vec::new();
    for oid in revwalk.take(limit).flatten() {
        if let Ok(commit) = repo.find_commit(oid) {
            let mut h = indexmap::IndexMap::new();
            h.insert("sha".into(), StrykeValue::string(oid.to_string()));
            h.insert(
                "short".into(),
                StrykeValue::string(oid.to_string()[..7].to_string()),
            );
            h.insert(
                "message".into(),
                StrykeValue::string(commit.message().unwrap_or("").trim().to_string()),
            );
            h.insert(
                "author".into(),
                StrykeValue::string(commit.author().name().unwrap_or("").to_string()),
            );
            h.insert(
                "email".into(),
                StrykeValue::string(commit.author().email().unwrap_or("").to_string()),
            );
            h.insert("time".into(), StrykeValue::integer(commit.time().seconds()));
            result.push(StrykeValue::hash_ref(Arc::new(parking_lot::RwLock::new(h))));
        }
    }
    Ok(StrykeValue::array(result))
}

/// `git_status` — working tree status as array of hashrefs {path, status}.
fn builtin_git_status(
    interp: &VMHelper,
    args: &[StrykeValue],
    line: usize,
) -> StrykeResult<StrykeValue> {
    let repo = open_git_repo(interp, args, line)?;
    let statuses = repo
        .statuses(None)
        .map_err(|e| StrykeError::runtime(format!("git_status: {}", e), line))?;
    let mut result = Vec::new();
    for entry in statuses.iter() {
        let path = entry.path().unwrap_or("").to_string();
        let st = entry.status();
        let status_str = if st.contains(git2::Status::WT_NEW) {
            "new"
        } else if st.contains(git2::Status::WT_MODIFIED) {
            "modified"
        } else if st.contains(git2::Status::WT_DELETED) {
            "deleted"
        } else if st.contains(git2::Status::WT_RENAMED) {
            "renamed"
        } else if st.contains(git2::Status::INDEX_NEW) {
            "staged_new"
        } else if st.contains(git2::Status::INDEX_MODIFIED) {
            "staged_modified"
        } else if st.contains(git2::Status::INDEX_DELETED) {
            "staged_deleted"
        } else {
            "unknown"
        };
        let mut h = indexmap::IndexMap::new();
        h.insert("path".into(), StrykeValue::string(path));
        h.insert("status".into(), StrykeValue::string(status_str.to_string()));
        result.push(StrykeValue::hash_ref(Arc::new(parking_lot::RwLock::new(h))));
    }
    Ok(StrykeValue::array(result))
}

/// `git_diff` — diff of working tree vs HEAD as string.
fn builtin_git_diff(
    interp: &VMHelper,
    args: &[StrykeValue],
    line: usize,
) -> StrykeResult<StrykeValue> {
    let repo = open_git_repo(interp, args, line)?;
    let diff = repo
        .diff_index_to_workdir(None, None)
        .map_err(|e| StrykeError::runtime(format!("git_diff: {}", e), line))?;
    let mut buf = String::new();
    diff.print(git2::DiffFormat::Patch, |_delta, _hunk, line| {
        let origin = line.origin();
        if origin == '+' || origin == '-' || origin == ' ' {
            buf.push(origin);
        }
        buf.push_str(std::str::from_utf8(line.content()).unwrap_or(""));
        true
    })
    .ok();
    Ok(StrykeValue::string(buf))
}

/// `git_branches` — list branches as array of hashrefs {name, is_head}.
fn builtin_git_branches(
    interp: &VMHelper,
    args: &[StrykeValue],
    line: usize,
) -> StrykeResult<StrykeValue> {
    let repo = open_git_repo(interp, args, line)?;
    let branches = repo
        .branches(Some(git2::BranchType::Local))
        .map_err(|e| StrykeError::runtime(format!("git_branches: {}", e), line))?;
    let mut result = Vec::new();
    for branch in branches.flatten() {
        let (b, _) = branch;
        let name = b.name().ok().flatten().unwrap_or("").to_string();
        let is_head = b.is_head();
        let mut h = indexmap::IndexMap::new();
        h.insert("name".into(), StrykeValue::string(name));
        h.insert(
            "is_head".into(),
            StrykeValue::integer(if is_head { 1 } else { 0 }),
        );
        result.push(StrykeValue::hash_ref(Arc::new(parking_lot::RwLock::new(h))));
    }
    Ok(StrykeValue::array(result))
}

/// `git_tags` — list tags as array of strings.
fn builtin_git_tags(
    interp: &VMHelper,
    args: &[StrykeValue],
    line: usize,
) -> StrykeResult<StrykeValue> {
    let repo = open_git_repo(interp, args, line)?;
    let tags = repo
        .tag_names(None)
        .map_err(|e| StrykeError::runtime(format!("git_tags: {}", e), line))?;
    let result: Vec<StrykeValue> = tags
        .iter()
        .flatten()
        .map(|t| StrykeValue::string(t.to_string()))
        .collect();
    Ok(StrykeValue::array(result))
}

/// `git_blame FILE` — blame output as array of hashrefs {line, sha, author, text}.
fn builtin_git_blame(args: &[StrykeValue], line: usize) -> StrykeResult<StrykeValue> {
    let file_path = args.first().map(|v| v.to_string()).unwrap_or_default();
    let repo = git2::Repository::discover(".")
        .map_err(|e| StrykeError::runtime(format!("git_blame: {}", e), line))?;
    let blame = repo
        .blame_file(std::path::Path::new(&file_path), None)
        .map_err(|e| StrykeError::runtime(format!("git_blame: {}: {}", file_path, e), line))?;
    let file_content = std::fs::read_to_string(&file_path).unwrap_or_default();
    let lines: Vec<&str> = file_content.lines().collect();
    let mut result = Vec::new();
    for (i, hunk) in (0..blame.len()).filter_map(|i| blame.get_index(i).map(|h| (i, h))) {
        let sig = hunk.final_signature();
        let mut h = indexmap::IndexMap::new();
        h.insert("line".into(), StrykeValue::integer(i as i64 + 1));
        h.insert(
            "sha".into(),
            StrykeValue::string(hunk.final_commit_id().to_string()[..7].to_string()),
        );
        h.insert(
            "author".into(),
            StrykeValue::string(sig.name().unwrap_or("").to_string()),
        );
        h.insert(
            "text".into(),
            StrykeValue::string(lines.get(i).unwrap_or(&"").to_string()),
        );
        result.push(StrykeValue::hash_ref(Arc::new(parking_lot::RwLock::new(h))));
    }
    Ok(StrykeValue::array(result))
}

/// `git_authors` — unique authors as array of hashrefs {name, email, commits}.
fn builtin_git_authors(
    interp: &VMHelper,
    args: &[StrykeValue],
    line: usize,
) -> StrykeResult<StrykeValue> {
    let repo = open_git_repo(interp, args, line)?;
    let mut revwalk = repo
        .revwalk()
        .map_err(|e| StrykeError::runtime(format!("git_authors: {}", e), line))?;
    revwalk.push_head().ok();
    let mut counts: indexmap::IndexMap<String, (String, i64)> = indexmap::IndexMap::new();
    for oid in revwalk.flatten() {
        if let Ok(commit) = repo.find_commit(oid) {
            let name = commit.author().name().unwrap_or("").to_string();
            let email = commit.author().email().unwrap_or("").to_string();
            let entry = counts.entry(name.clone()).or_insert((email, 0));
            entry.1 += 1;
        }
    }
    let mut result: Vec<StrykeValue> = counts
        .into_iter()
        .map(|(name, (email, count))| {
            let mut h = indexmap::IndexMap::new();
            h.insert("name".into(), StrykeValue::string(name));
            h.insert("email".into(), StrykeValue::string(email));
            h.insert("commits".into(), StrykeValue::integer(count));
            StrykeValue::hash_ref(Arc::new(parking_lot::RwLock::new(h)))
        })
        .collect();
    result.sort_by(|a, b| {
        let ac = a
            .as_hash_ref()
            .map(|h| h.read().get("commits").map(|v| v.to_int()).unwrap_or(0))
            .unwrap_or(0);
        let bc = b
            .as_hash_ref()
            .map(|h| h.read().get("commits").map(|v| v.to_int()).unwrap_or(0))
            .unwrap_or(0);
        bc.cmp(&ac)
    });
    Ok(StrykeValue::array(result))
}

/// `git_files` — list tracked files as array of strings.
fn builtin_git_files(
    interp: &VMHelper,
    args: &[StrykeValue],
    line: usize,
) -> StrykeResult<StrykeValue> {
    let repo = open_git_repo(interp, args, line)?;
    let head = repo
        .head()
        .and_then(|r| r.peel_to_tree())
        .map_err(|e| StrykeError::runtime(format!("git_files: {}", e), line))?;
    let mut files = Vec::new();
    head.walk(git2::TreeWalkMode::PreOrder, |dir, entry| {
        if entry.kind() == Some(git2::ObjectType::Blob) {
            let path = if dir.is_empty() {
                entry.name().unwrap_or("").to_string()
            } else {
                format!("{}{}", dir, entry.name().unwrap_or(""))
            };
            files.push(StrykeValue::string(path));
        }
        git2::TreeWalkResult::Ok
    })
    .ok();
    Ok(StrykeValue::array(files))
}

/// `git_show SHA` — show commit details as hashref.
fn builtin_git_show(args: &[StrykeValue], line: usize) -> StrykeResult<StrykeValue> {
    let sha = args.first().map(|v| v.to_string()).unwrap_or_default();
    let repo = git2::Repository::discover(".")
        .map_err(|e| StrykeError::runtime(format!("git_show: {}", e), line))?;
    let oid = git2::Oid::from_str(&sha)
        .or_else(|_| {
            // Try as short SHA
            let obj = repo
                .revparse_single(&sha)
                .map_err(|e| StrykeError::runtime(format!("git_show: {}: {}", sha, e), line))?;
            Ok::<git2::Oid, StrykeError>(obj.id())
        })
        .map_err(|e| StrykeError::runtime(format!("git_show: {}: {}", sha, e), line))?;
    let commit = repo
        .find_commit(oid)
        .map_err(|e| StrykeError::runtime(format!("git_show: {}", e), line))?;
    let mut h = indexmap::IndexMap::new();
    h.insert("sha".into(), StrykeValue::string(oid.to_string()));
    h.insert(
        "message".into(),
        StrykeValue::string(commit.message().unwrap_or("").to_string()),
    );
    h.insert(
        "author".into(),
        StrykeValue::string(commit.author().name().unwrap_or("").to_string()),
    );
    h.insert(
        "email".into(),
        StrykeValue::string(commit.author().email().unwrap_or("").to_string()),
    );
    h.insert("time".into(), StrykeValue::integer(commit.time().seconds()));
    h.insert(
        "parents".into(),
        StrykeValue::integer(commit.parent_count() as i64),
    );
    // Diff stats
    if let Ok(parent) = commit.parent(0) {
        if let (Ok(pt), Ok(ct)) = (parent.tree(), commit.tree()) {
            if let Ok(diff) = repo.diff_tree_to_tree(Some(&pt), Some(&ct), None) {
                if let Ok(stats) = diff.stats() {
                    h.insert(
                        "insertions".into(),
                        StrykeValue::integer(stats.insertions() as i64),
                    );
                    h.insert(
                        "deletions".into(),
                        StrykeValue::integer(stats.deletions() as i64),
                    );
                    h.insert(
                        "files_changed".into(),
                        StrykeValue::integer(stats.files_changed() as i64),
                    );
                }
            }
        }
    }
    Ok(StrykeValue::hash_ref(Arc::new(parking_lot::RwLock::new(h))))
}

/// `git_root` — return the repo root path.
fn builtin_git_root(
    interp: &VMHelper,
    args: &[StrykeValue],
    line: usize,
) -> StrykeResult<StrykeValue> {
    let repo = open_git_repo(interp, args, line)?;
    Ok(StrykeValue::string(
        repo.workdir()
            .map(|p| p.to_string_lossy().to_string())
            .unwrap_or_default(),
    ))
}

