/// `load_avg` — System load averages [1m, 5m, 15m] as arrayref.
#[cfg(unix)]
fn builtin_load_avg() -> StrykeResult<StrykeValue> {
    let mut loads = [0f64; 3];
    let n = unsafe { libc::getloadavg(loads.as_mut_ptr(), 3) };
    if n < 3 {
        return Ok(StrykeValue::UNDEF);
    }
    Ok(StrykeValue::array_ref(Arc::new(RwLock::new(vec![
        StrykeValue::float(loads[0]),
        StrykeValue::float(loads[1]),
        StrykeValue::float(loads[2]),
    ]))))
}
#[cfg(not(unix))]
fn builtin_load_avg() -> StrykeResult<StrykeValue> {
    Ok(StrykeValue::UNDEF)
}

// ── System uptime ───────────────────────────────────────────────────────

/// `sys_uptime` — System uptime in seconds (float).
#[cfg(target_os = "linux")]
fn builtin_sys_uptime() -> StrykeResult<StrykeValue> {
    if let Ok(data) = std::fs::read_to_string("/proc/uptime") {
        if let Some(secs) = data
            .split_whitespace()
            .next()
            .and_then(|s| s.parse::<f64>().ok())
        {
            return Ok(StrykeValue::float(secs));
        }
    }
    Ok(StrykeValue::UNDEF)
}
#[cfg(target_os = "macos")]
fn builtin_sys_uptime() -> StrykeResult<StrykeValue> {
    // kern.boottime returns struct timeval { tv_sec, tv_usec }
    let mut boottime = libc::timeval {
        tv_sec: 0,
        tv_usec: 0,
    };
    let mut len = std::mem::size_of::<libc::timeval>();
    let name = b"kern.boottime\0";
    let rc = unsafe {
        libc::sysctlbyname(
            name.as_ptr() as *const libc::c_char,
            &mut boottime as *mut libc::timeval as *mut libc::c_void,
            &mut len,
            std::ptr::null_mut(),
            0,
        )
    };
    if rc != 0 {
        return Ok(StrykeValue::UNDEF);
    }
    let mut now = libc::timeval {
        tv_sec: 0,
        tv_usec: 0,
    };
    unsafe { libc::gettimeofday(&mut now, std::ptr::null_mut()) };
    let secs = (now.tv_sec - boottime.tv_sec) as f64
        + (now.tv_usec - boottime.tv_usec) as f64 / 1_000_000.0;
    Ok(StrykeValue::float(secs))
}
#[cfg(not(any(target_os = "linux", target_os = "macos")))]
fn builtin_sys_uptime() -> StrykeResult<StrykeValue> {
    Ok(StrykeValue::UNDEF)
}

