/// `os_version` — OS kernel version/release string.
fn builtin_os_version() -> StrykeResult<StrykeValue> {
    #[cfg(unix)]
    {
        let mut uts: libc::utsname = unsafe { std::mem::zeroed() };
        if unsafe { libc::uname(&mut uts) } == 0 {
            let s = unsafe { CStr::from_ptr(uts.release.as_ptr()) };
            return Ok(StrykeValue::string(s.to_string_lossy().into_owned()));
        }
    }
    Ok(StrykeValue::UNDEF)
}

