/// `is_palindrome` — Test whether the argument is palindrome. Returns 1 (true) or 0 (false). Defaults to `$_`.
fn builtin_is_palindrome(interp: &VMHelper, args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    let s = first_arg_or_topic(interp, args).to_string();
    let clean: String = s
        .chars()
        .filter(|c| c.is_alphanumeric())
        .map(|c| c.to_ascii_lowercase())
        .collect();
    let rev: String = clean.chars().rev().collect();
    Ok(bool_iv(clean == rev))
}
/// `hamming` — Hamming. Returns an integer.
fn builtin_hamming(args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    let a = args.first();
    let b = args.get(1);
    let a_is_arr = a.is_some_and(|v| v.as_array_ref().is_some() || v.as_array_vec().is_some());
    let b_is_arr = b.is_some_and(|v| v.as_array_ref().is_some() || v.as_array_vec().is_some());
    if a_is_arr || b_is_arr {
        let v1 = a.map(arg_to_vec).unwrap_or_default();
        let v2 = b.map(arg_to_vec).unwrap_or_default();
        if v1.len() != v2.len() {
            return Ok(StrykeValue::UNDEF);
        }
        let dist = v1
            .iter()
            .zip(v2.iter())
            .filter(|(x, y)| x.to_string() != y.to_string())
            .count();
        return Ok(StrykeValue::integer(dist as i64));
    }
    let sa = a.map(|v| v.to_string()).unwrap_or_default();
    let sb = b.map(|v| v.to_string()).unwrap_or_default();
    if sa.chars().count() != sb.chars().count() {
        return Ok(StrykeValue::UNDEF);
    }
    Ok(StrykeValue::integer(
        sa.chars().zip(sb.chars()).filter(|(x, y)| x != y).count() as i64,
    ))
}
/// `lcp` — Lcp. Returns a string.
fn builtin_lcp(args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    let strs: Vec<String> = args.iter().map(|v| v.to_string()).collect();
    if strs.is_empty() {
        return Ok(StrykeValue::string(String::new()));
    }
    let min_len = strs.iter().map(|s| s.chars().count()).min().unwrap_or(0);
    let mut out = String::new();
    'outer: for i in 0..min_len {
        let c = strs[0].chars().nth(i).unwrap();
        for s in &strs[1..] {
            if s.chars().nth(i) != Some(c) {
                break 'outer;
            }
        }
        out.push(c);
    }
    Ok(StrykeValue::string(out))
}
/// `ord_char` — Ord char. Returns an integer. Defaults to `$_` when called with no args.
