// ── Stats / sorting / array / format / cmp / hash / regex / string / color / conversions ──
/// `min_max` — Min max. Returns a float.
fn builtin_min_max(args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    let xs = collect_numbers(args);
    if xs.is_empty() {
        return Ok(StrykeValue::UNDEF);
    }
    let (mn, mx) = xs
        .iter()
        .fold((f64::INFINITY, f64::NEG_INFINITY), |(a, b), &x| {
            (a.min(x), b.max(x))
        });
    Ok(StrykeValue::array_ref(Arc::new(RwLock::new(vec![
        StrykeValue::float(mn),
        StrykeValue::float(mx),
    ]))))
}
/// `percentile` — Percentile. Returns a float.
fn builtin_percentile(args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    let p = args
        .first()
        .map(|v| v.to_number())
        .unwrap_or(50.0)
        .clamp(0.0, 100.0);
    let mut xs = collect_numbers(&args[1..]);
    if xs.is_empty() {
        return Ok(StrykeValue::UNDEF);
    }
    xs.sort_by(|a, b| a.partial_cmp(b).unwrap_or(std::cmp::Ordering::Equal));
    let idx = ((p / 100.0) * (xs.len() - 1) as f64).round() as usize;
    Ok(StrykeValue::float(xs[idx.min(xs.len() - 1)]))
}
/// `harmonic_mean` — Harmonic mean. Returns a float.
fn builtin_harmonic_mean(args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    let xs = collect_numbers(args);
    if xs.is_empty() || xs.contains(&0.0) {
        return Ok(StrykeValue::UNDEF);
    }
    Ok(StrykeValue::float(
        xs.len() as f64 / xs.iter().map(|x| 1.0 / x).sum::<f64>(),
    ))
}
/// `geometric_mean` — Geometric mean. Returns a float.
fn builtin_geometric_mean(args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    let xs = collect_numbers(args);
    if xs.is_empty() {
        return Ok(StrykeValue::UNDEF);
    }
    Ok(StrykeValue::float(
        xs.iter().product::<f64>().powf(1.0 / xs.len() as f64),
    ))
}
/// `zscore` — Zscore. Returns a float.
fn builtin_zscore(args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    let x = args.first().map(|v| v.to_number()).unwrap_or(0.0);
    let xs = collect_numbers(&args[1..]);
    if xs.is_empty() {
        return Ok(StrykeValue::UNDEF);
    }
    let mean = xs.iter().sum::<f64>() / xs.len() as f64;
    let var = xs.iter().map(|v| (v - mean).powi(2)).sum::<f64>() / xs.len() as f64;
    let sd = var.sqrt();
    if sd == 0.0 {
        return Ok(StrykeValue::float(0.0));
    }
    Ok(StrykeValue::float((x - mean) / sd))
}
/// `sorted` — Sorted. Returns a list. No arguments → `sorted($_)`; a lone
/// string topic is split into chars so `map { sorted } qw(cba)` → "abc".
fn builtin_sorted(interp: &VMHelper, args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    let mut topic = StrykeValue::UNDEF;
    let args = variadic_list_or_topic(interp, args, &mut topic);
    let mut xs = flatten_args_split_lone_string(args);
    xs.sort_by_key(|a| a.to_string());
    Ok(StrykeValue::array(xs))
}
/// `sorted_desc` — Sorted desc. Returns a list. No arguments → `sorted_desc($_)`.
fn builtin_sorted_desc(interp: &VMHelper, args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    let mut topic = StrykeValue::UNDEF;
    let args = variadic_list_or_topic(interp, args, &mut topic);
    let mut xs = flatten_args_split_lone_string(args);
    xs.sort_by_key(|v| std::cmp::Reverse(v.to_string()));
    Ok(StrykeValue::array(xs))
}
/// `sorted_nums` — Sorted nums. Returns a list. No arguments → `sorted_nums($_)`.
fn builtin_sorted_nums(interp: &VMHelper, args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    let mut topic = StrykeValue::UNDEF;
    let args = variadic_list_or_topic(interp, args, &mut topic);
    let mut xs = flatten_args_split_lone_string(args);
    xs.sort_by(|a, b| {
        a.to_number()
            .partial_cmp(&b.to_number())
            .unwrap_or(std::cmp::Ordering::Equal)
    });
    Ok(StrykeValue::array(xs))
}
/// `sorted_by_length` — Sorted by length. Returns a list. No arguments → `sorted_by_length($_)`.
fn builtin_sorted_by_length(interp: &VMHelper, args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    let mut topic = StrykeValue::UNDEF;
    let args = variadic_list_or_topic(interp, args, &mut topic);
    let mut xs = flatten_args_split_lone_string(args);
    xs.sort_by_key(|v| v.to_string().chars().count());
    Ok(StrykeValue::array(xs))
}
/// `reverse_list` — Reverse list. Returns a list. No arguments →
/// `reverse_list($_)`; a lone string topic is split into chars so
/// `map { reverse_list } qw(ab cd)` → "ba dc".
fn builtin_reverse_list(interp: &VMHelper, args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    let mut topic = StrykeValue::UNDEF;
    let args = variadic_list_or_topic(interp, args, &mut topic);
    let mut xs = flatten_args_split_lone_string(args);
    xs.reverse();
    Ok(StrykeValue::array(xs))
}
/// `without` — Without. Returns a list.
fn builtin_without(args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    let Some(drop) = args.first() else {
        return Ok(StrykeValue::array(vec![]));
    };
    let drop_set: std::collections::HashSet<String> =
        if drop.as_array_ref().is_some() || drop.as_array_vec().is_some() {
            arg_to_vec(drop)
                .into_iter()
                .map(|v| v.to_string())
                .collect()
        } else {
            std::iter::once(drop.to_string()).collect()
        };
    Ok(StrykeValue::array(
        flatten_args(&args[1..])
            .into_iter()
            .filter(|v| !drop_set.contains(&v.to_string()))
            .collect(),
    ))
}
/// `without_nth` — Without nth. Returns a list.
fn builtin_without_nth(args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    let n = args.first().map(|v| v.to_int()).unwrap_or(-1);
    let xs = flatten_args(&args[1..]);
    Ok(StrykeValue::array(
        xs.into_iter()
            .enumerate()
            .filter(|(i, _)| *i as i64 != n)
            .map(|(_, v)| v)
            .collect(),
    ))
}
/// `take_last` — Take last. Returns a list.
fn builtin_take_last(args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    let n = args
        .first()
        .map(|v| v.to_int().max(0) as usize)
        .unwrap_or(0);
    let xs = flatten_args(&args[1..]);
    let start = xs.len().saturating_sub(n);
    Ok(StrykeValue::array(xs[start..].to_vec()))
}
/// `drop_last` — Drop last. Returns a list.
fn builtin_drop_last(args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    let n = args
        .first()
        .map(|v| v.to_int().max(0) as usize)
        .unwrap_or(0);
    let xs = flatten_args(&args[1..]);
    let end = xs.len().saturating_sub(n);
    Ok(StrykeValue::array(xs[..end].to_vec()))
}
/// `pairwise` — Pairwise. Returns a list. No arguments → `pairwise($_)`.
fn builtin_pairwise(interp: &VMHelper, args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    let mut topic = StrykeValue::UNDEF;
    let args = variadic_list_or_topic(interp, args, &mut topic);
    let xs = flatten_args(args);
    Ok(StrykeValue::array(
        xs.windows(2)
            .map(|w| StrykeValue::array_ref(Arc::new(RwLock::new(w.to_vec()))))
            .collect(),
    ))
}

// ─────────────────────────────────────────────────────────────────────────
// Clojure stdlib functions
// ─────────────────────────────────────────────────────────────────────────

fn exec_to_perl_result(
    result: Result<StrykeValue, crate::vm_helper::FlowOrError>,
    name: &str,
    line: usize,
) -> StrykeResult<StrykeValue> {
    use crate::vm_helper::{Flow, FlowOrError};
    match result {
        Ok(v) => Ok(v),
        Err(FlowOrError::Error(e)) => Err(e),
        Err(FlowOrError::Flow(Flow::Return(v))) => Ok(v),
        Err(FlowOrError::Flow(_)) => Err(StrykeError::runtime(
            format!("{name}: unsupported control flow in block"),
            line,
        )),
    }
}

/// `first [CODEREF,] LIST` — if first arg is a code ref, returns first element matching predicate.
/// Otherwise returns the first element of the list (Clojure's first).
fn builtin_first_clj(
    interp: &mut VMHelper,
    args: &[StrykeValue],
    line: usize,
) -> StrykeResult<StrykeValue> {
    if args.is_empty() {
        return Ok(StrykeValue::UNDEF);
    }
    if let Some(sub) = args.first().and_then(|v| v.as_code_ref()) {
        let xs = flatten_args(&args[1..]);
        for x in xs {
            let result = exec_to_perl_result(
                interp.call_sub(&sub, vec![x.clone()], WantarrayCtx::Scalar, line),
                "first",
                line,
            )?;
            if result.is_true() {
                return Ok(x);
            }
        }
        return Ok(StrykeValue::UNDEF);
    }
    let xs = flatten_args(args);
    Ok(xs.first().cloned().unwrap_or(StrykeValue::UNDEF))
}

/// `rest LIST` — returns all but the first element as an array.
fn builtin_rest(args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    let xs = flatten_args(args);
    if xs.is_empty() {
        return Ok(StrykeValue::array(vec![]));
    }
    Ok(StrykeValue::array(xs[1..].to_vec()))
}

/// `second LIST` — returns the second element, or undef if not enough elements.
fn builtin_second(args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    let xs = flatten_args(args);
    Ok(xs.get(1).cloned().unwrap_or(StrykeValue::UNDEF))
}

/// `last_clj LIST` — returns the last element, or undef if empty.
fn builtin_last_clj(args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    let xs = flatten_args(args);
    Ok(xs.last().cloned().unwrap_or(StrykeValue::UNDEF))
}

/// `butlast LIST` — returns all but the last element.
fn builtin_butlast(args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    let xs = flatten_args(args);
    if xs.is_empty() {
        return Ok(StrykeValue::array(vec![]));
    }
    Ok(StrykeValue::array(xs[..xs.len() - 1].to_vec()))
}

/// `ffirst LIST` — returns first(first(list)), i.e., first element of the first element.
fn builtin_ffirst(args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    let xs = flatten_args(args);
    let first_elem = xs.first().cloned().unwrap_or(StrykeValue::UNDEF);
    let inner = first_elem.to_list();
    Ok(inner.first().cloned().unwrap_or(StrykeValue::UNDEF))
}

/// `fnext LIST` — returns first(rest(list)), i.e., second element.
fn builtin_fnext(args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    builtin_second(args)
}

/// `nfirst LIST` — returns rest(first(list)), i.e., rest of the first element.
fn builtin_nfirst(args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    let xs = flatten_args(args);
    let first_elem = xs.first().cloned().unwrap_or(StrykeValue::UNDEF);
    let inner = first_elem.to_list();
    if inner.is_empty() {
        return Ok(StrykeValue::array(vec![]));
    }
    Ok(StrykeValue::array(inner[1..].to_vec()))
}

/// `nnext LIST` — returns rest(rest(list)), i.e., all but the first two elements.
fn builtin_nnext(args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    let xs = flatten_args(args);
    if xs.len() <= 2 {
        return Ok(StrykeValue::array(vec![]));
    }
    Ok(StrykeValue::array(xs[2..].to_vec()))
}

/// `cons ITEM, LIST` — prepends ITEM to LIST.
fn builtin_cons(args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    let item = args.first().cloned().unwrap_or(StrykeValue::UNDEF);
    let mut result = vec![item];
    result.extend(flatten_args(&args[1..]));
    Ok(StrykeValue::array(result))
}

/// `conj LIST, ITEM` — appends ITEM to LIST (Clojure semantics for vectors).
fn builtin_conj(args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    if args.is_empty() {
        return Ok(StrykeValue::array(vec![]));
    }
    let mut result = flatten_args(std::slice::from_ref(&args[0]));
    for item in args.iter().skip(1) {
        result.push(item.clone());
    }
    Ok(StrykeValue::array(result))
}

/// `peek_clj LIST` — returns the last element (like last, for vectors).
fn builtin_peek_clj(args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    builtin_last_clj(args)
}

/// `pop_clj LIST` — returns the list without the last element (like butlast).
fn builtin_pop_clj(args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    builtin_butlast(args)
}

/// `some PREDICATE, LIST` — returns the first truthy value for which pred returns true.
fn builtin_some(
    interp: &mut VMHelper,
    args: &[StrykeValue],
    line: usize,
) -> StrykeResult<StrykeValue> {
    if args.is_empty() {
        return Ok(StrykeValue::UNDEF);
    }
    let pred = args.first().cloned().unwrap_or(StrykeValue::UNDEF);
    let Some(sub) = pred.as_code_ref() else {
        return Err(StrykeError::runtime(
            "some: first argument must be a code reference",
            line,
        ));
    };
    let xs = flatten_args(&args[1..]);
    for x in xs {
        let result = exec_to_perl_result(
            interp.call_sub(&sub, vec![x.clone()], WantarrayCtx::Scalar, line),
            "some",
            line,
        )?;
        if result.is_true() {
            return Ok(x);
        }
    }
    Ok(StrykeValue::UNDEF)
}

/// `every PREDICATE, LIST` — returns true if pred is true for all elements.
fn builtin_every(
    interp: &mut VMHelper,
    args: &[StrykeValue],
    line: usize,
) -> StrykeResult<StrykeValue> {
    if args.is_empty() {
        return Ok(bool_iv(true));
    }
    let pred = args.first().cloned().unwrap_or(StrykeValue::UNDEF);
    let Some(sub) = pred.as_code_ref() else {
        return Err(StrykeError::runtime(
            "every: first argument must be a code reference",
            line,
        ));
    };
    let xs = flatten_args(&args[1..]);
    for x in xs {
        let result = exec_to_perl_result(
            interp.call_sub(&sub, vec![x], WantarrayCtx::Scalar, line),
            "every",
            line,
        )?;
        if !result.is_true() {
            return Ok(bool_iv(false));
        }
    }
    Ok(bool_iv(true))
}

/// `not_any PREDICATE, LIST` — returns true if pred is false for all elements.
fn builtin_not_any(
    interp: &mut VMHelper,
    args: &[StrykeValue],
    line: usize,
) -> StrykeResult<StrykeValue> {
    if args.is_empty() {
        return Ok(bool_iv(true));
    }
    let pred = args.first().cloned().unwrap_or(StrykeValue::UNDEF);
    let Some(sub) = pred.as_code_ref() else {
        return Err(StrykeError::runtime(
            "not_any: first argument must be a code reference",
            line,
        ));
    };
    let xs = flatten_args(&args[1..]);
    for x in xs {
        let result = exec_to_perl_result(
            interp.call_sub(&sub, vec![x], WantarrayCtx::Scalar, line),
            "not_any",
            line,
        )?;
        if result.is_true() {
            return Ok(bool_iv(false));
        }
    }
    Ok(bool_iv(true))
}

/// `not_every PREDICATE, LIST` — returns true if pred is false for at least one element.
fn builtin_not_every(
    interp: &mut VMHelper,
    args: &[StrykeValue],
    line: usize,
) -> StrykeResult<StrykeValue> {
    if args.is_empty() {
        return Ok(bool_iv(false));
    }
    let pred = args.first().cloned().unwrap_or(StrykeValue::UNDEF);
    let Some(sub) = pred.as_code_ref() else {
        return Err(StrykeError::runtime(
            "not_every: first argument must be a code reference",
            line,
        ));
    };
    let xs = flatten_args(&args[1..]);
    for x in xs {
        let result = exec_to_perl_result(
            interp.call_sub(&sub, vec![x], WantarrayCtx::Scalar, line),
            "not_every",
            line,
        )?;
        if !result.is_true() {
            return Ok(bool_iv(true));
        }
    }
    Ok(bool_iv(false))
}

/// `compose \&f, \&g, ...` / `comp \&f, \&g, ...` — right-to-left function composition.
/// `compose(\&f, \&g)->(x)` == `f(g(x))`.
fn builtin_comp(args: &[StrykeValue], line: usize) -> StrykeResult<StrykeValue> {
    if args.is_empty() {
        return Err(StrykeError::runtime(
            "compose: requires at least one function",
            line,
        ));
    }
    if args.iter().any(|v| v.as_code_ref().is_none()) {
        return Err(StrykeError::runtime(
            "compose: all arguments must be code references",
            line,
        ));
    }
    let composed = StrykeSub {
        name: "__comp__".to_string(),
        params: vec![],
        body: vec![],
        closure_env: Some(vec![(
            "__comp_fns__".to_string(),
            StrykeValue::array(args.to_vec()),
        )]),
        prototype: None,
        fib_like: None,
    };
    Ok(StrykeValue::code_ref(Arc::new(composed)))
}

/// `partial \&f, @bound` — partial application: `partial(\&add, 1)->(2)` == `add(1, 2)`.
fn builtin_partial(args: &[StrykeValue], line: usize) -> StrykeResult<StrykeValue> {
    if args.is_empty() {
        return Err(StrykeError::runtime(
            "partial: requires at least one function",
            line,
        ));
    }
    let f = args[0].clone();
    if f.as_code_ref().is_none() {
        return Err(StrykeError::runtime(
            "partial: first argument must be a code reference",
            line,
        ));
    }
    let bound_args: Vec<StrykeValue> = args[1..].to_vec();
    let partial_sub = StrykeSub {
        name: "__partial__".to_string(),
        params: vec![],
        body: vec![],
        closure_env: Some(vec![
            ("__partial_fn__".to_string(), f),
            (
                "__partial_args__".to_string(),
                StrykeValue::array(bound_args),
            ),
        ]),
        prototype: None,
        fib_like: None,
    };
    Ok(StrykeValue::code_ref(Arc::new(partial_sub)))
}

/// `constantly VALUE` — returns a function that always returns VALUE.
fn builtin_constantly(args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    let value = args.first().cloned().unwrap_or(StrykeValue::UNDEF);
    let const_sub = StrykeSub {
        name: "__constantly__".to_string(),
        params: vec![],
        body: vec![],
        closure_env: Some(vec![("__const_val__".to_string(), value)]),
        prototype: None,
        fib_like: None,
    };
    Ok(StrykeValue::code_ref(Arc::new(const_sub)))
}

/// `complement \&f` — returns a function that negates the boolean result of `f`.
fn builtin_complement(args: &[StrykeValue], line: usize) -> StrykeResult<StrykeValue> {
    if args.is_empty() {
        return Err(StrykeError::runtime(
            "complement: requires a function",
            line,
        ));
    }
    let f = args[0].clone();
    if f.as_code_ref().is_none() {
        return Err(StrykeError::runtime(
            "complement: argument must be a code reference",
            line,
        ));
    }
    let compl_sub = StrykeSub {
        name: "__complement__".to_string(),
        params: vec![],
        body: vec![],
        closure_env: Some(vec![("__complement_fn__".to_string(), f)]),
        prototype: None,
        fib_like: None,
    };
    Ok(StrykeValue::code_ref(Arc::new(compl_sub)))
}

/// `fnil \&f, @defaults` — returns a function that replaces undef args with defaults.
fn builtin_fnil(args: &[StrykeValue], line: usize) -> StrykeResult<StrykeValue> {
    if args.is_empty() {
        return Err(StrykeError::runtime(
            "fnil: requires at least one function",
            line,
        ));
    }
    let f = args[0].clone();
    if f.as_code_ref().is_none() {
        return Err(StrykeError::runtime(
            "fnil: first argument must be a code reference",
            line,
        ));
    }
    let defaults: Vec<StrykeValue> = args[1..].to_vec();
    let fnil_sub = StrykeSub {
        name: "__fnil__".to_string(),
        params: vec![],
        body: vec![],
        closure_env: Some(vec![
            ("__fnil_fn__".to_string(), f),
            (
                "__fnil_defaults__".to_string(),
                StrykeValue::array(defaults),
            ),
        ]),
        prototype: None,
        fib_like: None,
    };
    Ok(StrykeValue::code_ref(Arc::new(fnil_sub)))
}

/// `juxt FN1, FN2, ...` — returns a function that applies all fns and returns array of results.
fn builtin_juxt(args: &[StrykeValue], line: usize) -> StrykeResult<StrykeValue> {
    if args.is_empty() {
        return Err(StrykeError::runtime(
            "juxt: requires at least one function",
            line,
        ));
    }
    for (i, a) in args.iter().enumerate() {
        if a.as_code_ref().is_none() {
            return Err(StrykeError::runtime(
                format!("juxt: argument {} must be a code reference", i),
                line,
            ));
        }
    }
    let juxt_sub = StrykeSub {
        name: "__juxt__".to_string(),
        params: vec![],
        body: vec![],
        closure_env: Some(vec![(
            "__juxt_fns__".to_string(),
            StrykeValue::array(args.to_vec()),
        )]),
        prototype: None,
        fib_like: None,
    };
    Ok(StrykeValue::code_ref(Arc::new(juxt_sub)))
}

/// `iterate FN, X` — returns a lazy iterator of x, f(x), f(f(x)), etc.
fn builtin_iterate(args: &[StrykeValue], line: usize) -> StrykeResult<StrykeValue> {
    let f = args.first().cloned().unwrap_or(StrykeValue::UNDEF);
    let Some(sub) = f.as_code_ref() else {
        return Err(StrykeError::runtime(
            "iterate: first argument must be a code reference",
            line,
        ));
    };
    let x = args.get(1).cloned().unwrap_or(StrykeValue::UNDEF);
    Ok(StrykeValue::iterator(Arc::new(IterateIterator::new(
        sub, x,
    ))))
}

struct IterateIterator {
    sub: Arc<StrykeSub>,
    current: Mutex<StrykeValue>,
    first: Mutex<bool>,
}

impl IterateIterator {
    fn new(sub: Arc<StrykeSub>, x: StrykeValue) -> Self {
        Self {
            sub,
            current: Mutex::new(x),
            first: Mutex::new(true),
        }
    }
}

impl StrykeIterator for IterateIterator {
    fn next_item(&self) -> Option<StrykeValue> {
        let mut first_flag = self.first.lock();
        let mut current = self.current.lock();
        if *first_flag {
            *first_flag = false;
            return Some(current.clone());
        }
        let mut interp = VMHelper::new();
        let result = interp.call_sub(&self.sub, vec![current.clone()], WantarrayCtx::Scalar, 0);
        match result {
            Ok(v) => {
                *current = v.clone();
                Some(v)
            }
            Err(_) => None,
        }
    }

    fn collect_all(&self) -> Vec<StrykeValue> {
        vec![]
    }
}

/// `repeatedly FN [, N]` — returns a lazy iterator that calls f repeatedly.
fn builtin_repeatedly(args: &[StrykeValue], line: usize) -> StrykeResult<StrykeValue> {
    let f = args.first().cloned().unwrap_or(StrykeValue::UNDEF);
    let Some(sub) = f.as_code_ref() else {
        return Err(StrykeError::runtime(
            "repeatedly: first argument must be a code reference",
            line,
        ));
    };
    let n = args.get(1).map(|v| v.to_int() as usize);
    Ok(StrykeValue::iterator(Arc::new(RepeatedlyIterator::new(
        sub, n,
    ))))
}

struct RepeatedlyIterator {
    sub: Arc<StrykeSub>,
    limit: Option<usize>,
    count: Mutex<usize>,
}

impl RepeatedlyIterator {
    fn new(sub: Arc<StrykeSub>, limit: Option<usize>) -> Self {
        Self {
            sub,
            limit,
            count: Mutex::new(0),
        }
    }
}

impl StrykeIterator for RepeatedlyIterator {
    fn next_item(&self) -> Option<StrykeValue> {
        let mut count = self.count.lock();
        if let Some(limit) = self.limit {
            if *count >= limit {
                return None;
            }
        }
        *count += 1;
        let mut interp = VMHelper::new();
        interp
            .call_sub(&self.sub, vec![], WantarrayCtx::Scalar, 0)
            .ok()
    }

    fn collect_all(&self) -> Vec<StrykeValue> {
        if let Some(limit) = self.limit {
            let mut result = Vec::with_capacity(limit);
            while let Some(v) = self.next_item() {
                result.push(v);
                if result.len() >= limit {
                    break;
                }
            }
            result
        } else {
            vec![]
        }
    }
}

/// `cycle LIST` — returns an infinite iterator that cycles through the list.
fn builtin_cycle(args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    let xs = flatten_args(args);
    if xs.is_empty() {
        return Ok(StrykeValue::iterator(Arc::new(EmptyIterator)));
    }
    Ok(StrykeValue::iterator(Arc::new(CycleIterator::new(xs))))
}

struct EmptyIterator;

impl StrykeIterator for EmptyIterator {
    fn next_item(&self) -> Option<StrykeValue> {
        None
    }
    fn collect_all(&self) -> Vec<StrykeValue> {
        vec![]
    }
}

struct CycleIterator {
    items: Vec<StrykeValue>,
    index: Mutex<usize>,
}

impl CycleIterator {
    fn new(items: Vec<StrykeValue>) -> Self {
        Self {
            items,
            index: Mutex::new(0),
        }
    }
}

impl StrykeIterator for CycleIterator {
    fn next_item(&self) -> Option<StrykeValue> {
        if self.items.is_empty() {
            return None;
        }
        let mut index = self.index.lock();
        let item = self.items[*index].clone();
        *index = (*index + 1) % self.items.len();
        Some(item)
    }

    fn collect_all(&self) -> Vec<StrykeValue> {
        vec![]
    }
}

/// `mapcat FN, LIST` — maps f over list and concatenates the results.
fn builtin_mapcat(
    interp: &mut VMHelper,
    args: &[StrykeValue],
    line: usize,
) -> StrykeResult<StrykeValue> {
    if args.is_empty() {
        return Ok(StrykeValue::array(vec![]));
    }
    let f = args.first().cloned().unwrap_or(StrykeValue::UNDEF);
    let Some(sub) = f.as_code_ref() else {
        return Err(StrykeError::runtime(
            "mapcat: first argument must be a code reference",
            line,
        ));
    };
    let xs = flatten_args(&args[1..]);
    let mut result = Vec::new();
    for x in xs {
        let mapped = exec_to_perl_result(
            interp.call_sub(&sub, vec![x], WantarrayCtx::List, line),
            "mapcat",
            line,
        )?;
        result.extend(mapped.to_list());
    }
    Ok(StrykeValue::array(result))
}

/// `keep FN, LIST` — returns non-nil results of mapping f over list.
fn builtin_keep(
    interp: &mut VMHelper,
    args: &[StrykeValue],
    line: usize,
) -> StrykeResult<StrykeValue> {
    if args.is_empty() {
        return Ok(StrykeValue::array(vec![]));
    }
    let f = args.first().cloned().unwrap_or(StrykeValue::UNDEF);
    let Some(sub) = f.as_code_ref() else {
        return Err(StrykeError::runtime(
            "keep: first argument must be a code reference",
            line,
        ));
    };
    let xs = flatten_args(&args[1..]);
    let mut result = Vec::new();
    for x in xs {
        let mapped = exec_to_perl_result(
            interp.call_sub(&sub, vec![x], WantarrayCtx::Scalar, line),
            "keep",
            line,
        )?;
        if !mapped.is_undef() {
            result.push(mapped);
        }
    }
    Ok(StrykeValue::array(result))
}

/// `remove_clj FN, LIST` — removes elements for which pred returns true.
fn builtin_remove_clj(
    interp: &mut VMHelper,
    args: &[StrykeValue],
    line: usize,
) -> StrykeResult<StrykeValue> {
    if args.is_empty() {
        return Ok(StrykeValue::array(vec![]));
    }
    let f = args.first().cloned().unwrap_or(StrykeValue::UNDEF);
    let Some(sub) = f.as_code_ref() else {
        return Err(StrykeError::runtime(
            "remove: first argument must be a code reference",
            line,
        ));
    };
    let xs = flatten_args(&args[1..]);
    let mut result = Vec::new();
    for x in xs {
        let mapped = exec_to_perl_result(
            interp.call_sub(&sub, vec![x.clone()], WantarrayCtx::Scalar, line),
            "remove",
            line,
        )?;
        if !mapped.is_true() {
            result.push(x);
        }
    }
    Ok(StrykeValue::array(result))
}

/// `reductions FN, INIT, LIST` — returns intermediate values of reduce.
fn builtin_reductions(
    interp: &mut VMHelper,
    args: &[StrykeValue],
    line: usize,
) -> StrykeResult<StrykeValue> {
    if args.is_empty() {
        return Ok(StrykeValue::array(vec![]));
    }
    let f = args.first().cloned().unwrap_or(StrykeValue::UNDEF);
    let Some(sub) = f.as_code_ref() else {
        return Err(StrykeError::runtime(
            "reductions: first argument must be a code reference",
            line,
        ));
    };
    let (init, xs) = if args.len() >= 3 {
        (args[1].clone(), flatten_args(&args[2..]))
    } else {
        let list = flatten_args(&args[1..]);
        if list.is_empty() {
            return Ok(StrykeValue::array(vec![]));
        }
        (list[0].clone(), list[1..].to_vec())
    };
    let mut result = vec![init.clone()];
    let mut acc = init;
    for x in xs {
        acc = exec_to_perl_result(
            interp.call_sub(&sub, vec![acc, x], WantarrayCtx::Scalar, line),
            "reductions",
            line,
        )?;
        result.push(acc.clone());
    }
    Ok(StrykeValue::array(result))
}

/// `partition_by FN, LIST` — partitions list into sublists when f returns a new value.
fn builtin_partition_by(
    interp: &mut VMHelper,
    args: &[StrykeValue],
    line: usize,
) -> StrykeResult<StrykeValue> {
    if args.is_empty() {
        return Ok(StrykeValue::array(vec![]));
    }
    let f = args.first().cloned().unwrap_or(StrykeValue::UNDEF);
    let Some(sub) = f.as_code_ref() else {
        return Err(StrykeError::runtime(
            "partition_by: first argument must be a code reference",
            line,
        ));
    };
    let xs = flatten_args(&args[1..]);
    if xs.is_empty() {
        return Ok(StrykeValue::array(vec![]));
    }
    let mut result: Vec<StrykeValue> = Vec::new();
    let mut current_group: Vec<StrykeValue> = Vec::new();
    let mut last_key: Option<String> = None;
    for x in xs {
        let key = exec_to_perl_result(
            interp.call_sub(&sub, vec![x.clone()], WantarrayCtx::Scalar, line),
            "partition_by",
            line,
        )?
        .to_string();
        if last_key.as_ref() != Some(&key) && !current_group.is_empty() {
            result.push(StrykeValue::array_ref(Arc::new(RwLock::new(
                std::mem::take(&mut current_group),
            ))));
        }
        current_group.push(x);
        last_key = Some(key);
    }
    if !current_group.is_empty() {
        result.push(StrykeValue::array_ref(Arc::new(RwLock::new(current_group))));
    }
    Ok(StrykeValue::array(result))
}

/// `partition_all N, LIST` — partitions list into groups of N (last may be shorter).
fn builtin_partition_all(args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    let n = args
        .first()
        .map(|v| v.to_int().max(1) as usize)
        .unwrap_or(1);
    let xs = flatten_args(&args[1..]);
    let result: Vec<StrykeValue> = xs
        .chunks(n)
        .map(|chunk| StrykeValue::array_ref(Arc::new(RwLock::new(chunk.to_vec()))))
        .collect();
    Ok(StrykeValue::array(result))
}

/// `split_at N, LIST` — splits list at index N into two lists.
fn builtin_split_at(args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    let n = args
        .first()
        .map(|v| v.to_int().max(0) as usize)
        .unwrap_or(0);
    let xs = flatten_args(&args[1..]);
    let (left, right) = if n >= xs.len() {
        (xs.clone(), vec![])
    } else {
        (xs[..n].to_vec(), xs[n..].to_vec())
    };
    Ok(StrykeValue::array(vec![
        StrykeValue::array_ref(Arc::new(RwLock::new(left))),
        StrykeValue::array_ref(Arc::new(RwLock::new(right))),
    ]))
}

/// `split_with FN, LIST` — splits list at first element where pred is false.
fn builtin_split_with(
    interp: &mut VMHelper,
    args: &[StrykeValue],
    line: usize,
) -> StrykeResult<StrykeValue> {
    if args.is_empty() {
        return Ok(StrykeValue::array(vec![
            StrykeValue::array_ref(Arc::new(RwLock::new(vec![]))),
            StrykeValue::array_ref(Arc::new(RwLock::new(vec![]))),
        ]));
    }
    let f = args.first().cloned().unwrap_or(StrykeValue::UNDEF);
    let Some(sub) = f.as_code_ref() else {
        return Err(StrykeError::runtime(
            "split_with: first argument must be a code reference",
            line,
        ));
    };
    let xs = flatten_args(&args[1..]);
    let mut left = Vec::new();
    let mut right_idx = xs.len();
    for (i, x) in xs.iter().enumerate() {
        let result = exec_to_perl_result(
            interp.call_sub(&sub, vec![x.clone()], WantarrayCtx::Scalar, line),
            "split_with",
            line,
        )?;
        if !result.is_true() {
            right_idx = i;
            break;
        }
        left.push(x.clone());
    }
    let right = xs[right_idx..].to_vec();
    Ok(StrykeValue::array(vec![
        StrykeValue::array_ref(Arc::new(RwLock::new(left))),
        StrykeValue::array_ref(Arc::new(RwLock::new(right))),
    ]))
}

/// `assoc HASH, KEY, VALUE` — returns a new hash with key set to value.
fn builtin_assoc(args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    let mut out: indexmap::IndexMap<String, StrykeValue> = indexmap::IndexMap::new();
    if let Some(h) = args.first() {
        if let Some(m) = h.as_hash_map() {
            out = m.clone();
        } else if let Some(r) = h.as_hash_ref() {
            out = r.read().clone();
        }
    }
    let mut i = 1;
    while i + 1 < args.len() {
        let k = args[i].to_string();
        let v = args[i + 1].clone();
        out.insert(k, v);
        i += 2;
    }
    Ok(StrykeValue::hash_ref(Arc::new(RwLock::new(out))))
}

/// `dissoc HASH, KEY...` — returns a new hash without the specified keys.
fn builtin_dissoc(args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    let mut out: indexmap::IndexMap<String, StrykeValue> = indexmap::IndexMap::new();
    if let Some(h) = args.first() {
        if let Some(m) = h.as_hash_map() {
            out = m.clone();
        } else if let Some(r) = h.as_hash_ref() {
            out = r.read().clone();
        }
    }
    for k in args.iter().skip(1) {
        out.shift_remove(&k.to_string());
    }
    Ok(StrykeValue::hash_ref(Arc::new(RwLock::new(out))))
}

/// `get_in HASH, [KEY1, KEY2, ...]` — gets nested value in hash.
fn builtin_get_in(args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    let hash = args.first().cloned().unwrap_or(StrykeValue::UNDEF);
    let keys = args.get(1).map(|v| v.to_list()).unwrap_or_default();
    let mut current = hash;
    for key in keys {
        let k = key.to_string();
        if let Some(m) = current.as_hash_map() {
            current = m.get(&k).cloned().unwrap_or(StrykeValue::UNDEF);
        } else if let Some(r) = current.as_hash_ref() {
            current = r.read().get(&k).cloned().unwrap_or(StrykeValue::UNDEF);
        } else {
            return Ok(StrykeValue::UNDEF);
        }
    }
    Ok(current)
}

/// `assoc_in HASH, [KEY1, KEY2, ...], VALUE` — sets nested value in hash.
fn builtin_assoc_in(args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    let hash = args.first().cloned().unwrap_or(StrykeValue::UNDEF);
    let keys = args.get(1).map(|v| v.to_list()).unwrap_or_default();
    let value = args.get(2).cloned().unwrap_or(StrykeValue::UNDEF);

    fn assoc_in_recursive(
        current: StrykeValue,
        keys: &[StrykeValue],
        value: StrykeValue,
    ) -> StrykeValue {
        if keys.is_empty() {
            return value;
        }
        let key = keys[0].to_string();
        let mut out: indexmap::IndexMap<String, StrykeValue> = indexmap::IndexMap::new();
        if let Some(m) = current.as_hash_map() {
            out = m.clone();
        } else if let Some(r) = current.as_hash_ref() {
            out = r.read().clone();
        }
        let nested = out.get(&key).cloned().unwrap_or(StrykeValue::UNDEF);
        out.insert(key, assoc_in_recursive(nested, &keys[1..], value));
        StrykeValue::hash_ref(Arc::new(RwLock::new(out)))
    }

    Ok(assoc_in_recursive(hash, &keys, value))
}

/// `update_in HASH, [KEY1, KEY2, ...], FN` — updates nested value with function.
fn builtin_update_in(
    interp: &mut VMHelper,
    args: &[StrykeValue],
    line: usize,
) -> StrykeResult<StrykeValue> {
    let hash = args.first().cloned().unwrap_or(StrykeValue::UNDEF);
    let keys = args.get(1).map(|v| v.to_list()).unwrap_or_default();
    let f = args.get(2).cloned().unwrap_or(StrykeValue::UNDEF);
    let Some(sub) = f.as_code_ref() else {
        return Err(StrykeError::runtime(
            "update_in: third argument must be a code reference",
            line,
        ));
    };
    let extra_args: Vec<StrykeValue> = args.get(3..).map(|s| s.to_vec()).unwrap_or_default();

    let current_val = {
        let mut cur = hash.clone();
        for key in &keys {
            let k = key.to_string();
            if let Some(m) = cur.as_hash_map() {
                cur = m.get(&k).cloned().unwrap_or(StrykeValue::UNDEF);
            } else if let Some(r) = cur.as_hash_ref() {
                cur = r.read().get(&k).cloned().unwrap_or(StrykeValue::UNDEF);
            } else {
                cur = StrykeValue::UNDEF;
                break;
            }
        }
        cur
    };

    let mut call_args = vec![current_val];
    call_args.extend(extra_args);
    let new_val = exec_to_perl_result(
        interp.call_sub(&sub, call_args, WantarrayCtx::Scalar, line),
        "update_in",
        line,
    )?;

    fn update_in_recursive(
        current: StrykeValue,
        keys: &[StrykeValue],
        value: StrykeValue,
    ) -> StrykeValue {
        if keys.is_empty() {
            return value;
        }
        let key = keys[0].to_string();
        let mut out: indexmap::IndexMap<String, StrykeValue> = indexmap::IndexMap::new();
        if let Some(m) = current.as_hash_map() {
            out = m.clone();
        } else if let Some(r) = current.as_hash_ref() {
            out = r.read().clone();
        }
        let nested = out.get(&key).cloned().unwrap_or(StrykeValue::UNDEF);
        out.insert(key, update_in_recursive(nested, &keys[1..], value));
        StrykeValue::hash_ref(Arc::new(RwLock::new(out)))
    }

    Ok(update_in_recursive(hash, &keys, new_val))
}

/// `into TO, FROM` — adds all items from FROM into TO.
fn builtin_into(args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    let to = args.first().cloned().unwrap_or(StrykeValue::UNDEF);
    let from = args.get(1).cloned().unwrap_or(StrykeValue::UNDEF);

    if to.as_hash_ref().is_some() || to.as_hash_map().is_some() {
        let mut out: indexmap::IndexMap<String, StrykeValue> = indexmap::IndexMap::new();
        if let Some(m) = to.as_hash_map() {
            out = m.clone();
        } else if let Some(r) = to.as_hash_ref() {
            out = r.read().clone();
        }
        let from_list = from.to_list();
        for chunk in from_list.chunks(2) {
            if let [k, v] = chunk {
                out.insert(k.to_string(), v.clone());
            } else if let [k] = chunk {
                out.insert(k.to_string(), StrykeValue::UNDEF);
            }
        }
        Ok(StrykeValue::hash_ref(Arc::new(RwLock::new(out))))
    } else {
        let mut result = to.to_list();
        result.extend(from.to_list());
        Ok(StrykeValue::array(result))
    }
}

/// `empty COLL` — returns an empty collection of the same type.
fn builtin_empty_clj(args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    let coll = args.first().cloned().unwrap_or(StrykeValue::UNDEF);
    if coll.as_hash_ref().is_some() || coll.as_hash_map().is_some() {
        Ok(StrykeValue::hash_ref(Arc::new(RwLock::new(
            indexmap::IndexMap::new(),
        ))))
    } else {
        Ok(StrykeValue::array(vec![]))
    }
}

/// `seq COLL` — returns nil if empty, otherwise the collection as a list.
fn builtin_seq(args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    let coll = args.first().cloned().unwrap_or(StrykeValue::UNDEF);
    if coll.is_undef() {
        return Ok(StrykeValue::UNDEF);
    }
    let list = coll.to_list();
    if list.is_empty() {
        Ok(StrykeValue::UNDEF)
    } else {
        Ok(StrykeValue::array(list))
    }
}

/// `vec_clj COLL` — converts collection to a vector (array).
fn builtin_vec_clj(args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    let coll = args.first().cloned().unwrap_or(StrykeValue::UNDEF);
    Ok(StrykeValue::array(coll.to_list()))
}

/// `apply FN, ARGS...` — applies function to args, with last arg spread if it's a list.
fn builtin_apply(
    interp: &mut VMHelper,
    args: &[StrykeValue],
    line: usize,
) -> StrykeResult<StrykeValue> {
    if args.is_empty() {
        return Ok(StrykeValue::UNDEF);
    }
    let f = args[0].clone();
    let Some(sub) = f.as_code_ref() else {
        return Err(StrykeError::runtime(
            "apply: first argument must be a code reference",
            line,
        ));
    };
    if args.len() == 1 {
        return exec_to_perl_result(
            interp.call_sub(&sub, vec![], WantarrayCtx::Scalar, line),
            "apply",
            line,
        );
    }
    let mut call_args: Vec<StrykeValue> = args[1..args.len() - 1].to_vec();
    let last = &args[args.len() - 1];
    call_args.extend(last.to_list());
    exec_to_perl_result(
        interp.call_sub(&sub, call_args, WantarrayCtx::Scalar, line),
        "apply",
        line,
    )
}

