// Python/Ruby stdlib functions
// ─────────────────────────────────────────────────────────────────────────

/// `divmod A, B` — returns (quotient, remainder) pair (Python's divmod).
fn builtin_divmod(args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    let a = args.first().map(|v| v.to_int()).unwrap_or(0);
    let b = args.get(1).map(|v| v.to_int()).unwrap_or(1);
    if b == 0 {
        return Ok(StrykeValue::array(vec![
            StrykeValue::UNDEF,
            StrykeValue::UNDEF,
        ]));
    }
    Ok(StrykeValue::array(vec![
        StrykeValue::integer(a / b),
        StrykeValue::integer(a % b),
    ]))
}

/// `accumulate FN, LIST` — returns cumulative results (Python's itertools.accumulate).
fn builtin_accumulate(
    interp: &mut VMHelper,
    args: &[StrykeValue],
    line: usize,
) -> StrykeResult<StrykeValue> {
    if args.is_empty() {
        return Ok(StrykeValue::array(vec![]));
    }
    let (f, xs) = if args.first().and_then(|v| v.as_code_ref()).is_some() {
        let sub = args[0].as_code_ref().unwrap();
        (Some(sub), flatten_args(&args[1..]))
    } else {
        (None, flatten_args(args))
    };
    if xs.is_empty() {
        return Ok(StrykeValue::array(vec![]));
    }
    let mut result = vec![xs[0].clone()];
    let mut acc = xs[0].clone();
    for x in xs.iter().skip(1) {
        acc = if let Some(ref sub) = f {
            exec_to_perl_result(
                interp.call_sub(sub, vec![acc, x.clone()], WantarrayCtx::Scalar, line),
                "accumulate",
                line,
            )?
        } else {
            StrykeValue::float(acc.to_number() + x.to_number())
        };
        result.push(acc.clone());
    }
    Ok(StrykeValue::array(result))
}

/// `starmap FN, LIST_OF_LISTS` — maps fn over list, spreading each element as args (Python's itertools.starmap).
fn builtin_starmap(
    interp: &mut VMHelper,
    args: &[StrykeValue],
    line: usize,
) -> StrykeResult<StrykeValue> {
    if args.is_empty() {
        return Ok(StrykeValue::array(vec![]));
    }
    let f = args.first().cloned().unwrap_or(StrykeValue::UNDEF);
    let Some(sub) = f.as_code_ref() else {
        return Err(StrykeError::runtime(
            "starmap: first argument must be a code reference",
            line,
        ));
    };
    let xs: Vec<StrykeValue> = args[1..].to_vec();
    let mut result = Vec::new();
    for x in xs {
        let call_args = arg_to_vec(&x);
        let mapped = exec_to_perl_result(
            interp.call_sub(&sub, call_args, WantarrayCtx::Scalar, line),
            "starmap",
            line,
        )?;
        result.push(mapped);
    }
    Ok(StrykeValue::array(result))
}

/// `zip_fill FILL, LIST1, LIST2, ...` — zips lists, filling shorter ones with FILL (Python's itertools.zip_longest with explicit fill).
fn builtin_zip_fill(args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    if args.is_empty() {
        return Ok(StrykeValue::array(vec![]));
    }
    let fill = args.first().cloned().unwrap_or(StrykeValue::UNDEF);
    let lists: Vec<Vec<StrykeValue>> = args[1..].iter().map(arg_to_vec).collect();
    if lists.is_empty() {
        return Ok(StrykeValue::array(vec![]));
    }
    let max_len = lists.iter().map(|l| l.len()).max().unwrap_or(0);
    let mut result = Vec::with_capacity(max_len);
    for i in 0..max_len {
        let tuple: Vec<StrykeValue> = lists
            .iter()
            .map(|l| l.get(i).cloned().unwrap_or_else(|| fill.clone()))
            .collect();
        result.push(StrykeValue::array_ref(Arc::new(RwLock::new(tuple))));
    }
    Ok(StrykeValue::array(result))
}

/// `combinations N, LIST` — returns all N-element combinations (Python's itertools.combinations).
fn builtin_combinations(args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    let n = args
        .first()
        .map(|v| v.to_int().max(0) as usize)
        .unwrap_or(0);
    let xs = flatten_args(&args[1..]);
    if n == 0 || n > xs.len() {
        return Ok(StrykeValue::array(vec![]));
    }
    fn combine(
        items: &[StrykeValue],
        n: usize,
        start: usize,
        current: &mut Vec<StrykeValue>,
        result: &mut Vec<StrykeValue>,
    ) {
        if current.len() == n {
            result.push(StrykeValue::array_ref(Arc::new(RwLock::new(
                current.clone(),
            ))));
            return;
        }
        for i in start..items.len() {
            current.push(items[i].clone());
            combine(items, n, i + 1, current, result);
            current.pop();
        }
    }
    let mut result = Vec::new();
    let mut current = Vec::new();
    combine(&xs, n, 0, &mut current, &mut result);
    Ok(StrykeValue::array(result))
}

/// `comb` — Raku's string-decomposition builtin.
///
/// Four signatures:
/// * `comb($str)`                       — split into individual characters
/// * `comb($size:Int, $str [, $limit])` — fixed-size character chunks
/// * `comb($needle:Str, $str [, $limit])` — every literal occurrence of `$needle`
/// * `comb($re:Regex, $str [, $limit])` — every regex match (`m/.../g` semantics)
///
/// `$limit` caps the number of returned pieces; a negative limit means "unlimited"
/// (matches Raku's `Inf` default).
fn builtin_comb(args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    if args.is_empty() {
        return Ok(StrykeValue::array(vec![]));
    }

    if args.len() == 1 {
        let s = args[0].to_string();
        let out: Vec<StrykeValue> = s
            .chars()
            .map(|c| StrykeValue::string(c.to_string()))
            .collect();
        return Ok(StrykeValue::array(out));
    }

    let limit = if args.len() >= 3 {
        let n = args[2].to_int();
        if n < 0 {
            usize::MAX
        } else {
            n as usize
        }
    } else {
        usize::MAX
    };
    if limit == 0 {
        return Ok(StrykeValue::array(vec![]));
    }

    let matcher = &args[0];
    let input = args[1].to_string();

    if let Some(re) = matcher
        .with_heap(|h| match h {
            HeapObject::Regex(r, _, _) => Some(Arc::clone(r)),
            _ => None,
        })
        .flatten()
    {
        let mut out = Vec::new();
        for caps in re.captures_iter(&input) {
            if out.len() >= limit {
                break;
            }
            if let Some(m) = caps.get(0) {
                out.push(StrykeValue::string(m.text.to_string()));
            }
        }
        return Ok(StrykeValue::array(out));
    }

    if matcher.is_integer_like() {
        let size = matcher.to_int().max(0) as usize;
        if size == 0 || input.is_empty() {
            return Ok(StrykeValue::array(vec![]));
        }
        let mut out = Vec::new();
        let chars: Vec<char> = input.chars().collect();
        for chunk in chars.chunks(size) {
            if out.len() >= limit {
                break;
            }
            out.push(StrykeValue::string(chunk.iter().collect()));
        }
        return Ok(StrykeValue::array(out));
    }

    let needle = matcher.to_string();
    if needle.is_empty() || input.is_empty() {
        return Ok(StrykeValue::array(vec![]));
    }
    let mut out = Vec::new();
    let mut pos = 0usize;
    while pos <= input.len() {
        match input[pos..].find(&needle) {
            Some(idx) => {
                if out.len() >= limit {
                    break;
                }
                out.push(StrykeValue::string(needle.clone()));
                pos += idx + needle.len();
            }
            None => break,
        }
    }
    Ok(StrykeValue::array(out))
}

/// `permutations N, LIST` — returns all N-element permutations (Python's itertools.permutations).
/// Also accepts `permutations(ARRAYREF)` as shorthand for all permutations of the array.
fn builtin_permutations(args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    // Single arrayref arg: `permutations([1,2,3])` → all permutations
    let (n, xs) = if args.len() == 1 && args[0].as_array_ref().is_some() {
        let items = flatten_args(args);
        (items.len(), items)
    } else {
        let n = args
            .first()
            .map(|v| v.to_int().max(0) as usize)
            .unwrap_or(0);
        let xs = flatten_args(&args[1..]);
        (n, xs)
    };
    if n == 0 || n > xs.len() {
        return Ok(StrykeValue::array(vec![]));
    }
    fn permute(
        items: &[StrykeValue],
        n: usize,
        used: &mut Vec<bool>,
        current: &mut Vec<StrykeValue>,
        result: &mut Vec<StrykeValue>,
    ) {
        if current.len() == n {
            result.push(StrykeValue::array_ref(Arc::new(RwLock::new(
                current.clone(),
            ))));
            return;
        }
        for i in 0..items.len() {
            if !used[i] {
                used[i] = true;
                current.push(items[i].clone());
                permute(items, n, used, current, result);
                current.pop();
                used[i] = false;
            }
        }
    }
    let mut result = Vec::new();
    let mut current = Vec::new();
    let mut used = vec![false; xs.len()];
    permute(&xs, n, &mut used, &mut current, &mut result);
    Ok(StrykeValue::array(result))
}

/// `cartesian_product LIST1, LIST2, ...` — returns cartesian product (Python's itertools.product).
fn builtin_cartesian_product(args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    if args.is_empty() {
        return Ok(StrykeValue::array(vec![]));
    }
    let lists: Vec<Vec<StrykeValue>> = args.iter().map(arg_to_vec).collect();
    if lists.iter().any(|l| l.is_empty()) {
        return Ok(StrykeValue::array(vec![]));
    }
    fn product_helper(
        lists: &[Vec<StrykeValue>],
        idx: usize,
        current: &mut Vec<StrykeValue>,
        result: &mut Vec<StrykeValue>,
    ) {
        if idx == lists.len() {
            result.push(StrykeValue::array_ref(Arc::new(RwLock::new(
                current.clone(),
            ))));
            return;
        }
        for item in &lists[idx] {
            current.push(item.clone());
            product_helper(lists, idx + 1, current, result);
            current.pop();
        }
    }
    let mut result = Vec::new();
    let mut current = Vec::new();
    product_helper(&lists, 0, &mut current, &mut result);
    Ok(StrykeValue::array(result))
}

fn arg_to_vec(v: &StrykeValue) -> Vec<StrykeValue> {
    if let Some(r) = v.as_array_ref() {
        r.read().clone()
    } else if let Some(arr) = v.as_array_vec() {
        arr
    } else {
        v.to_list()
    }
}

/// `compress DATA, SELECTORS` — returns elements where selector is true (Python's itertools.compress).
fn builtin_compress(args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    let data = args.first().map(arg_to_vec).unwrap_or_default();
    let selectors = args.get(1).map(arg_to_vec).unwrap_or_default();
    let result: Vec<StrykeValue> = data
        .into_iter()
        .zip(selectors)
        .filter_map(|(d, s)| if s.is_true() { Some(d) } else { None })
        .collect();
    Ok(StrykeValue::array(result))
}

/// `filterfalse FN, LIST` — returns elements where predicate is false (Python's itertools.filterfalse).
fn builtin_filterfalse(
    interp: &mut VMHelper,
    args: &[StrykeValue],
    line: usize,
) -> StrykeResult<StrykeValue> {
    if args.is_empty() {
        return Ok(StrykeValue::array(vec![]));
    }
    let f = args.first().cloned().unwrap_or(StrykeValue::UNDEF);
    let Some(sub) = f.as_code_ref() else {
        return Err(StrykeError::runtime(
            "filterfalse: first argument must be a code reference",
            line,
        ));
    };
    let xs = flatten_args(&args[1..]);
    let mut result = Vec::new();
    for x in xs {
        let mapped = exec_to_perl_result(
            interp.call_sub(&sub, vec![x.clone()], WantarrayCtx::Scalar, line),
            "filterfalse",
            line,
        )?;
        if !mapped.is_true() {
            result.push(x);
        }
    }
    Ok(StrykeValue::array(result))
}

/// `islice START, STOP [, STEP], LIST` — returns slice of iterator (Python's itertools.islice).
fn builtin_islice(args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    if args.len() < 2 {
        return Ok(StrykeValue::array(vec![]));
    }
    let start = args[0].to_int().max(0) as usize;
    let stop = args[1].to_int().max(0) as usize;
    let (step, xs) = if args.len() >= 4 {
        (args[2].to_int().max(1) as usize, flatten_args(&args[3..]))
    } else {
        (1, flatten_args(&args[2..]))
    };
    let result: Vec<StrykeValue> = xs
        .into_iter()
        .enumerate()
        .filter(|(i, _)| *i >= start && *i < stop && (*i - start).is_multiple_of(step))
        .map(|(_, v)| v)
        .collect();
    Ok(StrykeValue::array(result))
}

/// `chain_from LIST_OF_LISTS` — flattens one level (Python's itertools.chain.from_iterable).
fn builtin_chain_from(args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    let lists = flatten_args(args);
    let mut result = Vec::new();
    for item in lists {
        result.extend(item.to_list());
    }
    Ok(StrykeValue::array(result))
}

/// `pairwise_iter LIST` — returns overlapping pairs (Python 3.10+ itertools.pairwise).
/// No arguments → `pairwise_iter($_)`.
fn builtin_pairwise_iter(interp: &VMHelper, args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    let mut topic = StrykeValue::UNDEF;
    let args = variadic_list_or_topic(interp, args, &mut topic);
    let xs = flatten_args(args);
    if xs.len() < 2 {
        return Ok(StrykeValue::array(vec![]));
    }
    let result: Vec<StrykeValue> = xs
        .windows(2)
        .map(|w| StrykeValue::array_ref(Arc::new(RwLock::new(w.to_vec()))))
        .collect();
    Ok(StrykeValue::array(result))
}

/// `tee_iter N, LIST` — returns N independent copies of the list (Python's itertools.tee).
fn builtin_tee_iter(args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    let n = args
        .first()
        .map(|v| v.to_int().max(1) as usize)
        .unwrap_or(2);
    let xs = flatten_args(&args[1..]);
    let copies: Vec<StrykeValue> = (0..n)
        .map(|_| StrykeValue::array_ref(Arc::new(RwLock::new(xs.clone()))))
        .collect();
    Ok(StrykeValue::array(copies))
}

/// `groupby_iter FN, LIST` — groups consecutive elements by key (Python's itertools.groupby).
fn builtin_groupby_iter(
    interp: &mut VMHelper,
    args: &[StrykeValue],
    line: usize,
) -> StrykeResult<StrykeValue> {
    if args.is_empty() {
        return Ok(StrykeValue::array(vec![]));
    }
    let (f, xs) = if args.first().and_then(|v| v.as_code_ref()).is_some() {
        let sub = args[0].as_code_ref().unwrap();
        (Some(sub), flatten_args(&args[1..]))
    } else {
        (None, flatten_args(args))
    };
    if xs.is_empty() {
        return Ok(StrykeValue::array(vec![]));
    }
    let mut result: Vec<StrykeValue> = Vec::new();
    let mut current_group: Vec<StrykeValue> = vec![xs[0].clone()];
    let mut last_key = if let Some(ref sub) = f {
        exec_to_perl_result(
            interp.call_sub(sub, vec![xs[0].clone()], WantarrayCtx::Scalar, line),
            "groupby",
            line,
        )?
        .to_string()
    } else {
        xs[0].to_string()
    };
    for x in xs.iter().skip(1) {
        let key = if let Some(ref sub) = f {
            exec_to_perl_result(
                interp.call_sub(sub, vec![x.clone()], WantarrayCtx::Scalar, line),
                "groupby",
                line,
            )?
            .to_string()
        } else {
            x.to_string()
        };
        if key != last_key {
            result.push(StrykeValue::array(vec![
                StrykeValue::string(last_key.clone()),
                StrykeValue::array_ref(Arc::new(RwLock::new(std::mem::take(&mut current_group)))),
            ]));
            last_key = key;
        }
        current_group.push(x.clone());
    }
    if !current_group.is_empty() {
        result.push(StrykeValue::array(vec![
            StrykeValue::string(last_key),
            StrykeValue::array_ref(Arc::new(RwLock::new(current_group))),
        ]));
    }
    Ok(StrykeValue::array(result))
}

// ── Ruby Enumerable methods ──

/// `each_slice N, LIST` — iterates over consecutive slices of size N (Ruby's each_slice).
fn builtin_each_slice(args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    let n = args
        .first()
        .map(|v| v.to_int().max(1) as usize)
        .unwrap_or(1);
    let xs = flatten_args(&args[1..]);
    let result: Vec<StrykeValue> = xs
        .chunks(n)
        .map(|chunk| StrykeValue::array_ref(Arc::new(RwLock::new(chunk.to_vec()))))
        .collect();
    Ok(StrykeValue::array(result))
}

/// `each_cons N, LIST` — iterates over consecutive N-element slices (Ruby's each_cons).
fn builtin_each_cons(args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    let n = args
        .first()
        .map(|v| v.to_int().max(1) as usize)
        .unwrap_or(2);
    let xs = flatten_args(&args[1..]);
    if xs.len() < n {
        return Ok(StrykeValue::array(vec![]));
    }
    let result: Vec<StrykeValue> = xs
        .windows(n)
        .map(|w| StrykeValue::array_ref(Arc::new(RwLock::new(w.to_vec()))))
        .collect();
    Ok(StrykeValue::array(result))
}

/// `one FN, LIST` — returns true if exactly one element matches (Ruby's one?).
fn builtin_one(
    interp: &mut VMHelper,
    args: &[StrykeValue],
    line: usize,
) -> StrykeResult<StrykeValue> {
    if args.is_empty() {
        return Ok(bool_iv(false));
    }
    let (f, xs) = if args.first().and_then(|v| v.as_code_ref()).is_some() {
        let sub = args[0].as_code_ref().unwrap();
        (Some(sub), flatten_args(&args[1..]))
    } else {
        (None, flatten_args(args))
    };
    let mut count = 0;
    for x in xs {
        let matches = if let Some(ref sub) = f {
            exec_to_perl_result(
                interp.call_sub(sub, vec![x.clone()], WantarrayCtx::Scalar, line),
                "one",
                line,
            )?
            .is_true()
        } else {
            x.is_true()
        };
        if matches {
            count += 1;
            if count > 1 {
                return Ok(bool_iv(false));
            }
        }
    }
    Ok(bool_iv(count == 1))
}

/// `none_match FN, LIST` — returns true if no elements match (Ruby's none?).
fn builtin_none_match(
    interp: &mut VMHelper,
    args: &[StrykeValue],
    line: usize,
) -> StrykeResult<StrykeValue> {
    if args.is_empty() {
        return Ok(bool_iv(true));
    }
    let (f, xs) = if args.first().and_then(|v| v.as_code_ref()).is_some() {
        let sub = args[0].as_code_ref().unwrap();
        (Some(sub), flatten_args(&args[1..]))
    } else {
        (None, flatten_args(args))
    };
    for x in xs {
        let matches = if let Some(ref sub) = f {
            exec_to_perl_result(
                interp.call_sub(sub, vec![x.clone()], WantarrayCtx::Scalar, line),
                "none_match",
                line,
            )?
            .is_true()
        } else {
            x.is_true()
        };
        if matches {
            return Ok(bool_iv(false));
        }
    }
    Ok(bool_iv(true))
}

/// `find_index_fn FN, LIST` — returns index of first match (Ruby's find_index with block).
fn builtin_find_index_fn(
    interp: &mut VMHelper,
    args: &[StrykeValue],
    line: usize,
) -> StrykeResult<StrykeValue> {
    if args.is_empty() {
        return Ok(StrykeValue::UNDEF);
    }
    let f = args.first().cloned().unwrap_or(StrykeValue::UNDEF);
    let Some(sub) = f.as_code_ref() else {
        return Err(StrykeError::runtime(
            "find_index: first argument must be a code reference",
            line,
        ));
    };
    let xs = flatten_args(&args[1..]);
    for (i, x) in xs.iter().enumerate() {
        let result = exec_to_perl_result(
            interp.call_sub(&sub, vec![x.clone()], WantarrayCtx::Scalar, line),
            "find_index",
            line,
        )?;
        if result.is_true() {
            return Ok(StrykeValue::integer(i as i64));
        }
    }
    Ok(StrykeValue::UNDEF)
}

/// `rindex_fn FN, LIST` — returns index of last match (Ruby's rindex with block).
fn builtin_rindex_fn(
    interp: &mut VMHelper,
    args: &[StrykeValue],
    line: usize,
) -> StrykeResult<StrykeValue> {
    if args.is_empty() {
        return Ok(StrykeValue::UNDEF);
    }
    let f = args.first().cloned().unwrap_or(StrykeValue::UNDEF);
    let Some(sub) = f.as_code_ref() else {
        return Err(StrykeError::runtime(
            "rindex_fn: first argument must be a code reference",
            line,
        ));
    };
    let xs = flatten_args(&args[1..]);
    for (i, x) in xs.iter().enumerate().rev() {
        let result = exec_to_perl_result(
            interp.call_sub(&sub, vec![x.clone()], WantarrayCtx::Scalar, line),
            "rindex_fn",
            line,
        )?;
        if result.is_true() {
            return Ok(StrykeValue::integer(i as i64));
        }
    }
    Ok(StrykeValue::UNDEF)
}

/// `minmax LIST` — returns [min, max] pair (Ruby's minmax).
fn builtin_minmax(args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    let xs = flatten_args(args);
    if xs.is_empty() {
        return Ok(StrykeValue::array(vec![
            StrykeValue::UNDEF,
            StrykeValue::UNDEF,
        ]));
    }
    let mut min = xs[0].clone();
    let mut max = xs[0].clone();
    for x in xs.iter().skip(1) {
        if x.to_number() < min.to_number() {
            min = x.clone();
        }
        if x.to_number() > max.to_number() {
            max = x.clone();
        }
    }
    Ok(StrykeValue::array(vec![min, max]))
}

/// `minmax_by FN, LIST` — returns [min, max] by key function (Ruby's minmax_by).
fn builtin_minmax_by(
    interp: &mut VMHelper,
    args: &[StrykeValue],
    line: usize,
) -> StrykeResult<StrykeValue> {
    if args.is_empty() {
        return Ok(StrykeValue::array(vec![
            StrykeValue::UNDEF,
            StrykeValue::UNDEF,
        ]));
    }
    let f = args.first().cloned().unwrap_or(StrykeValue::UNDEF);
    let Some(sub) = f.as_code_ref() else {
        return Err(StrykeError::runtime(
            "minmax_by: first argument must be a code reference",
            line,
        ));
    };
    let xs = flatten_args(&args[1..]);
    if xs.is_empty() {
        return Ok(StrykeValue::array(vec![
            StrykeValue::UNDEF,
            StrykeValue::UNDEF,
        ]));
    }
    let mut min_item = xs[0].clone();
    let mut max_item = xs[0].clone();
    let mut min_key = exec_to_perl_result(
        interp.call_sub(&sub, vec![xs[0].clone()], WantarrayCtx::Scalar, line),
        "minmax_by",
        line,
    )?
    .to_number();
    let mut max_key = min_key;
    for x in xs.iter().skip(1) {
        let key = exec_to_perl_result(
            interp.call_sub(&sub, vec![x.clone()], WantarrayCtx::Scalar, line),
            "minmax_by",
            line,
        )?
        .to_number();
        if key < min_key {
            min_key = key;
            min_item = x.clone();
        }
        if key > max_key {
            max_key = key;
            max_item = x.clone();
        }
    }
    Ok(StrykeValue::array(vec![min_item, max_item]))
}

/// `dig HASH, KEY1, KEY2, ...` — digs into nested structures (Ruby's dig).
fn builtin_dig(args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    if args.is_empty() {
        return Ok(StrykeValue::UNDEF);
    }
    let mut current = args[0].clone();
    for key in args.iter().skip(1) {
        if let Some(m) = current.as_hash_map() {
            current = m
                .get(&key.to_string())
                .cloned()
                .unwrap_or(StrykeValue::UNDEF);
        } else if let Some(r) = current.as_hash_ref() {
            current = r
                .read()
                .get(&key.to_string())
                .cloned()
                .unwrap_or(StrykeValue::UNDEF);
        } else if let Some(arr) = current.as_array_vec() {
            let idx = key.to_int();
            let idx = if idx < 0 { arr.len() as i64 + idx } else { idx } as usize;
            current = arr.get(idx).cloned().unwrap_or(StrykeValue::UNDEF);
        } else if let Some(r) = current.as_array_ref() {
            let arr = r.read();
            let idx = key.to_int();
            let idx = if idx < 0 { arr.len() as i64 + idx } else { idx } as usize;
            current = arr.get(idx).cloned().unwrap_or(StrykeValue::UNDEF);
        } else {
            return Ok(StrykeValue::UNDEF);
        }
    }
    Ok(current)
}

/// `values_at COLL, IDX1, IDX2, ...` — returns values at given indices (Ruby's values_at).
fn builtin_values_at(args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    if args.is_empty() {
        return Ok(StrykeValue::array(vec![]));
    }
    let list = arg_to_vec(&args[0]);
    let indices: Vec<i64> = args[1..].iter().map(|v| v.to_int()).collect();
    let result: Vec<StrykeValue> = indices
        .into_iter()
        .map(|idx| {
            let idx = if idx < 0 {
                list.len() as i64 + idx
            } else {
                idx
            } as usize;
            list.get(idx).cloned().unwrap_or(StrykeValue::UNDEF)
        })
        .collect();
    Ok(StrykeValue::array(result))
}

/// `fetch_val COLL, KEY [, DEFAULT]` — fetches value with optional default (Ruby's fetch).
fn builtin_fetch_val(args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    if args.is_empty() {
        return Ok(StrykeValue::UNDEF);
    }
    let coll = args[0].clone();
    let key = args.get(1).cloned().unwrap_or(StrykeValue::UNDEF);
    let default = args.get(2).cloned();
    let value = if let Some(m) = coll.as_hash_map() {
        m.get(&key.to_string()).cloned()
    } else if let Some(r) = coll.as_hash_ref() {
        r.read().get(&key.to_string()).cloned()
    } else {
        let list = arg_to_vec(&coll);
        let idx = key.to_int();
        let idx = if idx < 0 {
            list.len() as i64 + idx
        } else {
            idx
        } as usize;
        list.get(idx).cloned()
    };
    Ok(value.or(default).unwrap_or(StrykeValue::UNDEF))
}

/// `slice_arr COLL, START, LEN` — returns slice of array (Ruby's slice).
fn builtin_slice_arr(args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    if args.is_empty() {
        return Ok(StrykeValue::array(vec![]));
    }
    let list = arg_to_vec(&args[0]);
    let start = args.get(1).map(|v| v.to_int()).unwrap_or(0);
    let start = if start < 0 {
        (list.len() as i64 + start).max(0)
    } else {
        start
    } as usize;
    let len = args
        .get(2)
        .map(|v| v.to_int().max(0) as usize)
        .unwrap_or(list.len().saturating_sub(start));
    let end = (start + len).min(list.len());
    if start >= list.len() {
        return Ok(StrykeValue::array(vec![]));
    }
    Ok(StrykeValue::array(list[start..end].to_vec()))
}

/// `transform_keys FN, HASH` — transforms hash keys (Ruby's transform_keys).
fn builtin_transform_keys(
    interp: &mut VMHelper,
    args: &[StrykeValue],
    line: usize,
) -> StrykeResult<StrykeValue> {
    if args.is_empty() {
        return Ok(StrykeValue::hash_ref(Arc::new(RwLock::new(
            indexmap::IndexMap::new(),
        ))));
    }
    let f = args.first().cloned().unwrap_or(StrykeValue::UNDEF);
    let Some(sub) = f.as_code_ref() else {
        return Err(StrykeError::runtime(
            "transform_keys: first argument must be a code reference",
            line,
        ));
    };
    let hash = args.get(1).cloned().unwrap_or(StrykeValue::UNDEF);
    let mut out: indexmap::IndexMap<String, StrykeValue> = indexmap::IndexMap::new();
    let pairs: Vec<(String, StrykeValue)> = if let Some(m) = hash.as_hash_map() {
        m.iter().map(|(k, v)| (k.clone(), v.clone())).collect()
    } else if let Some(r) = hash.as_hash_ref() {
        r.read()
            .iter()
            .map(|(k, v)| (k.clone(), v.clone()))
            .collect()
    } else {
        vec![]
    };
    for (k, v) in pairs {
        let new_key = exec_to_perl_result(
            interp.call_sub(
                &sub,
                vec![StrykeValue::string(k)],
                WantarrayCtx::Scalar,
                line,
            ),
            "transform_keys",
            line,
        )?
        .to_string();
        out.insert(new_key, v);
    }
    Ok(StrykeValue::hash_ref(Arc::new(RwLock::new(out))))
}

/// `transform_values FN, HASH` — transforms hash values (Ruby's transform_values).
fn builtin_transform_values(
    interp: &mut VMHelper,
    args: &[StrykeValue],
    line: usize,
) -> StrykeResult<StrykeValue> {
    if args.is_empty() {
        return Ok(StrykeValue::hash_ref(Arc::new(RwLock::new(
            indexmap::IndexMap::new(),
        ))));
    }
    let f = args.first().cloned().unwrap_or(StrykeValue::UNDEF);
    let Some(sub) = f.as_code_ref() else {
        return Err(StrykeError::runtime(
            "transform_values: first argument must be a code reference",
            line,
        ));
    };
    let hash = args.get(1).cloned().unwrap_or(StrykeValue::UNDEF);
    let mut out: indexmap::IndexMap<String, StrykeValue> = indexmap::IndexMap::new();
    let pairs: Vec<(String, StrykeValue)> = if let Some(m) = hash.as_hash_map() {
        m.iter().map(|(k, v)| (k.clone(), v.clone())).collect()
    } else if let Some(r) = hash.as_hash_ref() {
        r.read()
            .iter()
            .map(|(k, v)| (k.clone(), v.clone()))
            .collect()
    } else {
        vec![]
    };
    for (k, v) in pairs {
        let new_val = exec_to_perl_result(
            interp.call_sub(&sub, vec![v], WantarrayCtx::Scalar, line),
            "transform_values",
            line,
        )?;
        out.insert(k, new_val);
    }
    Ok(StrykeValue::hash_ref(Arc::new(RwLock::new(out))))
}

/// `sum_by FN, LIST` — sums values by key function (Ruby's sum with block).
fn builtin_sum_by(
    interp: &mut VMHelper,
    args: &[StrykeValue],
    line: usize,
) -> StrykeResult<StrykeValue> {
    if args.is_empty() {
        return Ok(StrykeValue::float(0.0));
    }
    let f = args.first().cloned().unwrap_or(StrykeValue::UNDEF);
    let Some(sub) = f.as_code_ref() else {
        return Err(StrykeError::runtime(
            "sum_by: first argument must be a code reference",
            line,
        ));
    };
    let xs = flatten_args(&args[1..]);
    let mut sum = 0.0;
    for x in xs {
        let val = exec_to_perl_result(
            interp.call_sub(&sub, vec![x], WantarrayCtx::Scalar, line),
            "sum_by",
            line,
        )?;
        sum += val.to_number();
    }
    Ok(StrykeValue::float(sum))
}

/// `uniq_by FN, LIST` — returns unique elements by key function (Ruby's uniq with block).
fn builtin_uniq_by(
    interp: &mut VMHelper,
    args: &[StrykeValue],
    line: usize,
) -> StrykeResult<StrykeValue> {
    if args.is_empty() {
        return Ok(StrykeValue::array(vec![]));
    }
    let f = args.first().cloned().unwrap_or(StrykeValue::UNDEF);
    let Some(sub) = f.as_code_ref() else {
        return Err(StrykeError::runtime(
            "uniq_by: first argument must be a code reference",
            line,
        ));
    };
    let xs = flatten_args(&args[1..]);
    let mut seen: std::collections::HashSet<String> = std::collections::HashSet::new();
    let mut result = Vec::new();
    for x in xs {
        let key = exec_to_perl_result(
            interp.call_sub(&sub, vec![x.clone()], WantarrayCtx::Scalar, line),
            "uniq_by",
            line,
        )?
        .to_string();
        if seen.insert(key) {
            result.push(x);
        }
    }
    Ok(StrykeValue::array(result))
}

/// `flat_map_fn FN, LIST` — maps and flattens one level (Ruby's flat_map).
fn builtin_flat_map_fn(
    interp: &mut VMHelper,
    args: &[StrykeValue],
    line: usize,
) -> StrykeResult<StrykeValue> {
    builtin_mapcat(interp, args, line)
}

/// `then_fn FN, VALUE` — passes value to fn and returns result (Ruby's then/yield_self).
fn builtin_then_fn(
    interp: &mut VMHelper,
    args: &[StrykeValue],
    line: usize,
) -> StrykeResult<StrykeValue> {
    if args.is_empty() {
        return Ok(StrykeValue::UNDEF);
    }
    let f = args.first().cloned().unwrap_or(StrykeValue::UNDEF);
    let Some(sub) = f.as_code_ref() else {
        return Err(StrykeError::runtime(
            "then_fn: first argument must be a code reference",
            line,
        ));
    };
    let value = args.get(1).cloned().unwrap_or(StrykeValue::UNDEF);
    exec_to_perl_result(
        interp.call_sub(&sub, vec![value], WantarrayCtx::Scalar, line),
        "then_fn",
        line,
    )
}

/// `times_fn N, FN` — calls fn N times with index (Ruby's times).
fn builtin_times_fn(
    interp: &mut VMHelper,
    args: &[StrykeValue],
    line: usize,
) -> StrykeResult<StrykeValue> {
    let n = args.first().map(|v| v.to_int().max(0)).unwrap_or(0);
    let f = args.get(1).cloned().unwrap_or(StrykeValue::UNDEF);
    let Some(sub) = f.as_code_ref() else {
        return Err(StrykeError::runtime(
            "times_fn: second argument must be a code reference",
            line,
        ));
    };
    let mut result = Vec::with_capacity(n as usize);
    for i in 0..n {
        let val = exec_to_perl_result(
            interp.call_sub(
                &sub,
                vec![StrykeValue::integer(i)],
                WantarrayCtx::Scalar,
                line,
            ),
            "times_fn",
            line,
        )?;
        result.push(val);
    }
    Ok(StrykeValue::array(result))
}

/// `step START, END, STEP` — generates range with step (Ruby's step).
fn builtin_step(args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    let start = args.first().map(|v| v.to_number()).unwrap_or(0.0);
    let end = args.get(1).map(|v| v.to_number()).unwrap_or(0.0);
    let step = args.get(2).map(|v| v.to_number()).unwrap_or(1.0);
    if step == 0.0 {
        return Ok(StrykeValue::array(vec![]));
    }
    let mut result = Vec::new();
    let mut current = start;
    if step > 0.0 {
        while current <= end {
            result.push(StrykeValue::float(current));
            current += step;
        }
    } else {
        while current >= end {
            result.push(StrykeValue::float(current));
            current += step;
        }
    }
    Ok(StrykeValue::array(result))
}

/// `upto START, END` — generates ascending range (Ruby's upto).
fn builtin_upto(args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    let start = args.first().map(|v| v.to_int()).unwrap_or(0);
    let end = args.get(1).map(|v| v.to_int()).unwrap_or(0);
    let result: Vec<StrykeValue> = (start..=end).map(StrykeValue::integer).collect();
    Ok(StrykeValue::array(result))
}

/// `downto START, END` — generates descending range (Ruby's downto).
fn builtin_downto(args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    let start = args.first().map(|v| v.to_int()).unwrap_or(0);
    let end = args.get(1).map(|v| v.to_int()).unwrap_or(0);
    let result: Vec<StrykeValue> = (end..=start).rev().map(StrykeValue::integer).collect();
    Ok(StrykeValue::array(result))
}

