/// `span_fn FN, LIST` — splits list at first element where predicate fails (Haskell's span).
fn builtin_span_fn(
    interp: &mut VMHelper,
    args: &[StrykeValue],
    line: usize,
) -> StrykeResult<StrykeValue> {
    if args.is_empty() {
        return Ok(StrykeValue::array(vec![
            StrykeValue::array_ref(Arc::new(RwLock::new(vec![]))),
            StrykeValue::array_ref(Arc::new(RwLock::new(vec![]))),
        ]));
    }
    let f = args.first().cloned().unwrap_or(StrykeValue::UNDEF);
    let Some(sub) = f.as_code_ref() else {
        return Err(StrykeError::runtime(
            "span: first argument must be a code reference",
            line,
        ));
    };
    let xs = flatten_args(&args[1..]);
    let mut prefix = Vec::new();
    let mut suffix_start = xs.len();
    for (i, x) in xs.iter().enumerate() {
        let result = exec_to_perl_result(
            interp.call_sub(&sub, vec![x.clone()], WantarrayCtx::Scalar, line),
            "span",
            line,
        )?;
        if !result.is_true() {
            suffix_start = i;
            break;
        }
        prefix.push(x.clone());
    }
    let suffix: Vec<StrykeValue> = xs[suffix_start..].to_vec();
    Ok(StrykeValue::array(vec![
        StrykeValue::array_ref(Arc::new(RwLock::new(prefix))),
        StrykeValue::array_ref(Arc::new(RwLock::new(suffix))),
    ]))
}

/// `break_fn FN, LIST` — splits list at first element where predicate succeeds (Haskell's break).
fn builtin_break_fn(
    interp: &mut VMHelper,
    args: &[StrykeValue],
    line: usize,
) -> StrykeResult<StrykeValue> {
    if args.is_empty() {
        return Ok(StrykeValue::array(vec![
            StrykeValue::array_ref(Arc::new(RwLock::new(vec![]))),
            StrykeValue::array_ref(Arc::new(RwLock::new(vec![]))),
        ]));
    }
    let f = args.first().cloned().unwrap_or(StrykeValue::UNDEF);
    let Some(sub) = f.as_code_ref() else {
        return Err(StrykeError::runtime(
            "break_fn: first argument must be a code reference",
            line,
        ));
    };
    let xs = flatten_args(&args[1..]);
    let mut prefix = Vec::new();
    let mut suffix_start = xs.len();
    for (i, x) in xs.iter().enumerate() {
        let result = exec_to_perl_result(
            interp.call_sub(&sub, vec![x.clone()], WantarrayCtx::Scalar, line),
            "break_fn",
            line,
        )?;
        if result.is_true() {
            suffix_start = i;
            break;
        }
        prefix.push(x.clone());
    }
    let suffix: Vec<StrykeValue> = xs[suffix_start..].to_vec();
    Ok(StrykeValue::array(vec![
        StrykeValue::array_ref(Arc::new(RwLock::new(prefix))),
        StrykeValue::array_ref(Arc::new(RwLock::new(suffix))),
    ]))
}

/// `group_runs LIST` — groups consecutive equal elements (Haskell's group).
fn builtin_group_runs(args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    let xs = flatten_args(args);
    if xs.is_empty() {
        return Ok(StrykeValue::array(vec![]));
    }
    let mut result: Vec<StrykeValue> = Vec::new();
    let mut current_group: Vec<StrykeValue> = vec![xs[0].clone()];
    let mut last_key = xs[0].to_string();
    for x in xs.iter().skip(1) {
        let key = x.to_string();
        if key == last_key {
            current_group.push(x.clone());
        } else {
            result.push(StrykeValue::array_ref(Arc::new(RwLock::new(
                std::mem::take(&mut current_group),
            ))));
            current_group.push(x.clone());
            last_key = key;
        }
    }
    if !current_group.is_empty() {
        result.push(StrykeValue::array_ref(Arc::new(RwLock::new(current_group))));
    }
    Ok(StrykeValue::array(result))
}

/// `nub LIST` — removes duplicates preserving order (Haskell's nub).
fn builtin_nub(args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    let xs = flatten_args(args);
    let mut seen: std::collections::HashSet<String> = std::collections::HashSet::new();
    let mut result = Vec::new();
    for x in xs {
        let key = x.to_string();
        if seen.insert(key) {
            result.push(x);
        }
    }
    Ok(StrykeValue::array(result))
}

/// `sort_on FN, LIST` — sorts by key function (Haskell's sortOn).
fn builtin_sort_on(
    interp: &mut VMHelper,
    args: &[StrykeValue],
    line: usize,
) -> StrykeResult<StrykeValue> {
    if args.is_empty() {
        return Ok(StrykeValue::array(vec![]));
    }
    let f = args.first().cloned().unwrap_or(StrykeValue::UNDEF);
    let Some(sub) = f.as_code_ref() else {
        return Err(StrykeError::runtime(
            "sort_on: first argument must be a code reference",
            line,
        ));
    };
    let xs = flatten_args(&args[1..]);
    let mut keyed: Vec<(f64, StrykeValue)> = Vec::with_capacity(xs.len());
    for x in xs {
        let key = exec_to_perl_result(
            interp.call_sub(&sub, vec![x.clone()], WantarrayCtx::Scalar, line),
            "sort_on",
            line,
        )?
        .to_number();
        keyed.push((key, x));
    }
    keyed.sort_by(|a, b| a.0.partial_cmp(&b.0).unwrap_or(std::cmp::Ordering::Equal));
    Ok(StrykeValue::array(
        keyed.into_iter().map(|(_, v)| v).collect(),
    ))
}

/// `intersperse_val SEP, LIST` — inserts separator between elements (Haskell's intersperse).
fn builtin_intersperse_val(args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    let sep = args.first().cloned().unwrap_or(StrykeValue::UNDEF);
    let xs = flatten_args(&args[1..]);
    if xs.is_empty() {
        return Ok(StrykeValue::array(vec![]));
    }
    let mut result = Vec::with_capacity(xs.len() * 2 - 1);
    for (i, x) in xs.into_iter().enumerate() {
        if i > 0 {
            result.push(sep.clone());
        }
        result.push(x);
    }
    Ok(StrykeValue::array(result))
}

/// `intercalate SEP_LIST, LIST_OF_LISTS` — inserts separator list between lists and flattens (Haskell's intercalate).
fn builtin_intercalate(args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    let sep = arg_to_vec(&args.first().cloned().unwrap_or(StrykeValue::UNDEF));
    let lists: Vec<Vec<StrykeValue>> = args[1..].iter().map(arg_to_vec).collect();
    if lists.is_empty() {
        return Ok(StrykeValue::array(vec![]));
    }
    let mut result = Vec::new();
    for (i, list) in lists.into_iter().enumerate() {
        if i > 0 {
            result.extend(sep.clone());
        }
        result.extend(list);
    }
    Ok(StrykeValue::array(result))
}

/// `replicate_val N, VALUE` — creates list of N copies of value (Haskell's replicate).
fn builtin_replicate_val(args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    let n = args
        .first()
        .map(|v| v.to_int().max(0) as usize)
        .unwrap_or(0);
    let value = args.get(1).cloned().unwrap_or(StrykeValue::UNDEF);
    Ok(StrykeValue::array(vec![value; n]))
}

/// `elem_of VALUE, LIST` — checks if value is in list (Haskell's elem).
fn builtin_elem_of(args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    let value = args.first().cloned().unwrap_or(StrykeValue::UNDEF);
    let xs = flatten_args(&args[1..]);
    let value_str = value.to_string();
    for x in xs {
        if x.to_string() == value_str {
            return Ok(bool_iv(true));
        }
    }
    Ok(bool_iv(false))
}

/// `not_elem VALUE, LIST` — checks if value is not in list (Haskell's notElem).
fn builtin_not_elem(args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    let value = args.first().cloned().unwrap_or(StrykeValue::UNDEF);
    let xs = flatten_args(&args[1..]);
    let value_str = value.to_string();
    for x in xs {
        if x.to_string() == value_str {
            return Ok(bool_iv(false));
        }
    }
    Ok(bool_iv(true))
}

/// `lookup_assoc KEY, PAIRS` — finds value by key in association list (Haskell's lookup).
fn builtin_lookup_assoc(args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    let key = args.first().map(|v| v.to_string()).unwrap_or_default();
    let pairs = args.get(1..).map(|s| s.to_vec()).unwrap_or_default();
    for pair in pairs {
        let list = arg_to_vec(&pair);
        if list.len() >= 2 && list[0].to_string() == key {
            return Ok(list[1].clone());
        }
    }
    Ok(StrykeValue::UNDEF)
}

/// `scanl FN, INIT, LIST` — like foldl but returns intermediate values (Haskell's scanl).
fn builtin_scanl(
    interp: &mut VMHelper,
    args: &[StrykeValue],
    line: usize,
) -> StrykeResult<StrykeValue> {
    if args.is_empty() {
        return Ok(StrykeValue::array(vec![]));
    }
    let f = args.first().cloned().unwrap_or(StrykeValue::UNDEF);
    let Some(sub) = f.as_code_ref() else {
        return Err(StrykeError::runtime(
            "scanl: first argument must be a code reference",
            line,
        ));
    };
    let init = args.get(1).cloned().unwrap_or(StrykeValue::UNDEF);
    let xs = flatten_args(&args[2..]);
    let mut result = vec![init.clone()];
    let mut acc = init;
    for x in xs {
        acc = exec_to_perl_result(
            interp.call_sub(&sub, vec![acc, x], WantarrayCtx::Scalar, line),
            "scanl",
            line,
        )?;
        result.push(acc.clone());
    }
    Ok(StrykeValue::array(result))
}

/// `scanr FN, INIT, LIST` — like foldr but returns intermediate values (Haskell's scanr).
fn builtin_scanr(
    interp: &mut VMHelper,
    args: &[StrykeValue],
    line: usize,
) -> StrykeResult<StrykeValue> {
    if args.is_empty() {
        return Ok(StrykeValue::array(vec![]));
    }
    let f = args.first().cloned().unwrap_or(StrykeValue::UNDEF);
    let Some(sub) = f.as_code_ref() else {
        return Err(StrykeError::runtime(
            "scanr: first argument must be a code reference",
            line,
        ));
    };
    let init = args.get(1).cloned().unwrap_or(StrykeValue::UNDEF);
    let xs = flatten_args(&args[2..]);
    let mut result = vec![init.clone()];
    let mut acc = init;
    for x in xs.into_iter().rev() {
        acc = exec_to_perl_result(
            interp.call_sub(&sub, vec![x, acc], WantarrayCtx::Scalar, line),
            "scanr",
            line,
        )?;
        result.push(acc.clone());
    }
    result.reverse();
    Ok(StrykeValue::array(result))
}

/// `unfoldr FN, SEED` — generates list from seed function (Haskell's unfoldr).
fn builtin_unfoldr(
    interp: &mut VMHelper,
    args: &[StrykeValue],
    line: usize,
) -> StrykeResult<StrykeValue> {
    if args.is_empty() {
        return Ok(StrykeValue::array(vec![]));
    }
    let f = args.first().cloned().unwrap_or(StrykeValue::UNDEF);
    let Some(sub) = f.as_code_ref() else {
        return Err(StrykeError::runtime(
            "unfoldr: first argument must be a code reference",
            line,
        ));
    };
    let mut seed = args.get(1).cloned().unwrap_or(StrykeValue::UNDEF);
    let mut result = Vec::new();
    let max_iter = 10000;
    for _ in 0..max_iter {
        let out = exec_to_perl_result(
            interp.call_sub(&sub, vec![seed.clone()], WantarrayCtx::List, line),
            "unfoldr",
            line,
        )?;
        if out.is_undef() {
            break;
        }
        let list = arg_to_vec(&out);
        if list.is_empty() {
            break;
        }
        result.push(list[0].clone());
        seed = list.get(1).cloned().unwrap_or(StrykeValue::UNDEF);
        if seed.is_undef() {
            break;
        }
    }
    Ok(StrykeValue::array(result))
}

