/// `partition_either FN, LIST` — partitions into (left, right) based on return value (Rust's partition_map).
fn builtin_partition_either(
    interp: &mut VMHelper,
    args: &[StrykeValue],
    line: usize,
) -> StrykeResult<StrykeValue> {
    if args.is_empty() {
        return Ok(StrykeValue::array(vec![
            StrykeValue::array_ref(Arc::new(RwLock::new(vec![]))),
            StrykeValue::array_ref(Arc::new(RwLock::new(vec![]))),
        ]));
    }
    let f = args.first().cloned().unwrap_or(StrykeValue::UNDEF);
    let Some(sub) = f.as_code_ref() else {
        return Err(StrykeError::runtime(
            "partition_either: first argument must be a code reference",
            line,
        ));
    };
    let xs = flatten_args(&args[1..]);
    let mut left = Vec::new();
    let mut right = Vec::new();
    for x in xs {
        let result = exec_to_perl_result(
            interp.call_sub(&sub, vec![x], WantarrayCtx::List, line),
            "partition_either",
            line,
        )?;
        let list = arg_to_vec(&result);
        if list.len() >= 2 {
            let tag = list[0].to_string();
            let value = list[1].clone();
            if tag == "left" || tag == "L" || tag == "0" {
                left.push(value);
            } else {
                right.push(value);
            }
        }
    }
    Ok(StrykeValue::array(vec![
        StrykeValue::array_ref(Arc::new(RwLock::new(left))),
        StrykeValue::array_ref(Arc::new(RwLock::new(right))),
    ]))
}

/// `try_fold FN, INIT, LIST` — fold that short-circuits on undef (Rust's try_fold).
