/// `combinations_rep N, LIST` — combinations with replacement (Python itertools).
fn builtin_combinations_rep(args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    let n = args
        .first()
        .map(|v| v.to_int().max(0) as usize)
        .unwrap_or(0);
    let xs = flatten_args(&args[1..]);
    if n == 0 || xs.is_empty() {
        return Ok(StrykeValue::array(vec![]));
    }
    fn combine_rep(
        items: &[StrykeValue],
        n: usize,
        start: usize,
        current: &mut Vec<StrykeValue>,
        result: &mut Vec<StrykeValue>,
    ) {
        if current.len() == n {
            result.push(StrykeValue::array_ref(Arc::new(RwLock::new(
                current.clone(),
            ))));
            return;
        }
        for i in start..items.len() {
            current.push(items[i].clone());
            combine_rep(items, n, i, current, result);
            current.pop();
        }
    }
    let mut result = Vec::new();
    let mut current = Vec::new();
    combine_rep(&xs, n, 0, &mut current, &mut result);
    Ok(StrykeValue::array(result))
}

/// `inits LIST` — all initial segments (Haskell Data.List.inits).
fn builtin_inits(args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    let xs = flatten_args(args);
    let mut result = vec![StrykeValue::array_ref(Arc::new(RwLock::new(vec![])))];
    for i in 1..=xs.len() {
        result.push(StrykeValue::array_ref(Arc::new(RwLock::new(
            xs[..i].to_vec(),
        ))));
    }
    Ok(StrykeValue::array(result))
}

/// `tails LIST` — all final segments (Haskell Data.List.tails).
fn builtin_tails(args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    let xs = flatten_args(args);
    let mut result = Vec::with_capacity(xs.len() + 1);
    for i in 0..=xs.len() {
        result.push(StrykeValue::array_ref(Arc::new(RwLock::new(
            xs[i..].to_vec(),
        ))));
    }
    Ok(StrykeValue::array(result))
}

/// `subsequences LIST` — all subsequences / power set (Haskell Data.List.subsequences).
fn builtin_subsequences(args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    let xs = flatten_args(args);
    let n = xs.len();
    if n > 20 {
        return Err(StrykeError::runtime(
            "subsequences: list too long (max 20 elements)",
            0,
        ));
    }
    let mut result = Vec::with_capacity(1 << n);
    for mask in 0..(1u32 << n) {
        let mut subset = Vec::new();
        for (i, item) in xs.iter().enumerate() {
            if mask & (1 << i) != 0 {
                subset.push(item.clone());
            }
        }
        result.push(StrykeValue::array_ref(Arc::new(RwLock::new(subset))));
    }
    Ok(StrykeValue::array(result))
}

/// `nub_by FN, LIST` — remove duplicates using custom equality (Haskell nubBy).
fn builtin_nub_by(
    interp: &mut VMHelper,
    args: &[StrykeValue],
    line: usize,
) -> StrykeResult<StrykeValue> {
    if args.is_empty() {
        return Ok(StrykeValue::array(vec![]));
    }
    let f = args.first().cloned().unwrap_or(StrykeValue::UNDEF);
    let Some(sub) = f.as_code_ref() else {
        return Err(StrykeError::runtime(
            "nub_by: first argument must be a code reference",
            line,
        ));
    };
    let xs = flatten_args(&args[1..]);
    let mut result: Vec<StrykeValue> = Vec::new();
    'outer: for x in xs {
        for existing in &result {
            let eq = exec_to_perl_result(
                interp.call_sub(
                    &sub,
                    vec![x.clone(), existing.clone()],
                    WantarrayCtx::Scalar,
                    line,
                ),
                "nub_by",
                line,
            )?
            .is_true();
            if eq {
                continue 'outer;
            }
        }
        result.push(x);
    }
    Ok(StrykeValue::array(result))
}

/// `slice_when FN, LIST` — split when predicate true between adjacent elements (Ruby slice_when).
fn builtin_slice_when(
    interp: &mut VMHelper,
    args: &[StrykeValue],
    line: usize,
) -> StrykeResult<StrykeValue> {
    if args.is_empty() {
        return Ok(StrykeValue::array(vec![]));
    }
    let f = args.first().cloned().unwrap_or(StrykeValue::UNDEF);
    let Some(sub) = f.as_code_ref() else {
        return Err(StrykeError::runtime(
            "slice_when: first argument must be a code reference",
            line,
        ));
    };
    let xs = flatten_args(&args[1..]);
    if xs.is_empty() {
        return Ok(StrykeValue::array(vec![]));
    }
    let mut result: Vec<StrykeValue> = Vec::new();
    let mut current: Vec<StrykeValue> = vec![xs[0].clone()];
    for i in 1..xs.len() {
        let prev = &xs[i - 1];
        let curr = &xs[i];
        let should_split = exec_to_perl_result(
            interp.call_sub(
                &sub,
                vec![prev.clone(), curr.clone()],
                WantarrayCtx::Scalar,
                line,
            ),
            "slice_when",
            line,
        )?
        .is_true();
        if should_split {
            result.push(StrykeValue::array_ref(Arc::new(RwLock::new(
                std::mem::take(&mut current),
            ))));
        }
        current.push(curr.clone());
    }
    if !current.is_empty() {
        result.push(StrykeValue::array_ref(Arc::new(RwLock::new(current))));
    }
    Ok(StrykeValue::array(result))
}

/// `slice_before FN, LIST` — split before elements where predicate is true (Ruby slice_before).
fn builtin_slice_before(
    interp: &mut VMHelper,
    args: &[StrykeValue],
    line: usize,
) -> StrykeResult<StrykeValue> {
    if args.is_empty() {
        return Ok(StrykeValue::array(vec![]));
    }
    let f = args.first().cloned().unwrap_or(StrykeValue::UNDEF);
    let Some(sub) = f.as_code_ref() else {
        return Err(StrykeError::runtime(
            "slice_before: first argument must be a code reference",
            line,
        ));
    };
    let xs = flatten_args(&args[1..]);
    if xs.is_empty() {
        return Ok(StrykeValue::array(vec![]));
    }
    let mut result: Vec<StrykeValue> = Vec::new();
    let mut current: Vec<StrykeValue> = Vec::new();
    for x in xs {
        let should_split = exec_to_perl_result(
            interp.call_sub(&sub, vec![x.clone()], WantarrayCtx::Scalar, line),
            "slice_before",
            line,
        )?
        .is_true();
        if should_split && !current.is_empty() {
            result.push(StrykeValue::array_ref(Arc::new(RwLock::new(
                std::mem::take(&mut current),
            ))));
        }
        current.push(x);
    }
    if !current.is_empty() {
        result.push(StrykeValue::array_ref(Arc::new(RwLock::new(current))));
    }
    Ok(StrykeValue::array(result))
}

/// `slice_after FN, LIST` — split after elements where predicate is true (Ruby slice_after).
fn builtin_slice_after(
    interp: &mut VMHelper,
    args: &[StrykeValue],
    line: usize,
) -> StrykeResult<StrykeValue> {
    if args.is_empty() {
        return Ok(StrykeValue::array(vec![]));
    }
    let f = args.first().cloned().unwrap_or(StrykeValue::UNDEF);
    let Some(sub) = f.as_code_ref() else {
        return Err(StrykeError::runtime(
            "slice_after: first argument must be a code reference",
            line,
        ));
    };
    let xs = flatten_args(&args[1..]);
    if xs.is_empty() {
        return Ok(StrykeValue::array(vec![]));
    }
    let mut result: Vec<StrykeValue> = Vec::new();
    let mut current: Vec<StrykeValue> = Vec::new();
    for x in xs {
        current.push(x.clone());
        let should_split = exec_to_perl_result(
            interp.call_sub(&sub, vec![x], WantarrayCtx::Scalar, line),
            "slice_after",
            line,
        )?
        .is_true();
        if should_split {
            result.push(StrykeValue::array_ref(Arc::new(RwLock::new(
                std::mem::take(&mut current),
            ))));
        }
    }
    if !current.is_empty() {
        result.push(StrykeValue::array_ref(Arc::new(RwLock::new(current))));
    }
    Ok(StrykeValue::array(result))
}

/// `each_with_object OBJ, FN, LIST` — reduce with mutable object (Ruby each_with_object).
fn builtin_each_with_object(
    interp: &mut VMHelper,
    args: &[StrykeValue],
    line: usize,
) -> StrykeResult<StrykeValue> {
    if args.len() < 2 {
        return Ok(StrykeValue::UNDEF);
    }
    let obj = args[0].clone();
    let f = args.get(1).cloned().unwrap_or(StrykeValue::UNDEF);
    let Some(sub) = f.as_code_ref() else {
        return Err(StrykeError::runtime(
            "each_with_object: second argument must be a code reference",
            line,
        ));
    };
    let xs = flatten_args(&args[2..]);
    for x in xs {
        let _ = exec_to_perl_result(
            interp.call_sub(&sub, vec![x, obj.clone()], WantarrayCtx::Void, line),
            "each_with_object",
            line,
        );
    }
    Ok(obj)
}

/// `reduce_right FN, INIT, LIST` — alias for fold_right (JS reduceRight).
fn builtin_reduce_right(
    interp: &mut VMHelper,
    args: &[StrykeValue],
    line: usize,
) -> StrykeResult<StrykeValue> {
    builtin_fold_right(interp, args, line)
}

/// `is_sorted_by FN, LIST` — check if sorted by comparator (Rust is_sorted_by).
fn builtin_is_sorted_by(
    interp: &mut VMHelper,
    args: &[StrykeValue],
    line: usize,
) -> StrykeResult<StrykeValue> {
    if args.is_empty() {
        return Ok(bool_iv(true));
    }
    let f = args.first().cloned().unwrap_or(StrykeValue::UNDEF);
    let Some(sub) = f.as_code_ref() else {
        return Err(StrykeError::runtime(
            "is_sorted_by: first argument must be a code reference",
            line,
        ));
    };
    let xs = flatten_args(&args[1..]);
    if xs.len() < 2 {
        return Ok(bool_iv(true));
    }
    for i in 1..xs.len() {
        let cmp = exec_to_perl_result(
            interp.call_sub(
                &sub,
                vec![xs[i - 1].clone(), xs[i].clone()],
                WantarrayCtx::Scalar,
                line,
            ),
            "is_sorted_by",
            line,
        )?
        .to_int();
        if cmp > 0 {
            return Ok(bool_iv(false));
        }
    }
    Ok(bool_iv(true))
}

/// `intersperse_with FN, LIST` — intersperse with function results (Rust intersperse_with).
fn builtin_intersperse_with(
    interp: &mut VMHelper,
    args: &[StrykeValue],
    line: usize,
) -> StrykeResult<StrykeValue> {
    if args.is_empty() {
        return Ok(StrykeValue::array(vec![]));
    }
    let f = args.first().cloned().unwrap_or(StrykeValue::UNDEF);
    let Some(sub) = f.as_code_ref() else {
        return Err(StrykeError::runtime(
            "intersperse_with: first argument must be a code reference",
            line,
        ));
    };
    let xs = flatten_args(&args[1..]);
    if xs.is_empty() {
        return Ok(StrykeValue::array(vec![]));
    }
    let mut result = Vec::with_capacity(xs.len() * 2 - 1);
    for (i, x) in xs.into_iter().enumerate() {
        if i > 0 {
            let sep = exec_to_perl_result(
                interp.call_sub(&sub, vec![], WantarrayCtx::Scalar, line),
                "intersperse_with",
                line,
            )?;
            result.push(sep);
        }
        result.push(x);
    }
    Ok(StrykeValue::array(result))
}

/// `running_reduce FN, LIST` — like scanl but without init, starts with first element (Kotlin runningReduce).
fn builtin_running_reduce(
    interp: &mut VMHelper,
    args: &[StrykeValue],
    line: usize,
) -> StrykeResult<StrykeValue> {
    if args.is_empty() {
        return Ok(StrykeValue::array(vec![]));
    }
    let f = args.first().cloned().unwrap_or(StrykeValue::UNDEF);
    let Some(sub) = f.as_code_ref() else {
        return Err(StrykeError::runtime(
            "running_reduce: first argument must be a code reference",
            line,
        ));
    };
    let xs = flatten_args(&args[1..]);
    if xs.is_empty() {
        return Ok(StrykeValue::array(vec![]));
    }
    let mut result = vec![xs[0].clone()];
    let mut acc = xs[0].clone();
    for x in xs.iter().skip(1) {
        interp.scope.set_sort_pair(acc.clone(), x.clone());
        acc = exec_to_perl_result(
            interp.call_sub(
                &sub,
                vec![acc.clone(), x.clone()],
                WantarrayCtx::Scalar,
                line,
            ),
            "running_reduce",
            line,
        )?;
        result.push(acc.clone());
    }
    Ok(StrykeValue::array(result))
}

/// `windowed_circular N, LIST` — sliding window that wraps around.
fn builtin_windowed_circular(args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    let n = args
        .first()
        .map(|v| v.to_int().max(1) as usize)
        .unwrap_or(2);
    let xs = flatten_args(&args[1..]);
    if xs.is_empty() || n > xs.len() {
        return Ok(StrykeValue::array(vec![]));
    }
    let mut result = Vec::with_capacity(xs.len());
    for i in 0..xs.len() {
        let mut window = Vec::with_capacity(n);
        for j in 0..n {
            window.push(xs[(i + j) % xs.len()].clone());
        }
        result.push(StrykeValue::array_ref(Arc::new(RwLock::new(window))));
    }
    Ok(StrykeValue::array(result))
}

/// `distinct_by FN, LIST` — alias for uniq_by (Kotlin distinctBy).
fn builtin_distinct_by(
    interp: &mut VMHelper,
    args: &[StrykeValue],
    line: usize,
) -> StrykeResult<StrykeValue> {
    builtin_uniq_by(interp, args, line)
}

/// `average LIST` — arithmetic mean (Kotlin average).
fn builtin_average(args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    let xs = flatten_args(args);
    if xs.is_empty() {
        return Ok(StrykeValue::float(f64::NAN));
    }
    let sum: f64 = xs.iter().map(|x| x.to_number()).sum();
    Ok(StrykeValue::float(sum / xs.len() as f64))
}

/// `copy_within TARGET, START, END, LIST` — copy part of array to another position (JS copyWithin).
fn builtin_copy_within(args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    let target = args.first().map(|v| v.to_int()).unwrap_or(0);
    let start = args.get(1).map(|v| v.to_int()).unwrap_or(0);
    let end = args.get(2).map(|v| v.to_int());
    let mut list = flatten_args(&args[3..]);
    let len = list.len() as i64;
    let target = if target < 0 {
        (len + target).max(0)
    } else {
        target.min(len)
    } as usize;
    let start = if start < 0 {
        (len + start).max(0)
    } else {
        start.min(len)
    } as usize;
    let end = end
        .map(|e| if e < 0 { (len + e).max(0) } else { e.min(len) } as usize)
        .unwrap_or(list.len());
    let to_copy: Vec<StrykeValue> = list[start..end.min(list.len())].to_vec();
    for (i, val) in to_copy.into_iter().enumerate() {
        let idx = target + i;
        if idx < list.len() {
            list[idx] = val;
        }
    }
    Ok(StrykeValue::array(list))
}

/// `and_list LIST` — returns true if all elements are truthy (Haskell and).
fn builtin_and_list(args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    let xs = flatten_args(args);
    for x in xs {
        if !x.is_true() {
            return Ok(bool_iv(false));
        }
    }
    Ok(bool_iv(true))
}

/// `or_list LIST` — returns true if any element is truthy (Haskell or).
fn builtin_or_list(args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    let xs = flatten_args(args);
    for x in xs {
        if x.is_true() {
            return Ok(bool_iv(true));
        }
    }
    Ok(bool_iv(false))
}

/// `concat_map FN, LIST` — map then flatten one level (Haskell concatMap).
fn builtin_concat_map(
    interp: &mut VMHelper,
    args: &[StrykeValue],
    line: usize,
) -> StrykeResult<StrykeValue> {
    builtin_mapcat(interp, args, line)
}

/// `elem_index VALUE, LIST` — index of first occurrence (Haskell elemIndex).
fn builtin_elem_index(args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    let value = args.first().map(|v| v.to_string()).unwrap_or_default();
    let xs = flatten_args(&args[1..]);
    for (i, x) in xs.iter().enumerate() {
        if x.to_string() == value {
            return Ok(StrykeValue::integer(i as i64));
        }
    }
    Ok(StrykeValue::UNDEF)
}

/// `elem_indices VALUE, LIST` — all indices of occurrences (Haskell elemIndices).
fn builtin_elem_indices(args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    let value = args.first().map(|v| v.to_string()).unwrap_or_default();
    let xs = flatten_args(&args[1..]);
    let indices: Vec<StrykeValue> = xs
        .iter()
        .enumerate()
        .filter(|(_, x)| x.to_string() == value)
        .map(|(i, _)| StrykeValue::integer(i as i64))
        .collect();
    Ok(StrykeValue::array(indices))
}

/// `find_indices FN, LIST` — indices where predicate is true (Haskell findIndices).
fn builtin_find_indices(
    interp: &mut VMHelper,
    args: &[StrykeValue],
    line: usize,
) -> StrykeResult<StrykeValue> {
    if args.is_empty() {
        return Ok(StrykeValue::array(vec![]));
    }
    let f = args.first().cloned().unwrap_or(StrykeValue::UNDEF);
    let Some(sub) = f.as_code_ref() else {
        return Err(StrykeError::runtime(
            "find_indices: first argument must be a code reference",
            line,
        ));
    };
    let xs = flatten_args(&args[1..]);
    let mut indices = Vec::new();
    for (i, x) in xs.iter().enumerate() {
        let matches = exec_to_perl_result(
            interp.call_sub(&sub, vec![x.clone()], WantarrayCtx::Scalar, line),
            "find_indices",
            line,
        )?
        .is_true();
        if matches {
            indices.push(StrykeValue::integer(i as i64));
        }
    }
    Ok(StrykeValue::array(indices))
}

/// `delete_first VALUE, LIST` — remove first occurrence (Haskell delete).
fn builtin_delete_first(args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    let value = args.first().map(|v| v.to_string()).unwrap_or_default();
    let xs = flatten_args(&args[1..]);
    let mut result = Vec::with_capacity(xs.len());
    let mut deleted = false;
    for x in xs {
        if !deleted && x.to_string() == value {
            deleted = true;
        } else {
            result.push(x);
        }
    }
    Ok(StrykeValue::array(result))
}

/// `delete_by FN, VALUE, LIST` — remove first element equal by predicate (Haskell deleteBy).
fn builtin_delete_by(
    interp: &mut VMHelper,
    args: &[StrykeValue],
    line: usize,
) -> StrykeResult<StrykeValue> {
    if args.is_empty() {
        return Ok(StrykeValue::array(vec![]));
    }
    let f = args.first().cloned().unwrap_or(StrykeValue::UNDEF);
    let Some(sub) = f.as_code_ref() else {
        return Err(StrykeError::runtime(
            "delete_by: first argument must be a code reference",
            line,
        ));
    };
    let value = args.get(1).cloned().unwrap_or(StrykeValue::UNDEF);
    let xs = flatten_args(&args[2..]);
    let mut result = Vec::with_capacity(xs.len());
    let mut deleted = false;
    for x in xs {
        if !deleted {
            let eq = exec_to_perl_result(
                interp.call_sub(
                    &sub,
                    vec![value.clone(), x.clone()],
                    WantarrayCtx::Scalar,
                    line,
                ),
                "delete_by",
                line,
            )?
            .is_true();
            if eq {
                deleted = true;
                continue;
            }
        }
        result.push(x);
    }
    Ok(StrykeValue::array(result))
}

/// `insert_sorted VALUE, LIST` — insert into sorted list maintaining order (Haskell insert).
fn builtin_insert_sorted(args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    let value = args.first().cloned().unwrap_or(StrykeValue::UNDEF);
    let xs = flatten_args(&args[1..]);
    let val_num = value.to_number();
    let mut result = Vec::with_capacity(xs.len() + 1);
    let mut inserted = false;
    for x in xs {
        if !inserted && val_num <= x.to_number() {
            result.push(value.clone());
            inserted = true;
        }
        result.push(x);
    }
    if !inserted {
        result.push(value);
    }
    Ok(StrykeValue::array(result))
}

/// `union_list LIST1, LIST2` — set union preserving order (Haskell union).
fn builtin_union_list(args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    let xs = arg_to_vec(&args.first().cloned().unwrap_or(StrykeValue::UNDEF));
    let ys = arg_to_vec(&args.get(1).cloned().unwrap_or(StrykeValue::UNDEF));
    let mut seen: std::collections::HashSet<String> = std::collections::HashSet::new();
    let mut result = Vec::new();
    for x in xs {
        let key = x.to_string();
        if seen.insert(key) {
            result.push(x);
        }
    }
    for y in ys {
        let key = y.to_string();
        if seen.insert(key) {
            result.push(y);
        }
    }
    Ok(StrykeValue::array(result))
}

/// `intersect_list LIST1, LIST2` — set intersection preserving order (Haskell intersect).
fn builtin_intersect_list(args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    let xs = arg_to_vec(&args.first().cloned().unwrap_or(StrykeValue::UNDEF));
    let ys = arg_to_vec(&args.get(1).cloned().unwrap_or(StrykeValue::UNDEF));
    let ys_set: std::collections::HashSet<String> = ys.iter().map(|y| y.to_string()).collect();
    let result: Vec<StrykeValue> = xs
        .into_iter()
        .filter(|x| ys_set.contains(&x.to_string()))
        .collect();
    Ok(StrykeValue::array(result))
}

/// `maximum_by FN, LIST` — max by comparator (Haskell maximumBy).
fn builtin_maximum_by(
    interp: &mut VMHelper,
    args: &[StrykeValue],
    line: usize,
) -> StrykeResult<StrykeValue> {
    if args.is_empty() {
        return Ok(StrykeValue::UNDEF);
    }
    let f = args.first().cloned().unwrap_or(StrykeValue::UNDEF);
    let Some(sub) = f.as_code_ref() else {
        return Err(StrykeError::runtime(
            "maximum_by: first argument must be a code reference",
            line,
        ));
    };
    let xs = flatten_args(&args[1..]);
    if xs.is_empty() {
        return Ok(StrykeValue::UNDEF);
    }
    let mut max_item = xs[0].clone();
    for x in xs.iter().skip(1) {
        let cmp = exec_to_perl_result(
            interp.call_sub(
                &sub,
                vec![x.clone(), max_item.clone()],
                WantarrayCtx::Scalar,
                line,
            ),
            "maximum_by",
            line,
        )?
        .to_int();
        if cmp > 0 {
            max_item = x.clone();
        }
    }
    Ok(max_item)
}

/// `minimum_by FN, LIST` — min by comparator (Haskell minimumBy).
fn builtin_minimum_by(
    interp: &mut VMHelper,
    args: &[StrykeValue],
    line: usize,
) -> StrykeResult<StrykeValue> {
    if args.is_empty() {
        return Ok(StrykeValue::UNDEF);
    }
    let f = args.first().cloned().unwrap_or(StrykeValue::UNDEF);
    let Some(sub) = f.as_code_ref() else {
        return Err(StrykeError::runtime(
            "minimum_by: first argument must be a code reference",
            line,
        ));
    };
    let xs = flatten_args(&args[1..]);
    if xs.is_empty() {
        return Ok(StrykeValue::UNDEF);
    }
    let mut min_item = xs[0].clone();
    for x in xs.iter().skip(1) {
        let cmp = exec_to_perl_result(
            interp.call_sub(
                &sub,
                vec![x.clone(), min_item.clone()],
                WantarrayCtx::Scalar,
                line,
            ),
            "minimum_by",
            line,
        )?
        .to_int();
        if cmp < 0 {
            min_item = x.clone();
        }
    }
    Ok(min_item)
}

/// `batched N, LIST` — chunk into batches of N (Python 3.12 itertools.batched).
fn builtin_batched(args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    let n = args
        .first()
        .map(|v| v.to_int().max(1) as usize)
        .unwrap_or(1);
    let xs = flatten_args(&args[1..]);
    let result: Vec<StrykeValue> = xs
        .chunks(n)
        .map(|chunk| StrykeValue::array_ref(Arc::new(RwLock::new(chunk.to_vec()))))
        .collect();
    Ok(StrykeValue::array(result))
}

