/// `match_all REGEX, STR` — returns all matches as array.
fn builtin_match_all(args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    let pattern = args.first().map(|v| v.to_string()).unwrap_or_default();
    let text = args.get(1).map(|v| v.to_string()).unwrap_or_default();
    let re = regex::Regex::new(&pattern)
        .map_err(|e| StrykeError::runtime(format!("match_all: {}", e), 0))?;
    let matches: Vec<StrykeValue> = re
        .find_iter(&text)
        .map(|m| StrykeValue::string(m.as_str().to_string()))
        .collect();
    Ok(StrykeValue::array(matches))
}

/// `capture_groups REGEX, STR` — returns capture groups as array of arrays.
fn builtin_capture_groups(args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    let pattern = args.first().map(|v| v.to_string()).unwrap_or_default();
    let text = args.get(1).map(|v| v.to_string()).unwrap_or_default();
    let re = regex::Regex::new(&pattern)
        .map_err(|e| StrykeError::runtime(format!("capture_groups: {}", e), 0))?;
    let mut result = Vec::new();
    for caps in re.captures_iter(&text) {
        let groups: Vec<StrykeValue> = caps
            .iter()
            .map(|m| {
                m.map(|x| StrykeValue::string(x.as_str().to_string()))
                    .unwrap_or(StrykeValue::UNDEF)
            })
            .collect();
        result.push(StrykeValue::array_ref(Arc::new(RwLock::new(groups))));
    }
    Ok(StrykeValue::array(result))
}

/// `is_match REGEX, STR` — returns true if regex matches.
fn builtin_is_match(args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    let pattern = args.first().map(|v| v.to_string()).unwrap_or_default();
    let text = args.get(1).map(|v| v.to_string()).unwrap_or_default();
    let re = regex::Regex::new(&pattern)
        .map_err(|e| StrykeError::runtime(format!("is_match: {}", e), 0))?;
    Ok(bool_iv(re.is_match(&text)))
}

/// `split_regex REGEX, STR [, LIMIT]` — split string by regex.
fn builtin_split_regex(args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    let pattern = args.first().map(|v| v.to_string()).unwrap_or_default();
    let text = args.get(1).map(|v| v.to_string()).unwrap_or_default();
    let limit = args.get(2).map(|v| v.to_int() as usize).unwrap_or(0);
    let re = regex::Regex::new(&pattern)
        .map_err(|e| StrykeError::runtime(format!("split_regex: {}", e), 0))?;
    let parts: Vec<StrykeValue> = if limit > 0 {
        re.splitn(&text, limit)
            .map(|s| StrykeValue::string(s.to_string()))
            .collect()
    } else {
        re.split(&text)
            .map(|s| StrykeValue::string(s.to_string()))
            .collect()
    };
    Ok(StrykeValue::array(parts))
}

/// `replace_regex REGEX, REPLACEMENT, STR` — replace all matches.
fn builtin_replace_regex(args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    let pattern = args.first().map(|v| v.to_string()).unwrap_or_default();
    let replacement = args.get(1).map(|v| v.to_string()).unwrap_or_default();
    let text = args.get(2).map(|v| v.to_string()).unwrap_or_default();
    let re = regex::Regex::new(&pattern)
        .map_err(|e| StrykeError::runtime(format!("replace_regex: {}", e), 0))?;
    Ok(StrykeValue::string(
        re.replace_all(&text, replacement.as_str()).to_string(),
    ))
}

/// `is_ascii STR` — returns true if string is all ASCII.
fn builtin_is_ascii(interp: &VMHelper, args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    let s = first_arg_or_topic(interp, args).to_string();
    Ok(bool_iv(s.is_ascii()))
}

/// `to_ascii STR` — converts to ASCII, replacing non-ASCII with '?'.
fn builtin_to_ascii(interp: &VMHelper, args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    let s = first_arg_or_topic(interp, args).to_string();
    let ascii: String = s
        .chars()
        .map(|c| if c.is_ascii() { c } else { '?' })
        .collect();
    Ok(StrykeValue::string(ascii))
}

/// `char_at STR, INDEX` — returns character at index.
fn builtin_char_at(args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    let s = args.first().map(|v| v.to_string()).unwrap_or_default();
    let idx = args.get(1).map(|v| v.to_int()).unwrap_or(0);
    let chars: Vec<char> = s.chars().collect();
    let idx = if idx < 0 {
        chars.len() as i64 + idx
    } else {
        idx
    };
    if idx >= 0 && (idx as usize) < chars.len() {
        Ok(StrykeValue::string(chars[idx as usize].to_string()))
    } else {
        Ok(StrykeValue::UNDEF)
    }
}

/// `code_point_at STR, INDEX` — returns Unicode code point at index.
fn builtin_code_point_at(args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    let s = args.first().map(|v| v.to_string()).unwrap_or_default();
    let idx = args.get(1).map(|v| v.to_int()).unwrap_or(0);
    let chars: Vec<char> = s.chars().collect();
    let idx = if idx < 0 {
        chars.len() as i64 + idx
    } else {
        idx
    };
    if idx >= 0 && (idx as usize) < chars.len() {
        Ok(StrykeValue::integer(chars[idx as usize] as i64))
    } else {
        Ok(StrykeValue::UNDEF)
    }
}

/// `from_code_point CODE` — converts code point to character.
fn builtin_from_code_point(args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    let code = args.first().map(|v| v.to_int() as u32).unwrap_or(0);
    if let Some(c) = char::from_u32(code) {
        Ok(StrykeValue::string(c.to_string()))
    } else {
        Ok(StrykeValue::UNDEF)
    }
}

/// `normalize_spaces STR` — collapses whitespace to single spaces.
fn builtin_normalize_spaces(interp: &VMHelper, args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    let s = first_arg_or_topic(interp, args).to_string();
    let normalized: String = s.split_whitespace().collect::<Vec<_>>().join(" ");
    Ok(StrykeValue::string(normalized))
}

/// `remove_whitespace STR` — removes all whitespace.
fn builtin_remove_whitespace(interp: &VMHelper, args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    let s = first_arg_or_topic(interp, args).to_string();
    let result: String = s.chars().filter(|c| !c.is_whitespace()).collect();
    Ok(StrykeValue::string(result))
}

/// `pluralize WORD, COUNT` — simple pluralization.
fn builtin_pluralize(args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    let word = args.first().map(|v| v.to_string()).unwrap_or_default();
    let count = args.get(1).map(|v| v.to_int()).unwrap_or(1);
    if count == 1 {
        Ok(StrykeValue::string(word))
    } else if word.ends_with('s')
        || word.ends_with('x')
        || word.ends_with("ch")
        || word.ends_with("sh")
    {
        Ok(StrykeValue::string(format!("{}es", word)))
    } else if word.ends_with('y')
        && !word.ends_with("ay")
        && !word.ends_with("ey")
        && !word.ends_with("oy")
        && !word.ends_with("uy")
    {
        Ok(StrykeValue::string(format!(
            "{}ies",
            &word[..word.len() - 1]
        )))
    } else {
        Ok(StrykeValue::string(format!("{}s", word)))
    }
}

/// `ordinalize NUM` — converts number to ordinal (1st, 2nd, 3rd, etc).
fn builtin_ordinalize(args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    let n = args.first().map(|v| v.to_int()).unwrap_or(0);
    let suffix = match (n % 10, n % 100) {
        (1, 11) | (2, 12) | (3, 13) => "th",
        (1, _) => "st",
        (2, _) => "nd",
        (3, _) => "rd",
        _ => "th",
    };
    Ok(StrykeValue::string(format!("{}{}", n, suffix)))
}

/// `parse_int STR [, RADIX]` — parse string to integer.
fn builtin_parse_int(args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    let s = args.first().map(|v| v.to_string()).unwrap_or_default();
    let radix = args.get(1).map(|v| v.to_int() as u32).unwrap_or(10);
    match i64::from_str_radix(s.trim(), radix) {
        Ok(n) => Ok(StrykeValue::integer(n)),
        Err(_) => Ok(StrykeValue::UNDEF),
    }
}

/// `parse_float STR` — parse string to float.
fn builtin_parse_float(args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    let s = args.first().map(|v| v.to_string()).unwrap_or_default();
    match s.trim().parse::<f64>() {
        Ok(n) => Ok(StrykeValue::float(n)),
        Err(_) => Ok(StrykeValue::UNDEF),
    }
}

/// `parse_bool STR` — parse string to boolean.
fn builtin_parse_bool(args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    let s = args
        .first()
        .map(|v| v.to_string())
        .unwrap_or_default()
        .to_lowercase();
    match s.as_str() {
        "true" | "yes" | "on" | "1" => Ok(bool_iv(true)),
        "false" | "no" | "off" | "0" | "" => Ok(bool_iv(false)),
        _ => Ok(StrykeValue::UNDEF),
    }
}

/// `levenshtein STR1, STR2` — Levenshtein edit distance.
fn builtin_levenshtein(args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    let s1 = args.first().map(|v| v.to_string()).unwrap_or_default();
    let s2 = args.get(1).map(|v| v.to_string()).unwrap_or_default();
    let s1: Vec<char> = s1.chars().collect();
    let s2: Vec<char> = s2.chars().collect();
    let m = s1.len();
    let n = s2.len();
    let mut dp = vec![vec![0usize; n + 1]; m + 1];
    for (i, row) in dp.iter_mut().enumerate().take(m + 1) {
        row[0] = i;
    }
    for (j, cell) in dp[0].iter_mut().enumerate().take(n + 1) {
        *cell = j;
    }
    for i in 1..=m {
        for j in 1..=n {
            let cost = if s1[i - 1] == s2[j - 1] { 0 } else { 1 };
            dp[i][j] = (dp[i - 1][j] + 1)
                .min(dp[i][j - 1] + 1)
                .min(dp[i - 1][j - 1] + cost);
        }
    }
    Ok(StrykeValue::integer(dp[m][n] as i64))
}

/// `soundex STR` — Soundex phonetic encoding.
fn builtin_soundex(args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    let s = args
        .first()
        .map(|v| v.to_string())
        .unwrap_or_default()
        .to_uppercase();
    if s.is_empty() {
        return Ok(StrykeValue::string("".to_string()));
    }
    let chars: Vec<char> = s.chars().filter(|c| c.is_ascii_alphabetic()).collect();
    if chars.is_empty() {
        return Ok(StrykeValue::string("".to_string()));
    }
    let code = |c: char| -> char {
        match c {
            'B' | 'F' | 'P' | 'V' => '1',
            'C' | 'G' | 'J' | 'K' | 'Q' | 'S' | 'X' | 'Z' => '2',
            'D' | 'T' => '3',
            'L' => '4',
            'M' | 'N' => '5',
            'R' => '6',
            _ => '0',
        }
    };
    let mut result = String::with_capacity(4);
    result.push(chars[0]);
    let mut prev = code(chars[0]);
    for &c in &chars[1..] {
        let curr = code(c);
        if curr != '0' && curr != prev {
            result.push(curr);
            if result.len() == 4 {
                break;
            }
        }
        prev = curr;
    }
    while result.len() < 4 {
        result.push('0');
    }
    Ok(StrykeValue::string(result))
}

/// `similarity STR1, STR2` — returns similarity ratio 0.0-1.0.
fn builtin_similarity(args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    let s1 = args.first().map(|v| v.to_string()).unwrap_or_default();
    let s2 = args.get(1).map(|v| v.to_string()).unwrap_or_default();
    if s1.is_empty() && s2.is_empty() {
        return Ok(StrykeValue::float(1.0));
    }
    let max_len = s1.len().max(s2.len());
    if max_len == 0 {
        return Ok(StrykeValue::float(1.0));
    }
    let s1c: Vec<char> = s1.chars().collect();
    let s2c: Vec<char> = s2.chars().collect();
    let m = s1c.len();
    let n = s2c.len();
    let mut dp = vec![vec![0usize; n + 1]; m + 1];
    for (i, row) in dp.iter_mut().enumerate().take(m + 1) {
        row[0] = i;
    }
    for (j, cell) in dp[0].iter_mut().enumerate().take(n + 1) {
        *cell = j;
    }
    for i in 1..=m {
        for j in 1..=n {
            let cost = if s1c[i - 1] == s2c[j - 1] { 0 } else { 1 };
            dp[i][j] = (dp[i - 1][j] + 1)
                .min(dp[i][j - 1] + 1)
                .min(dp[i - 1][j - 1] + cost);
        }
    }
    let dist = dp[m][n];
    Ok(StrykeValue::float(1.0 - (dist as f64 / max_len as f64)))
}

/// `common_prefix STR1, STR2` — longest common prefix.
fn builtin_common_prefix(args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    let s1 = args.first().map(|v| v.to_string()).unwrap_or_default();
    let s2 = args.get(1).map(|v| v.to_string()).unwrap_or_default();
    let prefix: String = s1
        .chars()
        .zip(s2.chars())
        .take_while(|(a, b)| a == b)
        .map(|(a, _)| a)
        .collect();
    Ok(StrykeValue::string(prefix))
}

/// `common_suffix STR1, STR2` — longest common suffix.
fn builtin_common_suffix(args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    let s1 = args.first().map(|v| v.to_string()).unwrap_or_default();
    let s2 = args.get(1).map(|v| v.to_string()).unwrap_or_default();
    let suffix: String = s1
        .chars()
        .rev()
        .zip(s2.chars().rev())
        .take_while(|(a, b)| a == b)
        .map(|(a, _)| a)
        .collect::<String>()
        .chars()
        .rev()
        .collect();
    Ok(StrykeValue::string(suffix))
}

/// `wrap_text STR, WIDTH` — wraps text to width.
fn builtin_wrap_text(args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    let text = args.first().map(|v| v.to_string()).unwrap_or_default();
    let width = args
        .get(1)
        .map(|v| v.to_int().max(1) as usize)
        .unwrap_or(80);
    let mut result = String::new();
    let mut line_len = 0;
    for word in text.split_whitespace() {
        if line_len + word.len() + 1 > width && line_len > 0 {
            result.push('\n');
            line_len = 0;
        }
        if line_len > 0 {
            result.push(' ');
            line_len += 1;
        }
        result.push_str(word);
        line_len += word.len();
    }
    Ok(StrykeValue::string(result))
}

/// `dedent STR` — removes common leading whitespace from lines.
fn builtin_dedent(args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    let text = args.first().map(|v| v.to_string()).unwrap_or_default();
    let lines: Vec<&str> = text.lines().collect();
    let min_indent = lines
        .iter()
        .filter(|l| !l.trim().is_empty())
        .map(|l| l.len() - l.trim_start().len())
        .min()
        .unwrap_or(0);
    let result: String = lines
        .iter()
        .map(|l| {
            if l.len() >= min_indent {
                &l[min_indent..]
            } else {
                *l
            }
        })
        .collect::<Vec<_>>()
        .join("\n");
    Ok(StrykeValue::string(result))
}

/// `indent STR, PREFIX` — adds prefix to each line.
fn builtin_indent(args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    let text = args.first().map(|v| v.to_string()).unwrap_or_default();
    let prefix = args
        .get(1)
        .map(|v| v.to_string())
        .unwrap_or_else(|| "  ".to_string());
    let result: String = text
        .lines()
        .map(|l| format!("{}{}", prefix, l))
        .collect::<Vec<_>>()
        .join("\n");
    Ok(StrykeValue::string(result))
}

// ─────────────────────────────────────────────────────────────────────────
// Extended stdlib: Advanced Numeric/Math
// ─────────────────────────────────────────────────────────────────────────

/// `lerp A, B, T` — linear interpolation.
fn builtin_lerp(args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    let a = args.first().map(|v| v.to_number()).unwrap_or(0.0);
    let b = args.get(1).map(|v| v.to_number()).unwrap_or(1.0);
    let t = args.get(2).map(|v| v.to_number()).unwrap_or(0.5);
    Ok(StrykeValue::float(a + (b - a) * t))
}

/// `inv_lerp A, B, V` — inverse linear interpolation.
fn builtin_inv_lerp(args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    let a = args.first().map(|v| v.to_number()).unwrap_or(0.0);
    let b = args.get(1).map(|v| v.to_number()).unwrap_or(1.0);
    let v = args.get(2).map(|v| v.to_number()).unwrap_or(0.5);
    if (b - a).abs() < f64::EPSILON {
        return Ok(StrykeValue::float(0.0));
    }
    Ok(StrykeValue::float((v - a) / (b - a)))
}

/// `smoothstep EDGE0, EDGE1, X` — smooth Hermite interpolation.
fn builtin_smoothstep(args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    let edge0 = args.first().map(|v| v.to_number()).unwrap_or(0.0);
    let edge1 = args.get(1).map(|v| v.to_number()).unwrap_or(1.0);
    let x = args.get(2).map(|v| v.to_number()).unwrap_or(0.5);
    let t = ((x - edge0) / (edge1 - edge0)).clamp(0.0, 1.0);
    Ok(StrykeValue::float(t * t * (3.0 - 2.0 * t)))
}

/// `remap VALUE, IN_MIN, IN_MAX, OUT_MIN, OUT_MAX` — remap value from one range to another.
fn builtin_remap(args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    let value = args.first().map(|v| v.to_number()).unwrap_or(0.0);
    let in_min = args.get(1).map(|v| v.to_number()).unwrap_or(0.0);
    let in_max = args.get(2).map(|v| v.to_number()).unwrap_or(1.0);
    let out_min = args.get(3).map(|v| v.to_number()).unwrap_or(0.0);
    let out_max = args.get(4).map(|v| v.to_number()).unwrap_or(1.0);
    if (in_max - in_min).abs() < f64::EPSILON {
        return Ok(StrykeValue::float(out_min));
    }
    let t = (value - in_min) / (in_max - in_min);
    Ok(StrykeValue::float(out_min + (out_max - out_min) * t))
}

/// `dot_product VEC1, VEC2` — dot product of two vectors.
#[allow(dead_code)]
fn builtin_dot_product(args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    let v1 = arg_to_vec(&args.first().cloned().unwrap_or(StrykeValue::UNDEF));
    let v2 = arg_to_vec(&args.get(1).cloned().unwrap_or(StrykeValue::UNDEF));
    let sum: f64 = v1
        .iter()
        .zip(v2.iter())
        .map(|(a, b)| a.to_number() * b.to_number())
        .sum();
    Ok(StrykeValue::float(sum))
}

/// `cross_product VEC1, VEC2` — cross product of 3D vectors.
fn builtin_cross_product(args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    let v1 = arg_to_vec(&args.first().cloned().unwrap_or(StrykeValue::UNDEF));
    let v2 = arg_to_vec(&args.get(1).cloned().unwrap_or(StrykeValue::UNDEF));
    if v1.len() < 3 || v2.len() < 3 {
        return Err(StrykeError::runtime(
            "cross_product: vectors must have at least 3 elements",
            0,
        ));
    }
    let (a1, a2, a3) = (v1[0].to_number(), v1[1].to_number(), v1[2].to_number());
    let (b1, b2, b3) = (v2[0].to_number(), v2[1].to_number(), v2[2].to_number());
    Ok(StrykeValue::array(vec![
        StrykeValue::float(a2 * b3 - a3 * b2),
        StrykeValue::float(a3 * b1 - a1 * b3),
        StrykeValue::float(a1 * b2 - a2 * b1),
    ]))
}

/// `magnitude VEC` — magnitude/length of vector.
fn builtin_magnitude(args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    let v = flatten_args(args);
    let sum_sq: f64 = v.iter().map(|x| x.to_number().powi(2)).sum();
    Ok(StrykeValue::float(sum_sq.sqrt()))
}

/// `normalize_vec VEC` — normalizes vector to unit length.
fn builtin_normalize_vec(args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    let v = flatten_args(args);
    let mag: f64 = v.iter().map(|x| x.to_number().powi(2)).sum::<f64>().sqrt();
    if mag < f64::EPSILON {
        return Ok(StrykeValue::array(v));
    }
    let result: Vec<StrykeValue> = v
        .iter()
        .map(|x| StrykeValue::float(x.to_number() / mag))
        .collect();
    Ok(StrykeValue::array(result))
}

/// `distance VEC1, VEC2` — Euclidean distance between vectors.
fn builtin_distance(args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    let v1 = arg_to_vec(&args.first().cloned().unwrap_or(StrykeValue::UNDEF));
    let v2 = arg_to_vec(&args.get(1).cloned().unwrap_or(StrykeValue::UNDEF));
    let sum_sq: f64 = v1
        .iter()
        .zip(v2.iter())
        .map(|(a, b)| (a.to_number() - b.to_number()).powi(2))
        .sum();
    Ok(StrykeValue::float(sum_sq.sqrt()))
}

/// `manhattan_distance VEC1, VEC2` — Manhattan/taxicab distance.
#[allow(dead_code)]
fn builtin_manhattan_distance(args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    let v1 = arg_to_vec(&args.first().cloned().unwrap_or(StrykeValue::UNDEF));
    let v2 = arg_to_vec(&args.get(1).cloned().unwrap_or(StrykeValue::UNDEF));
    let sum: f64 = v1
        .iter()
        .zip(v2.iter())
        .map(|(a, b)| (a.to_number() - b.to_number()).abs())
        .sum();
    Ok(StrykeValue::float(sum))
}

/// `covariance LIST1, LIST2` — sample covariance.
fn builtin_covariance(args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    let xs = arg_to_vec(&args.first().cloned().unwrap_or(StrykeValue::UNDEF));
    let ys = arg_to_vec(&args.get(1).cloned().unwrap_or(StrykeValue::UNDEF));
    let n = xs.len().min(ys.len());
    if n < 2 {
        return Ok(StrykeValue::float(0.0));
    }
    let mean_x: f64 = xs.iter().take(n).map(|x| x.to_number()).sum::<f64>() / n as f64;
    let mean_y: f64 = ys.iter().take(n).map(|y| y.to_number()).sum::<f64>() / n as f64;
    let cov: f64 = xs
        .iter()
        .zip(ys.iter())
        .take(n)
        .map(|(x, y)| (x.to_number() - mean_x) * (y.to_number() - mean_y))
        .sum::<f64>()
        / (n - 1) as f64;
    Ok(StrykeValue::float(cov))
}

/// `correlation LIST1, LIST2` — Pearson correlation coefficient.
fn builtin_correlation(args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    let xs = arg_to_vec(&args.first().cloned().unwrap_or(StrykeValue::UNDEF));
    let ys = arg_to_vec(&args.get(1).cloned().unwrap_or(StrykeValue::UNDEF));
    let n = xs.len().min(ys.len());
    if n < 2 {
        return Ok(StrykeValue::float(0.0));
    }
    let mean_x: f64 = xs.iter().take(n).map(|x| x.to_number()).sum::<f64>() / n as f64;
    let mean_y: f64 = ys.iter().take(n).map(|y| y.to_number()).sum::<f64>() / n as f64;
    let mut cov = 0.0;
    let mut var_x = 0.0;
    let mut var_y = 0.0;
    for i in 0..n {
        let dx = xs[i].to_number() - mean_x;
        let dy = ys[i].to_number() - mean_y;
        cov += dx * dy;
        var_x += dx * dx;
        var_y += dy * dy;
    }
    let denom = (var_x * var_y).sqrt();
    if denom < f64::EPSILON {
        return Ok(StrykeValue::float(0.0));
    }
    Ok(StrykeValue::float(cov / denom))
}

/// `iqr LIST` — interquartile range.
#[allow(dead_code)]
fn builtin_iqr(args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    let mut xs: Vec<f64> = flatten_args(args).iter().map(|x| x.to_number()).collect();
    if xs.len() < 4 {
        return Ok(StrykeValue::float(0.0));
    }
    xs.sort_by(|a, b| a.partial_cmp(b).unwrap_or(std::cmp::Ordering::Equal));
    let q1_idx = xs.len() / 4;
    let q3_idx = (3 * xs.len()) / 4;
    Ok(StrykeValue::float(xs[q3_idx] - xs[q1_idx]))
}

/// `quantile LIST, P` — returns p-th quantile (0.0-1.0).
fn builtin_quantile(args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    let xs = flatten_args(&args[..args.len().saturating_sub(1)]);
    let p = args
        .last()
        .map(|v| v.to_number())
        .unwrap_or(0.5)
        .clamp(0.0, 1.0);
    if xs.is_empty() {
        return Ok(StrykeValue::UNDEF);
    }
    let mut sorted: Vec<f64> = xs.iter().map(|x| x.to_number()).collect();
    sorted.sort_by(|a, b| a.partial_cmp(b).unwrap_or(std::cmp::Ordering::Equal));
    let idx = p * (sorted.len() - 1) as f64;
    let lo = idx.floor() as usize;
    let hi = idx.ceil() as usize;
    let frac = idx - lo as f64;
    Ok(StrykeValue::float(
        sorted[lo] * (1.0 - frac) + sorted[hi.min(sorted.len() - 1)] * frac,
    ))
}

/// `quantiles \@DATA, \@PROBS` — batch quantile lookup. Returns a list with
/// one element per probability in `\@PROBS`, computed via the same linear
/// Best-effort recursive size of `path`. Returns 0 on any I/O error,
/// caps the walk at ~250 entries so a runaway store doesn't make the
/// `doctor` builtin slow.
fn walk_size_bytes(path: &std::path::Path) -> Option<u64> {
    let md = std::fs::metadata(path).ok()?;
    if md.is_file() {
        return Some(md.len());
    }
    let mut total = 0u64;
    let mut visited = 0usize;
    let mut stack = vec![path.to_path_buf()];
    while let Some(dir) = stack.pop() {
        if visited > 250 {
            break;
        }
        let Ok(rd) = std::fs::read_dir(&dir) else {
            continue;
        };
        for ent in rd.flatten() {
            visited += 1;
            if visited > 250 {
                break;
            }
            let Ok(m) = ent.metadata() else { continue };
            if m.is_file() {
                total += m.len();
            } else if m.is_dir() {
                stack.push(ent.path());
            }
        }
    }
    Some(total)
}

/// Human-readable bytes (KB/MB/GB) — for `doctor`'s path summary.
fn human_bytes(n: u64) -> String {
    const KB: u64 = 1024;
    const MB: u64 = KB * 1024;
    const GB: u64 = MB * 1024;
    if n >= GB {
        format!("{:.1} GB", n as f64 / GB as f64)
    } else if n >= MB {
        format!("{:.1} MB", n as f64 / MB as f64)
    } else if n >= KB {
        format!("{:.1} KB", n as f64 / KB as f64)
    } else {
        format!("{} B", n)
    }
}

/// `doctor` / `health` — runtime diagnostics. Prints a colored
/// report covering version, paths, runtime flags, environment overrides,
/// builtin counts, worker-pool size, and toolchain availability. Returns
/// the number of warnings found (0 = healthy).
///
/// Designed to be a stryke-script-callable builtin (`s -e 'doctor'`)
/// rather than a CLI subcommand, so it can introspect the live runtime
/// state — `%b` / `%all` counts, current `compat_mode()` /
/// `no_interop_mode()` settings, scope-level bindings, etc.
fn builtin_doctor(interp: &mut VMHelper, _args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    use std::io::IsTerminal;
    let isatty = std::io::stdout().is_terminal();
    let (c, g, y, r, b, d, n) = if isatty {
        (
            "\x1b[36m",   // cyan
            "\x1b[32m",   // green
            "\x1b[1;33m", // yellow
            "\x1b[31m",   // red
            "\x1b[1m",    // bold
            "\x1b[2m",    // dim
            "\x1b[0m",    // reset
        )
    } else {
        ("", "", "", "", "", "", "")
    };

    let mut warnings = 0usize;
    let mut out = String::new();

    let banner = format!(
        "{c}╔══════════════════════════════════════════════╗{n}\n\
         {c}║{n}  {b}STRYKE DOCTOR{n}  {d}//{n}  {g}runtime diagnostics{n}    {c}║{n}\n\
         {c}╚══════════════════════════════════════════════╝{n}\n"
    );
    out.push_str(&banner);

    // ── Version & binary ────────────────────────────────────────
    out.push_str(&format!("\n{b}>>  identity{n}\n"));
    out.push_str(&format!(
        "  {c}version{n}     {g}{}{n}\n",
        env!("CARGO_PKG_VERSION")
    ));
    let exe = std::env::current_exe()
        .map(|p| p.display().to_string())
        .unwrap_or_else(|_| "<unknown>".to_string());
    out.push_str(&format!("  {c}binary{n}      {}\n", exe));
    let build_profile = if cfg!(debug_assertions) {
        format!("{y}debug{n} {d}(use cargo build --release for production){n}")
    } else {
        format!("{g}release{n}")
    };
    out.push_str(&format!("  {c}build{n}       {}\n", build_profile));
    let triple = format!("{}-{}", std::env::consts::OS, std::env::consts::ARCH);
    out.push_str(&format!("  {c}target{n}      {}\n", triple));

    // ── Runtime flags ───────────────────────────────────────────
    out.push_str(&format!("\n{b}>>  runtime flags{n}\n"));
    let yn = |v: bool| {
        if v {
            format!("{g}on{n}")
        } else {
            format!("{d}off{n}")
        }
    };
    out.push_str(&format!(
        "  {c}--compat{n}            {}\n",
        yn(crate::compat_mode())
    ));
    out.push_str(&format!(
        "  {c}--no-interop{n}        {}\n",
        yn(crate::no_interop_mode())
    ));
    out.push_str(&format!(
        "  {c}use bigint{n}          {}\n",
        yn(crate::bigint_pragma())
    ));
    out.push_str(&format!(
        "  {c}strict_vars{n}         {}\n",
        yn(interp.strict_vars)
    ));
    out.push_str(&format!(
        "  {c}strict_refs{n}         {}\n",
        yn(interp.strict_refs)
    ));

    // ── Environment overrides ───────────────────────────────────
    out.push_str(&format!("\n{b}>>  environment{n}\n"));
    let env_check = |name: &str| -> String {
        match std::env::var(name) {
            Ok(v) if !v.is_empty() => format!("{g}{}{n}", v),
            _ => format!("{d}unset{n}"),
        }
    };
    for var in [
        "STRYKE_NO_TTY",
        "NO_TTY",
        "STRYKE_NO_JIT",
        "STRYKE_NO_CACHE",
        "STRYKE_PROFILE",
        "RUST_LOG",
    ] {
        out.push_str(&format!("  {c}{:18}{n} {}\n", var, env_check(var)));
    }

    // ── Builtin / reflection counts ─────────────────────────────
    out.push_str(&format!("\n{b}>>  reflection{n}\n"));
    let primaries = CATEGORY_MAP.len();
    let all_spellings = ALL_CATEGORY_MAP.len();
    let aliases = all_spellings.saturating_sub(primaries);
    let categories = {
        let mut seen = std::collections::HashSet::new();
        for (_, c) in CATEGORY_MAP {
            seen.insert(*c);
        }
        seen.len()
    };
    out.push_str(&format!(
        "  {c}primaries{n}           {g}{}{n}\n",
        primaries
    ));
    out.push_str(&format!("  {c}aliases{n}             {g}{}{n}\n", aliases));
    out.push_str(&format!(
        "  {c}all spellings (%all){n} {g}{}{n}\n",
        all_spellings
    ));
    out.push_str(&format!(
        "  {c}categories{n}          {g}{}{n}\n",
        categories
    ));
    out.push_str(&format!(
        "  {c}list builtins{n}       {g}{}{n}\n",
        crate::list_builtins::LIST_BUILTIN_NAMES.len()
    ));

    // ── Concurrency ─────────────────────────────────────────────
    out.push_str(&format!("\n{b}>>  concurrency{n}\n"));
    let n_cpus = std::thread::available_parallelism()
        .map(|n| n.get())
        .unwrap_or(1);
    out.push_str(&format!("  {c}logical cpus{n}        {g}{}{n}\n", n_cpus));
    let rayon_threads = rayon::current_num_threads();
    out.push_str(&format!(
        "  {c}rayon pool{n}          {g}{}{n}\n",
        rayon_threads
    ));

    // ── Stryke home & cache dirs ────────────────────────────────
    // Stryke uses a single `~/.stryke/` root for everything (matches
    // `~/.cargo/`, `~/.rustup/` style — not XDG / Library paths).
    // Honor `$STRYKE_HOME` if set (mirrors `pkg::store::Store::open`).
    out.push_str(&format!("\n{b}>>  paths{n}\n"));
    let stryke_home = std::env::var("STRYKE_HOME")
        .ok()
        .map(std::path::PathBuf::from)
        .or_else(|| dirs::home_dir().map(|p| p.join(".stryke")))
        .map(|p| p.display().to_string())
        .unwrap_or_else(|| "<unavailable>".to_string());
    let report_path = |p: &str| -> String {
        let pb = std::path::PathBuf::from(p);
        if pb.exists() {
            let size = walk_size_bytes(&pb).unwrap_or(0);
            format!("{} {d}({}){n}", p, human_bytes(size), d = d, n = n)
        } else {
            format!("{} {d}(missing){n}", p, d = d, n = n)
        }
    };
    let home = dirs::home_dir()
        .map(|p| p.display().to_string())
        .unwrap_or_else(|| "<unavailable>".to_string());
    out.push_str(&format!("  {c}$HOME{n}             {}\n", home));
    out.push_str(&format!(
        "  {c}stryke home{n}       {}\n",
        report_path(&stryke_home)
    ));
    let scripts_cache = format!("{}/scripts.rkyv", stryke_home);
    let store_dir = format!("{}/store", stryke_home);
    let bin_dir = format!("{}/bin", stryke_home);
    let history = format!("{}/history", stryke_home);
    let ffi_cache = format!("{}/ffi", stryke_home);
    out.push_str(&format!(
        "  {c}bytecode cache{n}    {}\n",
        report_path(&scripts_cache)
    ));
    out.push_str(&format!(
        "  {c}package store{n}     {}\n",
        report_path(&store_dir)
    ));
    out.push_str(&format!(
        "  {c}global bin{n}        {}\n",
        report_path(&bin_dir)
    ));
    out.push_str(&format!(
        "  {c}repl history{n}      {}\n",
        report_path(&history)
    ));
    out.push_str(&format!(
        "  {c}rust FFI cache{n}    {}\n",
        report_path(&ffi_cache)
    ));

    // ── Toolchain detection (best-effort) ───────────────────────
    out.push_str(&format!("\n{b}>>  toolchain{n}\n"));
    let which = |bin: &str| -> Option<String> {
        std::process::Command::new(bin)
            .arg("--version")
            .output()
            .ok()
            .and_then(|o| {
                if o.status.success() {
                    String::from_utf8(o.stdout)
                        .ok()
                        .map(|s| s.lines().next().unwrap_or("").to_string())
                } else {
                    None
                }
            })
    };
    for bin in ["rustc", "cargo", "perl", "git", "rg"] {
        match which(bin) {
            Some(v) => out.push_str(&format!("  {g}✓{n} {c}{:6}{n}  {d}{}{n}\n", bin, v)),
            None => {
                out.push_str(&format!("  {y}—{n} {c}{:6}{n}  {d}not on PATH{n}\n", bin));
            }
        }
    }

    // ── Sanity checks ───────────────────────────────────────────
    out.push_str(&format!("\n{b}>>  sanity{n}\n"));
    let check = |label: &str, ok: bool, detail: &str, warn: &mut usize| -> String {
        if ok {
            format!("  {g}✓{n} {c}{:32}{n}  {d}{}{n}\n", label, detail)
        } else {
            *warn += 1;
            format!("  {r}✗{n} {c}{:32}{n}  {d}{}{n}\n", label, detail)
        }
    };
    out.push_str(&check(
        "primaries non-empty",
        primaries > 0,
        &format!("{} dispatch primaries", primaries),
        &mut warnings,
    ));
    out.push_str(&check(
        "all-spellings ⊇ primaries",
        all_spellings >= primaries,
        &format!("{} ≥ {}", all_spellings, primaries),
        &mut warnings,
    ));
    out.push_str(&check(
        "rayon pool ≥ 1",
        rayon_threads >= 1,
        &format!("{} threads", rayon_threads),
        &mut warnings,
    ));
    out.push_str(&check(
        "stryke home resolved",
        !stryke_home.starts_with('<'),
        &stryke_home,
        &mut warnings,
    ));
    let categorized = CATEGORY_MAP
        .iter()
        .filter(|(_, c)| *c != "uncategorized")
        .count();
    let uncategorized = primaries.saturating_sub(categorized);
    out.push_str(&check(
        "no uncategorized primaries",
        uncategorized == 0,
        &format!("{} uncategorized", uncategorized),
        &mut warnings,
    ));

    // ── Summary ─────────────────────────────────────────────────
    out.push_str(&format!("\n{b}>>  summary{n}\n"));
    if warnings == 0 {
        out.push_str(&format!("  {g}✓ healthy{n}  {d}no warnings{n}\n"));
    } else {
        out.push_str(&format!(
            "  {y}⚠ {} warning{}{n}\n",
            warnings,
            if warnings == 1 { "" } else { "s" }
        ));
    }

    print!("{}", out);
    Ok(StrykeValue::integer(warnings as i64))
}

/// `lsp_completion_words` (alias `lsp_words`) — emits every name LSP
/// tab-complete should know about, sorted ASCII. Three sources merged:
///
///   1. **`%stryke::all` keys** (`~9089` bare callable spellings,
///      primaries + aliases) — the bulk of the list.
///   2. **Sigil-prefixed reflection hashes / special vars** — `%a`,
///      `%b`, `%all`, `%parameters`, `%ENV`, `@ARGV`, `$stryke::VERSION`,
///      `@+`, `@-`, etc. Required so tab-complete works on
///      `keys %<TAB>` and similar.
///   3. **Stryke-language keywords** that aren't in `%all` (`fn`,
///      `match`, `class`, `struct`, `enum`, `mysync`, `oursync`,
///      `frozen`, `const`, `typed`, …) so users can complete them
///      after typing the first letter.
///
/// The file `strykelang/lsp_completion_words.txt` is the canonical
/// snapshot. Regenerate it with:
///
/// ```sh
/// stryke -e 'lsp_completion_words |> e p' > strykelang/lsp_completion_words.txt
/// ```
///
/// Two consumers read the file:
///   * `static_analysis.rs` checks bare-name hits via `is_sub_defined`
///     — sigil-prefixed entries are inert there (never matched against
///     a bare-name lookup).
///   * The LSP completion provider uses every entry as a candidate.
///
/// Internal compiler-generated scratch names (`__foreach_list__`,
/// `__foreach_i__`, `__pf_foreach_list__`, `__pf_foreach_i__`,
/// `__list_assign_tmp__`, `__list_assign_swap__`, …) are interned into
/// scope when the compiler emits postfix-foreach / list-assign / etc.,
/// then leak through `refresh_parameters_hash`. Filter them so they
/// never surface in `lsp_words` / completion / `s docs --list-all`.
/// Perl-defined `__NAME__` tokens (`__FILE__`, `__LINE__`,
/// `__PACKAGE__`, `__SUB__`, `__DATA__`, `__END__`) stay because
/// they're user-facing.
fn is_internal_scratch_name(name: &str) -> bool {
    let bare = match name.as_bytes().first() {
        Some(b'$') | Some(b'@') | Some(b'%') | Some(b'&') => &name[1..],
        _ => name,
    };
    if matches!(
        bare,
        "__FILE__" | "__LINE__" | "__PACKAGE__" | "__SUB__" | "__DATA__" | "__END__"
    ) {
        return false;
    }
    bare.starts_with("__") && bare.ends_with("__") && bare.len() > 4
}

fn builtin_lsp_completion_words(
    interp: &mut VMHelper,
    _args: &[StrykeValue],
) -> StrykeResult<StrykeValue> {
    use std::collections::BTreeSet;
    let mut set: BTreeSet<String> = BTreeSet::new();

    // Source 1: every bare-name dispatch spelling (primary + alias)
    // that `build.rs` parsed from the main `try_builtin` arms.
    for (n, _) in ALL_CATEGORY_MAP {
        set.insert((*n).to_string());
    }

    // Source 1b: list builtins routed through `list_builtins::dispatch_by_name`
    // (sum, min, max, pairs, blessed, refaddr, etc.). build.rs also picks
    // these up now (scans `LIST_BUILTIN_NAMES`) so they show in `%b`/`%all`,
    // but include them here too as a belt-and-braces guard against drift.
    for n in crate::list_builtins::LIST_BUILTIN_NAMES {
        set.insert((*n).to_string());
    }

    // Source 2: every sigil-prefixed binding the runtime knows about —
    // `%a`, `%all`, `%b`, `%parameters`, `@ARGV`, `@INC`, `@fpath`,
    // `@path`, `$_`, `$stryke::VERSION`, etc.
    //
    // The reflection hashes (`%a`/`%b`/`%c`/…/`%stryke::*`) are lazily
    // installed on first access to keep cold-start under 4 ms. We have
    // to force that lazy init *before* refreshing `%parameters`, or
    // the snapshot misses every reflection hash on a script that
    // never read them. Then `refresh_parameters_hash` walks the now-
    // complete scope and rebuilds the materialized table.
    interp.ensure_reflection_hashes();
    interp.refresh_parameters_hash();
    let params_snapshot = interp.scope.get_hash("parameters");
    for name in params_snapshot.keys() {
        if is_internal_scratch_name(name) {
            continue;
        }
        set.insert(name.clone());
        // Also emit the `main::`-qualified spelling for every
        // unqualified binding so tab-complete on `$main::<TAB>` /
        // `@main::<TAB>` / `%main::<TAB>` surfaces every live name.
        if !name.contains("::") && name.len() > 1 {
            let (sigil, rest) = name.split_at(1);
            if matches!(sigil, "$" | "@" | "%") {
                set.insert(format!("{sigil}main::{rest}"));
            }
        }
    }

    // Source 3: every callable bare-name also lives under the `CORE::`
    // pseudo-package — `CORE::print`, `CORE::sum`, `CORE::sprintf`, etc.
    // all dispatch identically at runtime (`try_builtin` strips the
    // prefix). Surface the prefixed spelling so tab-complete on
    // `CORE::<TAB>` finds every builtin. `main::{name}` is NOT emitted
    // here: builtins live in CORE::, not main::. A user calling
    // `main::sort()` resolves to a *user-defined* sub in package main
    // (if any), not the builtin — so seeding `main::sort` would
    // promise something the runtime doesn't deliver. User-defined
    // subs in main are picked up live from the AST walk.
    let bare_names: Vec<String> = set
        .iter()
        .filter(|n| {
            // Bare-name candidates: no sigil prefix, no `::`, real ident.
            !n.is_empty()
                && !n.contains("::")
                && !n.starts_with('$')
                && !n.starts_with('@')
                && !n.starts_with('%')
                && !n.starts_with('&')
        })
        .cloned()
        .collect();
    for n in bare_names {
        set.insert(format!("CORE::{n}"));
    }

    // Source 3: stryke language keywords. `%all` covers callable builtins;
    // these are reserved keywords that the parser handles directly and
    // that tab-complete should still suggest after the first character.
    // Single source of truth: the module-level `KEYWORDS` table (also
    // drives `%k`).
    for (name, _) in KEYWORDS {
        set.insert((*name).to_string());
    }
    // Source 3b: completion-only extras that aren't in any reflection
    // map — pseudo-namespaces with hand-written hover docs (`CORE`,
    // `main`), lifecycle hooks (`DESTROY`, `BUILD`), and a few not-yet-
    // keyword identifiers (`abstract`, `final`) that LSP completion
    // should still surface. Excluded here: `die` / `warn` (callable
    // builtins, already in `CATEGORY_MAP` → covered by Source 1) and
    // every name in `%k` (covered by Source 3 above).
    const COMPLETION_EXTRAS: &[&str] = &["CORE", "main", "abstract", "final", "DESTROY", "BUILD"];
    for k in COMPLETION_EXTRAS {
        set.insert((*k).to_string());
    }

    // Source 4: Perl special variables. These are documented punctuation
    // names — the runtime may not have them in scope when `lsp_words`
    // runs (e.g. no `<>` read yet, no eval error pending), so the scope
    // walk above misses them. Hard-code the canonical list so LSP /
    // REPL / `s docs --list-all` always offer them on `$<TAB>`.
    const SPECIAL_VARS: &[&str] = &[
        // Topic + match-related scalars
        "$_",
        "$&",
        "$`",
        "$'",
        "$+",
        "$^N",
        "$^R",
        // Regex captures (1..9 — beyond that users use @+ / @-)
        "$1",
        "$2",
        "$3",
        "$4",
        "$5",
        "$6",
        "$7",
        "$8",
        "$9",
        // I/O record / field / list separators
        "$/",
        "$\\",
        "$,",
        "$;",
        "$\"",
        "$.",
        // Process / runtime state
        "$0",
        "$$",
        "$!",
        "$?",
        "$@",
        "$|",
        "$<",
        "$>",
        "$(",
        "$)",
        // ^FOO control vars
        "$^O",
        "$^V",
        "$^X",
        "$^W",
        "$^I",
        "$^T",
        "$^P",
        "$^F",
        "$^A",
        "$^C",
        "$^D",
        "$^E",
        "$^H",
        "$^L",
        "$^M",
        "$^N",
        "$^R",
        "$^S",
        // ARGV current-input scalar
        "$ARGV",
        // awk record vars (populated in the -n/-p loop)
        "$NR",
        "$NF",
        "$FNR",
        // stryke version (mirrored from %stryke::VERSION)
        "$stryke::VERSION",
        // Punctuation arrays
        "@_",
        "@+",
        "@-",
        "@F",
        "@ARGV",
        "@INC",
        "@ENV",
        "@^CAPTURE",
        "@^CAPTURE_ALL",
        // Punctuation hashes
        "%ENV",
        "%SIG",
        "%INC",
        "%ENV",
        "%^H",
    ];
    for v in SPECIAL_VARS {
        set.insert((*v).to_string());
        // Also emit `main::`-qualified spellings for the named ones so
        // tab-complete on `$main::<TAB>` / `@main::<TAB>` / `%main::<TAB>`
        // surfaces them too. Skip punctuation-only names (`$_`, `$/`,
        // …) since `main::/` etc are not valid Perl spellings.
        if v.len() <= 1 {
            continue;
        }
        let (sigil, rest) = v.split_at(1);
        if !matches!(sigil, "$" | "@" | "%") {
            continue;
        }
        if rest.contains("::") {
            continue;
        }
        if rest
            .chars()
            .next()
            .map(|c| c.is_ascii_alphabetic() || c == '_')
            .unwrap_or(false)
        {
            set.insert(format!("{sigil}main::{rest}"));
        }
    }

    // Source 5: Special bareword filehandles forced into main per Perl
    // semantics. These have NO sigil — `print STDOUT "hi"` works,
    // `print main::STDOUT "hi"` does NOT (the parser sees it as a sub
    // call). Only the bare forms go in the wordlist; no `main::` alias.
    const SPECIAL_FILEHANDLES: &[&str] = &["STDIN", "STDOUT", "STDERR", "ARGV", "ARGVOUT", "DATA"];
    for fh in SPECIAL_FILEHANDLES {
        set.insert((*fh).to_string());
    }

    Ok(StrykeValue::array(
        set.into_iter().map(StrykeValue::string).collect(),
    ))
}

/// interpolation as `quantile`. Sorts the data exactly once across all
/// probability points so callers don't pay an O(n log n) sort per quantile.
fn builtin_quantiles(args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    if args.len() < 2 {
        return Ok(StrykeValue::array(Vec::new()));
    }
    // Data side: accept either a single arrayref or a flat list of all but
    // the last argument (which is the probability list).
    let data_vec: Vec<StrykeValue> = if let Some(r) = args[0].as_array_ref() {
        r.read().clone()
    } else {
        flatten_args(&args[..args.len() - 1])
    };
    if data_vec.is_empty() {
        return Ok(StrykeValue::array(Vec::new()));
    }
    let mut sorted: Vec<f64> = data_vec.iter().map(|x| x.to_number()).collect();
    sorted.sort_by(|a, b| a.partial_cmp(b).unwrap_or(std::cmp::Ordering::Equal));
    // Probability side: an arrayref of probabilities (canonical) or a flat
    // tail list of probabilities after the data arg.
    let last = &args[args.len() - 1];
    let probs: Vec<f64> = if let Some(r) = last.as_array_ref() {
        r.read().iter().map(|v| v.to_number()).collect()
    } else {
        args[1..].iter().map(|v| v.to_number()).collect()
    };
    let n_minus_1 = (sorted.len() - 1) as f64;
    let max_idx = sorted.len() - 1;
    let out: Vec<StrykeValue> = probs
        .iter()
        .map(|p| {
            let p = p.clamp(0.0, 1.0);
            let idx = p * n_minus_1;
            let lo = idx.floor() as usize;
            let hi = idx.ceil() as usize;
            let frac = idx - lo as f64;
            StrykeValue::float(sorted[lo] * (1.0 - frac) + sorted[hi.min(max_idx)] * frac)
        })
        .collect();
    Ok(StrykeValue::array(out))
}

/// `clamp_int VALUE, MIN, MAX` — clamp integer value.
fn builtin_clamp_int(args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    let val = args.first().map(|v| v.to_int()).unwrap_or(0);
    let min = args.get(1).map(|v| v.to_int()).unwrap_or(i64::MIN);
    let max = args.get(2).map(|v| v.to_int()).unwrap_or(i64::MAX);
    Ok(StrykeValue::integer(val.clamp(min, max)))
}

/// `in_range VALUE, MIN, MAX` — returns true if value in range [min, max].
fn builtin_in_range(args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    let val = args.first().map(|v| v.to_number()).unwrap_or(0.0);
    let min = args.get(1).map(|v| v.to_number()).unwrap_or(0.0);
    let max = args.get(2).map(|v| v.to_number()).unwrap_or(1.0);
    Ok(bool_iv(val >= min && val <= max))
}

/// `wrap_range VALUE, MIN, MAX` — wraps value into range.
fn builtin_wrap_range(args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    let val = args.first().map(|v| v.to_number()).unwrap_or(0.0);
    let min = args.get(1).map(|v| v.to_number()).unwrap_or(0.0);
    let max = args.get(2).map(|v| v.to_number()).unwrap_or(1.0);
    let range = max - min;
    if range <= 0.0 {
        return Ok(StrykeValue::float(min));
    }
    let mut result = val;
    while result < min {
        result += range;
    }
    while result >= max {
        result -= range;
    }
    Ok(StrykeValue::float(result))
}

/// `sum_squares LIST` — sum of squares.
fn builtin_sum_squares(args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    let sum: f64 = flatten_args(args)
        .iter()
        .map(|x| x.to_number().powi(2))
        .sum();
    Ok(StrykeValue::float(sum))
}

/// `root_mean_square LIST` — RMS.
fn builtin_rms(args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    let xs = flatten_args(args);
    if xs.is_empty() {
        return Ok(StrykeValue::float(0.0));
    }
    let sum_sq: f64 = xs.iter().map(|x| x.to_number().powi(2)).sum();
    Ok(StrykeValue::float((sum_sq / xs.len() as f64).sqrt()))
}

/// `cumsum LIST` — cumulative sum.
fn builtin_cumsum(args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    let xs = flatten_args(args);
    let mut sum = 0.0;
    let result: Vec<StrykeValue> = xs
        .iter()
        .map(|x| {
            sum += x.to_number();
            StrykeValue::float(sum)
        })
        .collect();
    Ok(StrykeValue::array(result))
}

/// `cumprod LIST` — cumulative product.
fn builtin_cumprod(args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    let xs = flatten_args(args);
    let mut prod = 1.0;
    let result: Vec<StrykeValue> = xs
        .iter()
        .map(|x| {
            prod *= x.to_number();
            StrykeValue::float(prod)
        })
        .collect();
    Ok(StrykeValue::array(result))
}

/// `diff LIST` — differences between consecutive elements.
fn builtin_diff(args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    let xs = flatten_args(args);
    if xs.len() < 2 {
        return Ok(StrykeValue::array(vec![]));
    }
    let result: Vec<StrykeValue> = xs
        .windows(2)
        .map(|w| StrykeValue::float(w[1].to_number() - w[0].to_number()))
        .collect();
    Ok(StrykeValue::array(result))
}

// ─────────────────────────────────────────────────────────────────────────
// Extended stdlib: Date/Time
// ─────────────────────────────────────────────────────────────────────────

/// `add_days DATE, N` — add N days to Unix timestamp.
fn builtin_add_days(args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    let ts = args.first().map(|v| v.to_int()).unwrap_or(0);
    let days = args.get(1).map(|v| v.to_int()).unwrap_or(0);
    Ok(StrykeValue::integer(ts + days * 86400))
}

/// `add_hours DATE, N` — add N hours to Unix timestamp.
fn builtin_add_hours(args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    let ts = args.first().map(|v| v.to_int()).unwrap_or(0);
    let hours = args.get(1).map(|v| v.to_int()).unwrap_or(0);
    Ok(StrykeValue::integer(ts + hours * 3600))
}

/// `add_minutes DATE, N` — add N minutes to Unix timestamp.
fn builtin_add_minutes(args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    let ts = args.first().map(|v| v.to_int()).unwrap_or(0);
    let mins = args.get(1).map(|v| v.to_int()).unwrap_or(0);
    Ok(StrykeValue::integer(ts + mins * 60))
}

/// `diff_days DATE1, DATE2` — difference in days.
fn builtin_diff_days(args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    let ts1 = args.first().map(|v| v.to_int()).unwrap_or(0);
    let ts2 = args.get(1).map(|v| v.to_int()).unwrap_or(0);
    Ok(StrykeValue::integer((ts2 - ts1) / 86400))
}

/// `diff_hours DATE1, DATE2` — difference in hours.
fn builtin_diff_hours(args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    let ts1 = args.first().map(|v| v.to_int()).unwrap_or(0);
    let ts2 = args.get(1).map(|v| v.to_int()).unwrap_or(0);
    Ok(StrykeValue::integer((ts2 - ts1) / 3600))
}

/// `start_of_day TS` — returns timestamp at start of day.
fn builtin_start_of_day(args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    let ts = args.first().map(|v| v.to_int()).unwrap_or(0);
    Ok(StrykeValue::integer(ts - (ts % 86400)))
}

/// `end_of_day TS` — returns timestamp at end of day.
fn builtin_end_of_day(args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    let ts = args.first().map(|v| v.to_int()).unwrap_or(0);
    Ok(StrykeValue::integer(ts - (ts % 86400) + 86399))
}

/// `start_of_hour TS` — returns timestamp at start of hour.
fn builtin_start_of_hour(args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    let ts = args.first().map(|v| v.to_int()).unwrap_or(0);
    Ok(StrykeValue::integer(ts - (ts % 3600)))
}

/// `start_of_minute TS` — returns timestamp at start of minute.
fn builtin_start_of_minute(args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    let ts = args.first().map(|v| v.to_int()).unwrap_or(0);
    Ok(StrykeValue::integer(ts - (ts % 60)))
}

// ── dateutils-style builtins ────────────────────────────────────────────

/// Parse a date string (ISO 8601 or common formats) into a chrono NaiveDateTime.
fn parse_date_flexible(s: &str) -> Option<chrono::NaiveDateTime> {
    use chrono::NaiveDate;
    use chrono::NaiveDateTime;
    // Try ISO 8601 with T separator
    if let Ok(dt) = NaiveDateTime::parse_from_str(s, "%Y-%m-%dT%H:%M:%S") {
        return Some(dt);
    }
    if let Ok(dt) = NaiveDateTime::parse_from_str(s, "%Y-%m-%dT%H:%M:%S%.f") {
        return Some(dt);
    }
    // Space separator
    if let Ok(dt) = NaiveDateTime::parse_from_str(s, "%Y-%m-%d %H:%M:%S") {
        return Some(dt);
    }
    if let Ok(dt) = NaiveDateTime::parse_from_str(s, "%Y-%m-%d %H:%M:%S%.f") {
        return Some(dt);
    }
    if let Ok(dt) = NaiveDateTime::parse_from_str(s, "%Y-%m-%d %H:%M") {
        return Some(dt);
    }
    // Date only
    if let Ok(d) = NaiveDate::parse_from_str(s, "%Y-%m-%d") {
        return Some(d.and_hms_opt(0, 0, 0).unwrap());
    }
    if let Ok(d) = NaiveDate::parse_from_str(s, "%Y/%m/%d") {
        return Some(d.and_hms_opt(0, 0, 0).unwrap());
    }
    if let Ok(d) = NaiveDate::parse_from_str(s, "%m/%d/%Y") {
        return Some(d.and_hms_opt(0, 0, 0).unwrap());
    }
    if let Ok(d) = NaiveDate::parse_from_str(s, "%d-%b-%Y") {
        return Some(d.and_hms_opt(0, 0, 0).unwrap());
    }
    // Epoch integer/float
    if let Ok(epoch) = s.parse::<f64>() {
        return chrono::DateTime::from_timestamp(epoch as i64, 0).map(|dt| dt.naive_utc());
    }
    None
}

type DurationPattern = (&'static str, fn(i64) -> chrono::Duration);

/// Parse a duration string: "1d", "2w", "3h", "30m", "1y", "1mo", "1 week", etc.
fn parse_duration_str(s: &str) -> Option<chrono::Duration> {
    let s = s.trim().to_lowercase();
    // Try formats like "1d", "2w", "3h", "30m", "5s", "1y", "1mo"
    let re_patterns: &[DurationPattern] = &[
        ("seconds", |n| chrono::Duration::seconds(n)),
        ("second", |n| chrono::Duration::seconds(n)),
        ("secs", |n| chrono::Duration::seconds(n)),
        ("sec", |n| chrono::Duration::seconds(n)),
        ("minutes", |n| chrono::Duration::minutes(n)),
        ("minute", |n| chrono::Duration::minutes(n)),
        ("mins", |n| chrono::Duration::minutes(n)),
        ("min", |n| chrono::Duration::minutes(n)),
        ("hours", |n| chrono::Duration::hours(n)),
        ("hour", |n| chrono::Duration::hours(n)),
        ("hrs", |n| chrono::Duration::hours(n)),
        ("hr", |n| chrono::Duration::hours(n)),
        ("days", |n| chrono::Duration::days(n)),
        ("day", |n| chrono::Duration::days(n)),
        ("weeks", |n| chrono::Duration::weeks(n)),
        ("week", |n| chrono::Duration::weeks(n)),
        ("months", |n| chrono::Duration::days(n * 30)),
        ("month", |n| chrono::Duration::days(n * 30)),
        ("years", |n| chrono::Duration::days(n * 365)),
        ("year", |n| chrono::Duration::days(n * 365)),
    ];
    for &(suffix, f) in re_patterns {
        if let Some(num_str) = s.strip_suffix(suffix) {
            if let Ok(n) = num_str.trim().parse::<i64>() {
                return Some(f(n));
            }
        }
    }
    // Short suffixes: "1d", "2w", "3h", "30m", "5s", "1y"
    if s.len() >= 2 {
        let (num_str, unit) = s.split_at(s.len() - 1);
        if let Ok(n) = num_str.trim().parse::<i64>() {
            return match unit {
                "s" => Some(chrono::Duration::seconds(n)),
                "m" => Some(chrono::Duration::minutes(n)),
                "h" => Some(chrono::Duration::hours(n)),
                "d" => Some(chrono::Duration::days(n)),
                "w" => Some(chrono::Duration::weeks(n)),
                "y" => Some(chrono::Duration::days(n * 365)),
                _ => None,
            };
        }
        // "1mo"
        if s.len() >= 3 {
            let (num_str2, unit2) = s.split_at(s.len() - 2);
            if unit2 == "mo" {
                if let Ok(n) = num_str2.trim().parse::<i64>() {
                    return Some(chrono::Duration::days(n * 30));
                }
            }
        }
    }
    None
}

/// `dateseq START, END [, STEP]` — generate sequence of date strings.
/// Returns an array of ISO date strings. STEP defaults to "1d".
/// Example: `dateseq("2024-01-01", "2024-01-07")` → 7 dates
/// Example: `dateseq("2024-01-01", "2024-12-31", "1w")` → weekly dates
fn builtin_dateseq(args: &[StrykeValue], line: usize) -> StrykeResult<StrykeValue> {
    let start_str = args.first().map(|v| v.to_string()).unwrap_or_default();
    let end_str = args.get(1).map(|v| v.to_string()).unwrap_or_default();
    let step_str = args
        .get(2)
        .map(|v| v.to_string())
        .unwrap_or_else(|| "1d".to_string());
    let start = parse_date_flexible(&start_str).ok_or_else(|| {
        StrykeError::runtime(
            format!("dateseq: cannot parse start date: {}", start_str),
            line,
        )
    })?;
    let end = parse_date_flexible(&end_str).ok_or_else(|| {
        StrykeError::runtime(format!("dateseq: cannot parse end date: {}", end_str), line)
    })?;
    let step = parse_duration_str(&step_str).ok_or_else(|| {
        StrykeError::runtime(format!("dateseq: cannot parse step: {}", step_str), line)
    })?;
    if step.num_seconds() == 0 {
        return Err(StrykeError::runtime("dateseq: step cannot be zero", line));
    }
    let mut result = Vec::new();
    let mut cur = start;
    let forward = end >= start;
    let max_items = 100_000; // safety limit
    while (forward && cur <= end) || (!forward && cur >= end) {
        let fmt = if cur.time() == chrono::NaiveTime::from_hms_opt(0, 0, 0).unwrap() {
            cur.format("%Y-%m-%d").to_string()
        } else {
            cur.format("%Y-%m-%d %H:%M:%S").to_string()
        };
        result.push(StrykeValue::string(fmt));
        if result.len() >= max_items {
            break;
        }
        cur += step;
    }
    Ok(StrykeValue::array(result))
}

/// `dategrep PATTERN, LIST` — filter strings containing dates matching pattern.
/// PATTERN is a date string or glob-like: "2024-03-*", "2024-*", "2024-03-15".
/// Scans each line for ISO-ish dates and checks if they match the pattern.
fn builtin_dategrep(interp: &VMHelper, args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    let pattern = args.first().map(|v| v.to_string()).unwrap_or_default();
    let list = if args.len() > 1 {
        args[1..]
            .iter()
            .flat_map(|v| {
                let items = v.to_list();
                if items.is_empty() {
                    vec![v.clone()]
                } else {
                    items
                }
            })
            .collect::<Vec<_>>()
    } else {
        // Use $_ if no list given
        vec![interp.scope.get_scalar("_")]
    };
    // Convert glob pattern to regex: "2024-03-*" → "2024-03-\d+"
    let re_pat = pattern.replace('.', r"\.").replace('*', r"\d+");
    let re = regex::Regex::new(&re_pat).unwrap_or_else(|_| regex::Regex::new("^$").unwrap());
    let mut result = Vec::new();
    for item in list {
        let s = item.to_string();
        if re.is_match(&s) {
            result.push(item);
        }
    }
    Ok(StrykeValue::array(result))
}

/// `dateround DATE, UNIT` — round a date to the nearest unit.
/// UNIT: "second", "minute", "hour", "day", "week", "month", "year"
/// Example: `dateround("2024-03-15 14:37:22", "hour")` → "2024-03-15 15:00:00"
fn builtin_dateround(args: &[StrykeValue], line: usize) -> StrykeResult<StrykeValue> {
    use chrono::{Datelike, NaiveDate, Timelike};
    let date_str = args.first().map(|v| v.to_string()).unwrap_or_default();
    let unit = args
        .get(1)
        .map(|v| v.to_string())
        .unwrap_or_else(|| "day".to_string());
    let dt = parse_date_flexible(&date_str).ok_or_else(|| {
        StrykeError::runtime(format!("dateround: cannot parse: {}", date_str), line)
    })?;
    let rounded = match unit.as_str() {
        "second" | "sec" | "s" => dt.with_nanosecond(0).unwrap_or(dt),
        "minute" | "min" | "m" => {
            let base = dt
                .with_second(0)
                .and_then(|d| d.with_nanosecond(0))
                .unwrap_or(dt);
            if dt.second() >= 30 {
                base + chrono::Duration::minutes(1)
            } else {
                base
            }
        }
        "hour" | "hr" | "h" => {
            let base = dt
                .with_minute(0)
                .and_then(|d| d.with_second(0))
                .and_then(|d| d.with_nanosecond(0))
                .unwrap_or(dt);
            if dt.minute() >= 30 {
                base + chrono::Duration::hours(1)
            } else {
                base
            }
        }
        "day" | "d" => {
            let base = NaiveDate::from_ymd_opt(dt.year(), dt.month(), dt.day())
                .unwrap()
                .and_hms_opt(0, 0, 0)
                .unwrap();
            if dt.hour() >= 12 {
                base + chrono::Duration::days(1)
            } else {
                base
            }
        }
        "week" | "w" => {
            let weekday = dt.weekday().num_days_from_monday() as i64;
            let start = dt.date() - chrono::Duration::days(weekday);
            let base = start.and_hms_opt(0, 0, 0).unwrap();
            if weekday >= 4 {
                base + chrono::Duration::weeks(1)
            } else {
                base
            }
        }
        "month" | "mo" => {
            let base = NaiveDate::from_ymd_opt(dt.year(), dt.month(), 1)
                .unwrap()
                .and_hms_opt(0, 0, 0)
                .unwrap();
            if dt.day() >= 15 {
                let (y, m) = if dt.month() == 12 {
                    (dt.year() + 1, 1)
                } else {
                    (dt.year(), dt.month() + 1)
                };
                NaiveDate::from_ymd_opt(y, m, 1)
                    .unwrap()
                    .and_hms_opt(0, 0, 0)
                    .unwrap()
            } else {
                base
            }
        }
        "year" | "y" => {
            let base = NaiveDate::from_ymd_opt(dt.year(), 1, 1)
                .unwrap()
                .and_hms_opt(0, 0, 0)
                .unwrap();
            if dt.month() >= 7 {
                NaiveDate::from_ymd_opt(dt.year() + 1, 1, 1)
                    .unwrap()
                    .and_hms_opt(0, 0, 0)
                    .unwrap()
            } else {
                base
            }
        }
        _ => {
            return Err(StrykeError::runtime(
                format!("dateround: unknown unit: {}", unit),
                line,
            ))
        }
    };
    let fmt = if rounded.time() == chrono::NaiveTime::from_hms_opt(0, 0, 0).unwrap() {
        rounded.format("%Y-%m-%d").to_string()
    } else {
        rounded.format("%Y-%m-%d %H:%M:%S").to_string()
    };
    Ok(StrykeValue::string(fmt))
}

/// `datesort LIST` — sort strings chronologically by detected date.
/// Parses each string for an ISO-ish date and sorts by it.
fn builtin_datesort(args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    let mut items: Vec<StrykeValue> = args
        .iter()
        .flat_map(|v| {
            let list = v.to_list();
            if list.is_empty() {
                vec![v.clone()]
            } else {
                list
            }
        })
        .collect();
    items.sort_by(|a, b| {
        let da = parse_date_flexible(&a.to_string());
        let db = parse_date_flexible(&b.to_string());
        match (da, db) {
            (Some(a), Some(b)) => a.cmp(&b),
            (Some(_), None) => std::cmp::Ordering::Less,
            (None, Some(_)) => std::cmp::Ordering::Greater,
            (None, None) => a.to_string().cmp(&b.to_string()),
        }
    });
    Ok(StrykeValue::array(items))
}

