// Extended stdlib: Graph Algorithms
// ─────────────────────────────────────────────────────────────────────────

/// `topological_sort EDGES` — topological sort on DAG (edges as [[from, to], ...]).
fn builtin_topological_sort(args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    let edges = arg_to_vec(&args.first().cloned().unwrap_or(StrykeValue::UNDEF));
    let mut graph: std::collections::HashMap<String, Vec<String>> =
        std::collections::HashMap::new();
    let mut in_degree: std::collections::HashMap<String, usize> = std::collections::HashMap::new();
    let mut all_nodes: std::collections::HashSet<String> = std::collections::HashSet::new();
    for edge in edges {
        let e = arg_to_vec(&edge);
        if e.len() >= 2 {
            let from = e[0].to_string();
            let to = e[1].to_string();
            all_nodes.insert(from.clone());
            all_nodes.insert(to.clone());
            graph.entry(from.clone()).or_default().push(to.clone());
            *in_degree.entry(to).or_insert(0) += 1;
            in_degree.entry(from).or_insert(0);
        }
    }
    let mut queue: Vec<String> = all_nodes
        .iter()
        .filter(|n| *in_degree.get(*n).unwrap_or(&0) == 0)
        .cloned()
        .collect();
    queue.sort();
    let mut result = Vec::new();
    while let Some(node) = queue.pop() {
        result.push(StrykeValue::string(node.clone()));
        if let Some(neighbors) = graph.get(&node) {
            for neighbor in neighbors {
                if let Some(deg) = in_degree.get_mut(neighbor) {
                    *deg -= 1;
                    if *deg == 0 {
                        queue.push(neighbor.clone());
                        queue.sort();
                    }
                }
            }
        }
    }
    if result.len() != all_nodes.len() {
        return Err(StrykeError::runtime("topological_sort: cycle detected", 0));
    }
    Ok(StrykeValue::array(result))
}

/// `bfs_traverse START, EDGES` — breadth-first search traversal order.
fn builtin_bfs_traverse(args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    let start = args.first().map(|v| v.to_string()).unwrap_or_default();
    let edges = arg_to_vec(&args.get(1).cloned().unwrap_or(StrykeValue::UNDEF));
    let mut graph: std::collections::HashMap<String, Vec<String>> =
        std::collections::HashMap::new();
    for edge in edges {
        let e = arg_to_vec(&edge);
        if e.len() >= 2 {
            let from = e[0].to_string();
            let to = e[1].to_string();
            graph.entry(from).or_default().push(to);
        }
    }
    let mut visited: std::collections::HashSet<String> = std::collections::HashSet::new();
    let mut queue = std::collections::VecDeque::new();
    let mut result = Vec::new();
    queue.push_back(start.clone());
    visited.insert(start);
    while let Some(node) = queue.pop_front() {
        result.push(StrykeValue::string(node.clone()));
        if let Some(neighbors) = graph.get(&node) {
            for neighbor in neighbors {
                if !visited.contains(neighbor) {
                    visited.insert(neighbor.clone());
                    queue.push_back(neighbor.clone());
                }
            }
        }
    }
    Ok(StrykeValue::array(result))
}

/// `dfs_traverse START, EDGES` — depth-first search traversal order.
fn builtin_dfs_traverse(args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    let start = args.first().map(|v| v.to_string()).unwrap_or_default();
    let edges = arg_to_vec(&args.get(1).cloned().unwrap_or(StrykeValue::UNDEF));
    let mut graph: std::collections::HashMap<String, Vec<String>> =
        std::collections::HashMap::new();
    for edge in edges {
        let e = arg_to_vec(&edge);
        if e.len() >= 2 {
            let from = e[0].to_string();
            let to = e[1].to_string();
            graph.entry(from).or_default().push(to);
        }
    }
    let mut visited: std::collections::HashSet<String> = std::collections::HashSet::new();
    let mut stack = vec![start.clone()];
    let mut result = Vec::new();
    while let Some(node) = stack.pop() {
        if visited.contains(&node) {
            continue;
        }
        visited.insert(node.clone());
        result.push(StrykeValue::string(node.clone()));
        if let Some(neighbors) = graph.get(&node) {
            for neighbor in neighbors.iter().rev() {
                if !visited.contains(neighbor) {
                    stack.push(neighbor.clone());
                }
            }
        }
    }
    Ok(StrykeValue::array(result))
}

/// `shortest_path_bfs START, END, EDGES` — BFS-based shortest path (unweighted).
fn builtin_shortest_path_bfs(args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    let start = args.first().map(|v| v.to_string()).unwrap_or_default();
    let end = args.get(1).map(|v| v.to_string()).unwrap_or_default();
    let edges = arg_to_vec(&args.get(2).cloned().unwrap_or(StrykeValue::UNDEF));
    let mut graph: std::collections::HashMap<String, Vec<String>> =
        std::collections::HashMap::new();
    for edge in edges {
        let e = arg_to_vec(&edge);
        if e.len() >= 2 {
            let from = e[0].to_string();
            let to = e[1].to_string();
            graph.entry(from).or_default().push(to);
        }
    }
    let mut visited: std::collections::HashMap<String, String> = std::collections::HashMap::new();
    let mut queue = std::collections::VecDeque::new();
    queue.push_back(start.clone());
    visited.insert(start.clone(), String::new());
    while let Some(node) = queue.pop_front() {
        if node == end {
            let mut path = vec![StrykeValue::string(end.clone())];
            let mut current = end.clone();
            while let Some(prev) = visited.get(&current) {
                if prev.is_empty() {
                    break;
                }
                path.push(StrykeValue::string(prev.clone()));
                current = prev.clone();
            }
            path.reverse();
            return Ok(StrykeValue::array(path));
        }
        if let Some(neighbors) = graph.get(&node) {
            for neighbor in neighbors {
                if !visited.contains_key(neighbor) {
                    visited.insert(neighbor.clone(), node.clone());
                    queue.push_back(neighbor.clone());
                }
            }
        }
    }
    Ok(StrykeValue::array(vec![]))
}

/// `connected_components_graph EDGES` — find connected components (undirected).
fn builtin_connected_components_graph(args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    let edges = arg_to_vec(&args.first().cloned().unwrap_or(StrykeValue::UNDEF));
    let mut graph: std::collections::HashMap<String, Vec<String>> =
        std::collections::HashMap::new();
    let mut all_nodes: std::collections::HashSet<String> = std::collections::HashSet::new();
    for edge in edges {
        let e = arg_to_vec(&edge);
        if e.len() >= 2 {
            let a = e[0].to_string();
            let b = e[1].to_string();
            all_nodes.insert(a.clone());
            all_nodes.insert(b.clone());
            graph.entry(a.clone()).or_default().push(b.clone());
            graph.entry(b).or_default().push(a);
        }
    }
    let mut visited: std::collections::HashSet<String> = std::collections::HashSet::new();
    let mut components = Vec::new();
    for node in &all_nodes {
        if visited.contains(node) {
            continue;
        }
        let mut component = Vec::new();
        let mut stack = vec![node.clone()];
        while let Some(n) = stack.pop() {
            if visited.contains(&n) {
                continue;
            }
            visited.insert(n.clone());
            component.push(StrykeValue::string(n.clone()));
            if let Some(neighbors) = graph.get(&n) {
                for neighbor in neighbors {
                    if !visited.contains(neighbor) {
                        stack.push(neighbor.clone());
                    }
                }
            }
        }
        component.sort_by_key(|a| a.to_string());
        components.push(StrykeValue::array_ref(Arc::new(RwLock::new(component))));
    }
    Ok(StrykeValue::array(components))
}

/// `has_cycle_graph EDGES` — check if directed graph has a cycle.
fn builtin_has_cycle_graph(args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    let edges = arg_to_vec(&args.first().cloned().unwrap_or(StrykeValue::UNDEF));
    let mut graph: std::collections::HashMap<String, Vec<String>> =
        std::collections::HashMap::new();
    let mut all_nodes: std::collections::HashSet<String> = std::collections::HashSet::new();
    for edge in edges {
        let e = arg_to_vec(&edge);
        if e.len() >= 2 {
            let from = e[0].to_string();
            let to = e[1].to_string();
            all_nodes.insert(from.clone());
            all_nodes.insert(to.clone());
            graph.entry(from).or_default().push(to);
        }
    }
    fn dfs_cycle(
        node: &str,
        graph: &std::collections::HashMap<String, Vec<String>>,
        visiting: &mut std::collections::HashSet<String>,
        visited: &mut std::collections::HashSet<String>,
    ) -> bool {
        if visiting.contains(node) {
            return true;
        }
        if visited.contains(node) {
            return false;
        }
        visiting.insert(node.to_string());
        if let Some(neighbors) = graph.get(node) {
            for neighbor in neighbors {
                if dfs_cycle(neighbor, graph, visiting, visited) {
                    return true;
                }
            }
        }
        visiting.remove(node);
        visited.insert(node.to_string());
        false
    }
    let mut visiting = std::collections::HashSet::new();
    let mut visited = std::collections::HashSet::new();
    for node in &all_nodes {
        if dfs_cycle(node, &graph, &mut visiting, &mut visited) {
            return Ok(bool_iv(true));
        }
    }
    Ok(bool_iv(false))
}

/// `is_bipartite_graph EDGES` — check if graph is bipartite (two-colorable).
fn builtin_is_bipartite_graph(args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    let edges = arg_to_vec(&args.first().cloned().unwrap_or(StrykeValue::UNDEF));
    let mut graph: std::collections::HashMap<String, Vec<String>> =
        std::collections::HashMap::new();
    let mut all_nodes: std::collections::HashSet<String> = std::collections::HashSet::new();
    for edge in edges {
        let e = arg_to_vec(&edge);
        if e.len() >= 2 {
            let a = e[0].to_string();
            let b = e[1].to_string();
            all_nodes.insert(a.clone());
            all_nodes.insert(b.clone());
            graph.entry(a.clone()).or_default().push(b.clone());
            graph.entry(b).or_default().push(a);
        }
    }
    let mut color: std::collections::HashMap<String, i32> = std::collections::HashMap::new();
    for start in &all_nodes {
        if color.contains_key(start) {
            continue;
        }
        let mut queue = std::collections::VecDeque::new();
        queue.push_back(start.clone());
        color.insert(start.clone(), 0);
        while let Some(node) = queue.pop_front() {
            let c = *color.get(&node).unwrap();
            if let Some(neighbors) = graph.get(&node) {
                for neighbor in neighbors {
                    if let Some(&nc) = color.get(neighbor) {
                        if nc == c {
                            return Ok(bool_iv(false));
                        }
                    } else {
                        color.insert(neighbor.clone(), 1 - c);
                        queue.push_back(neighbor.clone());
                    }
                }
            }
        }
    }
    Ok(bool_iv(true))
}

