// ── Array Analysis ──────────────────────────────────────────────────────

/// `longest_run ARR` — length of longest run of equal elements.
fn builtin_longest_run(args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    let xs = flatten_args(args);
    if xs.is_empty() {
        return Ok(StrykeValue::integer(0));
    }
    let mut max_run = 1;
    let mut current_run = 1;
    for i in 1..xs.len() {
        if xs[i].to_string() == xs[i - 1].to_string() {
            current_run += 1;
            max_run = max_run.max(current_run);
        } else {
            current_run = 1;
        }
    }
    Ok(StrykeValue::integer(max_run))
}

/// `longest_increasing ARR` — length of longest increasing subsequence.
fn builtin_longest_increasing(args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    let xs: Vec<f64> = flatten_args(args).iter().map(|v| v.to_number()).collect();
    if xs.is_empty() {
        return Ok(StrykeValue::integer(0));
    }
    let mut dp = vec![1; xs.len()];
    for i in 1..xs.len() {
        for j in 0..i {
            if xs[i] > xs[j] {
                dp[i] = dp[i].max(dp[j] + 1);
            }
        }
    }
    Ok(StrykeValue::integer(*dp.iter().max().unwrap_or(&0)))
}

/// `longest_decreasing ARR` — length of longest decreasing subsequence.
fn builtin_longest_decreasing(args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    let xs: Vec<f64> = flatten_args(args).iter().map(|v| v.to_number()).collect();
    if xs.is_empty() {
        return Ok(StrykeValue::integer(0));
    }
    let mut dp = vec![1; xs.len()];
    for i in 1..xs.len() {
        for j in 0..i {
            if xs[i] < xs[j] {
                dp[i] = dp[i].max(dp[j] + 1);
            }
        }
    }
    Ok(StrykeValue::integer(*dp.iter().max().unwrap_or(&0)))
}

/// `max_sum_subarray ARR` — maximum sum subarray (Kadane's algorithm).
fn builtin_max_sum_subarray(args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    let xs: Vec<f64> = flatten_args(args).iter().map(|v| v.to_number()).collect();
    if xs.is_empty() {
        return Ok(StrykeValue::float(0.0));
    }
    let mut max_so_far = xs[0];
    let mut max_ending_here = xs[0];
    for &x in &xs[1..] {
        max_ending_here = x.max(max_ending_here + x);
        max_so_far = max_so_far.max(max_ending_here);
    }
    Ok(StrykeValue::float(max_so_far))
}

/// `majority_element ARR` — element appearing more than n/2 times (or undef).
fn builtin_majority_element(args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    let xs = flatten_args(args);
    if xs.is_empty() {
        return Ok(StrykeValue::UNDEF);
    }
    let mut candidate = xs[0].clone();
    let mut count = 1i64;
    for x in &xs[1..] {
        if count == 0 {
            candidate = x.clone();
            count = 1;
        } else if x.to_string() == candidate.to_string() {
            count += 1;
        } else {
            count -= 1;
        }
    }
    let freq = xs
        .iter()
        .filter(|x| x.to_string() == candidate.to_string())
        .count();
    if freq > xs.len() / 2 {
        Ok(candidate)
    } else {
        Ok(StrykeValue::UNDEF)
    }
}

/// `kth_largest ARR, K` — kth largest element.
fn builtin_kth_largest(args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    let mut xs: Vec<f64> = flatten_args(&args[..args.len().saturating_sub(1)])
        .iter()
        .map(|v| v.to_number())
        .collect();
    let k = args.last().map(|v| v.to_int().max(1) as usize).unwrap_or(1);
    if k > xs.len() {
        return Ok(StrykeValue::UNDEF);
    }
    xs.sort_by(|a, b| b.partial_cmp(a).unwrap_or(std::cmp::Ordering::Equal));
    Ok(StrykeValue::float(xs[k - 1]))
}

/// `kth_smallest ARR, K` — kth smallest element.
fn builtin_kth_smallest(args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    let mut xs: Vec<f64> = flatten_args(&args[..args.len().saturating_sub(1)])
        .iter()
        .map(|v| v.to_number())
        .collect();
    let k = args.last().map(|v| v.to_int().max(1) as usize).unwrap_or(1);
    if k > xs.len() {
        return Ok(StrykeValue::UNDEF);
    }
    xs.sort_by(|a, b| a.partial_cmp(b).unwrap_or(std::cmp::Ordering::Equal));
    Ok(StrykeValue::float(xs[k - 1]))
}

/// `count_inversions ARR` — count inversions in array.
fn builtin_count_inversions(args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    let xs: Vec<f64> = flatten_args(args).iter().map(|v| v.to_number()).collect();
    let mut count = 0i64;
    for i in 0..xs.len() {
        for j in i + 1..xs.len() {
            if xs[i] > xs[j] {
                count += 1;
            }
        }
    }
    Ok(StrykeValue::integer(count))
}

/// `is_monotonic ARR` — check if monotonically increasing or decreasing.
fn builtin_is_monotonic(args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    let xs: Vec<f64> = flatten_args(args).iter().map(|v| v.to_number()).collect();
    if xs.len() <= 1 {
        return Ok(bool_iv(true));
    }
    let mut inc = true;
    let mut dec = true;
    for i in 1..xs.len() {
        if xs[i] > xs[i - 1] {
            dec = false;
        }
        if xs[i] < xs[i - 1] {
            inc = false;
        }
    }
    Ok(bool_iv(inc || dec))
}

/// `equilibrium_index ARR` — index where left sum equals right sum.
fn builtin_equilibrium_index(args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    let xs: Vec<f64> = flatten_args(args).iter().map(|v| v.to_number()).collect();
    let total: f64 = xs.iter().sum();
    let mut left_sum = 0.0;
    for (i, &x) in xs.iter().enumerate() {
        let right_sum = total - left_sum - x;
        if (left_sum - right_sum).abs() < f64::EPSILON {
            return Ok(StrykeValue::integer(i as i64));
        }
        left_sum += x;
    }
    Ok(StrykeValue::integer(-1))
}

// ── Set Operations ──────────────────────────────────────────────────────

/// `jaccard_index SET1, SET2` — Jaccard similarity coefficient.
fn builtin_jaccard_index(args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    let s1: std::collections::HashSet<String> =
        arg_to_vec(&args.first().cloned().unwrap_or(StrykeValue::UNDEF))
            .iter()
            .map(|v| v.to_string())
            .collect();
    let s2: std::collections::HashSet<String> =
        arg_to_vec(&args.get(1).cloned().unwrap_or(StrykeValue::UNDEF))
            .iter()
            .map(|v| v.to_string())
            .collect();
    let intersection = s1.intersection(&s2).count() as f64;
    let union = s1.union(&s2).count() as f64;
    if union == 0.0 {
        return Ok(StrykeValue::float(1.0));
    }
    Ok(StrykeValue::float(intersection / union))
}

/// `dice_coefficient SET1, SET2` — Dice similarity coefficient.
fn builtin_dice_coefficient(args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    let s1: std::collections::HashSet<String> =
        arg_to_vec(&args.first().cloned().unwrap_or(StrykeValue::UNDEF))
            .iter()
            .map(|v| v.to_string())
            .collect();
    let s2: std::collections::HashSet<String> =
        arg_to_vec(&args.get(1).cloned().unwrap_or(StrykeValue::UNDEF))
            .iter()
            .map(|v| v.to_string())
            .collect();
    let intersection = s1.intersection(&s2).count() as f64;
    let total = (s1.len() + s2.len()) as f64;
    if total == 0.0 {
        return Ok(StrykeValue::float(1.0));
    }
    Ok(StrykeValue::float(2.0 * intersection / total))
}

/// `overlap_coefficient SET1, SET2` — overlap coefficient (Szymkiewicz-Simpson).
fn builtin_overlap_coefficient(args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    let s1: std::collections::HashSet<String> =
        arg_to_vec(&args.first().cloned().unwrap_or(StrykeValue::UNDEF))
            .iter()
            .map(|v| v.to_string())
            .collect();
    let s2: std::collections::HashSet<String> =
        arg_to_vec(&args.get(1).cloned().unwrap_or(StrykeValue::UNDEF))
            .iter()
            .map(|v| v.to_string())
            .collect();
    let intersection = s1.intersection(&s2).count() as f64;
    let min_size = s1.len().min(s2.len()) as f64;
    if min_size == 0.0 {
        return Ok(StrykeValue::float(1.0));
    }
    Ok(StrykeValue::float(intersection / min_size))
}

/// `power_set ARR` — all subsets of array.
fn builtin_power_set(args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    let xs = flatten_args(args);
    let n = xs.len();
    if n > 20 {
        return Err(StrykeError::runtime(
            "power_set: array too large (max 20)",
            0,
        ));
    }
    let count = 1usize << n;
    let mut result = Vec::with_capacity(count);
    for mask in 0..count {
        let mut subset = Vec::new();
        for (i, x) in xs.iter().enumerate().take(n) {
            if mask & (1 << i) != 0 {
                subset.push(x.clone());
            }
        }
        result.push(StrykeValue::array_ref(Arc::new(RwLock::new(subset))));
    }
    Ok(StrykeValue::array(result))
}

/// `cartesian_power ARR, N` — n-th Cartesian power.
fn builtin_cartesian_power(args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    let xs = arg_to_vec(&args.first().cloned().unwrap_or(StrykeValue::UNDEF));
    let n = args.get(1).map(|v| v.to_int().max(0) as usize).unwrap_or(1);
    if xs.is_empty() || n == 0 {
        return Ok(StrykeValue::array(vec![]));
    }
    if xs
        .len()
        .checked_pow(n as u32)
        .map(|x| x > 10000)
        .unwrap_or(true)
    {
        return Err(StrykeError::runtime("cartesian_power: result too large", 0));
    }
    fn generate(
        xs: &[StrykeValue],
        n: usize,
        current: &mut Vec<StrykeValue>,
        result: &mut Vec<StrykeValue>,
    ) {
        if current.len() == n {
            result.push(StrykeValue::array_ref(Arc::new(RwLock::new(
                current.clone(),
            ))));
            return;
        }
        for x in xs {
            current.push(x.clone());
            generate(xs, n, current, result);
            current.pop();
        }
    }
    let mut result = Vec::new();
    let mut current = Vec::new();
    generate(&xs, n, &mut current, &mut result);
    Ok(StrykeValue::array(result))
}

