// Helper fns for matrix/vector operations
fn nums_from_aref(v: &StrykeValue) -> Vec<f64> {
    v.as_array_ref()
        .map(|ar| ar.read().iter().map(|x| x.to_number()).collect())
        .unwrap_or_default()
}
fn aoa_from_args(args: &[StrykeValue]) -> Vec<Vec<f64>> {
    args.iter()
        .filter_map(|v| {
            v.as_array_ref()
                .map(|ar| ar.read().iter().map(|x| x.to_number()).collect())
        })
        .collect()
}
fn aoa_to_pv(rows: Vec<Vec<f64>>) -> StrykeValue {
    StrykeValue::array(
        rows.into_iter()
            .map(|r| {
                StrykeValue::array_ref(Arc::new(RwLock::new(
                    r.into_iter().map(StrykeValue::float).collect(),
                )))
            })
            .collect(),
    )
}
/// `juxt2` — Juxt2. Returns a list.
fn builtin_juxt2(args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    Ok(StrykeValue::array_ref(Arc::new(RwLock::new(
        args.iter().take(2).cloned().collect(),
    ))))
}
/// `juxt3` — Juxt3. Returns a list.
fn builtin_juxt3(args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    Ok(StrykeValue::array_ref(Arc::new(RwLock::new(
        args.iter().take(3).cloned().collect(),
    ))))
}

