fn builtin_after_n(args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    let n = args
        .first()
        .map(|v| v.to_int().max(0) as usize)
        .unwrap_or(0);
    Ok(StrykeValue::array(
        flatten_args(&args[1..]).into_iter().skip(n).collect(),
    ))
}
