/// `entropy` — Shannon entropy.
fn builtin_entropy(args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    let xs = collect_numbers(args);
    let sum: f64 = xs.iter().sum();
    if sum == 0.0 {
        return Ok(StrykeValue::float(0.0));
    }
    let e: f64 = xs
        .iter()
        .filter(|&&x| x > 0.0)
        .map(|&x| {
            let p = x / sum;
            -p * p.ln()
        })
        .sum();
    Ok(StrykeValue::float(e))
}
