    let xs = flatten_args(&args[1..]);
    Ok(StrykeValue::array(
        xs.into_iter()
            .enumerate()
            .filter(|(i, _)| (i + 1) % n != 0)
            .map(|(_, v)| v)
            .collect(),
    ))
