/// `from_csv_line` — From csv line.
fn builtin_from_csv_line(interp: &VMHelper, args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    let s = first_arg_or_topic(interp, args).to_string();
    let mut out = Vec::new();
    let mut field = String::new();
    let mut in_quote = false;
    for c in s.chars() {
        if in_quote {
            if c == '"' {
                in_quote = false;
            } else {
                field.push(c);
            }
        } else if c == '"' {
            in_quote = true;
        } else if c == ',' {
            out.push(StrykeValue::string(std::mem::take(&mut field)));
        } else {
            field.push(c);
        }
    }
    out.push(StrykeValue::string(field));
    Ok(StrykeValue::array(out))
}
