fn builtin_group_by_size(args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    let n = args
        .first()
        .map(|v| v.to_int().max(1) as usize)
        .unwrap_or(1);
    let xs = flatten_args(&args[1..]);
    Ok(StrykeValue::array(
        xs.chunks(n)
            .map(|c| StrykeValue::array_ref(Arc::new(RwLock::new(c.to_vec()))))
            .collect(),
    ))
}
/// `histogram_bins` — Histogram bins.
fn builtin_histogram_bins(args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    let nbins = args
        .first()
        .map(|v| v.to_int().max(1) as usize)
        .unwrap_or(10);
    let xs = collect_numbers(&args[1..]);
    if xs.is_empty() {
        return Ok(StrykeValue::array(vec![]));
    }
    let mn = xs.iter().copied().fold(f64::INFINITY, f64::min);
    let mx = xs.iter().copied().fold(f64::NEG_INFINITY, f64::max);
    let w = (mx - mn) / nbins as f64;
    if w == 0.0 {
        return Ok(StrykeValue::array(vec![StrykeValue::integer(
            xs.len() as i64
        )]));
    }
    let mut bins = vec![0i64; nbins];
    for &x in &xs {
        let i = ((x - mn) / w) as usize;
        bins[i.min(nbins - 1)] += 1;
    }
    Ok(StrykeValue::array(
        bins.into_iter().map(StrykeValue::integer).collect(),
    ))
}
