/// `interleave_lists` — Interleave lists.
fn builtin_interleave_lists(args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    let a = args
        .first()
        .and_then(|v| v.as_array_ref().map(|ar| ar.read().clone()))
        .unwrap_or_default();
    let b = args
        .get(1)
        .and_then(|v| v.as_array_ref().map(|ar| ar.read().clone()))
        .unwrap_or_default();
    let mut out = Vec::new();
    let n = a.len().max(b.len());
    for i in 0..n {
        if i < a.len() {
            out.push(a[i].clone());
        }
        if i < b.len() {
            out.push(b[i].clone());
        }
    }
    Ok(StrykeValue::array(out))
}
