// ── elapsed() ─────────────────────────────────────────────────────
/// Returns fractional seconds since process start with nanosecond precision.
fn builtin_elapsed() -> StrykeResult<StrykeValue> {
    let secs = PROCESS_START.elapsed().as_secs_f64();
    Ok(StrykeValue::float(secs))
}

// ── crc32(DATA) ───────────────────────────────────────────────────
/// CRC-32 checksum of the argument bytes; returns an unsigned 32-bit integer.
fn builtin_crc32(args: &[StrykeValue], line: usize) -> StrykeResult<StrykeValue> {
    if args.is_empty() {
        return Err(StrykeError::runtime("crc32: need DATA argument", line));
    }
    // Hash every positional argument so `crc32(@bytes)` and
    // `crc32($a, $b, $c)` produce the same digest as `crc32($a.$b.$c)`.
    let mut hasher = crc32fast::Hasher::new();
    for a in args {
        hasher.update(&perl_scalar_as_bytes(a));
    }
    Ok(StrykeValue::integer(hasher.finalize() as i64))
}

// ── par_find_files(PATH, PATTERN) ─────────────────────────────────
/// Parallel recursive file search. Returns all paths under PATH whose
/// filename matches the glob PATTERN (e.g. `"*.rs"`, `"test_*"`).
fn builtin_par_find_files(args: &[StrykeValue], line: usize) -> StrykeResult<StrykeValue> {
    use std::path::PathBuf;

    let root = args
        .first()
        .ok_or_else(|| StrykeError::runtime("par_find_files: need PATH, PATTERN", line))?
        .to_string();
    let pattern = args
        .get(1)
        .ok_or_else(|| StrykeError::runtime("par_find_files: need PATTERN", line))?
        .to_string();
    let pat = glob::Pattern::new(&pattern)
        .map_err(|e| StrykeError::runtime(format!("par_find_files: bad pattern: {}", e), line))?;

    let root_path = PathBuf::from(&root);
    if !root_path.is_dir() {
        return Ok(StrykeValue::array(vec![]));
    }
    let all = crate::par_walk::collect_paths(std::slice::from_ref(&root_path));
    let matched: Vec<StrykeValue> = all
        .into_par_iter()
        .filter(|p| {
            p.file_name()
                .and_then(|n| n.to_str())
                .is_some_and(|n| pat.matches(n))
        })
        .map(|p| StrykeValue::string(p.to_string_lossy().into_owned()))
        .collect();
    Ok(StrykeValue::array(matched))
}

// ── par_line_count(FILE, ...) ─────────────────────────────────────
/// Count lines across files in parallel. Returns total when called in
/// scalar context, or a list of per-file counts in list context.
fn builtin_par_line_count(args: &[StrykeValue], line: usize) -> StrykeResult<StrykeValue> {
    if args.is_empty() {
        return Err(StrykeError::runtime(
            "par_line_count: need at least one file path",
            line,
        ));
    }
    let paths: Vec<String> = args
        .iter()
        .flat_map(|a| a.to_list())
        .map(|v| v.to_string())
        .collect();
    let counts: Vec<StrykeValue> = paths
        .par_iter()
        .map(|p| {
            let n = std::fs::read(p).map(|b| bytecount(&b)).unwrap_or(0);
            StrykeValue::integer(n as i64)
        })
        .collect();
    if counts.len() == 1 {
        return Ok(counts.into_iter().next().unwrap());
    }
    Ok(StrykeValue::array(counts))
}

/// Count newline bytes. Equivalent to `memchr`-style `\n` counting.
#[inline]
fn bytecount(buf: &[u8]) -> usize {
    buf.iter().filter(|&&b| b == b'\n').count()
}

// ── chroot(DIRNAME) ────────────────────────────────────────────────
/// `chroot` — Chroot. Returns an integer.
fn builtin_chroot(args: &[StrykeValue], _line: usize) -> StrykeResult<StrykeValue> {
    #[cfg(unix)]
    {
        let dir = args
            .first()
            .map(|v| v.to_string())
            .unwrap_or_else(|| "/".into());
        match std::ffi::CString::new(dir.as_str()) {
            Ok(c) => {
                let r = unsafe { libc::chroot(c.as_ptr()) };
                Ok(StrykeValue::integer(if r == 0 { 1 } else { 0 }))
            }
            Err(_) => Ok(StrykeValue::integer(0)),
        }
    }
    #[cfg(not(unix))]
    {
        let _ = args;
        Err(StrykeError::runtime(
            "chroot: not implemented on this platform",
            line,
        ))
    }
}

// ── vec(STRING, OFFSET, BITS) ──────────────────────────────────────
/// `vec` — Vec. Returns an integer.
fn builtin_vec(args: &[StrykeValue], line: usize) -> StrykeResult<StrykeValue> {
    if args.len() < 3 {
        return Err(StrykeError::runtime("vec: not enough arguments", line));
    }
    // Prefer raw byte representation so previous vec() lvalue writes (which
    // may have produced non-UTF-8 sequences) round-trip correctly.
    let bytes_owned: Vec<u8> = if let Some(b) = args[0].as_bytes_arc() {
        (*b).clone()
    } else {
        args[0].to_string().into_bytes()
    };
    let bytes = bytes_owned.as_slice();
    let offset = args[1].to_int() as usize;
    let bits = args[2].to_int() as usize;
    if !matches!(bits, 1 | 2 | 4 | 8 | 16 | 32) {
        return Err(StrykeError::runtime(
            format!("vec: illegal number of bits ({})", bits),
            line,
        ));
    }
    let bit_offset = offset * bits;
    let byte_offset = bit_offset / 8;
    let bit_within = bit_offset % 8;
    if bits <= 8 {
        if byte_offset >= bytes.len() {
            return Ok(StrykeValue::integer(0));
        }
        let byte = bytes[byte_offset];
        let mask = ((1u16 << bits) - 1) as u8;
        let val = (byte >> bit_within) & mask;
        Ok(StrykeValue::integer(val as i64))
    } else if bits == 16 {
        // Perl's `vec` uses big-endian byte order for multi-byte BITS, and
        // pads with zero when the read runs past the end of the string.
        let b0 = *bytes.get(byte_offset).unwrap_or(&0);
        let b1 = *bytes.get(byte_offset + 1).unwrap_or(&0);
        let val = ((b0 as u16) << 8) | (b1 as u16);
        Ok(StrykeValue::integer(val as i64))
    } else {
        // 32 (big-endian, zero-padded past end)
        let b0 = *bytes.get(byte_offset).unwrap_or(&0);
        let b1 = *bytes.get(byte_offset + 1).unwrap_or(&0);
        let b2 = *bytes.get(byte_offset + 2).unwrap_or(&0);
        let b3 = *bytes.get(byte_offset + 3).unwrap_or(&0);
        let val = ((b0 as u32) << 24) | ((b1 as u32) << 16) | ((b2 as u32) << 8) | (b3 as u32);
        Ok(StrykeValue::integer(val as i64))
    }
}

// ── vec_set_value() ─────────────────────────────────────────────────
// Internal 4-arg helper used by the `vec(...) = $rhs` lvalue rewrite in
// the bytecode compiler (PARITY-010). Returns the modified string; the
// compiler arranges for it to be assigned back to the original lvalue.
fn builtin_vec_set_value(args: &[StrykeValue], line: usize) -> StrykeResult<StrykeValue> {
    if args.len() != 4 {
        return Err(StrykeError::runtime(
            format!("vec_set_value: expected 4 args, got {}", args.len()),
            line,
        ));
    }
    let offset = args[1].to_int();
    let bits = args[2].to_int();
    let value = args[3].to_int() as u64;
    if !matches!(bits, 1 | 2 | 4 | 8 | 16 | 32) {
        return Err(StrykeError::runtime(
            format!("Illegal number of bits in vec ({})", bits),
            line,
        ));
    }
    if offset < 0 {
        return Err(StrykeError::runtime(
            "Negative offset to vec in lvalue context",
            line,
        ));
    }
    // Preserve raw bytes — vec writes can produce non-UTF-8 sequences, so a
    // String round-trip would corrupt bytes via U+FFFD replacement.
    let mut bytes: Vec<u8> = if let Some(b) = args[0].as_bytes_arc() {
        (*b).clone()
    } else {
        args[0].to_string().into_bytes()
    };
    let bits_us = bits as usize;
    let bit_offset = (offset as usize) * bits_us;
    let byte_offset = bit_offset / 8;
    let bit_within = bit_offset % 8;
    let needed_len = if bits_us <= 8 {
        byte_offset + 1
    } else {
        byte_offset + (bits_us / 8)
    };
    if bytes.len() < needed_len {
        bytes.resize(needed_len, 0);
    }
    if bits_us <= 8 {
        let mask = ((1u16 << bits_us) - 1) as u8;
        let v = (value as u8) & mask;
        bytes[byte_offset] &= !(mask << bit_within);
        bytes[byte_offset] |= v << bit_within;
    } else if bits_us == 16 {
        // Perl uses big-endian for multi-byte BITS.
        let v = (value & 0xFFFF) as u16;
        bytes[byte_offset] = ((v >> 8) & 0xFF) as u8;
        bytes[byte_offset + 1] = (v & 0xFF) as u8;
    } else {
        let v = (value & 0xFFFF_FFFF) as u32;
        bytes[byte_offset] = ((v >> 24) & 0xFF) as u8;
        bytes[byte_offset + 1] = ((v >> 16) & 0xFF) as u8;
        bytes[byte_offset + 2] = ((v >> 8) & 0xFF) as u8;
        bytes[byte_offset + 3] = (v & 0xFF) as u8;
    }
    // If the result is valid UTF-8, return a string for friendlier interop;
    // otherwise return bytes so the raw sequence survives further reads.
    Ok(match String::from_utf8(bytes) {
        Ok(s) => StrykeValue::string(s),
        Err(e) => StrykeValue::bytes(std::sync::Arc::new(e.into_bytes())),
    })
}

// ── dump() ─────────────────────────────────────────────────────────
/// `dump` — Dump.
fn builtin_dump() -> StrykeResult<StrykeValue> {
    // Perl's dump() creates a core dump; we just abort.
    eprintln!("dump: intentional abort (Perl dump semantics)");
    std::process::abort();
}

