/// `prototype` — Prototype. Returns a string.
fn builtin_prototype(args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    if args.is_empty() {
        return Ok(StrykeValue::UNDEF);
    }
    Ok(args[0]
        .as_code_ref()
        .map(|sub| {
            if !sub.params.is_empty() {
                StrykeValue::UNDEF
            } else {
                StrykeValue::string(sub.prototype.clone().unwrap_or_default())
            }
        })
        .unwrap_or(StrykeValue::UNDEF))
}

