/// `syscall(NUM [, ARG ...])` — Perl-5-compatible raw `syscall(2)` entry point.
///
/// Calls `libc::syscall(num, arg1, arg2, …)`. Up to six arguments are passed
/// to the kernel (matching the platform ABI limit). Integer args are passed
/// as `c_long`; string args are passed by pointer to their UTF-8 bytes so
/// `read`-style scratch buffers work. Returns the kernel return value
/// (or `-1` on error, with `errno` reflected in `$!` via the standard
/// `*libc::__errno_location()` mechanism on Linux / `*libc::__error()` on
/// macOS).
///
/// Syscall numbers are deliberately not normalized across platforms — pass
/// the exact number for the host kernel (`SYS_*` in `<sys/syscall.h>`).
/// Wrong numbers can crash the process; this is an escape hatch, not a
/// portability layer. Use the wrapper builtins (`getpid`, `kill`, `fork`,
/// file ops) for portable code.
///
/// On non-Unix platforms returns `-1` and sets nothing.
#[cfg(unix)]
fn builtin_syscall(args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    if args.is_empty() {
        // Perl: `syscall` with no args is an error; Perl prints "Too few
        // arguments for syscall". Return -1 as a benign fallback so it can
        // still be tested behaviorally without crashing the interpreter.
        return Ok(StrykeValue::integer(-1));
    }
    // macOS `syscall(2)` takes `c_int`; Linux `syscall(2)` takes `c_long`.
    // The libc crate exposes whichever the host ABI uses, so cast at the
    // call site below.
    let num_raw = args[0].to_int();
    // Buffers for string args — kept alive across the syscall call so the
    // pointer args we pass stay valid.
    let mut buffers: Vec<std::ffi::CString> = Vec::with_capacity(args.len());
    // Resolved args as c_long (integer literal value, or pointer-as-long for strings).
    let mut a: [libc::c_long; 6] = [0; 6];
    for (i, v) in args.iter().skip(1).take(6).enumerate() {
        if let Some(s) = v.as_str() {
            // String: keep the bytes alive and pass the pointer.
            let c = std::ffi::CString::new(s.into_bytes()).unwrap_or_default();
            a[i] = c.as_ptr() as libc::c_long;
            buffers.push(c);
        } else {
            a[i] = v.to_int() as libc::c_long;
        }
    }
    #[cfg(target_os = "macos")]
    let r =
        unsafe { libc::syscall(num_raw as libc::c_int, a[0], a[1], a[2], a[3], a[4], a[5]) as i64 };
    #[cfg(all(unix, not(target_os = "macos")))]
    let r = unsafe {
        libc::syscall(num_raw as libc::c_long, a[0], a[1], a[2], a[3], a[4], a[5]) as i64
    };
    Ok(StrykeValue::integer(r))
}

#[cfg(not(unix))]
fn builtin_syscall(_args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    Ok(StrykeValue::integer(-1))
}

/// `alarm` — Alarm. Returns an integer.
fn builtin_alarm(args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    let sec = args.first().map(|v| v.to_int().max(0) as u32).unwrap_or(0);
    #[cfg(unix)]
    {
        let prev = unsafe { libc::alarm(sec) };
        Ok(StrykeValue::integer(prev as i64))
    }
    #[cfg(not(unix))]
    {
        let _ = sec;
        Ok(StrykeValue::integer(0))
    }
}

/// `sleep` — Sleep. Returns an integer.
fn builtin_sleep(args: &[StrykeValue]) -> StrykeResult<StrykeValue> {
    // Stock Perl's `sleep` is signal-interruptible and returns the actual seconds slept. We
    // mirror that by sleeping in short chunks and bailing as soon as `SIGINT`/`SIGTERM`/`SIGALRM`
    // are pending — otherwise a `pfor { sleep N }` worker would ignore Ctrl-C for the full `N`.
    let secs = args.first().map(|v| v.to_number()).unwrap_or(0.0).max(0.0);
    let total = Duration::from_secs_f64(secs);
    let start = Instant::now();
    let chunk = Duration::from_millis(100);
    while start.elapsed() < total {
        if crate::perl_signal::pending("INT")
            || crate::perl_signal::pending("TERM")
            || crate::perl_signal::pending("ALRM")
        {
            break;
        }
        let remaining = total - start.elapsed();
        std::thread::sleep(remaining.min(chunk));
    }
    Ok(StrykeValue::integer(start.elapsed().as_secs() as i64))
}

/// `times` — Times. Returns a float.
fn builtin_times() -> StrykeResult<StrykeValue> {
    #[cfg(unix)]
    {
        let mut tms: libc::tms = unsafe { std::mem::zeroed() };
        let _ = unsafe { libc::times(&mut tms) };
        let hz = unsafe { libc::sysconf(libc::_SC_CLK_TCK) }.max(1) as f64;
        let user = tms.tms_utime as f64 / hz;
        let system = tms.tms_stime as f64 / hz;
        let cuser = tms.tms_cutime as f64 / hz;
        let csystem = tms.tms_cstime as f64 / hz;
        Ok(StrykeValue::array(vec![
            StrykeValue::float(user),
            StrykeValue::float(system),
            StrykeValue::float(cuser),
            StrykeValue::float(csystem),
        ]))
    }
    #[cfg(not(unix))]
    {
        Ok(StrykeValue::array(vec![
            StrykeValue::float(0.0),
            StrykeValue::float(0.0),
            StrykeValue::float(0.0),
            StrykeValue::float(0.0),
        ]))
    }
}

/// `proceed()` — call the original sub from inside an `around` advice body.
/// Mirrors zshrs `intercept_proceed` (exec.rs:14926-14952): reads the top frame of
/// `Interpreter::intercept_ctx_stack`, runs the original synchronously with the
/// saved args, marks the ctx `proceeded=true`, and returns the retval.
fn builtin_proceed(interp: &mut VMHelper, line: usize) -> StrykeResult<StrykeValue> {
    let ctx_idx = interp
        .intercept_ctx_stack
        .len()
        .checked_sub(1)
        .ok_or_else(|| {
            crate::error::StrykeError::runtime(
                "proceed() called outside of an `around` advice block",
                line,
            )
        })?;
    let name = interp.intercept_ctx_stack[ctx_idx].name.clone();
    let args = interp.intercept_ctx_stack[ctx_idx].args.clone();

    interp.intercept_active_names.push(name.clone());
    let result: StrykeResult<StrykeValue> = if let Some(sub) = interp.resolve_sub_by_name(&name) {
        let want = interp.wantarray_kind;
        match interp.call_sub(&sub, args, want, line) {
            Ok(v) => Ok(v),
            Err(crate::vm_helper::FlowOrError::Flow(crate::vm_helper::Flow::Return(v))) => Ok(v),
            Err(crate::vm_helper::FlowOrError::Flow(_)) => Ok(StrykeValue::UNDEF),
            Err(crate::vm_helper::FlowOrError::Error(e)) => Err(e.at_line(line)),
        }
    } else {
        match crate::builtins::try_builtin(interp, &name, &args, line) {
            Some(Ok(v)) => Ok(v),
            Some(Err(e)) => Err(e.at_line(line)),
            None => Err(crate::error::StrykeError::runtime(
                format!("proceed: undefined sub `{}`", name),
                line,
            )),
        }
    };
    interp.intercept_active_names.pop();
    let retval = result?;
    if let Some(ctx) = interp.intercept_ctx_stack.get_mut(ctx_idx) {
        ctx.proceeded = true;
        ctx.retval = retval.clone();
    }
    Ok(retval)
}

/// `intercept_list()` — return registered AOP advice as an array of `[id, kind, pattern]` triples.
fn builtin_intercept_list(interp: &VMHelper) -> StrykeResult<StrykeValue> {
    let items: Vec<StrykeValue> = interp
        .intercepts
        .iter()
        .map(|i| {
            let kind = match i.kind {
                crate::ast::AdviceKind::Before => "before",
                crate::ast::AdviceKind::After => "after",
                crate::ast::AdviceKind::Around => "around",
            };
            StrykeValue::array_ref(Arc::new(RwLock::new(vec![
                StrykeValue::integer(i.id as i64),
                StrykeValue::string(kind.to_string()),
                StrykeValue::string(i.pattern.clone()),
            ])))
        })
        .collect();
    Ok(StrykeValue::array(items))
}

/// `intercept_remove(id)` — remove advice by id; returns count removed (0 or 1).
fn builtin_intercept_remove(
    interp: &mut VMHelper,
    args: &[StrykeValue],
) -> StrykeResult<StrykeValue> {
    let id = args.first().map(|v| v.to_int()).unwrap_or(0).max(0) as u32;
    let before = interp.intercepts.len();
    interp.intercepts.retain(|i| i.id != id);
    Ok(StrykeValue::integer(
        (before - interp.intercepts.len()) as i64,
    ))
}

/// `intercept_clear()` — drop all registered advice; returns count cleared.
fn builtin_intercept_clear(interp: &mut VMHelper) -> StrykeResult<StrykeValue> {
    let n = interp.intercepts.len();
    interp.intercepts.clear();
    Ok(StrykeValue::integer(n as i64))
}

