    pub(crate) fn builtin_gethostbyname(
        &mut self,
        args: &[StrykeValue],
        line: usize,
    ) -> StrykeResult<StrykeValue> {
        let host = args
            .first()
            .ok_or_else(|| StrykeError::runtime("gethostbyname: need NAME", line))?
            .to_string();
        let mut addrs: Vec<SocketAddr> = match format!("{}:0", host.trim()).to_socket_addrs() {
            Ok(i) => i.collect(),
            Err(_) => return Ok(StrykeValue::UNDEF),
        };
        if addrs.is_empty() {
            return Ok(StrykeValue::UNDEF);
        }
        addrs.sort_by_key(|a| match a {
            SocketAddr::V4(_) => 0,
            SocketAddr::V6(_) => 1,
        });
        let list_ctx = matches!(self.wantarray_kind, WantarrayCtx::List);
        let mut packed: Vec<StrykeValue> = Vec::new();
        for a in &addrs {
            if let SocketAddr::V4(v4) = a {
                let port = v4.port();
                let ip = v4.ip().octets();
                let mut blob = Vec::with_capacity(16);
                blob.extend_from_slice(&(libc::AF_INET as u16).to_ne_bytes());
                blob.extend_from_slice(&port.to_be_bytes());
                blob.extend_from_slice(&ip);
                blob.resize(16, 0);
                packed.push(StrykeValue::bytes(Arc::new(blob)));
            }
        }
        if packed.is_empty() {
            return Ok(StrykeValue::UNDEF);
        }
        if !list_ctx {
            return Ok(packed[0].clone());
        }
        let len = packed
            .first()
            .and_then(|v| v.as_bytes_arc())
            .map(|b| b.len() as i64)
            .unwrap_or(16);
        Ok(StrykeValue::array(
            vec![
                StrykeValue::string(host.clone()),
                StrykeValue::string(String::new()),
                StrykeValue::integer(libc::AF_INET as i64),
                StrykeValue::integer(len),
            ]
            .into_iter()
            .chain(packed)
            .collect(),
        ))
    }

    pub(crate) fn builtin_getprotobyname(
        &mut self,
        args: &[StrykeValue],
        line: usize,
    ) -> StrykeResult<StrykeValue> {
        #[cfg(not(unix))]
        {
            let _ = (args, line, self);
            return Ok(StrykeValue::UNDEF);
        }
        #[cfg(unix)]
        {
            let name = args
                .first()
                .ok_or_else(|| StrykeError::runtime("getprotobyname: need NAME", line))?
                .to_string();
            let cname = CString::new(name.as_bytes())
                .map_err(|_| StrykeError::runtime("getprotobyname: invalid name", line))?;
            let p = unsafe { libc::getprotobyname(cname.as_ptr()) };
            if p.is_null() {
                return Ok(StrykeValue::UNDEF);
            }
            let proto = unsafe { (*p).p_proto as i64 };
            let pname = if unsafe { (*p).p_name }.is_null() {
                name.clone()
            } else {
                unsafe { CStr::from_ptr((*p).p_name) }
                    .to_string_lossy()
                    .into_owned()
            };
            // `protoent.p_aliases` layout is platform-specific; skip walking the alias list to
            // avoid misaligned / incompatible pointer chains (e.g. macOS vs Linux).
            let aliases = String::new();
            if matches!(self.wantarray_kind, WantarrayCtx::List) {
                return Ok(StrykeValue::array(vec![
                    StrykeValue::string(pname),
                    StrykeValue::string(aliases),
                    StrykeValue::integer(proto),
                ]));
            }
            Ok(StrykeValue::integer(proto))
        }
    }

    pub(crate) fn builtin_getservbyname(
        &mut self,
        args: &[StrykeValue],
        line: usize,
    ) -> StrykeResult<StrykeValue> {
        #[cfg(not(unix))]
        {
            let _ = (args, line, self);
            return Ok(StrykeValue::UNDEF);
        }
        #[cfg(unix)]
        {
            let serv = args
                .first()
                .ok_or_else(|| StrykeError::runtime("getservbyname: need SERVICE", line))?
                .to_string();
            let proto = args
                .get(1)
                .ok_or_else(|| StrykeError::runtime("getservbyname: need PROTOCOL", line))?
                .to_string();
            let cs = CString::new(serv.as_bytes())
                .map_err(|_| StrykeError::runtime("getservbyname: invalid service name", line))?;
            let cp = CString::new(proto.as_bytes())
                .map_err(|_| StrykeError::runtime("getservbyname: invalid protocol", line))?;
            let se = unsafe { libc::getservbyname(cs.as_ptr(), cp.as_ptr()) };
            if se.is_null() {
                return Ok(StrykeValue::UNDEF);
            }
            let port_host = u16::from_be(unsafe { (*se).s_port as u16 }) as i64;
            let sname = if unsafe { (*se).s_name }.is_null() {
                serv.clone()
            } else {
                unsafe { CStr::from_ptr((*se).s_name) }
                    .to_string_lossy()
                    .into_owned()
            };
            let aliases = String::new();
            let protonum = unsafe {
                let p = libc::getprotobyname(cp.as_ptr());
                if p.is_null() {
                    0
                } else {
                    (*p).p_proto as i64
                }
            };
            if matches!(self.wantarray_kind, WantarrayCtx::List) {
                return Ok(StrykeValue::array(vec![
                    StrykeValue::string(sname),
                    StrykeValue::string(aliases),
                    StrykeValue::integer(port_host),
                    StrykeValue::integer(protonum),
                ]));
            }
            Ok(StrykeValue::integer(port_host))
        }
    }

    #[cfg(unix)]
    fn socket_raw_fd(&self, fh: &str) -> Option<libc::c_int> {
        self.socket_handles.get(fh).map(|s| match s {
            StrykeSocket::Stream(sock) => sock.as_raw_fd(),
            StrykeSocket::Listener(l) => l.as_raw_fd(),
            StrykeSocket::Udp(u) => u.as_raw_fd(),
        })
    }

    pub(crate) fn builtin_setsockopt(
        &mut self,
        args: &[StrykeValue],
        line: usize,
    ) -> StrykeResult<StrykeValue> {
        #[cfg(not(unix))]
        {
            let _ = (args, line, self);
            return Err(StrykeError::runtime(
                "setsockopt: not available on this platform",
                line,
            ));
        }
        #[cfg(unix)]
        {
            if args.len() < 4 {
                return Err(StrykeError::runtime(
                    "setsockopt: need SOCK, LEVEL, OPTNAME, OPTVAL",
                    line,
                ));
            }
            let fh = args[0].to_string();
            let level = args[1].to_int() as libc::c_int;
            let optname = args[2].to_int() as libc::c_int;
            let payload = sockopt_payload(&args[3]);
            let fd = self.socket_raw_fd(&fh).ok_or_else(|| {
                StrykeError::runtime(format!("setsockopt: not a socket {}", fh), line)
            })?;
            let r = unsafe {
                libc::setsockopt(
                    fd,
                    level,
                    optname,
                    payload.as_ptr().cast(),
                    payload.len() as libc::socklen_t,
                )
            };
            if r != 0 {
                return Ok(StrykeValue::integer(0));
            }
            Ok(StrykeValue::integer(1))
        }
    }

    pub(crate) fn builtin_getsockopt(
        &mut self,
        args: &[StrykeValue],
        line: usize,
    ) -> StrykeResult<StrykeValue> {
        #[cfg(not(unix))]
        {
            let _ = (args, line, self);
            return Err(StrykeError::runtime(
                "getsockopt: not available on this platform",
                line,
            ));
        }
        #[cfg(unix)]
        {
            if args.len() < 3 {
                return Err(StrykeError::runtime(
                    "getsockopt: need SOCK, LEVEL, OPTNAME",
                    line,
                ));
            }
            let fh = args[0].to_string();
            let level = args[1].to_int() as libc::c_int;
            let optname = args[2].to_int() as libc::c_int;
            let fd = self.socket_raw_fd(&fh).ok_or_else(|| {
                StrykeError::runtime(format!("getsockopt: not a socket {}", fh), line)
            })?;
            let mut buf = vec![0u8; 256];
            let mut len = buf.len() as libc::socklen_t;
            let r =
                unsafe { libc::getsockopt(fd, level, optname, buf.as_mut_ptr().cast(), &mut len) };
            if r != 0 {
                return Ok(StrykeValue::UNDEF);
            }
            buf.truncate(len as usize);
            Ok(StrykeValue::bytes(Arc::new(buf)))
        }
    }

    pub(crate) fn builtin_getpeername(
        &mut self,
        args: &[StrykeValue],
        line: usize,
    ) -> StrykeResult<StrykeValue> {
        #[cfg(not(unix))]
        {
            let _ = (args, line, self);
            return Err(StrykeError::runtime(
                "getpeername: not available on this platform",
                line,
            ));
        }
        #[cfg(unix)]
        {
            let fh = args
                .first()
                .ok_or_else(|| StrykeError::runtime("getpeername: need SOCK", line))?
                .to_string();
            let fd = self.socket_raw_fd(&fh).ok_or_else(|| {
                StrykeError::runtime(format!("getpeername: not a socket {}", fh), line)
            })?;
            let mut storage: libc::sockaddr_storage = unsafe { std::mem::zeroed() };
            let mut len = std::mem::size_of::<libc::sockaddr_storage>() as libc::socklen_t;
            let r = unsafe {
                libc::getpeername(
                    fd,
                    (&mut storage as *mut libc::sockaddr_storage).cast(),
                    &mut len,
                )
            };
            if r != 0 {
                return Ok(StrykeValue::UNDEF);
            }
            let bytes = unsafe {
                std::slice::from_raw_parts(
                    (&storage as *const libc::sockaddr_storage).cast(),
                    len as usize,
                )
            };
            Ok(StrykeValue::bytes(Arc::new(bytes.to_vec())))
        }
    }

